-- Poems batch 450
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-22','送張郎中副使自南省赴鳳翔府幕','羊士諤','唐','御定全唐诗','yuding','','[]','仙郎佐氏謀，廷議寵元侯。城郭須來貢，河隍亦順流。',48,'御定全唐詩/json/332.json','["仙郎佐氏謀，廷議寵元侯。城郭須來貢，河隍亦順流。", "亞夫高壘靜，充國大田秋。當奮燕然筆，銘功向隴頭。"]'),
('yuding-23','和竇吏部雪中寓直','羊士諤','唐','御定全唐诗','yuding','','[]','瑞花飄朔雪，灝氣滿南宮。迢遞層城掩，徘徊午夜中。',48,'御定全唐詩/json/332.json','["瑞花飄朔雪，灝氣滿南宮。迢遞層城掩，徘徊午夜中。", "金閨通籍恨，銀燭直廬空。誰問烏台客，家山憶桂叢。"]'),
('yuding-24','小園春至偶呈吏部竇郎中','羊士諤','唐','御定全唐诗','yuding','','[]','松筱雖苦節，冰霜慘其間。欣然發佳色，如喜東風還。',96,'御定全唐詩/json/332.json','["松筱雖苦節，冰霜慘其間。欣然發佳色，如喜東風還。", "幽抱想前躅，冥鴻度南山。春台一以眺，達士亦解顏。", "偃息非老圃，沉吟閟玄關。馳暉忽複失，壯氣不得閒。", "君子當濟物，丹梯誰共攀。心期自有約，去掃蒼苔斑。"]'),
('yuding-25','酬吏部竇郎中直夜見寄','羊士諤','唐','御定全唐诗','yuding','','[]','解巾侍雲陛，三命早為郎。複以雕龍彩，旋歸振鷺行。',48,'御定全唐詩/json/332.json','["解巾侍雲陛，三命早為郎。複以雕龍彩，旋歸振鷺行。", "玉書期養素，金印已懷黃。茲夕南宮詠，遐情愧不忘。"]'),
('yuding-26','永寧裏園亭休沐悵然成詠','羊士諤','唐','御定全唐诗','yuding','','[]','雲景含初夏，休歸曲陌深。幽簾宜永日，珍樹始清陰。',72,'御定全唐詩/json/332.json','["雲景含初夏，休歸曲陌深。幽簾宜永日，珍樹始清陰。", "遲客唯長簟，忘言有匣琴。畫披靈物態，書見古人心。", "芳草多留步，鮮飆自滿襟。勞形非立事，瀟灑愧頭簪。"]'),
('yuding-27','登樂游原寄司封孟郎中盧補闕','羊士諤','唐','御定全唐诗','yuding','','[]','爽節時清眺，秋懷悵獨過。神皋值宿雨，曲水已增波。',48,'御定全唐詩/json/332.json','["爽節時清眺，秋懷悵獨過。神皋值宿雨，曲水已增波。", "白鳥淩風迥，紅蕖濯露多。伊川有歸思，君子複如何。"]'),
('yuding-28','乾元初嚴黃門自京兆少尹貶牧巴郡以長才英氣固多暇日每遊郡之東山山側精舍有盤石細泉疏為浮杯之勝苔深樹老蒼然遺躅士諤謬因出守得繼茲賞乃賦詩十四韻刻於石壁','羊士諤','唐','御定全唐诗','yuding','','[]','石座雙峰古，雲泉九曲深。寂寥疏鑿意，蕪沒歲時侵。',168,'御定全唐詩/json/332.json','["石座雙峰古，雲泉九曲深。寂寥疏鑿意，蕪沒歲時侵。", "繞席流還壅，浮杯咽複沉。追懷王謝侶，更似會稽岑。", "誰謂天池翼，相期宅畔吟。光輝輕尺璧，然諾重黃金。", "幾醉東山妓，長懸北闕心。蕙蘭留雜佩，桃李想華簪。", "閉閣余何事，鳴騶亦屢尋。軒裳遵往轍，風景憩中林。", "橫吹多淒調，安歌送好音。初筵方側弁，故老忽沾襟。", "盛世當弘濟，平生諒所欽。無能愧陳力，惆悵拂瑤琴。"]'),
('yuding-29','閑齋示一二道者','羊士諤','唐','御定全唐诗','yuding','','[]','幽蘭誰複奏，閑匣以端憂。知止慚先覺，歸歟想故侯。',48,'御定全唐詩/json/332.json','["幽蘭誰複奏，閑匣以端憂。知止慚先覺，歸歟想故侯。", "山蟬鈴閣晚，江雨麥田秋。唯有空門學，相期老一丘。"]'),
('yuding-30','南池荷花','羊士諤','唐','御定全唐诗','yuding','','[]','蟬噪城溝水，芙蓉忽已繁。紅花迷越豔，芳意過湘沅。',48,'御定全唐詩/json/332.json','["蟬噪城溝水，芙蓉忽已繁。紅花迷越豔，芳意過湘沅。", "湛露宜清暑，披香正滿軒。朝朝只自賞，穠李亦何言。"]'),
('yuding-31','郡中玩月，寄江南李少尹虞部孟員外三首','羊士諤','唐','御定全唐诗','yuding','','[]','月滿自高丘，江通無狹流。軒窗開到曉，風物坐含秋。',144,'御定全唐詩/json/332.json','["月滿自高丘，江通無狹流。軒窗開到曉，風物坐含秋。", "鵲警銀河斷，蛩悲翠幕幽。清光望不極，耿耿下西樓。", "桂華臨洛浦，如挹李膺仙。茲夕披雲望，還吟擲地篇。", "鳳池分直夜，牛渚泛舟年。會是風流賞，惟君內史賢。", "圓景曠佳賓，徘徊夜漏頻。金波徒泛酒，瑤瑟已生塵。", "露白移長簟，風清掛幅巾。西園舊才子，想見洛陽人。"]'),
('yuding-32','城隍廟賽雨二首','羊士諤','唐','御定全唐诗','yuding','','[]','零雨慰斯人，齋心薦綠蘋。山風簫鼓響，如祭敬亭神。',48,'御定全唐詩/json/332.json','["零雨慰斯人，齋心薦綠蘋。山風簫鼓響，如祭敬亭神。", "積潤通千里，推誠奠一卮。回飆經畫壁，忽似偃雲旗。"]'),
('yuding-33','郡樓晴望二首','羊士諤','唐','御定全唐诗','yuding','','[]','霽色朝雲盡，亭皋露亦晞。褰開臨曲檻，蕭瑟換輕衣。',96,'御定全唐詩/json/332.json','["霽色朝雲盡，亭皋露亦晞。褰開臨曲檻，蕭瑟換輕衣。", "地遠秦人望，天晴社燕飛。無功慚歲晚，唯念故山歸。", "一雨晴山郭，驚秋碧樹風。蘭卮誰與薦，玉旆自無悰。", "雲景嘶賓雁，嵐陰露彩虹。閑吟懶閉閣，旦夕郡樓中。"]'),
('yuding-34','初移琪樹','羊士諤','唐','御定全唐诗','yuding','','[]','愛此丘中物，煙霜盡日看。無窮碧雲意，更助綠窗寒。',24,'御定全唐詩/json/332.json','["愛此丘中物，煙霜盡日看。無窮碧雲意，更助綠窗寒。"]'),
('yuding-35','燕居','羊士諤','唐','御定全唐诗','yuding','','[]','秋齋膏沐暇，旭日照軒墀。露重芭蕉葉，香凝橘柚枝。',48,'御定全唐詩/json/332.json','["秋齋膏沐暇，旭日照軒墀。露重芭蕉葉，香凝橘柚枝。", "簡書隨吏散，寶騎與僧期。報國得何力，流年已覺衰。"]'),
('yuding-36','寄黔府竇中丞','羊士諤','唐','御定全唐诗','yuding','','[]','漢臣旌節貴，萬里護牂牁。夏月天無暑，秋風水不波。',48,'御定全唐詩/json/332.json','["漢臣旌節貴，萬里護牂牁。夏月天無暑，秋風水不波。", "朝衣蟠艾綬，戎幕偃雕戈。滿歲歸龍闕，良哉佇作歌。"]'),
('yuding-37','書樓懷古','羊士諤','唐','御定全唐诗','yuding','','[]','何獨文翁化，風流與代深。泉雲無舊轍，騷雅有遺音。',48,'御定全唐詩/json/332.json','["何獨文翁化，風流與代深。泉雲無舊轍，騷雅有遺音。", "遠目窮巴漢，閒情閱古今。忘言意不極，日暮但橫琴。"]'),
('yuding-38','九月十日郡樓獨酌','羊士諤','唐','御定全唐诗','yuding','','[]','掾史當授衣，郡中稀物役。嘉辰悵已失，殘菊誰為惜。',72,'御定全唐詩/json/332.json','["掾史當授衣，郡中稀物役。嘉辰悵已失，殘菊誰為惜。", "欞軒一尊泛，天景洞虛碧。暮節獨賞心，寒江鳴湍石。", "歸期北州裏，舊友東山客。飄蕩雲海深，相思桂花白。"]'),
('yuding-39','暮秋言懷','羊士諤','唐','御定全唐诗','yuding','','[]','城隅凝彩畫，紅樹帶青山。遲客金尊晚，談空玉柄閑。',48,'御定全唐詩/json/332.json','["城隅凝彩畫，紅樹帶青山。遲客金尊晚，談空玉柄閑。", "馳暉三峽水，旅夢百勞關。非是淮陽薄，丘中只望還。"]'),
('yuding-40','題枇杷樹','羊士諤','唐','御定全唐诗','yuding','','[]','珍樹寒始花，氛氳九秋月。佳期若有待，芳意常無絕。',48,'御定全唐詩/json/332.json','["珍樹寒始花，氛氳九秋月。佳期若有待，芳意常無絕。", "嫋嫋碧海風，濛濛綠枝雪。急景自餘妍，春禽幸流悅。"]'),
('yuding-41','上元日紫極宮門觀州民然燈張樂','羊士諤','唐','御定全唐诗','yuding','','[]','山郭通衢隘，瑤壇紫府深。燈花助春意，舞綬織歡心。',48,'御定全唐詩/json/332.json','["山郭通衢隘，瑤壇紫府深。燈花助春意，舞綬織歡心。", "閑似淮陽臥，恭聞樂職吟。唯將聖明化，聊以達飛沉。"]'),
('yuding-42','西郊蘭若','羊士諤','唐','御定全唐诗','yuding','','[]','雲天宜北戶，塔廟似西方。林下僧無事，江清日複長。',48,'御定全唐詩/json/332.json','["雲天宜北戶，塔廟似西方。林下僧無事，江清日複長。", "石泉盈掬冷，山實滿枝香。寂寞傳心印，玄言亦已忘。"]'),
('yuding-43','在郡三年，今秋見白髮，聊以書事','羊士諤','唐','御定全唐诗','yuding','','[]','二毛非騎省，朝鏡忽秋風。絲縷寒衣上，霜華舊簡中。',48,'御定全唐詩/json/332.json','["二毛非騎省，朝鏡忽秋風。絲縷寒衣上，霜華舊簡中。", "承明那足厭，車服愧無功。日日山城守，淹留岩桂叢。"]'),
('yuding-44','郡中端居，有懷袁州王員外使君','羊士諤','唐','御定全唐诗','yuding','','[]','憶作同門友，承明奉直廬。禁闈人自異，休浣跡非疏。',144,'御定全唐詩/json/332.json','["憶作同門友，承明奉直廬。禁闈人自異，休浣跡非疏。", "珥筆金華殿，三朝玉璽書。恩光榮侍從，文彩應符徐。", "青眼真知我，玄談愧起予。蘭卮招促膝，松砌引長裾。", "麗日流鶯早，涼天墜露初。前山臨紫閣，曲水眺紅蕖。", "誰為音塵曠，俄驚歲月除。風波移故轍，符守忽離居。", "濟物陰功在，分憂盛業餘。弱翁方大用，延首遲雙魚。"]'),
('yuding-45','山寺題壁','羊士諤','唐','御定全唐诗','yuding','','[]','物外真何事，幽廊步不窮。一燈心法在，三世影堂空。',48,'御定全唐詩/json/332.json','["物外真何事，幽廊步不窮。一燈心法在，三世影堂空。", "山果青苔上，寒蟬落葉中。歸來還閉閣，棠樹幾秋風。"]'),
('yuding-46','暇日適值澄霽江亭遊宴','羊士諤','唐','御定全唐诗','yuding','','[]','碧落風如洗，清光鏡不分。弦歌方對酒，山谷盡無雲。',48,'御定全唐詩/json/332.json','["碧落風如洗，清光鏡不分。弦歌方對酒，山谷盡無雲。", "振臥淮陽病，悲秋宋玉文。今來強攜妓，醉舞石榴裙。"]'),
('yuding-47','玩槿花','羊士諤','唐','御定全唐诗','yuding','','[]','何乃詩人興，妍詞屬舜華。風流感異代，窈窕比同車。',48,'御定全唐詩/json/332.json','["何乃詩人興，妍詞屬舜華。風流感異代，窈窕比同車。", "凝豔垂清露，驚秋隔絳紗。蟬鳴複蟲思，惆悵竹陰斜。"]'),
('yuding-48','郡齋讀經','羊士諤','唐','御定全唐诗','yuding','','[]','壯齡非濟物，柔翰誤為儒。及此齋心暇，翛然與道俱。',144,'御定全唐詩/json/332.json','["壯齡非濟物，柔翰誤為儒。及此齋心暇，翛然與道俱。", "散材誠獨善，正覺豈無徒。半偈蓮生水，幽香桂滿爐。", "息陰慚蔽芾，講義得醍醐。跡似桃源客，身攖竹使符。", "華夷參吏事，巴漢混州圖。偃草懷君子，移風念嗇夫。", "翳桑俄有績，宿麥複盈租。圓寂期超詣，凋殘幸已蘇。", "解空囊不智，滅景谷何愚。幾日遵歸轍，東菑殆欲蕪。"]'),
('yuding-49','州民自言巴士冬溼且多陰晦今茲晴朗苦寒霜頗甚故老咸異之因示寮吏','羊士諤','唐','御定全唐诗','yuding','','[]','雨霜以成歲，看舊感前聞。愛景隨朝日，凝陰積暮雲。',48,'御定全唐詩/json/332.json','["雨霜以成歲，看舊感前聞。愛景隨朝日，凝陰積暮雲。", "□□□□□，忘言酒暫醺。□□□□□，□□□□□。"]'),
('yuding-50','齋中有獸皮茵偶成詠','羊士諤','唐','御定全唐诗','yuding','','[]','逸才豈凡獸，服猛愚人得。山澤生異姿，蒙戎蔚佳色。',48,'御定全唐詩/json/332.json','["逸才豈凡獸，服猛愚人得。山澤生異姿，蒙戎蔚佳色。", "青氈持與藉，重錦裁為飾。臥閣幸相宜，溫然承宴息。"]'),
('yuding-51','野夫采鞭於東山偶得元者','羊士諤','唐','御定全唐诗','yuding','','[]','追風豈無策，持斧有遐想。鳳去留孤根，岩懸非朽壤。',48,'御定全唐詩/json/332.json','["追風豈無策，持斧有遐想。鳳去留孤根，岩懸非朽壤。", "苔斑自天生，玉節垂雲長。勿謂山之幽，丹梯亦可上。"]'),
('yuding-52','守郡累年俄及知命聊以言志','羊士諤','唐','御定全唐诗','yuding','','[]','南國疑逋客，東山作老夫。登朝非大隱，出穀是真愚。',48,'御定全唐詩/json/332.json','["南國疑逋客，東山作老夫。登朝非大隱，出穀是真愚。", "氣直慚龍劍，心清愛玉壺。聊持循吏傳，早晚□為徒。"]'),
('yuding-53','東渡早梅一樹，歲華如雪，酣賞成詠','羊士諤','唐','御定全唐诗','yuding','','[]','暇日留□事，期雲亦□開。鄉心持歲酒，津下賞山梅。',48,'御定全唐詩/json/332.json','["暇日留□事，期雲亦□開。鄉心持歲酒，津下賞山梅。", "晚實和商鼎，濃香拂壽杯。唯應招北客，日日踏青來。"]'),
('yuding-54','題郡南山光福寺即嚴黃門所置時自給事中京兆少尹出守年三十性樂山水故老云每旬數至後分閫川州門有去思碑即郄拾遺之詞也','羊士諤','唐','御定全唐诗','yuding','','[]','傳聞黃閣守，茲地賦長沙。少壯稱時傑，功名惜歲華。',72,'御定全唐詩/json/332.json','["傳聞黃閣守，茲地賦長沙。少壯稱時傑，功名惜歲華。", "岩廊初建刹，賓從亟鳴笳。玉帳空嚴道，甘棠見野花。", "碑殘猶墮淚，城古自歸鴉。籍籍清風在，懷人諒不遐。"]'),
('yuding-55','雨中寒食','羊士諤','唐','御定全唐诗','yuding','','[]','令節逢煙雨，園亭但掩關。佳人宿妝薄，芳樹彩繩閑。',48,'御定全唐詩/json/332.json','["令節逢煙雨，園亭但掩關。佳人宿妝薄，芳樹彩繩閑。", "歸思偏消酒，春寒為近山。花枝不可見，別恨灞陵間。"]'),
('yuding-56','晚夏郡中臥疾','羊士諤','唐','御定全唐诗','yuding','','[]','事外心如寄，虛齋臥更幽。微風生白羽，畏日隔青油。',48,'御定全唐詩/json/332.json','["事外心如寄，虛齋臥更幽。微風生白羽，畏日隔青油。", "用拙懷歸去，沉痾畏借留。東山自有計，蓬鬢莫先秋。"]'),
('yuding-57','酬盧司門晚夏過永甯裏弊居林亭見寄','羊士諤','唐','御定全唐诗','yuding','','[]','自歎淮陽臥，誰知去國心。幽亭來北戶，高韻得南金。',48,'御定全唐詩/json/332.json','["自歎淮陽臥，誰知去國心。幽亭來北戶，高韻得南金。", "苔甃窺泉少，籃輿愛竹深。風蟬一清暑，應喜脫朝簪。"]'),
('yuding-58','山郭風雨朝霽悵然秋思','羊士諤','唐','御定全唐诗','yuding','','[]','桐竹離披曉，涼風似故園。驚秋對旭日，感物坐前軒。',48,'御定全唐詩/json/332.json','["桐竹離披曉，涼風似故園。驚秋對旭日，感物坐前軒。", "江燕飛還盡，山榴落尚繁。平生信有意，衰久已忘言。"]'),
('yuding-59','南館林塘','羊士諤','唐','御定全唐诗','yuding','','[]','郡閣山斜對，風煙隔短牆。清池如寫月，珍樹盡淩霜。',48,'御定全唐詩/json/332.json','["郡閣山斜對，風煙隔短牆。清池如寫月，珍樹盡淩霜。", "行樂知無悶，加餐頗自強。心期空歲晚，魚意久相忘。"]'),
('yuding-60','臘夜對酒','羊士諤','唐','御定全唐诗','yuding','','[]','琥珀杯中物，瓊枝席上人。樂聲方助醉，燭影已含春。',48,'御定全唐詩/json/332.json','["琥珀杯中物，瓊枝席上人。樂聲方助醉，燭影已含春。", "自顧行將老，何辭坐達晨。傳觴稱厚德，不問吐車茵。"]'),
('yuding-61','池上構小山詠懷','羊士諤','唐','御定全唐诗','yuding','','[]','玉立出岩石，風清曲□□。偶成聊近意，靜對想凝神。',48,'御定全唐詩/json/332.json','["玉立出岩石，風清曲□□。偶成聊近意，靜對想凝神。", "牛渚中流月，蘭亭上道春。古來心可見，寂寞為斯人。"]'),
('yuding-62','林塘臘候','羊士諤','唐','御定全唐诗','yuding','','[]','南國冰霜晚，年華已暗歸。閑招別館客，遠念故山薇。',48,'御定全唐詩/json/332.json','["南國冰霜晚，年華已暗歸。閑招別館客，遠念故山薇。", "野艇虛還觸，籠禽倦更飛。忘言亦何事，酣賞步清輝。"]'),
('yuding-63','酬禮部崔員外備獨永寧里弊居見寄來詩云圖書鎖塵閣符節守山城','羊士諤','唐','御定全唐诗','yuding','','[]','守土親巴俗，腰章□漢儀。春行樂職詠，秋感伴牢詞。',48,'御定全唐詩/json/332.json','["守土親巴俗，腰章□漢儀。春行樂職詠，秋感伴牢詞。", "舊裏藏舊閣，閑門閉槿籬。遙慚退朝客，下馬獨相思。"]'),
('yuding-64','梁國惠康公主挽歌詞二首','羊士諤','唐','御定全唐诗','yuding','','[]','湯沐成陳跡，山林遂寂寥。鵲飛應織素，鳳起獨吹簫。',96,'御定全唐詩/json/332.json','["湯沐成陳跡，山林遂寂寥。鵲飛應織素，鳳起獨吹簫。", "玉殿中參罷，雲輧上漢遙。皇情非不極，空輟未央朝。", "授冊榮天使，陳詩感聖恩。山河啟梁國，縞素及於門。", "泉向金卮咽，霜來玉樹繁。都人聽哀挽，淚盡望寒原。"]'),
('yuding-65','南池晨望','羊士諤','唐','御定全唐诗','yuding','','[]','起來林上月，瀟灑故人情。鈴閣人何事，蓮塘曉獨行。',48,'御定全唐詩/json/332.json','["起來林上月，瀟灑故人情。鈴閣人何事，蓮塘曉獨行。", "衣沾竹露爽，茶對石泉清。鼓吹前賢薄，群蛙試一鳴。"]'),
('yuding-66','林館避暑','羊士諤','唐','御定全唐诗','yuding','','[]','池島清陰裏，無人泛酒船。山蜩金奏響，荷露水精圓。',48,'御定全唐詩/json/332.json','["池島清陰裏，無人泛酒船。山蜩金奏響，荷露水精圓。", "靜勝朝還暮，幽觀白已玄。家林正如此，何事賦歸田。"]'),
('yuding-67','巴南郡齋雨中偶看長曆是日小雪有懷昔年朝謁因成八韻','羊士諤','唐','御定全唐诗','yuding','','[]','夷落朝雲候，王正小雪辰。緬懷朝紫陌，曾是灑朱輪。',96,'御定全唐詩/json/332.json','["夷落朝雲候，王正小雪辰。緬懷朝紫陌，曾是灑朱輪。", "氣耿簪裾肅，風嚴刻漏頻。暗飛金馬仗，寒舞玉京塵。", "豸角隨中憲，龍池列近臣。蕊珠凝瑞彩，懸圃淨華茵。", "帝澤千箱慶，天顏萬物春。明廷猶咫尺，高詠愧巴人。"]'),
('yuding-68','褒城驛池塘玩月','羊士諤','唐','御定全唐诗','yuding','','[]','夜長秋始半，圓景麗銀河。北渚清光溢，西山爽氣多。',48,'御定全唐詩/json/332.json','["夜長秋始半，圓景麗銀河。北渚清光溢，西山爽氣多。", "鶴飛聞墜露，魚戲見增波。千里家林望，涼飆換綠蘿。"]'),
('yuding-69','資陽郡中詠懷','羊士諤','唐','御定全唐诗','yuding','','[]','腰章非達士，閉閣是潛夫。匣劍寧求試，籠禽但自拘。',48,'御定全唐詩/json/332.json','["腰章非達士，閉閣是潛夫。匣劍寧求試，籠禽但自拘。", "江清牛渚鎮，酒熟步兵廚。唯此前賢意，風流似不孤。"]'),
('yuding-70','寒食宴城北山池，即故郡守榮陽鄭鋼目為折柳亭','羊士諤','唐','御定全唐诗','yuding','','[]','別館青山郭，遊人折柳行。落花經上巳，細雨帶清明。',48,'御定全唐詩/json/332.json','["別館青山郭，遊人折柳行。落花經上巳，細雨帶清明。", "鶗鴂流芳暗，鴛鴦曲水平。歸心何處醉，寶瑟有餘聲。"]'),
('yuding-71','酬彭州蕭使君秋中言懷','羊士諤','唐','御定全唐诗','yuding','','[]','右職移青綬，雄藩拜紫泥。江回玉壘下，氣爽錦城西。',48,'御定全唐詩/json/332.json','["右職移青綬，雄藩拜紫泥。江回玉壘下，氣爽錦城西。", "皋鶴驚秋律，琴烏怨夜啼。離居同舍念，宿昔奉金閨。"]'),
('yuding-72','資中早春','羊士諤','唐','御定全唐诗','yuding','','[]','一雨東風晚，山鶯獨報春。淹留巫峽夢，惆悵洛陽人。',48,'御定全唐詩/json/332.json','["一雨東風晚，山鶯獨報春。淹留巫峽夢，惆悵洛陽人。", "柳意籠丹檻，梅香覆錦茵。年華行可惜，瑤瑟莫生塵。"]'),
('yuding-73','郡樓懷長安親友','羊士諤','唐','御定全唐诗','yuding','','[]','殘暑三巴地，沉陰八月天。氣昏高閣雨，夢倦下簾眠。',48,'御定全唐詩/json/332.json','["殘暑三巴地，沉陰八月天。氣昏高閣雨，夢倦下簾眠。", "愁鬢華簪小，歸心社燕前。相思杜陵野，溝水獨潺湲。"]'),
('yuding-74','王起居獨遊青龍寺玩紅葉因寄','羊士諤','唐','御定全唐诗','yuding','','[]','十畝蒼苔繞畫廊，幾株紅樹過清霜。',32,'御定全唐詩/json/332.json','["十畝蒼苔繞畫廊，幾株紅樹過清霜。", "高情還似看花去，閑對南山步夕陽。"]'),
('yuding-75','夜聽琵琶三首','羊士諤','唐','御定全唐诗','yuding','','[]','掩抑危弦咽又通，朔雲邊月想朦朧。',96,'御定全唐詩/json/332.json','["掩抑危弦咽又通，朔雲邊月想朦朧。", "當時誰佩將軍印，長使蛾眉怨不窮。", "一曲徘徊星漢稀，夜蘭幽怨重依依。", "忽似摐金來上馬，南枝棲鳥盡驚飛。", "破撥聲繁恨已長，低鬟斂黛更摧藏。", "潺湲隴水聽難盡，並覺風沙繞杏梁。"]'),
('yuding-76','彭州蕭使君出妓夜宴見送','羊士諤','唐','御定全唐诗','yuding','','[]','玉顏紅燭忽驚春，微步淩波暗拂塵。',32,'御定全唐詩/json/332.json','["玉顏紅燭忽驚春，微步淩波暗拂塵。", "自是當歌斂眉黛，不因惆悵為行人。"]'),
('yuding-77','題松江館','羊士諤','唐','御定全唐诗','yuding','','[]','津柳江風白浪平，棹移高館古今情。',32,'御定全唐詩/json/332.json','["津柳江風白浪平，棹移高館古今情。", "扁舟一去鴟夷子，應笑分符計日程。"]'),
('yuding-78','偶題寄獨孤使君','羊士諤','唐','御定全唐诗','yuding','','[]','病起淮陽自有時，秋來未覺長年悲。',32,'御定全唐詩/json/332.json','["病起淮陽自有時，秋來未覺長年悲。", "坐逢在日唯相望，嫋嫋涼風滿桂枝。"]'),
('yuding-79','永寧裏小園與沈校書接近，悵然題寄','羊士諤','唐','御定全唐诗','yuding','','[]','故里心期奈別何，手移芳樹憶庭柯。',32,'御定全唐詩/json/332.json','["故里心期奈別何，手移芳樹憶庭柯。", "東皋黍熟君應醉，梨葉初紅白露多。"]'),
('yuding-80','齋中詠懷','羊士諤','唐','御定全唐诗','yuding','','[]','無心唯有白雲知，閑臥高齋夢蝶時。',32,'御定全唐詩/json/332.json','["無心唯有白雲知，閑臥高齋夢蝶時。", "不覺東風過寒食，雨來萱草出巴籬。"]'),
('yuding-81','登郡前山','羊士諤','唐','御定全唐诗','yuding','','[]','洛陽歸客滯巴東，處處山櫻雪滿叢。',32,'御定全唐詩/json/332.json','["洛陽歸客滯巴東，處處山櫻雪滿叢。", "峴首當時為風景，豈將官舍作池籠。"]'),
('yuding-82','客有自渠州來說常諫議使君故事，悵然成詠','羊士諤','唐','御定全唐诗','yuding','','[]','才子長沙暫左遷，能將意氣慰當年。',32,'御定全唐詩/json/332.json','["才子長沙暫左遷，能將意氣慰當年。", "至今猶有東山妓，長使歌詩被管弦。"]'),
('yuding-83','春日朝罷呈台中寮友','羊士諤','唐','御定全唐诗','yuding','','[]','退食鵷行振羽儀，九霄雙闕迥參差。雲披彩仗春風度，',40,'御定全唐詩/json/332.json','["退食鵷行振羽儀，九霄雙闕迥參差。雲披彩仗春風度，", "時清執法慚無事，未有長楊漢主知。"]'),
('yuding-84','州民有獻杏者，瑰麗溢目，因感花未幾，聊以成詠','羊士諤','唐','御定全唐诗','yuding','','[]','南郭東風賞杏壇，幾株芳樹昨留歡。卻憶落花飄綺席，',40,'御定全唐詩/json/332.json','["南郭東風賞杏壇，幾株芳樹昨留歡。卻憶落花飄綺席，", "志士古來悲節換，美人啼鳥亦長歎。"]'),
('yuding-85','西川獨孤侍御見寄七言四韻一首為郡翰墨都捐逮此酬答誠乖拙速','羊士諤','唐','御定全唐诗','yuding','','[]','百雉層城上將壇，列營西照雪峰寒。文章立事須銘鼎，',40,'御定全唐詩/json/332.json','["百雉層城上將壇，列營西照雪峰寒。文章立事須銘鼎，", "雙金未比三千字，負弩空慚知者難。"]'),
('yuding-86','都城從事蕭員外寄海梨花詩，盡綺麗至惠然遠及','羊士諤','唐','御定全唐诗','yuding','','[]','珠履行台擁附蟬，外郎高步似神仙。陳詞今見唐風盛，',40,'御定全唐詩/json/332.json','["珠履行台擁附蟬，外郎高步似神仙。陳詞今見唐風盛，", "東山芳意須同賞，子看囊盛幾日傳。"]'),
('yuding-87','赴資陽經嶓塚山','羊士諤','唐','御定全唐诗','yuding','','[]','甯辭舊路駕朱轓，重使疲人感漢恩。',32,'御定全唐詩/json/332.json','["甯辭舊路駕朱轓，重使疲人感漢恩。", "今日鳴騶到嶓峽，還勝博望至河源。"]'),
('yuding-88','郡中言懷寄西川蕭員外','羊士諤','唐','御定全唐诗','yuding','','[]','功名無力愧勤王，已近終南得草堂。身外盡歸天竺偈，',40,'御定全唐詩/json/332.json','["功名無力愧勤王，已近終南得草堂。身外盡歸天竺偈，", "歲晚我知仙客意，懸心應在白雲鄉。"]'),
('yuding-89','郡齋感物寄長安親友','羊士諤','唐','御定全唐诗','yuding','','[]','晴天春意並無窮，過臘江樓日日風。瓊樹花香故人別，',40,'御定全唐詩/json/332.json','["晴天春意並無窮，過臘江樓日日風。瓊樹花香故人別，", "自愧朝衣猶在篋，歸來應是白頭翁。"]'),
('yuding-90','息舟荊溪，入陽羨南山，游善權寺，呈李功曹巨','羊士諤','唐','御定全唐诗','yuding','','[]','結纜蘭香渚，柴車上連岡。晏溫值初霽，去繞山河長。',120,'御定全唐詩/json/332.json','["結纜蘭香渚，柴車上連岡。晏溫值初霽，去繞山河長。", "獻歲冰雪盡，細泉生路傍。行披煙杉入，激澗橫石樑。", "層閣表精廬，飛甍切雲翔。沖襟得高步，清眺極遠方。", "潭嶂積佳氣，荑英多早芳。具觀澤國秀，重使春心傷。", "念遵煩促途，榮利騖隙光。勉君脫冠意，共匿無何鄉。"]'),
('yuding-91','亂後曲江','羊士諤','唐','御定全唐诗','yuding','','[]','憶昔曾遊曲水濱，春來長有探春人。',32,'御定全唐詩/json/332.json','["憶昔曾遊曲水濱，春來長有探春人。", "遊春人靜空地在，直至春深不似春。"]'),
('yuding-92','尋山家','羊士諤','唐','御定全唐诗','yuding','','[]','獨訪山家歇還涉，茅屋斜連隔松葉。',32,'御定全唐詩/json/332.json','["獨訪山家歇還涉，茅屋斜連隔松葉。", "主人聞語未開門，繞籬野菜飛黃蝶。"]'),
('yuding-93','寄裴校書','羊士諤','唐','御定全唐诗','yuding','','[]','登高何處見瓊枝，白露黃花自繞籬。',32,'御定全唐詩/json/332.json','["登高何處見瓊枝，白露黃花自繞籬。", "惟有樓中好山色，稻畦殘水入秋池。"]'),
('yuding-94','句','羊士諤','唐','御定全唐诗','yuding','','[]','風泉留古韻，笙磬想遺音。',73,'御定全唐詩/json/332.json','["風泉留古韻，笙磬想遺音。", "桂朽有遺馥，鶯飛安可待。", "塵沙藹如霧，長波驚飆度。雁起汀洲寒，馬嘶高城暮。", "銀釭倦秋館，綺瑟瞻永路。重有攜手期，清光倚玉樹。", "。"]'),
('yuding-0','秋夜閒居即事寄廬山鄭員外、蜀郡符處士','楊巨源','唐','御定全唐诗','yuding','','[]','憂思繁未整，良辰會無由。引領遲佳音，星紀屢以周。',96,'御定全唐詩/json/333.json','["憂思繁未整，良辰會無由。引領遲佳音，星紀屢以周。", "蓬閬絕華耀，況乃處窮愁。墜葉寒擁砌，燈火夜悠悠。", "開琴弄清弦，窺月俯澄流。冉冉鴻雁度，蕭蕭帷箔秋。", "悵懷石門詠，緬慕碧雞遊。仿佛蒙顏色，崇蘭隱芳洲。"]'),
('yuding-1','獨不見','楊巨源','唐','御定全唐诗','yuding','','[]','東風豔陽色，柳綠花如霰。競理同心鬟，爭持合歡扇。',48,'御定全唐詩/json/333.json','["東風豔陽色，柳綠花如霰。競理同心鬟，爭持合歡扇。", "香傳賈娘手，粉離何郎面。最恨捲簾時，含情獨不見。"]'),
('yuding-2','題趙孟莊','楊巨源','唐','御定全唐诗','yuding','','[]','管鮑化為塵，交友存如線。升堂俱自媚，得路難相見。',96,'御定全唐詩/json/333.json','["管鮑化為塵，交友存如線。升堂俱自媚，得路難相見。", "懿君敦三益，頹俗期一變。心同襲芝蘭，氣合回霜霰。", "石門雲臥久，玉洞花尋遍。王浚愛旌旗，梁竦勞州縣。", "煙鴻秋更遠，天馬寒愈健。願事郭先生，青囊書幾卷。"]'),
('yuding-3','辭魏博田尚書出境後，感恩戀德，因登叢台','楊巨源','唐','御定全唐诗','yuding','','[]','薦書及龍鍾，此事鏤心骨。親知殊悢悢，徒禦方咄咄。',72,'御定全唐詩/json/333.json','["薦書及龍鍾，此事鏤心骨。親知殊悢悢，徒禦方咄咄。", "叢台邯鄲郭，臺上見新月。離恨始分明，歸思更超忽。", "懷仁淚空盡，感事情又發。他時躧履聲，曉日照丹闕。"]'),
('yuding-4','夏日苦熱，同長孫主簿過仁壽寺納涼','楊巨源','唐','御定全唐诗','yuding','','[]','火入天地爐，南方正何劇。四郊長雲紅，六合太陽赤。',120,'御定全唐詩/json/333.json','["火入天地爐，南方正何劇。四郊長雲紅，六合太陽赤。", "赫赫沸泉壑，焰焰焦砂石。思減祝融權，期匡諸子宅。", "因投竹林寺，一問青蓮客。心空得清涼，理證等喧寂。", "開襟天籟回，步履雨花積。微風動珠簾，惠氣入瑤席。", "境閑性方謐，塵遠趣皆適。淹駕殊未還，朱欄敞虛碧。"]'),
('yuding-5','送李虞仲秀才歸東都，因寄元李二友','楊巨源','唐','御定全唐诗','yuding','','[]','高翼閑未倦，孤雲曠無期。晴霞海西畔，秋草燕南時。',120,'御定全唐詩/json/333.json','["高翼閑未倦，孤雲曠無期。晴霞海西畔，秋草燕南時。", "鄴中多上才，耿耿丹霄姿。顧我於逆旅，與君發光儀。", "同將儒者方，獲忝攜人知。幽蘭與芳佩，寒玉鏘美詞。", "舊友在伊洛，鳴蟬思山陂。到來再春風，夢盡雙瓊枝。", "素業且無負，青冥殊未遲。南橋天氣好，脈脈一相思。"]'),
('yuding-6','和盧諫議朝回書情即事寄兩省閣老兼呈二起居諫院諸院長','楊巨源','唐','御定全唐诗','yuding','','[]','寵位資寂用，回頭憐二疏。超遙比鶴性，皎潔同僧居。',240,'御定全唐詩/json/333.json','["寵位資寂用，回頭憐二疏。超遙比鶴性，皎潔同僧居。", "華組澹無累，單床歡有餘。題詩天風灑，屬思紅霞舒。", "藹藹延合東，晨光映林初。爐香深內殿，山色明前除。", "對客默焚稿，何人知諫書。全仁氣逾勁，大辨言甚徐。", "逸步寄青瑣，閑吟親綺疏。清輝被鸞渚，瑞藹含龍渠。", "謝監營野墅，陶公愛吾廬。悠然遠者懷，聖代飄長裾。", "端弼緝元化，至音生太虛。一戎殄欃槍，重譯充儲胥。", "借地種寒竹，看雲憶春蔬。靈機棲杳冥，談笑登軒車。", "晚跡識麒麟，秋英見芙蕖。危言直且莊，曠抱鬱以攄。", "志業耿冰雪，光容粲璠璵。時賢儼仙掖，氣謝心何如。"]'),
('yuding-7','奉酬竇郎中早入省苦寒見寄','楊巨源','唐','御定全唐诗','yuding','','[]','玄冥怒含風，群物戒嚴節。空山頑石破，幽澗層冰裂。',180,'御定全唐詩/json/333.json','["玄冥怒含風，群物戒嚴節。空山頑石破，幽澗層冰裂。", "題詩金華彥，接武丹霄烈。曠懷玉京雲，孤唱粉垣雪。", "窮陰總凝冱，正氣直肅殺。天狼看墜地，霜兔敢拒穴。", "悠然蓬蒿士，亦得奉朝謁。羸驂苦遲遲，單僕怨切切。", "端闈仙階邃，廣陌凍橋滑。旭日鴛鷺行，瑞煙芙蓉闕。", "司寒申鄭重，成歲在凜冽。謝監逢酒時，袁生閉門月。", "漸思霜霰減，欲報陽和發。誰家挾纊心，何地當壚熱。", "慘舒能一改，恭聽遠者說。"]'),
('yuding-8','野園獻果呈員外','楊巨源','唐','御定全唐诗','yuding','','[]','西園果初熟，上客心逾愜。凝粉乍辭枝，飄紅仍帶葉。',48,'御定全唐詩/json/333.json','["西園果初熟，上客心逾愜。凝粉乍辭枝，飄紅仍帶葉。", "幽姿寫瓊實，殷彩呈妝頰。持此贈佳期，清芬羅袖裛。"]'),
('yuding-9','大堤曲','楊巨源','唐','御定全唐诗','yuding','','[]','二八嬋娟大堤女，開壚相對依江渚。待客登樓向水看，',72,'御定全唐詩/json/333.json','["二八嬋娟大堤女，開壚相對依江渚。待客登樓向水看，", "自傳芳酒涴紅袖，誰調妍妝回翠娥。珍簟華燈夕陽後，", "歲歲逢迎沙岸間，北人多識綠雲鬟。無端嫁與五陵少，"]'),
('yuding-10','楊花落','楊巨源','唐','御定全唐诗','yuding','','[]','北斗南回春物老，紅英落盡綠尚早。韶風澹蕩無所依，',64,'御定全唐詩/json/333.json','["北斗南回春物老，紅英落盡綠尚早。韶風澹蕩無所依，", "人家女兒出羅幕，靜掃玉庭待花落。寶環纖手捧更飛，", "東園桃李芳已歇，獨有楊花嬌暮春。"]'),
('yuding-11','月宮詞','楊巨源','唐','御定全唐诗','yuding','','[]','宮中月明何所似，如積如流滿田地。迥過前殿曾學眉，',96,'御定全唐詩/json/333.json','["宮中月明何所似，如積如流滿田地。迥過前殿曾學眉，", "藻井浮花共陵亂，玉階零露相裴回。稍映明河泛仙馭，", "皎皎蒼蒼千里同，穿煙飄葉九門通。珠簾欲卷畏成水，", "飛蓋愁看素暈低，稱觴願踏清輝遍。江上無雲夜可憐，"]'),
('yuding-12','贈從弟茂卿','楊巨源','唐','御定全唐诗','yuding','','[]','吾從驥足楊茂卿，性靈且奇才甚清。海內方微風雅道，',48,'御定全唐詩/json/333.json','["吾從驥足楊茂卿，性靈且奇才甚清。海內方微風雅道，", "王維證時符水月，杜甫狂處遺天地。流水東西岐路分，"]'),
('yuding-13','烏啼曲贈張評事','楊巨源','唐','御定全唐诗','yuding','','[]','可憐楊葉複楊花，雪淨煙深碧玉家。烏棲不定枝條弱，',24,'御定全唐詩/json/333.json','["可憐楊葉複楊花，雪淨煙深碧玉家。烏棲不定枝條弱，"]'),
('yuding-14','端午日伏蒙內侍賜晨服','楊巨源','唐','御定全唐诗','yuding','','[]','彩縷纖仍麗，淩風卷複開。方應五日至，應自九天來。',48,'御定全唐詩/json/333.json','["彩縷纖仍麗，淩風卷複開。方應五日至，應自九天來。", "在笥清光發，當軒暑氣回。遙知及時節，刀尺火雲催。"]'),
('yuding-15','胡姬詞','楊巨源','唐','御定全唐诗','yuding','','[]','妍豔照江頭，春風好客留。當壚知妾慣，送酒為郎羞。',48,'御定全唐詩/json/333.json','["妍豔照江頭，春風好客留。當壚知妾慣，送酒為郎羞。", "香渡傳蕉扇，妝成上竹樓。數錢憐皓腕，非是不能留。"]'),
('yuding-16','春日有贈','楊巨源','唐','御定全唐诗','yuding','','[]','堤暖柳絲斜，風光屬謝家。晚心應戀水，春恨定因花。',48,'御定全唐詩/json/333.json','["堤暖柳絲斜，風光屬謝家。晚心應戀水，春恨定因花。", "步遠憐芳草，歸遲見綺霞。由來感情思，獨自惜年華。"]'),
('yuding-17','襄陽樂','楊巨源','唐','御定全唐诗','yuding','','[]','閑隨少年去，試上大堤遊。畫角棲烏起，清弦過客愁。',48,'御定全唐詩/json/333.json','["閑隨少年去，試上大堤遊。畫角棲烏起，清弦過客愁。", "碑沉楚山石，珠徹漢江秋。處處風情好，盧家更上樓。"]'),
('yuding-18','關山月','楊巨源','唐','御定全唐诗','yuding','','[]','蒼茫臨故關，迢遞照秋山。萬里平蕪靜，孤城落葉閑。',48,'御定全唐詩/json/333.json','["蒼茫臨故關，迢遞照秋山。萬里平蕪靜，孤城落葉閑。", "露濃棲雁起，天遠戍兵還。複映征西府，光深組練間。"]'),
('yuding-19','長城聞笛','楊巨源','唐','御定全唐诗','yuding','','[]','孤城笛滿林，斷續共霜砧。夜月降羌淚，秋風老將心。',48,'御定全唐詩/json/333.json','["孤城笛滿林，斷續共霜砧。夜月降羌淚，秋風老將心。", "靜過寒壘遍，暗入故關深。惆悵梅花落，山川不可尋。"]'),
('yuding-20','春晚東歸留贈李功曹','楊巨源','唐','御定全唐诗','yuding','','[]','芳田岐路斜，脈脈惜年華。雲路青絲騎，香含翠幰車。',48,'御定全唐詩/json/333.json','["芳田岐路斜，脈脈惜年華。雲路青絲騎，香含翠幰車。", "歌聲仍隔水，醉色未侵花。唯有懷鄉客，東飛羨曙鴉。"]'),
('yuding-21','送殷員外使北蕃','楊巨源','唐','御定全唐诗','yuding','','[]','二軒將雨露，萬里入煙沙。和氣生中國，熏風屬外家。',48,'御定全唐詩/json/333.json','["二軒將雨露，萬里入煙沙。和氣生中國，熏風屬外家。", "塞蘆隨雁影，關柳拂駝花。努力黃雲北，仙曹有雉車。"]'),
('yuding-22','送許侍禦充雲南哀冊使判官','楊巨源','唐','御定全唐诗','yuding','','[]','萬里永昌城，威儀奉聖明。冰心瘴江冷，霜憲漏天晴。',48,'御定全唐詩/json/333.json','["萬里永昌城，威儀奉聖明。冰心瘴江冷，霜憲漏天晴。", "荒外開亭候，雲南降旆旌。他時功自許，絕域轉哀榮。"]'),
('yuding-23','秋日題陳宗儒圃亭，淒然感舊','楊巨源','唐','御定全唐诗','yuding','','[]','曾隨何水部，待月東亭宿。今日重憑欄，清風空在竹。',48,'御定全唐詩/json/333.json','["曾隨何水部，待月東亭宿。今日重憑欄，清風空在竹。", "前山依舊碧，閑草經秋綠。時物方宛然，蛛絲一何速。"]'),
('yuding-24','和鄭少師相公題慈恩寺禪院','楊巨源','唐','御定全唐诗','yuding','','[]','舊寺長桐孫，朝天是聖恩。謝公詩更老，蕭傅道方尊。',48,'御定全唐詩/json/333.json','["舊寺長桐孫，朝天是聖恩。謝公詩更老，蕭傅道方尊。", "白法知深得，蒼生要重論。若為將此望，心地向空門。"]'),
('yuding-25','同趙校書題普救寺','楊巨源','唐','御定全唐诗','yuding','','[]','東門高處天，一望幾悠然。白浪過城下，青山滿寺前。',48,'御定全唐詩/json/333.json','["東門高處天，一望幾悠然。白浪過城下，青山滿寺前。", "塵光分驛道，嵐色到人煙。氣象須文字，逢君大雅篇。"]'),
('yuding-26','春日與劉評事過故證上人院','楊巨源','唐','御定全唐诗','yuding','','[]','曾共劉諮議，同時事道林。與君方掩淚，來客是知心。',48,'御定全唐詩/json/333.json','["曾共劉諮議，同時事道林。與君方掩淚，來客是知心。", "階雪淩春積，鐘煙向夕深。依然舊童子，相送出花陰。"]'),
('yuding-27','春雪題興善寺廣宣上人竹院','楊巨源','唐','御定全唐诗','yuding','','[]','皎潔青蓮客，焚香對雪朝。竹內催淅瀝，花雨讓飄颻。',48,'御定全唐詩/json/333.json','["皎潔青蓮客，焚香對雪朝。竹內催淅瀝，花雨讓飄颻。", "觸石和雲積，縈池拂水消。只應將日月，顏色不相饒。"]'),
('yuding-28','清明日後土祠送田徹','楊巨源','唐','御定全唐诗','yuding','','[]','清明千萬家，處處是年華。榆柳芳辰火，梧桐今日花。',48,'御定全唐詩/json/333.json','["清明千萬家，處處是年華。榆柳芳辰火，梧桐今日花。", "祭祠結雲綺，遊陌擁香車。惆悵田郎去，原回煙樹斜。"]'),
('yuding-29','酬令狐員外直夜書懷見寄','楊巨源','唐','御定全唐诗','yuding','','[]','花枝暖欲舒，粉署夜方初。世職推傳盛，春刑是減餘。',48,'御定全唐詩/json/333.json','["花枝暖欲舒，粉署夜方初。世職推傳盛，春刑是減餘。", "芸香能護字，鉛槧善呈書。此地從頭白，經年望雉車。"]'),
('yuding-30','題表丈三大夫書齋','楊巨源','唐','御定全唐诗','yuding','','[]','盛府自蓮花，群公是歲華。蘭姿丈人圃，松色大夫家。',48,'御定全唐詩/json/333.json','["盛府自蓮花，群公是歲華。蘭姿丈人圃，松色大夫家。", "素卷堆瑤席，朱弦映絳紗。詩題三百首，高韻照春霞。"]'),
('yuding-31','春日送沈贊府歸潯陽覲叔父','楊巨源','唐','御定全唐诗','yuding','','[]','潯陽阮咸宅，九派竹林前。花嶼高如浪，雲峰遠似天。',48,'御定全唐詩/json/333.json','["潯陽阮咸宅，九派竹林前。花嶼高如浪，雲峰遠似天。", "江聲在南巷，海氣入東田。才子今朝去，風濤思渺然。"]'),
('yuding-32','與李文仲秀才同賦泛酒花詩','楊巨源','唐','御定全唐诗','yuding','','[]','若道春無賴，飛花合逐風。巧知人意裏，解入酒杯中。',48,'御定全唐詩/json/333.json','["若道春無賴，飛花合逐風。巧知人意裏，解入酒杯中。", "香濕勝含露，光搖似泛空。請君回首看，幾片舞芳叢。"]'),
('yuding-33','登寧州城樓','楊巨源','唐','御定全唐诗','yuding','','[]','宋玉本悲秋，今朝更上樓。清波城下去，此意重悠悠。',48,'御定全唐詩/json/333.json','["宋玉本悲秋，今朝更上樓。清波城下去，此意重悠悠。", "晚菊臨杯思，寒山滿郡愁。故關非內地，一為漢家羞。"]'),
('yuding-34','同薛侍禦登黎陽縣樓眺黃河','楊巨源','唐','御定全唐诗','yuding','','[]','倚檻恣流目，高城臨大川。九回紆白浪，一半在青天。',48,'御定全唐詩/json/333.json','["倚檻恣流目，高城臨大川。九回紆白浪，一半在青天。", "氣肅晴空外，光翻曉日邊。開襟值佳景，懷抱更悠然。"]'),
('yuding-35','和權相公南園閑涉寄廣宣上人','楊巨源','唐','御定全唐诗','yuding','','[]','浩氣抱天和，閑園載酒過。步因秋景曠，心向晚雲多。',48,'御定全唐詩/json/333.json','["浩氣抱天和，閑園載酒過。步因秋景曠，心向晚雲多。", "翠玉思回鳳，玄珠肯在鵝。問師登幾地，空性奈詩何。"]'),
('yuding-36','供奉定法師歸安南','楊巨源','唐','御定全唐诗','yuding','','[]','故鄉南越外，萬里白雲峰。經論辭天去，香花入海逢。',48,'御定全唐詩/json/333.json','["故鄉南越外，萬里白雲峰。經論辭天去，香花入海逢。", "鷺濤清梵徹，蜃閣化城重。心到長安陌，交州後夜鐘。"]'),
('yuding-37','池上竹','楊巨源','唐','御定全唐诗','yuding','','[]','一叢嬋娟色，四面清冷波。氣潤晚煙重，光閑秋露多。',48,'御定全唐詩/json/333.json','["一叢嬋娟色，四面清冷波。氣潤晚煙重，光閑秋露多。", "翠筠入疏柳，清影拂圓荷。歲晏琅玕實，心期有鳳過。"]'),
('yuding-38','長安春遊','楊巨源','唐','御定全唐诗','yuding','','[]','鳳城春報曲江頭，上客年年是勝遊。日暖雲山當廣陌，',40,'御定全唐詩/json/333.json','["鳳城春報曲江頭，上客年年是勝遊。日暖雲山當廣陌，", "桂壁朱門新邸第，漢家恩澤問酂侯。"]'),
('yuding-39','送定法師歸蜀，法師即紅樓院供奉廣宣上人兄弟','楊巨源','唐','御定全唐诗','yuding','','[]','鳳城初日照紅樓，禁寺公卿識惠休。詩引棣華沾一雨，',40,'御定全唐詩/json/333.json','["鳳城初日照紅樓，禁寺公卿識惠休。詩引棣華沾一雨，", "空性碧雲無處所，約公曾許剡溪遊。"]'),
('yuding-40','早朝','楊巨源','唐','御定全唐诗','yuding','','[]','鐘聲清禁才應徹，漏報仙闈儼已開。雙闕薄煙籠菡萏，',40,'御定全唐詩/json/333.json','["鐘聲清禁才應徹，漏報仙闈儼已開。雙闕薄煙籠菡萏，", "聖道逍遙更何事，願將巴曲贊康哉。"]'),
('yuding-41','贈張將軍','楊巨源','唐','御定全唐诗','yuding','','[]','關西諸將揖容光，獨立營門劍有霜。知愛魯連歸海上，',40,'御定全唐詩/json/333.json','["關西諸將揖容光，獨立營門劍有霜。知愛魯連歸海上，", "年少功高人最羨，漢家壇樹月蒼蒼。"]'),
('yuding-42','和侯大夫秋原山觀征人回','楊巨源','唐','御定全唐诗','yuding','','[]','兩河戰罷萬方清，原上軍回識舊營。立馬望雲秋塞靜，',40,'御定全唐詩/json/333.json','["兩河戰罷萬方清，原上軍回識舊營。立馬望雲秋塞靜，", "聖代止戈資廟略，諸侯不復更長征。"]'),
('yuding-43','送人過衛州','楊巨源','唐','御定全唐诗','yuding','','[]','憶昔征南府內遊，君家東合最淹留。縱橫聯句長侵曉，',40,'御定全唐詩/json/333.json','["憶昔征南府內遊，君家東合最淹留。縱橫聯句長侵曉，", "相思前路幾回首，滿眼青山過衛州。"]'),
('yuding-44','寄中書同年舍人','楊巨源','唐','御定全唐诗','yuding','','[]','晴明紫閣最高峰，仙掖開簾范彥龍。五色天書詞煥爛，',40,'御定全唐詩/json/333.json','["晴明紫閣最高峰，仙掖開簾范彥龍。五色天書詞煥爛，", "二十年前同日喜，碧霄何路得相逢。"]'),
('yuding-45','酬于駙馬二首','楊巨源','唐','御定全唐诗','yuding','','[]','綺陌塵香曙色分，碧山如畫又逢君。蛟藏秋月一片水，',80,'御定全唐詩/json/333.json','["綺陌塵香曙色分，碧山如畫又逢君。蛟藏秋月一片水，", "陽和本是煙霄曲，須向花間次第聞。", "芳時碧落心應斷，今日清詞事不同。瑤草秋殘仙圃在，", "長得聞詩歡自足，會看春露濕蘭叢。"]'),
('yuding-46','將歸東都寄令狐舍人','楊巨源','唐','御定全唐诗','yuding','','[]','綠楊紅杏滿城春，一騎悠悠萬井塵。岐路未關今日事，',40,'御定全唐詩/json/333.json','["綠楊紅杏滿城春，一騎悠悠萬井塵。岐路未關今日事，", "多病晚來還有策，雒陽山色舊相親。"]'),
('yuding-47','寄江州白司馬','楊巨源','唐','御定全唐诗','yuding','','[]','江州司馬平安否，惠遠東林住得無。湓浦曾聞似衣帶，',40,'御定全唐詩/json/333.json','["江州司馬平安否，惠遠東林住得無。湓浦曾聞似衣帶，", "莫謾拘牽雨花社，青雲依舊是前途。"]'),
('yuding-48','薛司空自青州歸朝','楊巨源','唐','御定全唐诗','yuding','','[]','天眷君陳久在東，歸朝人看大司空。黃河岸畔長無事，',40,'御定全唐詩/json/333.json','["天眷君陳久在東，歸朝人看大司空。黃河岸畔長無事，", "一門累葉淩煙閣，次第儀形漢上公。"]'),
('yuding-49','送章孝標校書歸杭州因寄白舍人','楊巨源','唐','御定全唐诗','yuding','','[]','曾過靈隱江邊寺，獨宿東樓看海門。潮色銀河鋪碧落，',40,'御定全唐詩/json/333.json','["曾過靈隱江邊寺，獨宿東樓看海門。潮色銀河鋪碧落，", "若訪郡人徐孺子，應須騎馬到沙村。"]'),
('yuding-50','述舊紀勳寄太原李光顏侍中二首','楊巨源','唐','御定全唐诗','yuding','','[]','玉塞含淒見雁行，北垣新詔拜龍驤。弟兄間世真飛將，',80,'御定全唐詩/json/333.json','["玉塞含淒見雁行，北垣新詔拜龍驤。弟兄間世真飛將，", "河源收地心猶壯，笑向天西萬里霜。", "倚天長劍截雲孤，報國縱橫見丈夫。五載登壇真宰相，", "料敵知機在方寸，不勞心力講陰符。"]'),
('yuding-51','酬盧員外','楊巨源','唐','御定全唐诗','yuding','','[]','謝傅旌旗控上游，盧郎樽俎借前籌。舜城風土臨清廟，',40,'御定全唐詩/json/333.json','["謝傅旌旗控上游，盧郎樽俎借前籌。舜城風土臨清廟，", "滿筵舊府笙歌在，獨有羊曇最淚流。"]'),
('yuding-52','古意贈王常侍','楊巨源','唐','御定全唐诗','yuding','','[]','繡戶紗窗北裏深，香風暗動鳳凰簪。組紃常在佳人手。',64,'御定全唐詩/json/333.json','["繡戶紗窗北裏深，香風暗動鳳凰簪。組紃常在佳人手。", "刀尺空搖寒女心。欲學齊謳逐雲管，還思楚練拂霜砧。", "東家少婦當機織，應念無衣雪滿林。"]'),
('yuding-53','送裴中丞出使','楊巨源','唐','御定全唐诗','yuding','','[]','一清淮甸假朝綱，金印初迎細柳黃。辭闕天威和雨露，',40,'御定全唐詩/json/333.json','["一清淮甸假朝綱，金印初迎細柳黃。辭闕天威和雨露，", "宣諭生靈真重任，回軒應問石渠郎。"]'),
('yuding-54','送絳州盧使君','楊巨源','唐','御定全唐诗','yuding','','[]','應將清淨結心期，又共陽和到郡時。絳老問年須算字，',40,'御定全唐詩/json/333.json','["應將清淨結心期，又共陽和到郡時。絳老問年須算字，", "他日征還作霖雨，不須求賽敬亭祠。"]'),
('yuding-55','贈李傅','楊巨源','唐','御定全唐诗','yuding','','[]','知因公望掩能文，誓激明誠在致君。曾罷雙旌瞻白日，',24,'御定全唐詩/json/333.json','["知因公望掩能文，誓激明誠在致君。曾罷雙旌瞻白日，"]'),
('yuding-56','上裴中丞','楊巨源','唐','御定全唐诗','yuding','','[]','六年西掖弘湯誥，三捷東堂總漢科。政引風霜成物色，',40,'御定全唐詩/json/333.json','["六年西掖弘湯誥，三捷東堂總漢科。政引風霜成物色，", "應笑白須揚執戟，可憐春日老如何。"]'),
('yuding-57','和人與人分惠賜冰','楊巨源','唐','御定全唐诗','yuding','','[]','天水藏來玉墮空，先頒密署幾人同。映盤皎潔非資月，',40,'御定全唐詩/json/333.json','["天水藏來玉墮空，先頒密署幾人同。映盤皎潔非資月，", "麗詞珍貺難雙有，迢遞金輿殿角東。"]'),
('yuding-58','觀打球有作','楊巨源','唐','御定全唐诗','yuding','','[]','親掃球場如砥平，龍驤驟馬曉光晴。入門百拜瞻雄勢，',40,'御定全唐詩/json/333.json','["親掃球場如砥平，龍驤驟馬曉光晴。入門百拜瞻雄勢，", "欲令四海氛煙靜，杖底纖塵不敢生。"]'),
('yuding-59','早春即事呈劉員外','楊巨源','唐','御定全唐诗','yuding','','[]','明朝晴暖即相隨，肯信春光被雨欺。且任文書堆案上，',40,'御定全唐詩/json/333.json','["明朝晴暖即相隨，肯信春光被雨欺。且任文書堆案上，", "更待雜芳成豔錦，鄴中爭唱仲宣詩。"]'),
('yuding-60','送司徒童子','楊巨源','唐','御定全唐诗','yuding','','[]','衛多君子魯多儒，七歲聞天笑舞雩。光彩春風初轉蕙，',40,'御定全唐詩/json/333.json','["衛多君子魯多儒，七歲聞天笑舞雩。光彩春風初轉蕙，", "況複元侯旌爾善，桂林枝上得鵷雛。"]'),
('yuding-61','寄昭應王丞','楊巨源','唐','御定全唐诗','yuding','','[]','武皇金輅輾香塵，每歲朝元及此辰。光動泉心初浴日，',40,'御定全唐詩/json/333.json','["武皇金輅輾香塵，每歲朝元及此辰。光動泉心初浴日，", "瑞靄朝朝猶望幸，天教赤縣有詩人。"]'),
('yuding-62','酬崔博士','楊巨源','唐','御定全唐诗','yuding','','[]','自知頑叟更何能，唯學雕蟲謬見稱。長被有情邀唱和，',40,'御定全唐詩/json/333.json','["自知頑叟更何能，唯學雕蟲謬見稱。長被有情邀唱和，", "今日為君書壁右，孤城莫怕世人憎。"]'),
('yuding-63','酬裴舍人見寄','楊巨源','唐','御定全唐诗','yuding','','[]','誰道重遷是舊班，自將霄漢比鄉關。二妃樓下宜臨水，',40,'御定全唐詩/json/333.json','["誰道重遷是舊班，自將霄漢比鄉關。二妃樓下宜臨水，", "詩陪亞相逾三紀，石笥煙霞不共攀。"]'),
('yuding-64','和劉員外陪韓僕射野亭公宴','楊巨源','唐','御定全唐诗','yuding','','[]','好客風流玳瑁簪，重簷高幕曉沉沉。綺筵霜重旌旗滿，',40,'御定全唐詩/json/333.json','["好客風流玳瑁簪，重簷高幕曉沉沉。綺筵霜重旌旗滿，", "寒笳一曲嚴城暮，雲騎連嘶香外林。"]'),
('yuding-65','酬崔駙馬惠箋百張兼貽四韻','楊巨源','唐','御定全唐诗','yuding','','[]','百張雲樣亂花開，七字文頭豔錦回。浮碧空從天上得，',40,'御定全唐詩/json/333.json','["百張雲樣亂花開，七字文頭豔錦回。浮碧空從天上得，", "滿篋清光應照眼，欲題凡韻輒裴回。"]'),
('yuding-66','贈史開封','楊巨源','唐','御定全唐诗','yuding','','[]','天低荒草誓師壇，鄧艾心知戰地寬。鼓角迥臨霜野曙，',40,'御定全唐詩/json/333.json','["天低荒草誓師壇，鄧艾心知戰地寬。鼓角迥臨霜野曙，", "曾從伏波征絕域，磧西蕃部怯金鞍。"]'),
('yuding-67','奉寄通州元九侍禦','楊巨源','唐','御定全唐诗','yuding','','[]','大明宮殿鬱蒼蒼，紫禁龍樓直署香。九陌華軒爭道路，',40,'御定全唐詩/json/333.json','["大明宮殿鬱蒼蒼，紫禁龍樓直署香。九陌華軒爭道路，", "共說聖朝容直氣，期君新歲奉恩光。"]'),
('yuding-68','贈渾鉅中允','楊巨源','唐','御定全唐诗','yuding','','[]','公子髫年四海聞，城南侍獵雪雰雰。馬盤曠野弦開月，',40,'御定全唐詩/json/333.json','["公子髫年四海聞，城南侍獵雪雰雰。馬盤曠野弦開月，", "一枝瓊萼朝光好，彩服飄飄從冠軍。"]'),
('yuding-69','重送胡大夫赴振武','楊巨源','唐','御定全唐诗','yuding','','[]','向年擢桂儒生業，今日分茅聖主恩。旌旆仍將過鄉路，',40,'御定全唐詩/json/333.json','["向年擢桂儒生業，今日分茅聖主恩。旌旆仍將過鄉路，", "布惠宣威大夫事，不妨詩思許琴尊。"]'),
('yuding-70','送陳判官罷舉赴江外','楊巨源','唐','御定全唐诗','yuding','','[]','練思多時冰雪清，拂衣無語別書生。莫將甲乙為前累，',40,'御定全唐詩/json/333.json','["練思多時冰雪清，拂衣無語別書生。莫將甲乙為前累，", "心期玉帳親台位，魏勃因君說姓名。"]'),
('yuding-71','奉和裴相公','楊巨源','唐','御定全唐诗','yuding','','[]','竹寺題名一半空，衰榮三十六人中。在生本要求知己，',40,'御定全唐詩/json/333.json','["竹寺題名一半空，衰榮三十六人中。在生本要求知己，", "若為問得蒼蒼意，造化無言自是功。"]'),
('yuding-72','和大夫邊春呈長安親故','楊巨源','唐','御定全唐诗','yuding','','[]','嚴城吹笛思寒梅，二月冰河一半開。紫陌詩情依舊在，',40,'御定全唐詩/json/333.json','["嚴城吹笛思寒梅，二月冰河一半開。紫陌詩情依舊在，", "旌旆朝天不知晚，將星高處近三台。"]'),
('yuding-73','張郎中段員外初直翰林報寄長句','楊巨源','唐','御定全唐诗','yuding','','[]','秋空如練瑞雲明，天上人間莫問程。丹鳳詞頭供二妙，',40,'御定全唐詩/json/333.json','["秋空如練瑞雲明，天上人間莫問程。丹鳳詞頭供二妙，", "啟沃朝朝深禁裏，香爐煙外是公卿。"]'),
('yuding-74','奉酬端公春雪見寄','楊巨源','唐','御定全唐诗','yuding','','[]','造化多情狀物親，剪花鋪玉萬重新。閑飄上路呈豐歲，',40,'御定全唐詩/json/333.json','["造化多情狀物親，剪花鋪玉萬重新。閑飄上路呈豐歲，", "遙知獨立芝蘭閣，滿眼清光壓俗塵。"]'),
('yuding-75','盧郎中拜陵遇雪蒙見召因寄','楊巨源','唐','御定全唐诗','yuding','','[]','南宮使者有光輝，欲拜諸陵瑞雪飛。蘋葉已修青玉薦，',40,'御定全唐詩/json/333.json','["南宮使者有光輝，欲拜諸陵瑞雪飛。蘋葉已修青玉薦，", "寒冷出郊猶未得，羨公將事看芳菲。"]'),
('yuding-76','冬夜陪丘侍禦先輩聽崔校書彈琴','楊巨源','唐','御定全唐诗','yuding','','[]','雪滿中庭月映林，謝家幽賞在瑤琴。楚妃波浪天南遠，',40,'御定全唐詩/json/333.json','["雪滿中庭月映林，謝家幽賞在瑤琴。楚妃波浪天南遠，", "若將雅調開詩興，未抵丘遲一片心。"]'),
('yuding-77','元日含元殿下立仗丹鳳樓門下宣赦相公稱賀二首','楊巨源','唐','御定全唐诗','yuding','','[]','天垂台耀掃欃槍，壽獻香山祝聖明。丹鳳樓前歌九奏，',80,'御定全唐詩/json/333.json','["天垂台耀掃欃槍，壽獻香山祝聖明。丹鳳樓前歌九奏，", "從此登封資廟略，兩河連海一時清。", "臨軒啟扇似雲收，率土朝天劇水流。瑞色含春當正殿，", "請問漢家功第一，麒麟閣上識酂侯。"]'),
('yuding-78','元日觀朝','楊巨源','唐','御定全唐诗','yuding','','[]','北極長尊報聖期，周家何用問元龜。天顏入曙千官拜，',40,'御定全唐詩/json/333.json','["北極長尊報聖期，周家何用問元龜。天顏入曙千官拜，", "微臣願獻堯人祝，壽酒年年太液池。"]'),
('yuding-79','題賈巡官林亭','楊巨源','唐','御定全唐诗','yuding','','[]','白鳥閑棲亭樹枝，綠樽仍對菊花籬。許詢本愛交禪侶，',40,'御定全唐詩/json/333.json','["白鳥閑棲亭樹枝，綠樽仍對菊花籬。許詢本愛交禪侶，", "門前長者無虛轍，一片寒光動水池。"]'),
('yuding-80','和元員外題升平裏新齋','楊巨源','唐','御定全唐诗','yuding','','[]','自知休沐諸幽勝，遂肯高齋枕廣衢。舊地已開新玉圃，',40,'御定全唐詩/json/333.json','["自知休沐諸幽勝，遂肯高齋枕廣衢。舊地已開新玉圃，", "此外唯應任真宰，同塵敢是道門樞。"]'),
('yuding-81','送澹公歸嵩山龍潭寺葬本師','楊巨源','唐','御定全唐诗','yuding','','[]','野煙秋水蒼茫遠，禪境真機去住閑。雙樹為家思舊壑，',40,'御定全唐詩/json/333.json','["野煙秋水蒼茫遠，禪境真機去住閑。雙樹為家思舊壑，", "莫戀本師金骨地，空門無處複無關。"]'),
('yuding-82','邵州陪王郎中宴','楊巨源','唐','御定全唐诗','yuding','','[]','西塞無塵多玉筵，貔貅鴛鷺儼相連。紅茵照水開樽俎，',40,'御定全唐詩/json/333.json','["西塞無塵多玉筵，貔貅鴛鷺儼相連。紅茵照水開樽俎，", "魯儒縱使他時有，不似歡娛及少年。"]'),
('yuding-83','和令狐舍人酬峰上人題山欄孤竹','楊巨源','唐','御定全唐诗','yuding','','[]','滿院冰姿粉籜殘，一莖青翠近簾端。離叢自欲親香火，',40,'御定全唐詩/json/333.json','["滿院冰姿粉籜殘，一莖青翠近簾端。離叢自欲親香火，", "范雲許訪西林寺，枝葉須和彩鳳看。"]'),
('yuding-84','寄贈田倉曹灣','楊巨源','唐','御定全唐诗','yuding','','[]','芳蘭媚庭除，灼灼紅英舒。身為陋巷客，門有絳轅車。',72,'御定全唐詩/json/333.json','["芳蘭媚庭除，灼灼紅英舒。身為陋巷客，門有絳轅車。", "朝覽夷吾傳，暮習潁陽書。眄雲高羽翼，待賈蘊璠璵。", "纓弁雖雲阻，音塵豈複疏。若因風雨晦，應念寂寥居。"]'),
('yuding-85','上劉侍中','楊巨源','唐','御定全唐诗','yuding','','[]','命代生申甫，承家翊禹湯。廟謨膺間氣，師律動清霜。',480,'御定全唐詩/json/333.json','["命代生申甫，承家翊禹湯。廟謨膺間氣，師律動清霜。", "鐘鼎勳庸大，山河誡誓長。英姿淩虎視，逸步壓龍驤。", "道協陶鈞力，恩回日月光。一言弘社稷，九命備珪璋。", "政洽軍逾肅，仁敷物已康。朱門重棨戟，丹詔半縑緗。", "位總雲龍野，師臨涿鹿鄉。射雕天更碧，吹角塞仍黃。", "深入平夷落，橫行辟漢疆。功垂貞石遠，名映色絲香。", "斷磧瞻貔武，臨池識鳳凰。舞腰凝綺榭，歌響拂雕梁。", "杯淨傳鸚鵡，裘鮮照鷫鸘。吟詩白羽扇，校獵綠沈槍。", "風景佳人地，煙沙壯士場。幕中邀謝鑒，麾下得周郎。", "珠影含空徹，瓊枝映座芳。王渾知武子，陳寔獎元方。", "富貴春無限，歡娛夜未央。管弦隨玉帳，尊俎奉金章。", "俗理寧因勸，邊城詎假防。軍容雄朔漠，公望冠岩廊。", "分野鄰孤島，京坻溢萬廂。曙華分碣石，秋色入衡陽。", "城遠迷玄兔，川明辯白狼。忠賢多感激，今古共蒼茫。", "堤擁紅蕖豔，橋分翠柳行。軒車紛自至，亭館鬱相當。", "珍簟回煩暑，層軒引早涼。聽琴知思靜，說劍覺神揚。", "佳景燕臺上，清輝鄭驛傍。鼓鼙喧北裏，珪玉映東床。", "敢衒由之瑟，甘循賜也牆。官微思假路，戰勝忝升堂。", "欲奮三年翼，頻回一夕腸。消憂期酒聖，乘興任詩狂。", "海內栽桃李，天涯荷稻粱。升沈門下意，誰道在蒼蒼。"]'),
('yuding-86','贈侯侍禦','楊巨源','唐','御定全唐诗','yuding','','[]','步逸辭群跡，機真結遠心。敦詩揚大雅，映古酌高音。',96,'御定全唐詩/json/333.json','["步逸辭群跡，機真結遠心。敦詩揚大雅，映古酌高音。", "逃禍棲蝸舍，因醒解豸簪。紫蘭秋露濕，黃鶴晚天陰。", "舊業餘荒草，寒山出遠林。月明多宿寺，世亂重悲琴。", "霄漢時應在，詩書道未沈。坐期閶闔霽，雲暖一開襟。"]'),
('yuding-87','懷德抒情寄上信州座主','楊巨源','唐','御定全唐诗','yuding','','[]','五馬江天郡，諸生淚共垂。宴餘明主德，恩在侍臣知。',120,'御定全唐詩/json/333.json','["五馬江天郡，諸生淚共垂。宴餘明主德，恩在侍臣知。", "悵望緘雙鯉，龍鍾假一枝。玉峰遙寄夢，雲海暗傷離。", "幢蓋全家去，琴書首路隨。滄州值康樂，明月向元規。", "鵷鳳終淩漢，蛟龍會出池。蕙香因曙發，松色肯寒移。", "舉世瞻風藻，當朝揖羽儀。加餐門下意，溪水綠逶迤。"]'),
('yuding-88','送杜郎中使君赴虔州','楊巨源','唐','御定全唐诗','yuding','','[]','迢遞南康路，清輝得使君。虎符秋領俗，鵷署早辭群。',72,'御定全唐詩/json/333.json','["迢遞南康路，清輝得使君。虎符秋領俗，鵷署早辭群。", "地遠仍連戍，城嚴本帶軍。傍江低檻月，當嶺滿窗雲。", "境勝閭閻間，天清水陸分。和詩將惠政，頌述九衢聞。"]'),
('yuding-89','別鶴詞送令狐校書之桂府','楊巨源','唐','御定全唐诗','yuding','','[]','海鶴一為別，高程方窅然。影搖江漢路，思結瀟湘天。',96,'御定全唐詩/json/333.json','["海鶴一為別，高程方窅然。影搖江漢路，思結瀟湘天。", "皎然仰白日，真姿棲紫煙。含情九霄際，顧侶五雲前。", "遐心屬清都，淒響激朱弦。超遙聞風雨，迢遞各山川。", "東南信多水，會合當有年。雌飛唳冥冥，此意何由傳。"]'),
('yuding-90','夏日裴尹員外西齋看花','楊巨源','唐','御定全唐诗','yuding','','[]','笑向東來客，看花枉在前。始知清夏月，更勝豔陽天。',96,'御定全唐詩/json/333.json','["笑向東來客，看花枉在前。始知清夏月，更勝豔陽天。", "露濕呈妝汙，風吹畏火燃。蔥蘢和葉盛，爛熳壓枝鮮。", "紅彩當鈴閣，清香到玉筵。蝶棲驚曙色，鶯語滯晴煙。", "得地殊堪賞，過時倍覺妍。芳菲遲最好，唯是謝家憐。"]'),
('yuding-91','贈鄰家老將','楊巨源','唐','御定全唐诗','yuding','','[]','白首羽林郎，丁年戍朔方。陰天瞻磧落，秋日渡遼陽。',168,'御定全唐詩/json/333.json','["白首羽林郎，丁年戍朔方。陰天瞻磧落，秋日渡遼陽。", "大漠寒山黑，孤城夜月黃。十年依蓐食，萬里帶金瘡。", "拂雪陳師祭，沖風立教場。箭飛瓊羽合，旗動火雲張。", "虎翼分營勢，魚鱗擁陣行。誓心清塞色，鬥血雜沙光。", "戰地晴輝薄，軍門曉氣長。寇深爭暗襲，關迥勒春防。", "身賤竟何訴，天高徒自傷。功成封寵將，力盡到貧鄉。", "雀老方悲海，鷹衰卻念霜。空餘孤劍在，開匣一沾裳。"]'),
('yuding-92','和呂舍人喜張員外自北番回至境上，先寄二十韻','楊巨源','唐','御定全唐诗','yuding','','[]','割愛天文動，敦和國步安。仙姿歸舊好，戎意結新歡。',241,'御定全唐詩/json/333.json','["割愛天文動，敦和國步安。仙姿歸舊好，戎意結新歡。", "並命瞻鵷鷺，同心揖蕙蘭。玉簫臨祖帳，金榜引征鞍。", "廣陌雙旌去，平沙萬里看。海雲侵鬢起，邊月向眉殘。", "突兀陰山迥，蒼茫朔野寬。毳廬同甲帳，韋橐比雕盤。", "義著親胡俗，儀全識漢官。地鄰冰鼠淨，天映燭龍寒。", "節異蘇卿執，弦殊蔡女彈。磧分黃渺渺，塞極黑漫漫。", "歡味膻腥列，征聲by僸攢。歸期先雁候，登路劇鵬摶。", "上客離心遠，西宮草詔殫。麗詞傳錦綺，珍價掩琅玕。", "百兩開戎壘，千蹄入禦欄。瑞光麟閣上，喜氣鳳城端。", "尚德曾辭劍，柔凶本舞幹。茫茫鬥星北，威服古來難。"]'),
('yuding-93','春日奉獻聖壽無疆詞十首','楊巨源','唐','御定全唐诗','yuding','','[]','文物京華盛，謳歌國步康。瑤池供壽酒，銀漢麗宸章。',576,'御定全唐詩/json/333.json','["文物京華盛，謳歌國步康。瑤池供壽酒，銀漢麗宸章。", "靈雨含雙闕，雷霆肅萬方。代推仙祚遠，春共聖恩長。", "鳳扆臨花暖，龍壚旁日香。遙知千萬歲，天意奉君王。", "鴛鷺彤庭際，軒車綺陌前。九城多好色，萬井半祥煙。", "人醉逢堯酒，鶯歌答舜弦。花明禦溝水，香暖禁城天。", "賜宴文逾盛，征歌物更妍。無窮豔陽月，長照太平年。", "雲陛臨黃道，天門在碧虛。大明含睿藻，元氣抱宸居。", "戈偃征苗後，詩傳宴鎬初。年華富仙苑，時哲滿公車。", "化入絪縕大，恩垂渙汗餘。悠然萬方靜，風俗揖華胥。", "玉漏飄青瑣，金鋪麗紫宸。雲山九門曙，天地一家春。", "瑞靄方呈賞，暄風本配仁。岩廊開鳳翼，水殿壓鼇身。", "文雅逢明代，歡娛及賤臣。年年未央闕，恩共物華新。", "垂拱乾坤正，歡心品類同。紫煙含北極，玄澤付東風。", "珠綴留晴景，金莖直曉空。發生資盛德，交泰讓全功。", "間氣登三事，祥光啟四聰。遐荒似川水，天外亦朝宗。", "代是文明晝，春當宴喜時。壚煙添柳重，宮漏出花遲。", "漢典方寬律，周官正采詩。碧宵傳鳳吹，紅旭在龍旗。", "造化膺神契，陽和沃聖思。無因隨百獸，率舞奉丹墀。", "睿德符玄化，芳情翊太和。日輪皇鑒遠，天仗聖朝多。", "曙色含金榜，晴光轉玉珂。中宮陳廣樂，元老進賡歌。", "蓮葉看龜上，桐花識鳳過。小臣空擊壤，滄海是恩波。", "物象朝高殿，簪裾溢上京。春當九衢好，天向萬方明。", "樂報簫韶發，杯看沆瀣生。芙蓉丹闕暖，楊柳玉樓晴。", "閶闔開中禁，衣裳儼太清。南山同聖壽，長對鳳凰城。"]'),
('yuding-94','銜魚翠鳥','楊巨源','唐','御定全唐诗','yuding','','[]','有意蓮葉間，瞥然下高樹。擘破得全魚，一點翠光去。',24,'御定全唐詩/json/333.json','["有意蓮葉間，瞥然下高樹。擘破得全魚，一點翠光去。"]'),
('yuding-95','和鄭相公尋宣上人不遇','楊巨源','唐','御定全唐诗','yuding','','[]','方尋蓮境去，又值竹房空。幾韻飄寒玉，餘清不在風。',24,'御定全唐詩/json/333.json','["方尋蓮境去，又值竹房空。幾韻飄寒玉，餘清不在風。"]'),
('yuding-96','題范陽金台驛','楊巨源','唐','御定全唐诗','yuding','','[]','六國唯求客，千金遂築台。若令逢聖代，憔悴郭生回。',24,'御定全唐詩/json/333.json','["六國唯求客，千金遂築台。若令逢聖代，憔悴郭生回。"]'),
('yuding-97','寄薛侍禦','楊巨源','唐','御定全唐诗','yuding','','[]','世上無窮事，生涯莫廢詩。何曾好風月，不是憶君時。',24,'御定全唐詩/json/333.json','["世上無窮事，生涯莫廢詩。何曾好風月，不是憶君時。"]'),
('yuding-98','賦得灞岸柳留辭鄭員外','楊巨源','唐','御定全唐诗','yuding','','[]','楊柳含煙灞岸春，年年攀折為行人。',32,'御定全唐詩/json/333.json','["楊柳含煙灞岸春，年年攀折為行人。", "好風倘借低枝便，莫遣青絲掃路塵。"]'),
('yuding-99','折楊柳','楊巨源','唐','御定全唐诗','yuding','','[]','水邊楊柳麹塵絲，立馬煩君折一枝。',32,'御定全唐詩/json/333.json','["水邊楊柳麹塵絲，立馬煩君折一枝。", "惟有春風最相惜，殷勤更向手中吹。"]'),
('yuding-100','雪中聽箏','楊巨源','唐','御定全唐诗','yuding','','[]','玉柱泠泠對寒雪，清商怨征聲何切。',32,'御定全唐詩/json/333.json','["玉柱泠泠對寒雪，清商怨征聲何切。", "誰憐楚客向隅時，一片愁心與弦絕。"]'),
('yuding-101','盧龍塞行送韋掌記二首','楊巨源','唐','御定全唐诗','yuding','','[]','雨雪紛紛黑水外，行人共指盧龍塞。',64,'御定全唐詩/json/333.json','["雨雪紛紛黑水外，行人共指盧龍塞。", "萬里飛沙壓鼓鼙，三軍殺氣凝旌旆。", "陳琳書記本翩翩，料敵能兵奪酒泉。", "聖主好文兼好武，封侯莫比漢皇年。"]'),
('yuding-102','題五老峰下費君書院','楊巨源','唐','御定全唐诗','yuding','','[]','解向花間栽碧松，門前不負老人峰。',32,'御定全唐詩/json/333.json','["解向花間栽碧松，門前不負老人峰。", "已將心事隨身隱，認得溪雲第幾重。"]'),
('yuding-103','僧院聽琴','楊巨源','唐','御定全唐诗','yuding','','[]','禪思何妨在玉琴，真僧不見聽時心。',32,'御定全唐詩/json/333.json','["禪思何妨在玉琴，真僧不見聽時心。", "離聲怨調秋堂夕，雲向蒼梧湘水深。"]'),
('yuding-104','和武相公春曉聞鶯','楊巨源','唐','御定全唐诗','yuding','','[]','語恨飛遲天欲明，殷勤似訴有餘情。',32,'御定全唐詩/json/333.json','["語恨飛遲天欲明，殷勤似訴有餘情。", "仁風已及芳菲節，猶向花溪鳴幾聲。"]'),
('yuding-105','唐昌觀玉蕊花','楊巨源','唐','御定全唐诗','yuding','','[]','晴空素豔照霞新，香灑天風不到塵。',32,'御定全唐詩/json/333.json','["晴空素豔照霞新，香灑天風不到塵。", "持贈昔聞將白雪，蕊珠宮上玉花春。"]'),
('yuding-106','山中主人','楊巨源','唐','御定全唐诗','yuding','','[]','十裏青山有一家，翠屏深處更添霞。',32,'御定全唐詩/json/333.json','["十裏青山有一家，翠屏深處更添霞。", "若為說得溪中事，錦石和煙四面花。"]'),
('yuding-107','太原贈李屬侍禦','楊巨源','唐','御定全唐诗','yuding','','[]','路入桑幹塞雁飛，棗郎年少有光輝。',32,'御定全唐詩/json/333.json','["路入桑幹塞雁飛，棗郎年少有光輝。", "春風走馬三千里，不廢看花君繡衣。"]'),
('yuding-108','崔娘詩','楊巨源','唐','御定全唐诗','yuding','','[]','清潤潘郎玉不如，中庭蕙草雪消初。',32,'御定全唐詩/json/333.json','["清潤潘郎玉不如，中庭蕙草雪消初。", "風流才子多春思，腸斷蕭娘一紙書。"]'),
('yuding-109','題雲師山房','楊巨源','唐','御定全唐诗','yuding','','[]','雲公蘭若深山裏，月明松殿微風起。',32,'御定全唐詩/json/333.json','["雲公蘭若深山裏，月明松殿微風起。", "試問空門清淨心，蓮花不著秋潭水。"]'),
('yuding-110','城東早春','楊巨源','唐','御定全唐诗','yuding','','[]','詩家清景在新春，綠柳才黃半未勻。',32,'御定全唐詩/json/333.json','["詩家清景在新春，綠柳才黃半未勻。", "若待上林花似錦，出門俱是看花人。"]'),
('yuding-111','秋日登亭贈薛侍禦','楊巨源','唐','御定全唐诗','yuding','','[]','潦倒從軍何取益，東西走馬暫同遊。',32,'御定全唐詩/json/333.json','["潦倒從軍何取益，東西走馬暫同遊。", "梁王舊客皆能賦，今日因何獨怨秋。"]'),
('yuding-112','石水詞二首','楊巨源','唐','御定全唐诗','yuding','','[]','銀罌深鎖貯清光，無限來人不得嘗。',64,'御定全唐詩/json/333.json','["銀罌深鎖貯清光，無限來人不得嘗。", "知共金丹爭氣力，一杯全勝五雲漿。", "山叟和雲劚翠屏，煎時分日檢仙經。", "天人持此扶衰病，勝得瑤池水一瓶。"]'),
('yuding-113','答振武李逢吉判官','楊巨源','唐','御定全唐诗','yuding','','[]','近來時輩都無興，把酒皆言肺病同。',32,'御定全唐詩/json/333.json','["近來時輩都無興，把酒皆言肺病同。", "唯有單于李評事，不將華髮負春風。"]'),
('yuding-114','宮燕詞','楊巨源','唐','御定全唐诗','yuding','','[]','毛衣似錦語如弦，日暖爭高綺陌天。',32,'御定全唐詩/json/333.json','["毛衣似錦語如弦，日暖爭高綺陌天。", "幾處野花留不得，雙雙飛向禦爐前。"]'),
('yuding-115','贈崔駙馬','楊巨源','唐','御定全唐诗','yuding','','[]','百尺梧桐畫閣齊，簫聲落處翠雲低。',32,'御定全唐詩/json/333.json','["百尺梧桐畫閣齊，簫聲落處翠雲低。", "平陽不惜黃金埒，細雨花驄踏作泥。"]'),
('yuding-116','聽李憑彈箜篌二首','楊巨源','唐','御定全唐诗','yuding','','[]','聽奏繁弦玉殿清，風傳曲度禁林明。',64,'御定全唐詩/json/333.json','["聽奏繁弦玉殿清，風傳曲度禁林明。", "君王聽樂梨園暖，翻到雲門第幾聲。", "花咽嬌鶯玉漱泉，名高半在禦筵前。", "漢王欲助人間樂，從遣新聲墜九天。"]'),
('yuding-117','臨水看花','楊巨源','唐','御定全唐诗','yuding','','[]','一樹紅花映綠波，晴明騎馬好經過。',32,'御定全唐詩/json/333.json','["一樹紅花映綠波，晴明騎馬好經過。", "今朝幾許風吹落，聞道蕭郎最惜多。"]'),
('yuding-118','觀妓人入道二首','楊巨源','唐','御定全唐诗','yuding','','[]','荀令歌鐘北裏亭，翠娥紅粉敞雲屏。',64,'御定全唐詩/json/333.json','["荀令歌鐘北裏亭，翠娥紅粉敞雲屏。", "舞衣施盡餘香在，今日花前學誦經。", "碧玉芳年事冠軍，清歌空得隔花聞。", "春來削髮芙蓉寺，蟬鬢臨風墮綠雲。"]'),
('yuding-119','方城驛逢孟侍禦','楊巨源','唐','御定全唐诗','yuding','','[]','走馬溫湯直隼飛，相逢矍鑠理征衣。',32,'御定全唐詩/json/333.json','["走馬溫湯直隼飛，相逢矍鑠理征衣。", "軍中得力兒男事，入驛從容見落暉。"]'),
('yuding-120','題清涼寺','楊巨源','唐','御定全唐诗','yuding','','[]','憑檻霏微松樹煙，陶潛曾用道林錢。',32,'御定全唐詩/json/333.json','["憑檻霏微松樹煙，陶潛曾用道林錢。", "一聲寒磬空心曉，花雨知從第幾天。"]'),
('yuding-121','酬令狐舍人','楊巨源','唐','御定全唐诗','yuding','','[]','曉禁蒼蒼換直還，暫低鸞翼向人間。',32,'御定全唐詩/json/333.json','["曉禁蒼蒼換直還，暫低鸞翼向人間。", "亦知受業公門事，數仞丘牆不見山。"]'),
('yuding-122','和令狐郎中','楊巨源','唐','御定全唐诗','yuding','','[]','題詩一代占清機，秉筆三年直紫微。',32,'御定全唐詩/json/333.json','["題詩一代占清機，秉筆三年直紫微。", "自稟道情齠齔異，不同蘧玉學知非。"]'),
('yuding-123','美人春怨','楊巨源','唐','御定全唐诗','yuding','','[]','妾家巫峽陽，羅幌寢蘭堂。曉日臨窗久，春風引夢長。',48,'御定全唐詩/json/333.json','["妾家巫峽陽，羅幌寢蘭堂。曉日臨窗久，春風引夢長。", "落釵仍掛鬢，微汗欲銷黃。縱便朦朧覺，魂猶逐楚王。"]'),
('yuding-124','豔女詞','楊巨源','唐','御定全唐诗','yuding','','[]','露井桃花發，雙雙燕並飛。美人姿態裏，春色上羅衣。',48,'御定全唐詩/json/333.json','["露井桃花發，雙雙燕並飛。美人姿態裏，春色上羅衣。", "自愛頻開鏡，時羞欲掩扉。心知行路客，遙惹五香歸。"]'),
('yuding-125','名姝詠','楊巨源','唐','御定全唐诗','yuding','','[]','阿嬌年未多，體弱性能和。怕重愁拈鏡，憐輕喜曳羅。',48,'御定全唐詩/json/333.json','["阿嬌年未多，體弱性能和。怕重愁拈鏡，憐輕喜曳羅。", "臨津雙洛浦，對月兩嫦娥。獨有荊王殿，時時暮雨過。"]'),
('yuding-126','送太和公主和蕃','楊巨源','唐','御定全唐诗','yuding','','[]','北路古來難，年光獨認寒。朔雲侵鬢起，邊月向眉殘。',48,'御定全唐詩/json/333.json','["北路古來難，年光獨認寒。朔雲侵鬢起，邊月向眉殘。", "蘆井尋沙到，花門度磧看。熏風一萬里，來處是長安。"]'),
('yuding-127','秋日韋少府廳池上詠石','楊巨源','唐','御定全唐诗','yuding','','[]','主人得幽石，日覺公堂清。一片池上色，孤峰雲外情。',48,'御定全唐詩/json/333.json','["主人得幽石，日覺公堂清。一片池上色，孤峰雲外情。", "舊溪紅蘚在，秋水綠痕生。何必澄湖徹，移來有令名。"]'),
('yuding-128','失題','楊巨源','唐','御定全唐诗','yuding','','[]','何事慰朝夕，不逾詩酒情。山河空道路，蕃漢共刀兵。',48,'御定全唐詩/json/333.json','["何事慰朝夕，不逾詩酒情。山河空道路，蕃漢共刀兵。", "禮樂新朝市，園林舊弟兄。向風一點淚，塞晚暮江平。"]'),
('yuding-129','春日題龍門香山寺','楊巨源','唐','御定全唐诗','yuding','','[]','眾香天上梵王宮，鐘磬寥寥半碧空。清景乍開松嶺月，',40,'御定全唐詩/json/333.json','["眾香天上梵王宮，鐘磬寥寥半碧空。清景乍開松嶺月，", "欲盡出尋那可得，三千世界本無窮。"]'),
('yuding-130','寄申州盧拱使君','楊巨源','唐','御定全唐诗','yuding','','[]','領郡仍聞總虎貔，致身還是見男兒。小船隔水催桃葉。',64,'御定全唐詩/json/333.json','["領郡仍聞總虎貔，致身還是見男兒。小船隔水催桃葉。", "大鼓當風舞柘枝。酒坐微酣諸客倒，球場慢撥幾人隨。", "從來樂事憎詩苦，莫放窗中遠岫知。"]'),
('yuding-131','郊居秋日酬奚贊府見寄','楊巨源','唐','御定全唐诗','yuding','','[]','繁菊照深居，芳香春不如。聞尋周處士，知伴庾尚書。',96,'御定全唐詩/json/333.json','["繁菊照深居，芳香春不如。聞尋周處士，知伴庾尚書。", "日晚汀洲曠，天晴草木疏。閑言揮麈柄，清步掩蝸廬。", "野老能親牧，高人念遠漁。幽叢臨古岸，輕葉度寒渠。", "暮色無狂蝶，秋華有嫩蔬。若為酬郢曲，從此愧璠璵。"]'),
('yuding-132','聖恩洗雪鎮州寄獻裴相公','楊巨源','唐','御定全唐诗','yuding','','[]','天借春光洗綠林，戰塵收盡見花陰。好生本是君王德，',40,'御定全唐詩/json/333.json','["天借春光洗綠林，戰塵收盡見花陰。好生本是君王德，", "井陘昨日雙旗入，蕭相無言淚濕襟。"]'),
('yuding-133','賀田僕射子弟榮拜金吾','楊巨源','唐','御定全唐诗','yuding','','[]','五侯恩澤不同年，叔侄朱門rV槊連。鳳沼九重相喜氣，',41,'御定全唐詩/json/333.json','["五侯恩澤不同年，叔侄朱門rV槊連。鳳沼九重相喜氣，", "為數麒麟高閣上，誰家父子勒燕然。"]'),
('yuding-134','和裴舍人觀田尚書出獵','楊巨源','唐','御定全唐诗','yuding','','[]','聖代司空比玉清，雄藩觀獵見皇情。雲禽已覺高無益，',40,'御定全唐詩/json/333.json','["聖代司空比玉清，雄藩觀獵見皇情。雲禽已覺高無益，", "今朝始賀將軍貴，紫禁詩人看旆旌。"]'),
('yuding-135','送李舍人歸蘭陵裏','楊巨源','唐','御定全唐诗','yuding','','[]','清詞舉世皆藏篋，美酒當山為滿樽。三畝嫩蔬臨綺陌，',40,'御定全唐詩/json/333.json','["清詞舉世皆藏篋，美酒當山為滿樽。三畝嫩蔬臨綺陌，", "惟有道情常自足，啟期天地易知恩。"]'),
('yuding-136','同太常尉遲博士闕下待漏','楊巨源','唐','御定全唐诗','yuding','','[]','沉沉延閣抱丹墀，松色苔花顥露滋。爽氣曉來青玉甃，',40,'御定全唐詩/json/333.json','["沉沉延閣抱丹墀，松色苔花顥露滋。爽氣曉來青玉甃，", "此地含香從白首，馮唐何事怨明時。"]'),
('yuding-137','見薛侍禦戴不損裹帽子因贈','楊巨源','唐','御定全唐诗','yuding','','[]','潘郎對青鏡，烏帽似新裁。曉露鴉初洗，春荷葉半開。',72,'御定全唐詩/json/333.json','["潘郎對青鏡，烏帽似新裁。曉露鴉初洗，春荷葉半開。", "堪將護巾櫛，不獨隔塵埃。已見籠蟬翼，無因映鹿胎。", "何人呈巧思，好手自西來。有意憐衰醜，煩君致一枚。"]'),
('yuding-138','胡二十拜戶部兼判度支','楊巨源','唐','御定全唐诗','yuding','','[]','清機果被公材撓，雄拜知承聖主恩。廟略已調天府實，',40,'御定全唐詩/json/333.json','["清機果被公材撓，雄拜知承聖主恩。廟略已調天府實，", "為愛山前新蔔第，不妨風月事琴樽。"]'),
('yuding-139','元日呈李逢吉舍人','楊巨源','唐','御定全唐诗','yuding','','[]','華夷文物賀新年，霜仗遙排鳳闕前。一片彩霞迎曙日，',40,'御定全唐詩/json/333.json','["華夷文物賀新年，霜仗遙排鳳闕前。一片彩霞迎曙日，", "共說正初當聖澤，試過西掖問群賢。"]'),
('yuding-140','和杜中丞西禪院看花','楊巨源','唐','御定全唐诗','yuding','','[]','一林堆錦映千燈，照眼牽情欲不勝。知倚晴明嬌自足，',72,'御定全唐詩/json/333.json','["一林堆錦映千燈，照眼牽情欲不勝。知倚晴明嬌自足，", "深處最憐鶯蹂踐，懶時先被蝶侵淩。對持真境應無取，", "幽含晚態憐丹桂，盛續春光識紫藤。每到花枝獨惆悵，"]'),
('yuding-141','句','楊巨源','唐','御定全唐诗','yuding','','[]','三刀夢益州，一箭取遼城。。',25,'御定全唐詩/json/333.json','["三刀夢益州，一箭取遼城。。", "伊陟無聞祖，韋賢不到孫。"]'),
('yuding-0','夏至日衡陽郡齋書懷','令狐楚','唐','御定全唐诗','yuding','','[]','一來江城守，七見江月圓。齒發將六十，鄉關越三千。',60,'御定全唐詩/json/334.json','["一來江城守，七見江月圓。齒發將六十，鄉關越三千。", "褰帷罕遊觀，閉合多沉眠。新節還複至，故交盡相捐。", "何時羾閶闔，上訴高高天。"]'),
('yuding-1','八月十七日夜書懷','令狐楚','唐','御定全唐诗','yuding','','[]','三五既不留，二八又還過。金蟾著未出，玉樹悲稍破。',60,'御定全唐詩/json/334.json','["三五既不留，二八又還過。金蟾著未出，玉樹悲稍破。", "誰向西園遊，空歸北堂臥。佳期信難得，永夕無可奈。", "撫枕獨高歌，煩君為予和。"]'),
('yuding-2','九日言懷','令狐楚','唐','御定全唐诗','yuding','','[]','二九即重陽，天清野菊黃。近來逢此日，多是在他鄉。',48,'御定全唐詩/json/334.json','["二九即重陽，天清野菊黃。近來逢此日，多是在他鄉。", "晚色霞千片，秋聲雁一行。不能高處望，恐斷老人腸。"]'),
('yuding-3','和寄竇七中丞','令狐楚','唐','御定全唐诗','yuding','','[]','仙吏秦峨別，新詩鄂渚來。才推今北斗，職賦舊三台。',48,'御定全唐詩/json/334.json','["仙吏秦峨別，新詩鄂渚來。才推今北斗，職賦舊三台。", "雕鏤心偏許，緘封手自開。何年相贈答，卻得到中台。"]'),
('yuding-4','立秋日悲懷','令狐楚','唐','御定全唐诗','yuding','','[]','清曉上高臺，秋風今日來。又添新節恨，猶抱故年哀。',48,'御定全唐詩/json/334.json','["清曉上高臺，秋風今日來。又添新節恨，猶抱故年哀。", "淚豈揮能盡，泉終閉不開。更傷春月過，私服示無縗。"]'),
('yuding-5','秋懷寄錢侍郎','令狐楚','唐','御定全唐诗','yuding','','[]','晚歲俱為郡，新秋各異鄉。燕鴻一聲叫，郢樹盡青蒼。',48,'御定全唐詩/json/334.json','["晚歲俱為郡，新秋各異鄉。燕鴻一聲叫，郢樹盡青蒼。", "山露侵衣潤，江風卷簟涼。相思如漢水，日夜向潯陽。"]'),
('yuding-6','立秋日','令狐楚','唐','御定全唐诗','yuding','','[]','平日本多恨，新秋偏易悲。燕詞如惜別，柳意已呈衰。',48,'御定全唐詩/json/334.json','["平日本多恨，新秋偏易悲。燕詞如惜別，柳意已呈衰。", "事國終無補，還家未有期。心中舊氣味，苦校去年時。"]'),
('yuding-7','贈毛仙翁','令狐楚','唐','御定全唐诗','yuding','','[]','宣州渾是上清宮，客有真人貌似童。紺發垂纓光髧髧，',40,'御定全唐詩/json/334.json','["宣州渾是上清宮，客有真人貌似童。紺發垂纓光髧髧，", "既許焚香為弟子，願教年紀共椿同。"]'),
('yuding-8','遊義興寺寄上李逢吉相公','令狐楚','唐','御定全唐诗','yuding','','[]','柳營無事詣蓮宮，步步猶疑是夢中。勞役徒為萬夫長，',40,'御定全唐詩/json/334.json','["柳營無事詣蓮宮，步步猶疑是夢中。勞役徒為萬夫長，", "松下花飛頻佇立，一心千里憶梁公。"]'),
('yuding-9','游晉祠上李逢吉相公','令狐楚','唐','御定全唐诗','yuding','','[]','不立晉祠三十年，白頭重到一淒然。泉聲自昔鏘寒玉，',40,'御定全唐詩/json/334.json','["不立晉祠三十年，白頭重到一淒然。泉聲自昔鏘寒玉，", "相思臨水下雙淚，寄入並汾向洛川。"]'),
('yuding-10','節度宣武酬樂天夢得','令狐楚','唐','御定全唐诗','yuding','','[]','蓬萊仙監客曹郎，曾枉高車客大樑。見擁旌旄治軍旅，',40,'御定全唐詩/json/334.json','["蓬萊仙監客曹郎，曾枉高車客大樑。見擁旌旄治軍旅，", "洛下相逢肯相寄，南金璀錯玉淒涼。"]'),
('yuding-11','奉和嚴司空重陽日同崔常侍崔郎及諸公登龍山落帽台佳宴','令狐楚','唐','御定全唐诗','yuding','','[]','謝公秋思渺天涯，蠟屐登高為菊花。貴重近臣光綺席，',40,'御定全唐詩/json/334.json','["謝公秋思渺天涯，蠟屐登高為菊花。貴重近臣光綺席，", "詠碎龍山歸出號，馬奔流電妓奔車。"]'),
('yuding-12','立春後言懷招汴州李匡衙推','令狐楚','唐','御定全唐诗','yuding','','[]','閑齋夜擊唾壺歌，試望夷門奈遠何。每聽塞笳離夢斷，',40,'御定全唐詩/json/334.json','["閑齋夜擊唾壺歌，試望夷門奈遠何。每聽塞笳離夢斷，", "海內故人君最老，花開鞭馬更相過。"]'),
('yuding-13','奉和僕射相公酬忠武李相公見寄之作','令狐楚','唐','御定全唐诗','yuding','','[]','麗藻飛來自相庭，五文相錯八音清。初瞻綺色連霞色，',40,'御定全唐詩/json/334.json','["麗藻飛來自相庭，五文相錯八音清。初瞻綺色連霞色，", "白頭老尹三川上，雙和陽春喜複驚。"]'),
('yuding-14','郡齋左偏栽竹百餘竿炎涼已周青翠不改而為牆垣所蔽有乖愛賞假日命去齋居之東牆由是俯臨軒階低映帷戶日夕相對頗有翛然之趣','令狐楚','唐','御定全唐诗','yuding','','[]','齋居栽竹北窗邊，素壁新開映碧鮮。青藹近當行藥處，',40,'御定全唐詩/json/334.json','["齋居栽竹北窗邊，素壁新開映碧鮮。青藹近當行藥處，", "老子憶山心暫緩，退公閑坐對嬋娟。"]'),
('yuding-15','省中直夜對雪寄李師素侍郎','令狐楚','唐','御定全唐诗','yuding','','[]','密雪紛初降，重城杳未開。雜花飛爛漫，連蝶舞徘徊。',144,'御定全唐詩/json/334.json','["密雪紛初降，重城杳未開。雜花飛爛漫，連蝶舞徘徊。", "灑散千株葉，銷凝九陌埃。素華凝粉署，清氣繞霜台。", "明覺侵窗積，寒知度塞來。謝家爭擬絮，越嶺誤驚梅。", "暗魄微茫照，嚴飆次第催。稍封黃竹亞，先集紫蘭摧。", "孫室臨書幌，梁園泛酒杯。靜懷瓊樹倚，醉憶玉山頹。", "翠陌饑烏噪，蒼雲遠雁哀。此時方夜直，想望意悠哉。"]'),
('yuding-16','南宮夜直宿見李給事封題其所下制敕知奏直在東省因以詩寄','令狐楚','唐','御定全唐诗','yuding','','[]','番直同遙夜，嚴扃限幾重。青編書白雀，黃紙降蒼龍。',96,'御定全唐詩/json/334.json','["番直同遙夜，嚴扃限幾重。青編書白雀，黃紙降蒼龍。", "北極絲綸句，東垣翰墨蹤。尚垂玄露點，猶濕紫泥封。", "炫眼凝仙燭，馳心嫋禁鐘。定應形夢寐，暫似接音容。", "玉樹春枝動，金樽臘釀醲。在朝君最舊，休浣許過從。"]'),
('yuding-17','將赴洛下，旅次漢南，獻上相公二十兄言懷八韻','令狐楚','唐','御定全唐诗','yuding','','[]','台室名曾繼，旌門節暫過。歡情老去少，苦事別離多。',96,'御定全唐詩/json/334.json','["台室名曾繼，旌門節暫過。歡情老去少，苦事別離多。", "便為開樽俎，應憐出網羅。百憂今已失，一醉孰知他。", "帝德千年日，君恩萬里波。許隨黃綺輩，閑唱紫芝歌。", "龍袞期重補，梅羹佇再和。嵩丘來攜手，君子意如何。"]'),
('yuding-18','青雲幹呂','令狐楚','唐','御定全唐诗','yuding','','[]','鬱鬱複紛紛，青霄幹呂雲。色令天下見，候向管中分。',72,'御定全唐詩/json/334.json','["鬱鬱複紛紛，青霄幹呂雲。色令天下見，候向管中分。", "遠覆無人境，遙彰有德君。瑞容驚不散，冥感信稀聞。", "湛露羞依草，南風恥帶熏。恭惟漢武帝，餘烈尚氛氳。"]'),
('yuding-19','聖明樂','令狐楚','唐','御定全唐诗','yuding','','[]','海浪恬月徼，邊塵靜異山。從今萬里外，不復鎖蕭關。',24,'御定全唐詩/json/334.json','["海浪恬月徼，邊塵靜異山。從今萬里外，不復鎖蕭關。"]'),
('yuding-20','春閨思','令狐楚','唐','御定全唐诗','yuding','','[]','戴勝飛晴野，淩澌下濁河。春風樓上望，誰見淚痕多。',24,'御定全唐詩/json/334.json','["戴勝飛晴野，淩澌下濁河。春風樓上望，誰見淚痕多。"]'),
('yuding-21','宮中樂五首','令狐楚','唐','御定全唐诗','yuding','','[]','楚塞金陵靖，巴山玉壘空。萬方無一事，端拱大明宮。',120,'御定全唐詩/json/334.json','["楚塞金陵靖，巴山玉壘空。萬方無一事，端拱大明宮。", "雪霽長楊苑，冰開太液池。宮中行樂日，天下盛明時。", "柳色煙相似，梨花雪不如。春風真有意，一一麗皇居。", "月上宮花靜，煙含苑樹深。銀台門已閉，仙漏夜沉沉。", "九重青瑣闥，百尺碧雲樓。明月秋風起，珠簾上玉鉤。"]'),
('yuding-22','春遊曲三首','令狐楚','唐','御定全唐诗','yuding','','[]','曉遊臨碧殿，日上望春亭。芳樹羅仙仗，晴山展翠屏。',72,'御定全唐詩/json/334.json','["曉遊臨碧殿，日上望春亭。芳樹羅仙仗，晴山展翠屏。", "一夜好風吹，新花一萬枝。風前調玉管，花下簇金羈。", "閶闔春風起，蓬萊雪水消。相將折楊柳，爭取最長條。"]'),
('yuding-23','遠別離二首','令狐楚','唐','御定全唐诗','yuding','','[]','楊柳黃金穗，梧桐碧玉枝。春來消息斷，早晚是歸期。',48,'御定全唐詩/json/334.json','["楊柳黃金穗，梧桐碧玉枝。春來消息斷，早晚是歸期。", "玳織鴛鴦履，金裝翡翠篸。畏人相問著，不擬到城南。"]'),
('yuding-24','閨人贈遠二首','令狐楚','唐','御定全唐诗','yuding','','[]','君行登隴上，妾夢在閨中。玉箸千行落，銀床一半空。',48,'御定全唐詩/json/334.json','["君行登隴上，妾夢在閨中。玉箸千行落，銀床一半空。", "綺席春眠覺，紗窗曉望迷。朦朧殘夢裏，猶自在遼西。"]'),
('yuding-25','從軍詞五首','令狐楚','唐','御定全唐诗','yuding','','[]','荒雞隔水啼，汗馬逐風嘶。終日隨征旆，何時罷鼓鼙。',120,'御定全唐詩/json/334.json','["荒雞隔水啼，汗馬逐風嘶。終日隨征旆，何時罷鼓鼙。", "孤心眠夜雪，滿眼是秋沙。萬里猶防塞，三年不見家。", "卻望冰河闊，前登雪嶺高。征人幾多在，又擬戰臨洮。", "胡風千里驚，漢月五更明。縱有還家夢，猶聞出塞聲。", "暮雪連青海，陰霞覆白山。可憐班定遠，生入玉門關。"]'),
('yuding-26','思君恩','令狐楚','唐','御定全唐诗','yuding','','[]','小苑鶯歌歇，長門蝶舞多。眼看春又去，翠輦不經過。',24,'御定全唐詩/json/334.json','["小苑鶯歌歇，長門蝶舞多。眼看春又去，翠輦不經過。"]'),
('yuding-27','王昭君','令狐楚','唐','御定全唐诗','yuding','','[]','錦車天外去，毳幕雪中開。魏闕蒼龍遠，蕭關赤雁哀。',24,'御定全唐詩/json/334.json','["錦車天外去，毳幕雪中開。魏闕蒼龍遠，蕭關赤雁哀。"]'),
('yuding-28','發潭州寄李甯常侍','令狐楚','唐','御定全唐诗','yuding','','[]','君今侍紫垣，我已墮青天。委廢從茲日，旋歸在幾年。',48,'御定全唐詩/json/334.json','["君今侍紫垣，我已墮青天。委廢從茲日，旋歸在幾年。", "心為西靡樹，眼是北流泉。更過長沙去，江風滿驛船。"]'),
('yuding-29','李相薨後題斷金集','令狐楚','唐','御定全唐诗','yuding','','[]','一覽斷金集，載悲埋玉人。牙弦千古絕，珠淚萬行新。',24,'御定全唐詩/json/334.json','["一覽斷金集，載悲埋玉人。牙弦千古絕，珠淚萬行新。"]'),
('yuding-30','年少行四首','令狐楚','唐','御定全唐诗','yuding','','[]','少小邊州慣放狂，驏騎蕃馬射黃羊。',128,'御定全唐詩/json/334.json','["少小邊州慣放狂，驏騎蕃馬射黃羊。", "如今年老無筋力，猶倚營門數雁行。", "家本清河住五城，須憑弓箭得功名。", "等閒飛鞚秋原上，獨向寒雲試射聲。", "弓背霞明劍照霜，秋風走馬出咸陽。", "未收天子河湟地，不擬回頭望故鄉。", "霜滿中庭月滿樓，金樽玉柱對清秋。", "當年稱意須行樂，不到天明不肯休。"]'),
('yuding-31','塞下曲二首','令狐楚','唐','御定全唐诗','yuding','','[]','雪滿衣裳冰滿須，曉隨飛將伐單于。',64,'御定全唐詩/json/334.json','["雪滿衣裳冰滿須，曉隨飛將伐單于。", "平生意氣今何在，把得家書淚似珠。", "邊草蕭條塞雁飛，征人南望淚沾衣。", "黃塵滿面長須戰，白髮生頭未得歸。"]'),
('yuding-32','遊春詞','令狐楚','唐','御定全唐诗','yuding','','[]','高樓曉見一花開，便覺春光四面來。',32,'御定全唐詩/json/334.json','["高樓曉見一花開，便覺春光四面來。", "暖日晴雲知次第，東風不用更相催。"]'),
('yuding-33','漢苑行','令狐楚','唐','御定全唐诗','yuding','','[]','雲霞五采浮天闕，梅柳千般夾禦溝。',32,'御定全唐詩/json/334.json','["雲霞五采浮天闕，梅柳千般夾禦溝。", "不上黃花南北望，豈知春色滿神州。"]'),
('yuding-34','中元日贈張尊師','令狐楚','唐','御定全唐诗','yuding','','[]','偶來人世值中元，不獻玄都永日閑。',32,'御定全唐詩/json/334.json','["偶來人世值中元，不獻玄都永日閑。", "寂寂焚香在仙觀，知師遙禮玉京山。"]'),
('yuding-35','赴東都別牡丹','令狐楚','唐','御定全唐诗','yuding','','[]','十年不見小庭花，紫萼臨開又別家。',32,'御定全唐詩/json/334.json','["十年不見小庭花，紫萼臨開又別家。", "上馬出門回首望，何時更得到京華。"]'),
('yuding-36','寄禮部劉郎中','令狐楚','唐','御定全唐诗','yuding','','[]','一別三年在上京，仙垣終日選群英。',32,'御定全唐詩/json/334.json','["一別三年在上京，仙垣終日選群英。", "除書每下皆先看，唯有劉郎無姓名。"]'),
('yuding-37','坐中聞思帝鄉有感','令狐楚','唐','御定全唐诗','yuding','','[]','年年不見帝鄉春，白日尋思夜夢頻。',32,'御定全唐詩/json/334.json','["年年不見帝鄉春，白日尋思夜夢頻。", "上酒忽聞吹此曲，坐中惆悵更何人。"]'),
('yuding-38','春思寄夢得樂天','令狐楚','唐','御定全唐诗','yuding','','[]','花滿中庭酒滿樽，平明獨坐到黃昏。',32,'御定全唐詩/json/334.json','["花滿中庭酒滿樽，平明獨坐到黃昏。", "春來詩思偏何處，飛過函關入鼎門。"]'),
('yuding-39','皇城中花園譏劉白賞春不及','令狐楚','唐','御定全唐诗','yuding','','[]','五鳳樓西花一園，低枝小樹盡芳繁。',32,'御定全唐詩/json/334.json','["五鳳樓西花一園，低枝小樹盡芳繁。", "洛陽才子何曾愛，下馬貪趨廣運門。"]'),
('yuding-40','相思河','令狐楚','唐','御定全唐诗','yuding','','[]','誰把相思號此河，塞垣車馬往來多。',32,'御定全唐詩/json/334.json','["誰把相思號此河，塞垣車馬往來多。", "只應自古征人淚，灑向空洲作碧波。"]'),
('yuding-41','三月晦日會李員外座中頻以老大不醉見譏因有此贈','令狐楚','唐','御定全唐诗','yuding','','[]','三月唯殘一日春，玉山傾倒白鷗馴。',32,'御定全唐詩/json/334.json','["三月唯殘一日春，玉山傾倒白鷗馴。", "不辭便學山公醉，花下無人作主人。"]'),
('yuding-42','賦山','令狐楚','唐','御定全唐诗','yuding','','[]','山。聳峻，回環。滄海上，白雲間。商老深尋，',21,'御定全唐詩/json/334.json','["山。聳峻，回環。滄海上，白雲間。商老深尋，"]'),
('yuding-43','句','令狐楚','唐','御定全唐诗','yuding','','[]','何日居三署，終年尾百僚。。',92,'御定全唐詩/json/334.json','["何日居三署，終年尾百僚。。", "移石幾回敲廢印，開箱何處送新圖。。", "唯應四仲祭，使者暫悲嗟。。", "偶逢蒲家郎，乃是葛仙客。行常乘青竹，饑即煮白石。", "腰間嫌大組，心內保尺宅。我願從之游，深蔔煉上液。", "。"]'),
('yuding-0','享惠昭太子廟樂章','裴度','唐','御定全唐诗','yuding','','[]','重輪始發祥，齒胄方興學。冥然升紫府，鏗爾薦清樂。',48,'御定全唐詩/json/335.json','["重輪始發祥，齒胄方興學。冥然升紫府，鏗爾薦清樂。", "奠斝致馨香，在庭紛羽鑰。禮成神既醉，仿佛緱山鶴。"]'),
('yuding-1','夏日對雨','裴度','唐','御定全唐诗','yuding','','[]','登樓逃盛夏，萬象正埃塵。對面雷嗔樹，當街雨趁人。',48,'御定全唐詩/json/335.json','["登樓逃盛夏，萬象正埃塵。對面雷嗔樹，當街雨趁人。", "簷疏蛛網重，地濕燕泥新。吟罷清風起，荷香滿四鄰。"]'),
('yuding-2','白二十二侍郎有雙鶴留在洛下予西園多野水長松可以棲息遂以詩請之','裴度','唐','御定全唐诗','yuding','','[]','聞君有雙鶴，羈旅洛城東。未放歸仙去，何如乞老翁。',48,'御定全唐詩/json/335.json','["聞君有雙鶴，羈旅洛城東。未放歸仙去，何如乞老翁。", "且將臨野水，莫閉在樊籠。好是長鳴處，西園白露中。"]'),
('yuding-3','竇七中丞見示初至夏口獻元戎詩，輒戲和之','裴度','唐','御定全唐诗','yuding','','[]','出佐青油幕，來吟白雪篇。須為九皋鶴，莫上五湖船。',48,'御定全唐詩/json/335.json','["出佐青油幕，來吟白雪篇。須為九皋鶴，莫上五湖船。", "故態君應在，新詩我亦便。元侯看再入，好被暫流連。"]'),
('yuding-4','酬張秘書因寄馬贈詩','裴度','唐','御定全唐诗','yuding','','[]','滿城馳逐皆求馬，古寺閑行獨與君。代步本慚非逸足，',40,'御定全唐詩/json/335.json','["滿城馳逐皆求馬，古寺閑行獨與君。代步本慚非逸足，", "飛控著鞭能顧我，當時王粲亦從軍。"]'),
('yuding-5','真慧寺','裴度','唐','御定全唐诗','yuding','','[]','遍尋真跡躡莓苔，世事全拋不忍回。上界不知何處去，',40,'御定全唐詩/json/335.json','["遍尋真跡躡莓苔，世事全拋不忍回。上界不知何處去，", "更有一般人不見，白蓮花向半天開。"]'),
('yuding-6','中書即事','裴度','唐','御定全唐诗','yuding','','[]','有意效承平，無功答聖明。灰心緣忍事，霜鬢為論兵。',72,'御定全唐詩/json/335.json','["有意效承平，無功答聖明。灰心緣忍事，霜鬢為論兵。", "道直身還在，恩深命轉輕。鹽梅非擬議，葵藿是平生。", "白日長懸照，蒼蠅謾發聲。高陽舊田裏，終使謝歸耕。"]'),
('yuding-7','中和節詔賜公卿尺','裴度','唐','御定全唐诗','yuding','','[]','陽和行慶賜，尺度及群公。荷寵承佳節，傾心立大中。',72,'御定全唐詩/json/335.json','["陽和行慶賜，尺度及群公。荷寵承佳節，傾心立大中。", "短長思合制，遠近貴攸同。共仰財成德，將酬分寸功。", "作程施有政，垂範播無窮。願續南山壽，千春奉聖躬。"]'),
('yuding-8','至日登樂遊園','裴度','唐','御定全唐诗','yuding','','[]','陰律隨寒改，陽和應節生。祥雲觀魏闕，瑞氣映秦城。',72,'御定全唐詩/json/335.json','["陰律隨寒改，陽和應節生。祥雲觀魏闕，瑞氣映秦城。", "驗炭論時政，書雲受歲盈。晷移長日至，霧斂遠霄清。", "景暖仙梅動，風柔禦柳傾。那堪封得意，空對物華情。"]'),
('yuding-9','奉酬中書相公至日圓丘攝事合於中書後閣宿齋移止於集賢院敘懷見寄之作','裴度','唐','御定全唐诗','yuding','','[]','翼亮登三命，謨猷本一心。致齋移秘府，祗事見沖襟。',72,'御定全唐詩/json/335.json','["翼亮登三命，謨猷本一心。致齋移秘府，祗事見沖襟。", "皓月當延閣，祥風自禁林。相庭方積玉，王度已如金。", "運偶唐虞盛，情同丙魏深。幽蘭與白雪，何處寄庸音。"]'),
('yuding-10','太原題廳壁','裴度','唐','御定全唐诗','yuding','','[]','危事經非一，浮榮得是空。白頭官舍裏，今日又春風。',24,'御定全唐詩/json/335.json','["危事經非一，浮榮得是空。白頭官舍裏，今日又春風。"]'),
('yuding-11','溪居','裴度','唐','御定全唐诗','yuding','','[]','門徑俯清溪，茅簷古木齊。紅塵飄不到，時有水禽啼。',24,'御定全唐詩/json/335.json','["門徑俯清溪，茅簷古木齊。紅塵飄不到，時有水禽啼。"]'),
('yuding-12','喜遇劉二十八','裴度','唐','御定全唐诗','yuding','','[]','病來佳興少，老去舊遊稀。笑語縱橫作，杯觴絡繹飛。',24,'御定全唐詩/json/335.json','["病來佳興少，老去舊遊稀。笑語縱橫作，杯觴絡繹飛。"]'),
('yuding-13','送劉','裴度','唐','御定全唐诗','yuding','','[]','不歸丹掖去，銅竹漫云云。惟喜因過我，須知未賀君。',24,'御定全唐詩/json/335.json','["不歸丹掖去，銅竹漫云云。惟喜因過我，須知未賀君。"]'),
('yuding-14','再送','裴度','唐','御定全唐诗','yuding','','[]','頃來多謔浪，此夕任喧紛。故態猶應在，行期未要聞。',24,'御定全唐詩/json/335.json','["頃來多謔浪，此夕任喧紛。故態猶應在，行期未要聞。"]'),
('yuding-15','涼風亭睡覺','裴度','唐','御定全唐诗','yuding','','[]','飽食緩行新睡覺，一甌新茗侍兒煎。',32,'御定全唐詩/json/335.json','["飽食緩行新睡覺，一甌新茗侍兒煎。", "脫巾斜倚繩床坐，風送水聲來耳邊。"]'),
('yuding-16','雪中訝諸公不相訪','裴度','唐','御定全唐诗','yuding','','[]','憶昨雨多泥又深，猶能攜妓遠過尋。',32,'御定全唐詩/json/335.json','["憶昨雨多泥又深，猶能攜妓遠過尋。", "滿空亂雪花相似，何事居然無賞心。"]'),
('yuding-17','傍水閑行','裴度','唐','御定全唐诗','yuding','','[]','閑餘何處覺身輕，暫脫朝衣傍水行。',32,'御定全唐詩/json/335.json','["閑餘何處覺身輕，暫脫朝衣傍水行。", "鷗鳥亦知人意靜，故來相近不相驚。"]'),
('yuding-18','句','裴度','唐','御定全唐诗','yuding','','[]','兩人同日事征西，今日君先奉紫泥。',65,'御定全唐詩/json/335.json','["兩人同日事征西，今日君先奉紫泥。", "待平賊壘報天子，莫指仙山示武夫。", "野人不識中書令，喚作陶家與謝家。。", "君若有心求逸足，我還留意在名姝。"]'),
('yuding-0','元和聖德詩','韓愈','唐','御定全唐诗','yuding','','[]','皇帝即阼，物無違拒。曰暘而暘，曰雨而雨。維是元年，',600,'御定全唐詩/json/336.json','["皇帝即阼，物無違拒。曰暘而暘，曰雨而雨。維是元年，", "負鄙為艱，縱則不可。出師征之，其眾十旅。軍其城下，", "疆外之險，莫過蜀土。韋皋去鎮，劉辟守後。血人於牙，", "汝為表書，求我帥汝。事始上聞，在列咸怒。皇帝曰然，", "朝發京師，夕至其部。辟喜謂黨，汝振而伍。蜀可全有，", "有恇其凶，有餌其誘。其出穰穰，隊以萬數。遂劫東川，", "有安其驅，無暴我野。日行三十，徐壁其右。辟党聚謀，", "四方節度，整兵頓馬。上章請討，俟命起坐。皇帝曰嘻，", "四軍齊作，殷其如阜。或拔其角，或脫其距。長驅洋洋，", "是日崇文，入處其宇。分散逐捕，搜原剔藪。辟窮見窘，", "取之江中，枷脰械手。婦女累累，啼哭拜叩。來獻闕下，", "婉婉弱子，赤立傴僂。牽頭曳足，先斷腰膂。次及其徒，", "優賞將吏，扶珪綴組。帛堆其家，粟塞其庾。哀憐陣沒，", "施令酬功，急疾如火。天地中間，莫不順序。幽恒青魏，", "掉棄兵革，私習簋簠。來請來覲，十百其耦。皇帝曰籲，", "躬執百禮，登降拜俯。薦于新宮，視瞻梁梠。戚見容色，", "除于國南，鱗筍毛簴。廬幕周施，開揭磊砢。獸盾騰拏，", "宵升於丘，奠璧獻斝。眾樂驚作，轟豗融冶。紫焰噓呵，", "瀆鬼蒙鴻，嶽祗嶪峨。飫沃膻薌，產祥降嘏。鳳凰應奏，", "踴躍歡呀，失喜噎歐。幹清坤夷，境落褰舉。帝車回來，", "續功臣嗣，拔賢任耇。孩養無告，仁滂施厚。皇帝神聖，", "天錫皇帝，為天下主。並包畜養，無異細鉅。億載萬年，", "敕戒四方，侈則有咎。天錫皇帝，多麥與黍。無召水旱，", "擅命而狂，既翦既去。盡逐群奸，靡有遺侶。天錫皇帝，"]'),
('yuding-1','琴操十首：將歸操','韓愈','唐','御定全唐诗','yuding','','[]','（孔子之趙，聞殺鳴犢作。趙殺鳴犢，孔子臨河，',47,'御定全唐詩/json/336.json','["（孔子之趙，聞殺鳴犢作。趙殺鳴犢，孔子臨河，", "秋之水兮，其色幽幽；我將濟兮，不得其由。涉其淺兮，"]'),
('yuding-2','琴操十首：猗蘭操','韓愈','唐','御定全唐诗','yuding','','[]','（孔子傷不逢時作。古琴操雲：習習谷風，以陰以雨。',129,'御定全唐詩/json/336.json','["（孔子傷不逢時作。古琴操雲：習習谷風，以陰以雨。", "之子於歸，遠送於野。何彼蒼天，不得其所。逍遙九州，", "蘭之猗猗，揚揚其香。不采而佩，于蘭何傷。", "今天之旋，其曷為然。我行四方，以日以年。", "雪霜貿貿，薺麥之茂。子如不傷，我不爾覯。", "薺麥之茂，薺麥之有。君子之傷，君子之守。"]'),
('yuding-3','琴操十首：龜山操','韓愈','唐','御定全唐诗','yuding','','[]','（孔子以季桓子受齊女樂，諫不從，望龜山而作。',81,'御定全唐詩/json/336.json','["（孔子以季桓子受齊女樂，諫不從，望龜山而作。", "龜山在太山博縣。古琴操雲：予欲望魯兮，龜山蔽之。", "手無斧柯，奈龜山何）", "龜之氛兮，不能雲雨。龜之枿兮，不中樑柱。龜之大兮，"]'),
('yuding-4','琴操十首：越裳操','韓愈','唐','御定全唐诗','yuding','','[]','雨之施物以孳，我何意於彼為。自周之先，其艱其勤。',49,'御定全唐詩/json/336.json','["雨之施物以孳，我何意於彼為。自周之先，其艱其勤。", "以有疆宇，私我後人。我祖在上，四方在下。厥臨孔威，"]'),
('yuding-5','琴操十首：拘幽操','韓愈','唐','御定全唐诗','yuding','','[]','（文王羑裏作。古琴操雲：殷道溷溷，浸濁煩兮。',73,'御定全唐詩/json/336.json','["（文王羑裏作。古琴操雲：殷道溷溷，浸濁煩兮。", "朱紫相合，不別分兮。迷亂聲色，信讒言兮。炎炎之虐，", "目窈窈兮，其凝其盲；耳肅肅兮，聽不聞聲。朝不日出兮，"]'),
('yuding-6','琴操十首：岐山操','韓愈','唐','御定全唐诗','yuding','','[]','（周公為太王作。本詞雲：狄戎侵兮，土地遷移。',104,'御定全唐詩/json/336.json','["（周公為太王作。本詞雲：狄戎侵兮，土地遷移。", "邦邑適於岐山，烝民不憂兮誰者知。嗟嗟奈何兮，", "我家於豳，自我先公。伊我承序，敢有不同。", "今狄之人，將土我疆。民為我戰，誰使死傷。", "彼岐有岨，我往獨處。爾莫餘追，無思我悲。"]'),
('yuding-7','琴操十首：履霜操','韓愈','唐','御定全唐诗','yuding','','[]','（尹吉甫子伯奇無罪，為後母譖而見逐，自傷作。',160,'御定全唐詩/json/336.json','["（尹吉甫子伯奇無罪，為後母譖而見逐，自傷作。", "本詞雲：朝履霜兮采晨寒，考不明其心兮信讒言。", "孤恩別離兮摧肺肝，何辜皇天兮遭斯愆。", "痛歿不同兮恩有偏，誰能流顧兮知我冤）", "父兮兒寒，母兮兒饑。兒罪當笞，逐兒何為。", "兒在中野，以宿以處。四無人聲，誰與兒語。", "兒寒何衣，兒饑何食。兒行于野，履霜以足。", "母生眾兒，有母憐之。獨無母憐，兒甯不悲。"]'),
('yuding-8','琴操十首：雉朝飛操','韓愈','唐','御定全唐诗','yuding','','[]','（牧犢子七十無妻，見雉雙飛，感之而作。本詞雲：',88,'御定全唐詩/json/336.json','["（牧犢子七十無妻，見雉雙飛，感之而作。本詞雲：", "雉朝飛兮鳴相和，雌雄群遊兮山之阿。", "我獨何命兮未有家，時將暮兮可奈何，嗟嗟暮兮可奈何）", "雉之飛，於朝日。群雌孤雄，意氣橫出。當東而西，"]'),
('yuding-9','琴操十首：別鵠操','韓愈','唐','御定全唐诗','yuding','','[]','（商陵穆子，娶妻五年無子。父母欲其改娶，其妻聞之，',75,'御定全唐詩/json/336.json','["（商陵穆子，娶妻五年無子。父母欲其改娶，其妻聞之，", "雄鵠銜枝來，雌鵠啄泥歸。巢成不生子，大義當乖離。", "江漢水之大，鵠身鳥之微。更無相逢日，且可繞樹相隨飛。"]'),
('yuding-10','琴操十首：殘形操','韓愈','唐','御定全唐诗','yuding','','[]','有獸維狸兮，我夢得之。其身孔明兮，而頭不知。',44,'御定全唐詩/json/336.json','["有獸維狸兮，我夢得之。其身孔明兮，而頭不知。", "吉凶何為兮，覺坐而思。巫咸上天兮，識者其誰。"]'),
('yuding-11','南山詩','韓愈','唐','御定全唐诗','yuding','','[]','吾聞京城南，茲惟群山囿。東西兩際海，巨細難悉究。',576,'御定全唐詩/json/336.json','["吾聞京城南，茲惟群山囿。東西兩際海，巨細難悉究。", "山經及地志，茫昧非受授。團辭試提挈，掛一念萬漏。", "欲休諒不能，粗敘所經覯。嘗升崇丘望，戢戢見相湊。", "晴明出棱角，縷脈碎分繡。蒸嵐相澒洞，表裏忽通透。", "無風自飄簸，融液煦柔茂。橫雲時平凝，點點露數岫。", "天空浮修眉，濃綠畫新就。孤撐有巉絕，海浴褰鵬噣。", "春陽潛沮洳，濯濯吐深秀。岩巒雖嵂崒，軟弱類含酎。", "夏炎百木盛，蔭鬱增埋覆。神靈日歊歔，雲氣爭結構。", "秋霜喜刻轢，磔卓立臒瘦。參差相疊重，剛耿陵宇宙。", "冬行雖幽墨，冰雪工琢鏤。新曦照危峨，億丈恒高袤。", "明昏無停態，頃刻異狀候。西南雄太白，突起莫間簉。", "藩都配德運，分宅占丁戊。逍遙越坤位，詆訐陷幹竇。", "空虛寒兢兢，風氣較搜漱。朱維方燒日，陰霰縱騰糅。", "昆明大池北，去覿偶晴晝。綿聯窮俯視，倒側困清漚。", "微瀾動水面，踴躍躁猱狖。驚呼惜破碎，仰喜呀不僕。", "前尋徑杜墅，岔蔽畢原陋。崎嶇上軒昂，始得觀覽富。", "行行將遂窮，嶺陸煩互走。勃然思坼裂，擁掩難恕宥。", "巨靈與誇蛾，遠賈期必售。還疑造物意，固護蓄精佑。", "力雖能排斡，雷電怯呵詬。攀緣脫手足，蹭蹬抵積甃。", "茫如試矯首，堛塞生怐愗。威容喪蕭爽，近新迷遠舊。", "拘官計日月，欲進不可又。因緣窺其湫，凝湛閟陰獸。", "魚蝦可俯掇，神物安敢寇。林柯有脫葉，欲墮鳥驚救。", "爭銜彎環飛，投棄急哺鷇。旋歸道回睨，達枿壯複奏。", "籲嗟信奇怪，峙質能化貿。前年遭譴謫，探曆得邂逅。"]'),
('yuding-12','謝自然詩','韓愈','唐','御定全唐诗','yuding','','[]','果州南充縣，寒女謝自然。童騃無所識，但聞有神仙。',408,'御定全唐詩/json/336.json','["果州南充縣，寒女謝自然。童騃無所識，但聞有神仙。", "輕生學其術，乃在金泉山。繁華榮慕絕，父母慈愛捐。", "凝心感魑魅，慌惚難具言。一朝坐空室，雲霧生其間。", "如聆笙竽韻，來自冥冥天。白日變幽晦，蕭蕭風景寒。", "簷楹暫明滅，五色光屬聯。觀者徒傾駭，躑躅詎敢前。", "須臾自輕舉，飄若風中煙。茫茫八紘大，影響無由緣。", "裏胥上其事，郡守驚且歎。驅車領官吏，氓俗爭相先。", "入門無所見，冠履同蛻蟬。皆雲神仙事，灼灼信可傳。", "余聞古夏後，象物知神奸。山林民可入，魍魎莫逢旃。", "逶迤不復振，後世恣欺謾。幽明紛雜亂，人鬼更相殘。", "秦皇雖篤好，漢武洪其源。自從二主來，此禍竟連連。", "木石生怪變，狐狸騁妖患。莫能盡性命，安得更長延。", "人生處萬類，知識最為賢。奈何不自信，反欲從物遷。", "往者不可悔，孤魂抱深冤。來者猶可誡，餘言豈空文。", "人生有常理，男女各有倫。寒衣及饑食，在紡績耕耘。", "下以保子孫，上以奉君親。苟異於此道，皆為棄其身。", "噫乎彼寒女，永托異物群。感傷遂成詩，昧者宜書紳。"]'),
('yuding-13','秋懷詩十一首','韓愈','唐','御定全唐诗','yuding','','[]','窗前兩好樹，眾葉光薿薿。秋風一拂披，策策鳴不已。',540,'御定全唐詩/json/336.json','["窗前兩好樹，眾葉光薿薿。秋風一拂披，策策鳴不已。", "微燈照空床，夜半偏入耳。愁憂無端來，感歎成坐起。", "天明視顏色，與故不相似。羲和驅日月，疾急不可恃。", "浮生雖多塗，趨死惟一軌。胡為浪自苦，得酒且歡喜。", "白露下百草，蕭蘭共雕悴。青青四牆下，已複生滿地。", "寒蟬暫寂寞，蟋蟀鳴自恣。運行無窮期，稟受氣苦異。", "適時各得所，松柏不必貴。", "彼時何卒卒，我志何曼曼。犀首空好飲，廉頗尚能飯。", "學堂日無事，驅馬適所願。茫茫出門路，欲去聊自勸。", "歸還閱書史，文字浩千萬。陳跡竟誰尋，賤嗜非貴獻。", "丈夫意有在，女子乃多怨。", "秋氣日惻惻，秋空日淩淩。上無枝上蜩，下無盤中蠅。", "豈不感時節，耳目去所憎。清曉卷書坐，南山見高棱。", "其下澄湫水，有蛟寒可罾。惜哉不得往，豈謂吾無能。", "離離掛空悲，戚戚抱虛警。露泫秋樹高，蟲吊寒夜永。", "斂退就新懦，趨營悼前猛。歸愚識夷塗，汲古得修綆。", "名浮猶有恥，味薄真自幸。庶幾遺悔尤，即此是幽屏。", "今晨不成起，端坐盡日景。蟲鳴室幽幽，月吐窗冏冏。", "喪懷若迷方，浮念劇含梗。塵埃慵伺候，文字浪馳騁。", "尚須勉其頑，王事有朝請。", "秋夜不可晨，秋日苦易暗。我無汲汲志，何以有此憾。", "寒雞空在棲，缺月煩屢瞰。有琴具徽弦，再鼓聽愈淡。", "古聲久埋滅，無由見真濫。低心逐時趨，苦勉祗能暫。", "有如乘風船，一縱不可纜。不如覷文字，丹鉛事點勘。"]'),
('yuding-14','赴江陵途中寄贈王二十補闕李十一拾遺李二十六員外翰林三學士','韓愈','唐','御定全唐诗','yuding','','[]','孤臣昔放逐，血泣追愆尤。汗漫不省識，恍如乘桴浮。',576,'御定全唐詩/json/336.json','["孤臣昔放逐，血泣追愆尤。汗漫不省識，恍如乘桴浮。", "或自疑上疏，上疏豈其由。是年京師旱，田畝少所收。", "上憐民無食，征賦半已休。有司恤經費，未免煩徵求。", "富者既雲急，貧者固已流。傳聞閭里間，赤子棄渠溝。", "持男易鬥粟，掉臂莫肯酬。我時出衢路，餓者何其稠。", "親逢道邊死，佇立久咿嚘。歸舍不能食，有如魚中鉤。", "適會除禦史，誠當得言秋。拜疏移合門，為忠寧自謀。", "上陳人疾苦，無令絕其喉。下陳畿甸內，根本理宜優。", "積雪驗豐熟，幸寬待蠶麰。天子惻然感，司空歎綢繆。", "謂言即施設，乃反遷炎州。同官盡才俊，偏善柳與劉。", "或慮語言泄，傳之落冤讎。二子不宜爾，將疑斷還不。", "中使臨門遣，頃刻不得留。病妹臥床褥，分知隔明幽。", "悲啼乞就別，百請不頷頭。弱妻抱稚子，出拜忘慚羞。", "黽勉不回顧，行行詣連州。朝為青雲士，暮作白頭囚。", "商山季冬月，冰凍絕行輈。春風洞庭浪，出沒驚孤舟。", "逾嶺到所任，低顏奉君侯。酸寒何足道，隨事生瘡疣。", "遠地觸途異，吏民似猿猴。生獰多忿很，辭舌紛嘲啁。", "白日屋簷下，雙鳴鬥鵂鶹。有蛇類兩首，有蠱群飛遊。", "窮冬或搖扇，盛夏或重裘。颶起最可畏，訇哮簸陵丘。", "雷霆助光怪，氣象難比侔。癘疫忽潛遘，十家無一瘳。", "猜嫌動置毒，對案輒懷愁。前日遇恩赦，私心喜還憂。", "果然又羈縶，不得歸鋤耰。此府雄且大，騰淩盡戈矛。", "棲棲法曹掾，何處事卑陬。生平企仁義，所學皆孔周。", "早知大理官，不列三後儔。何況親犴獄，敲搒發奸偷。"]'),
('yuding-15','暮行河堤上','韓愈','唐','御定全唐诗','yuding','','[]','暮行河堤上，四顧不見人。衰草際黃雲，感歎愁我神。',48,'御定全唐詩/json/336.json','["暮行河堤上，四顧不見人。衰草際黃雲，感歎愁我神。", "夜歸孤舟臥，輾轉空及晨。謀計竟何就，嗟嗟世與身。"]'),
('yuding-16','夜歌','韓愈','唐','御定全唐诗','yuding','','[]','靜夜有清光，閑堂仍獨息。念身幸無恨，志氣方自得。',36,'御定全唐詩/json/336.json','["靜夜有清光，閑堂仍獨息。念身幸無恨，志氣方自得。", "樂哉何所憂，所憂非我力。"]'),
('yuding-17','重雲李觀疾贈之','韓愈','唐','御定全唐诗','yuding','','[]','夭行失其度，陰氣來幹陽。重雲閉白日，炎燠成寒涼。',108,'御定全唐詩/json/336.json','["夭行失其度，陰氣來幹陽。重雲閉白日，炎燠成寒涼。", "小人但咨怨，君子惟憂傷。飲食為減少，身體豈甯康。", "此志誠足貴，懼非職所當。藜羹尚如此，肉食安可嘗。", "窮冬百草死，幽桂乃芬芳。且況天地間，大運自有常。", "勸君善飲食，鸞鳳本高翔。"]'),
('yuding-18','江漢答孟郊','韓愈','唐','御定全唐诗','yuding','','[]','江漢雖雲廣，乘舟渡無艱。流沙信難行，馬足常往還。',84,'御定全唐詩/json/336.json','["江漢雖雲廣，乘舟渡無艱。流沙信難行，馬足常往還。", "淒風結沖波，狐裘能禦寒。終宵處幽室，華燭光爛爛。", "苟能行忠信，可以居夷蠻。嗟余與夫子，此義每所敦。", "何為複見贈，繾綣在不諼。"]'),
('yuding-19','長安交遊者贈孟郊','韓愈','唐','御定全唐诗','yuding','','[]','長安交遊者，貧富各有徒。親朋相過時，亦各有以娛。',48,'御定全唐詩/json/336.json','["長安交遊者，貧富各有徒。親朋相過時，亦各有以娛。", "陋室有文史，高門有笙竽。何能辨榮悴，且欲分賢愚。"]'),
('yuding-20','岐山下二首','韓愈','唐','御定全唐诗','yuding','','[]','誰謂我有耳，不聞鳳凰鳴。朅來岐山下，日暮邊鴻驚。',96,'御定全唐詩/json/336.json','["誰謂我有耳，不聞鳳凰鳴。朅來岐山下，日暮邊鴻驚。", "丹穴五色羽，其名為鳳凰。昔周有盛德，此鳥鳴高岡。", "和聲隨祥風，窅窕相飄揚。聞者亦何事，但知時俗康。", "自從公旦死，千載閟其光。吾君亦勤理，遲爾一來翔。"]'),
('yuding-0','北極贈李觀','韓愈','唐','御定全唐诗','yuding','','[]','北極有羈羽，南溟有沈鱗。川源浩浩隔，影響兩無因。',108,'御定全唐詩/json/337.json','["北極有羈羽，南溟有沈鱗。川源浩浩隔，影響兩無因。", "風雲一朝會，變化成一身。誰言道裏遠，感激疾如神。", "我年二十五，求友昧其人。哀歌西京市，乃與夫子親。", "所尚苟同趨，賢愚豈異倫。方為金石姿，萬世無緇磷。", "無為兒女態，憔悴悲賤貧。"]'),
('yuding-1','此日足可惜贈張籍','韓愈','唐','御定全唐诗','yuding','','[]','此日足可惜，此酒不足嘗。舍酒去相語，共分一日光。',576,'御定全唐詩/json/337.json','["此日足可惜，此酒不足嘗。舍酒去相語，共分一日光。", "念昔未知子，孟君自南方。自矜有所得，言子有文章。", "我名屬相府，欲往不得行。思之不可見，百端在中腸。", "維時月魄死，冬日朝在房。驅馳公事退，聞子適及城。", "命車載之至，引坐于中堂。開懷聽其說，往往副所望。", "孔丘歿已遠，仁義路久荒。紛紛百家起，詭怪相披猖。", "長老守所聞，後生習為常。少知誠難得，純粹古已亡。", "譬彼植園木，有根易為長。留之不遣去，館置城西旁。", "歲時未雲幾，浩浩觀湖江。眾夫指之笑，謂我知不明。", "兒童畏雷電，魚鱉驚夜光。州家舉進士，選試繆所當。", "馳辭對我策，章句何煒煌。相公朝服立，工席歌鹿鳴。", "禮終樂亦闋，相拜送於庭。之子去須臾，赫赫流盛名。", "竊喜複竊歎，諒知有所成。人事安可恒，奄忽令我傷。", "聞子高第日，正從相公喪。哀情逢吉語，惝恍難為雙。", "暮宿偃師西，徒輾轉在床。夜聞汴州亂，繞壁行彷徨。", "我時留妻子，倉卒不及將。相見不復期，零落甘所丁。", "驕兒未絕乳，念之不能忘。忽如在我所，耳若聞啼聲。", "中途安得返，一日不可更。俄有東來說，我家免罹殃。", "乘船下汴水，東去趨彭城。從喪朝至洛，還走不及停。", "假道經盟津，出入行澗岡。日西入軍門，羸馬顛且僵。", "主人願少留，延入陳壺觴。卑賤不敢辭，忽忽心如狂。", "飲食豈知味，絲竹徒轟轟。平明脫身去，決若驚鳧翔。", "黃昏次汜水，欲過無舟航。號呼久乃至，夜濟十裏黃。", "中流上灘潬，沙水不可詳。驚波暗合遝，星宿爭翻芒。"]'),
('yuding-2','幽懷','韓愈','唐','御定全唐诗','yuding','','[]','幽懷不能寫，行此春江潯。適與佳節會，士女競光陰。',84,'御定全唐詩/json/337.json','["幽懷不能寫，行此春江潯。適與佳節會，士女競光陰。", "凝妝耀洲渚，繁吹蕩人心。間關林中鳥，亦知和為音。", "豈無一尊酒，自酌還自吟。但悲時易失，四序迭相侵。", "我歌君子行，視古猶視今。"]'),
('yuding-3','君子法天運','韓愈','唐','御定全唐诗','yuding','','[]','君子法天運，四時可前知。小人惟所遇，寒暑不可期。',48,'御定全唐詩/json/337.json','["君子法天運，四時可前知。小人惟所遇，寒暑不可期。", "利害有常勢，取捨無定姿。焉能使我心，皎皎遠憂疑。"]'),
('yuding-4','落葉送陳羽','韓愈','唐','御定全唐诗','yuding','','[]','落葉不更息，斷蓬無複歸。飄颻終自異，邂逅暫相依。',48,'御定全唐詩/json/337.json','["落葉不更息，斷蓬無複歸。飄颻終自異，邂逅暫相依。", "悄悄深夜語，悠悠寒月輝。誰雲少年別，流淚各沾衣。"]'),
('yuding-5','歸彭城','韓愈','唐','御定全唐诗','yuding','','[]','天下兵又動，太平竟何時。籲謨者誰子，無乃失所宜。',240,'御定全唐詩/json/337.json','["天下兵又動，太平竟何時。籲謨者誰子，無乃失所宜。", "前年關中旱，閭井多死饑。去歲東郡水，生民為流屍。", "上天不虛應，禍福各有隨。我欲進短策，無由至彤墀。", "刳肝以為紙，瀝血以書辭。上言陳堯舜，下言引龍夔。", "言詞多感激，文字少葳蕤。一讀已自怪，再尋良自疑。", "食芹雖雲美，獻禦固已癡。緘封在骨髓，耿耿空自奇。", "昨者到京城，屢陪高車馳。周行多俊異，議論無瑕疵。", "見待頗異禮，未能去毛皮。到口不敢吐，徐徐俟其巇。", "歸來戎馬間，驚顧似羈雌。連日或不語，終朝見相欺。", "乘閑輒騎馬，茫茫詣空陂。遇酒即酩酊，君知我為誰。"]'),
('yuding-6','醉後','韓愈','唐','御定全唐诗','yuding','','[]','煌煌東方星，奈此眾客醉。初喧或忿爭，中靜雜嘲戲。',48,'御定全唐詩/json/337.json','["煌煌東方星，奈此眾客醉。初喧或忿爭，中靜雜嘲戲。", "淋漓身上衣，顛倒筆下字。人生如此少，酒賤且勤置。"]'),
('yuding-7','醉贈張秘書','韓愈','唐','御定全唐诗','yuding','','[]','人皆勸我酒，我若耳不聞。今日到君家，呼酒持勸君。',240,'御定全唐詩/json/337.json','["人皆勸我酒，我若耳不聞。今日到君家，呼酒持勸君。", "為此座上客，及余各能文。君詩多態度，藹藹春空雲。", "東野動驚俗，天葩吐奇芬。張籍學古淡，軒鶴避雞群。", "阿買不識字，頗知書八分。詩成使之寫，亦足張吾軍。", "所以欲得酒，為文俟其醺。酒味既冷冽，酒氣又氛氳。", "性情漸浩浩，諧笑方云云。此誠得酒意，餘外徒繽紛。", "長安眾富兒，盤饌羅膻葷。不解文字飲，惟能醉紅裙。", "雖得一餉樂，有如聚飛蚊。今我及數子，固無蕕與熏。", "險語破鬼膽，高詞媲皇墳。至寶不雕琢，神功謝鋤耘。", "方今向太平，元凱承華勳。吾徒幸無事，庶以窮朝曛。"]'),
('yuding-8','同冠峽','韓愈','唐','御定全唐诗','yuding','','[]','南方二月半，春物亦已少。維舟山水間，晨坐聽百鳥。',72,'御定全唐詩/json/337.json','["南方二月半，春物亦已少。維舟山水間，晨坐聽百鳥。", "宿雲尚含姿，朝日忽升曉。羈旅感和鳴，囚拘念輕矯。", "潺湲淚久迸，詰曲思增繞。行矣且無然，蓋棺事乃了。"]'),
('yuding-9','送惠師','韓愈','唐','御定全唐诗','yuding','','[]','惠師浮屠者，乃是不羈人。十五愛山水，超然謝朋親。',516,'御定全唐詩/json/337.json','["惠師浮屠者，乃是不羈人。十五愛山水，超然謝朋親。", "脫冠剪頭髮，飛步遺蹤塵。發跡入四明，梯空上秋旻。", "遂登天臺望，眾壑皆嶙峋。夜宿最高頂，舉頭看星辰。", "光芒相照燭，南北爭羅陳。茲地絕翔走，自然嚴且神。", "微風吹木石，澎湃聞韶鈞。夜半起下視，溟波銜日輪。", "魚龍驚踴躍，叫嘯成悲辛。怪氣或紫赤，敲磨共輪囷。", "金鴉既騰翥，六合俄清新。常聞禹穴奇，東去窺甌閩。", "越俗不好古，流傳失其真。幽蹤邈難得，聖路嗟長堙。", "回臨浙江濤，屹起高峨岷。壯志死不息，千年如隔晨。", "是非竟何有，棄去非吾倫。淩江詣廬嶽，浩蕩極遊巡。", "崔崒沒雲表，陂陀浸湖淪。是時雨初霽，懸瀑垂天紳。", "前年往羅浮，步戛南海漘。大哉陽德盛，榮茂恒留春。", "鵬鶱墮長翮，鯨戲側修鱗。自來連州寺，曾未造城闉。", "日攜青雲客，探勝窮崖濱。太守邀不去，群官請徒頻。", "囊無一金資，翻謂富者貧。昨日忽不見，我令訪其鄰。", "奔波自追及，把手問所因。顧我卻興歎，君甯異於民。", "離合自古然，辭別安足珍。吾聞九疑好，夙志今欲伸。", "斑竹啼舜婦，清湘沈楚臣。衡山與洞庭，此固道所循。", "尋崧方抵洛，曆華遂之秦。浮游靡定處，偶往即通津。", "吾言子當去，子道非吾遵。江魚不池活，野鳥難籠馴。", "吾非西方教，憐子狂且醇。吾嫉惰遊者，憐子愚且諄。", "去矣各異趣，何為浪沾巾。"]'),
('yuding-10','送靈師','韓愈','唐','御定全唐诗','yuding','','[]','佛法入中國，爾來六百年。齊民逃賦役，高士著幽禪。',540,'御定全唐詩/json/337.json','["佛法入中國，爾來六百年。齊民逃賦役，高士著幽禪。", "官吏不之制，紛紛聽其然。耕桑日失隸，朝署時遺賢。", "靈師皇甫姓，胤胄本蟬聯。少小涉書史，早能綴文篇。", "中間不得意，失跡成延遷。逸志不拘教，軒騰斷牽攣。", "圍棋鬥白黑，生死隨機權。六博在一擲，梟盧叱迴旋。", "戰詩誰與敵，浩汗橫戈鋋。飲酒盡百盞，嘲諧思逾鮮。", "有時醉花月，高唱清且綿。四座咸寂默，杳如奏湘弦。", "尋勝不憚險，黔江屢洄沿。瞿塘五六月，驚電讓歸船。", "怒水忽中裂，千尋墮幽泉。環回勢益急，仰見團團天。", "投身豈得計，性命甘徒捐。浪沫蹙翻湧，漂浮再生全。", "同行二十人，魂骨俱坑填。靈師不掛懷，冒涉道轉延。", "開忠二州牧，詩賦時多傳。失職不把筆，珠璣為君編。", "強留費日月，密席羅嬋娟。昨者至林邑，使君數開筵。", "逐客三四公，盈懷贈蘭荃。湖遊泛漭沆，溪宴駐潺湲。", "別語不許出，行裾動遭牽。鄰州競招請，書劄何翩翩。", "十月下桂嶺，乘寒恣窺緣。落落王員外，爭迎獲其先。", "自從入賓館，占吝久能專。吾徒頗攜被，接宿窮歡妍。", "聽說兩京事，分明皆眼前。縱橫雜謠俗，瑣屑咸羅穿。", "材調真可惜，朱丹在磨研。方將斂之道，且欲冠其顛。", "韶陽李太守，高步淩雲煙。得客輒忘食，開囊乞繒錢。", "手持南曹敘，字重青瑤鐫。古氣參彖系，高標摧太玄。", "維舟事幹謁，披讀頭風痊。還如舊相識，傾壺暢幽悁。", "以此複留滯，歸驂幾時鞭。"]'),
('yuding-11','縣齋有懷','韓愈','唐','御定全唐诗','yuding','','[]','少小尚奇偉，平生足悲吒。猶嫌子夏儒，肯學樊遲稼。',480,'御定全唐詩/json/337.json','["少小尚奇偉，平生足悲吒。猶嫌子夏儒，肯學樊遲稼。", "事業窺皋稷，文章蔑曹謝。濯纓起江湖，綴佩雜蘭麝。", "悠悠指長道，去去策高駕。誰為傾國謀，自許連城價。", "初隨計吏貢，屢入澤宮射。雖免十上勞，何能一戰霸。", "人情忌殊異，世路多權詐。蹉跎顏遂低，摧折氣愈下。", "冶長信非罪，侯生或遭罵。懷書出皇都，銜淚渡清灞。", "身將老寂寞，志欲死閒暇。朝食不盈腸，冬衣才掩髂。", "軍書既頻召，戎馬乃連跨。大樑從相公，彭城赴僕射。", "弓箭圍狐兔，絲竹羅酒炙。兩府變荒涼，三年就休假。", "求官去東洛，犯雪過西華。塵埃紫陌春，風雨靈台夜。", "名聲荷朋友，援引乏姻婭。雖陪彤庭臣，詎縱青冥靶。", "寒空聳危闕，曉色曜修架。捐軀辰在丁，鎩翮時方蠟。", "投荒誠職分，領邑幸寬赦。湖波翻日車，嶺石坼天罅。", "毒霧恒熏晝，炎風每燒夏。雷威固已加，颶勢仍相借。", "氣象杳難測，聲音籲可怕。夷言聽未慣，越俗循猶乍。", "指摘兩憎嫌，睢盱互猜訝。只緣恩未報，豈謂生足藉。", "嗣皇新繼明，率土日流化。惟思滌瑕垢，長去事桑柘。", "劚嵩開雲扃，壓潁抗風榭。禾麥種滿地，梨棗栽繞舍。", "兒童稍長成，雀鼠得驅嚇。官租日輸納，村酒時邀迓。", "閑愛老農愚，歸弄小女姹。如今便可爾，何用畢婚嫁。"]'),
('yuding-12','合江亭','韓愈','唐','御定全唐诗','yuding','','[]','紅亭枕湘江，蒸水會其左。瞰臨眇空闊，綠淨不可唾。',241,'御定全唐詩/json/337.json','["紅亭枕湘江，蒸水會其左。瞰臨眇空闊，綠淨不可唾。", "維昔經營初，邦君實王佐。翦林遷神祠，買地費家貨。", "梁棟巨集可愛，結構麗匪過。伊人去軒騰，茲宇遂頹挫。", "老郎來何暮，高唱久乃和。樹蘭盈九畹，栽竹逾萬個。", "長綆汲滄浪，幽蹊下坎坷。波濤夜俯聽，雲樹朝對臥。", "初如遺宦情，終乃最郡課。人生誠無幾，事往悲豈奈。", "蕭條綿歲時，契闊繼庸懦。勝事誰複論，醜聲日已播。", "中丞黜凶邪，天子閔窮餓。君侯至之初，閭裏自相賀。", "淹滯樂閑曠，勤苦勸慵惰。為餘掃塵階，命樂醉眾座。", "窮秋感平分，新月憐半破。願書岩上石，勿使泥塵涴。"]'),
('yuding-13','陪杜侍禦遊湘西兩寺獨宿有題一首，因獻楊常侍','韓愈','唐','御定全唐诗','yuding','','[]','長沙千里平，勝地猶在險。況當江闊處，鬥起勢匪漸。',300,'御定全唐詩/json/337.json','["長沙千里平，勝地猶在險。況當江闊處，鬥起勢匪漸。", "深林高玲瓏，青山上琬琰。路窮台殿辟，佛事煥且儼。", "剖竹走泉源，開廊架崖廣。是時秋之殘，暑氣尚未斂。", "群行忘後先，朋息棄拘檢。客堂喜空涼，華榻有清簟。", "澗蔬煮蒿芹，水果剝菱芡。伊餘夙所慕，陪賞亦雲忝。", "幸逢車馬歸，獨宿門不掩。山樓黑無月，漁火燦星點。", "夜風一何喧，杉檜屢磨颭。猶疑在波濤，怵惕夢成魘。", "靜思屈原沈，遠憶賈誼貶。椒蘭爭妒忌，絳灌共讒諂。", "誰令悲生腸，坐使淚盈臉。翻飛乏羽翼，指摘困瑕玷。", "珥貂藩維重，政化類分陝。禮賢道何優，奉己事苦儉。", "大廈棟方隆，巨川楫行剡。經營誠少暇，遊宴固已歉。", "旅程愧淹留，徂歲嗟荏苒。平生每多感，柔翰遇頻染。", "輾轉嶺猿鳴，曙燈青睒睒。"]'),
('yuding-14','岳陽樓別竇司直','韓愈','唐','御定全唐诗','yuding','','[]','洞庭九州間，厥大誰與讓。南匯群崖水，北注何奔放。',552,'御定全唐詩/json/337.json','["洞庭九州間，厥大誰與讓。南匯群崖水，北注何奔放。", "瀦為七百里，吞納各殊狀。自古澄不清，環混無歸向。", "炎風日搜攪，幽怪多冗長。軒然大波起，宇宙隘而妨。", "巍峨拔嵩華，騰踔較健壯。聲音一何宏，轟輵車萬兩。", "猶疑帝軒轅，張樂就空曠。蛟螭露筍簴，縞練吹組帳。", "鬼神非人世，節奏頗跌踼。陽施見誇麗，陰閉感悽愴。", "朝過宜春口，極北缺堤障。夜纜巴陵洲，叢芮才可傍。", "星河盡涵泳，俯仰迷下上。餘瀾怒不已，喧聒鳴甕盎。", "明登岳陽樓，輝煥朝日亮。飛廉戢其威，清晏息纖纊。", "泓澄湛凝綠，物影巧相況。江豚時出戲，驚波忽蕩漾。", "時當冬之孟，隙竅縮寒漲。前臨指近岸，側坐眇難望。", "滌濯神魂醒，幽懷舒以暢。主人孩童舊，握手乍忻悵。", "憐我竄逐歸，相見得無恙。開筵交履舄，爛漫倒家釀。", "杯行無留停，高柱送清唱。中盤進橙栗，投擲傾脯醬。", "歡窮悲心生，婉孌不能忘。念昔始讀書，志欲幹霸王。", "屠龍破千金，為藝亦雲亢。愛才不擇行，觸事得讒謗。", "前年出官由，此禍最無妄。公卿采虛名，擢拜識天仗。", "奸猜畏彈射，斥逐恣欺誑。新恩移府庭，逼側廁諸將。", "於嗟苦駑緩，但懼失宜當。追思南渡時，魚腹甘所葬。", "嚴程迫風帆，劈箭入高浪。顛沈在須臾，忠鯁誰複諒。", "生還真可喜，克己自懲創。庶從今日後，粗識得與喪。", "事多改前好，趣有獲新尚。誓耕十畝田，不取萬乘相。", "細君知蠶織，稚子已能餉。行當掛其冠，生死君一訪。"]'),
('yuding-15','送文暢師北遊','韓愈','唐','御定全唐诗','yuding','','[]','昔在四門館，晨有僧來謁。自言本吳人，少小學城闕。',385,'御定全唐詩/json/337.json','["昔在四門館，晨有僧來謁。自言本吳人，少小學城闕。", "已窮佛根源，粗識事輗軏。攣拘屈吾真，戒轄思遠發。", "薦紳秉筆徒，聲譽耀前閥。從求送行詩，屢造忍顛蹶。", "今成十餘卷，浩汗羅斧鉞。先生閟窮巷，未得窺剞劂。", "又聞識大道，何路補黥刖。出其囊中文，滿聽實清越。", "謂僧當少安，草序頗排訐。上論古之初，所以施賞罰。", "下開迷惑胸，窙豁劚株橛。僧時不聽瑩，若飲水救暍。", "風塵一出門，時日多如發。三年竄荒嶺，守縣坐深樾。", "征租聚異物，詭制怛巾襪。幽窮誰共語，思想甚含噦。", "昨來得京官，照壁喜見蠍。況逢舊親識，無不比鶼蟩。", "長安多門戶，吊慶少休歇。而能勤來過，重惠安可揭。", "當今聖政初，恩澤完vr狘。胡為不自暇，飄戾逐鸇鷢。", "僕射領北門，威德壓胡羯。相公鎮幽都，竹帛爛勳伐。", "酒場舞閨姝，獵騎圍邊月。開張篋中寶，自可得津筏。", "從茲富裘馬，寧複茹藜蕨。余期報恩後，謝病老耕垡。", "庇身指蓬茅，逞志縱獫猲。僧還相訪來，山藥煮可掘。"]'),
('yuding-16','答張徹','韓愈','唐','御定全唐诗','yuding','','[]','辱贈不知報，我歌爾其聆。首敘始識面，次言後分形。',576,'御定全唐詩/json/337.json','["辱贈不知報，我歌爾其聆。首敘始識面，次言後分形。", "道途綿萬里，日月垂十齡。浚郊避兵亂，睢岸連門停。", "肝膽一古劍，波濤兩浮萍。漬墨竄舊史，磨丹注前經。", "義苑手秘寶，文堂耳驚霆。暄晨躡露舄，暑夕眠風欞。", "結友子讓抗，請師我慚丁。初味猶啖蔗，遂通斯建瓴。", "搜奇日有富，嗜善心無寧。石樑平侹侹，沙水光泠泠。", "乘枯摘野豔，沈細抽潛腥。遊寺去陟巘，尋徑返穿汀。", "緣雲竹竦竦，失路麻冥冥。淫潦忽翻野，平蕪眇開溟。", "防泄塹夜塞，懼沖城晝扃。及去事戎轡，相逢宴軍伶。", "觥秋縱兀兀，獵旦馳駉駉。從賦始分手，朝京忽同舲。", "急時促暗棹，戀月留虛亭。畢事驅傳馬，安居守窗螢。", "梅花灞水別，宮燭驪山醒。省選逮投足，鄉賓尚摧翎。", "塵祛又一摻，淚眥還雙熒。洛邑得休告，華山窮絕陘。", "倚岩睨海浪，引袖拂天星。日駕此回轄，金神所司刑。", "泉紳拖修白，石劍攢高青。磴蘚澾拳局，梯飆颭伶俜。", "悔狂已咋指，垂誡仍鐫銘。峨豸忝備列，伏蒲愧分涇。", "微誠慕橫草，瑣力摧撞筳。疊雪走商嶺，飛波航洞庭。", "下險疑墮井，守官類拘囹。荒餐茹獠蠱，幽夢感湘靈。", "刺史肅蓍蔡，吏人沸蝗螟。點綴簿上字，趨蹌合前鈴。", "賴其飽山水，得以娛瞻聽。紫樹雕斐亹，碧流滴瓏玲。", "映波鋪遠錦，插地列長屏。愁狖酸骨死，怪花醉魂馨。", "潛苞絳實坼，幽乳翠毛零。赦行五百里，月變三十蓂。", "漸階群振鷺，入學誨螟蛉。蘋甘謝鳴鹿，罍滿慚罄瓶。", "冏冏抱瑚璉，飛飛聯鶺鴒。魚鬣欲脫背，虯光先照硎。"]'),
('yuding-17','薦士','韓愈','唐','御定全唐诗','yuding','','[]','周詩三百篇，雅麗理訓誥。曾經聖人手，議論安敢到。',456,'御定全唐詩/json/337.json','["周詩三百篇，雅麗理訓誥。曾經聖人手，議論安敢到。", "五言出漢時，蘇李首更號。東都漸彌漫，派別百川導。", "建安能者七，卓犖變風操。逶迤抵晉宋，氣象日凋耗。", "中間數鮑謝，比近最清奧。齊梁及陳隋，眾作等蟬噪。", "搜春摘花卉，沿襲傷剽盜。國朝盛文章，子昂始高蹈。", "勃興得李杜，萬類困陵暴。後來相繼生，亦各臻閫奧。", "有窮者孟郊，受材實雄驁。冥觀洞古今，象外逐幽好。", "橫空盤硬語，妥帖力排奡。敷柔肆紆餘，奮猛卷海潦。", "榮華肖天秀，捷疾逾響報。行身踐規矩，甘辱恥媚灶。", "孟軻分邪正，眸子看了眊。杳然粹而清，可以鎮浮躁，", "俗流知者誰，指注競嘲傲。聖皇索遺逸，髦士日登造。", "廟堂有賢相，愛遇均覆燾。況承歸與張，二公迭嗟悼。", "青冥送吹噓，強箭射魯縞。胡為久無成，使以歸期告。", "霜風破佳菊，嘉節迫吹帽。念將決焉去，感物增戀嫪。", "彼微水中荇，尚煩左右芼。魯侯國至小，廟鼎猶納郜。", "幸當擇瑉玉，寧有棄珪瑁。悠悠我之思，擾擾風中纛。", "上言愧無路，日夜惟心禱。鶴翎不天生，變化在啄菢。", "通波非難圖，尺地易可漕。善善不汲汲，後時徒悔懊。", "救死具八珍，不如一簞犒。微詩公勿誚，愷悌神所勞。"]'),
('yuding-18','喜侯喜至贈張籍張徹','韓愈','唐','御定全唐诗','yuding','','[]','昔我在南時，數君常在念。搖搖不可止，諷詠日喁噞。',241,'御定全唐詩/json/337.json','["昔我在南時，數君常在念。搖搖不可止，諷詠日喁噞。", "如以膏濯衣，每漬垢逾染。又如心中疾，針石非所砭。", "常思得遊處，至死無倦厭。地遐物奇怪，水鏡涵石劍。", "荒花窮漫亂，幽獸工騰閃。礙目不忍窺，忽忽坐昏墊。", "逢神多所祝，豈忘靈即驗。依依夢歸路，歷歷想行店。", "今者誠自幸，所懷無一欠。孟生去雖索，侯氏來還歉。", "欹眠聽新詩，屋角月豔豔。雜作承間騁，交驚舌互bc。", "繽紛指瑕疵，拒捍阻城塹。以餘經摧挫，固請發鉛槧。", "居然妄推讓，見謂爇天焰。比疏語徒妍，悚息不敢占。", "呼奴具盤餐，飣餖魚菜贍。人生但如此，朱紫安足僭。"]'),
('yuding-19','古風','韓愈','唐','御定全唐诗','yuding','','[]','今日曷不樂，幸時不用兵。無曰既蹙矣，乃尚可以生。',59,'御定全唐詩/json/337.json','["今日曷不樂，幸時不用兵。無曰既蹙矣，乃尚可以生。", "彼州之賦，去汝不顧。此州之役，去我奚適。一邑之水，", "無念百年，聊樂一日。"]'),
('yuding-20','駑驥','韓愈','唐','御定全唐诗','yuding','','[]','駑駘誠齷齪，市者何其稠。力小若易制，價微良易酬。',240,'御定全唐詩/json/337.json','["駑駘誠齷齪，市者何其稠。力小若易制，價微良易酬。", "渴飲一鬥水，饑食一束芻。嘶鳴當大路，志氣若有餘。", "騏驥生絕域，自矜無匹儔。牽驅入市門，行者不為留。", "借問價幾何，黃金比嵩丘。借問行幾何，咫尺視九州。", "饑食玉山禾，渴飲醴泉流。問誰能為禦，曠世不可求。", "惟昔穆天子，乘之極遐遊。王良執其轡，造父挾其輈。", "因言天外事，茫惚使人愁。駑駘謂騏驥，餓死餘爾羞。", "有能必見用，有德必見收。孰雲時與命，通塞皆自由。", "騏驥不敢言，低徊但垂頭。人皆劣騏驥，共以駑駘優。", "喟餘獨興歎，才命不同謀。寄詩同心子，為我商聲謳。"]'),
('yuding-21','馬厭穀','韓愈','唐','御定全唐诗','yuding','','[]','馬厭穀兮，士不厭糠籺；土被文繡兮，士無短褐。',46,'御定全唐詩/json/337.json','["馬厭穀兮，士不厭糠籺；土被文繡兮，士無短褐。", "彼其得志兮，不我虞；一朝失志兮，其何如。已焉哉，"]'),
('yuding-22','出門','韓愈','唐','御定全唐诗','yuding','','[]','長安百萬家，出門無所之。豈敢尚幽獨，與世實參差。',72,'御定全唐詩/json/337.json','["長安百萬家，出門無所之。豈敢尚幽獨，與世實參差。", "古人雖已死，書上有其辭。開卷讀且想，千載若相期。", "出門各有道，我道方未夷。且於此中息，天命不吾欺。"]'),
('yuding-23','嗟哉董生行','韓愈','唐','御定全唐诗','yuding','','[]','淮水出桐柏，山東馳遙遙千里不能休；淝水出其側，',87,'御定全唐詩/json/337.json','["淮水出桐柏，山東馳遙遙千里不能休；淝水出其側，", "彷徨躑躅久不去，以翼來覆待狗歸。嗟哉董生，誰將與儔？", "時之人，夫妻相虐，兄弟為讎。食君之祿，而令父母愁。", "亦獨何心，嗟哉董生無與儔。"]'),
('yuding-24','烽火','韓愈','唐','御定全唐诗','yuding','','[]','登高望烽火，誰謂塞塵飛。王城富且樂，曷不事光輝。',60,'御定全唐詩/json/337.json','["登高望烽火，誰謂塞塵飛。王城富且樂，曷不事光輝。", "勿言日已暮，相見恐行稀。願君熟念此，秉燭夜中歸。", "我歌寧自感，乃獨淚沾衣。"]'),
('yuding-25','汴州亂二首','韓愈','唐','御定全唐诗','yuding','','[]','汴州城門朝不開，天狗墮地聲如雷。健兒爭誇殺留後，',48,'御定全唐詩/json/337.json','["汴州城門朝不開，天狗墮地聲如雷。健兒爭誇殺留後，", "母從子走者為誰，大夫夫人留後兒。昨日乘車騎大馬，"]'),
('yuding-26','利劍','韓愈','唐','御定全唐诗','yuding','','[]','利劍光耿耿，佩之使我無邪心。故人念我寡徒侶，',32,'御定全唐詩/json/337.json','["利劍光耿耿，佩之使我無邪心。故人念我寡徒侶，", "劍與我俱變化歸黃泉。"]'),
('yuding-27','齪齪','韓愈','唐','御定全唐诗','yuding','','[]','齪齪當世士，所憂在饑寒。但見賤者悲，不聞貴者歎。',144,'御定全唐詩/json/337.json','["齪齪當世士，所憂在饑寒。但見賤者悲，不聞貴者歎。", "大賢事業異，遠抱非俗觀。報國心皎潔，念時涕汍瀾。", "妖姬坐左右，柔指發哀彈。酒肴雖日陳，感激寧為歡。", "秋陰欺白日，泥潦不少幹。河堤決東郡，老弱隨驚湍。", "天意固有屬，誰能詰其端。願辱太守薦，得充諫諍官。", "排雲叫閶闔，披腹呈琅玕。致君豈無術，自進誠獨難。"]'),
('yuding-0','河之水二首寄子侄老成','韓愈','唐','御定全唐诗','yuding','','[]','河之水，去悠悠。我不如，水東流。我有孤侄在海陬，',48,'御定全唐詩/json/338.json','["河之水，去悠悠。我不如，水東流。我有孤侄在海陬，", "河之水，悠悠去。我不如，水東注。我有孤侄在海浦，"]'),
('yuding-1','山石','韓愈','唐','御定全唐诗','yuding','','[]','山石犖確行徑微，黃昏到寺蝙蝠飛。升堂坐階新雨足，',88,'御定全唐詩/json/338.json','["山石犖確行徑微，黃昏到寺蝙蝠飛。升堂坐階新雨足，", "鋪床拂席置羹飯，疏糲亦足飽我饑。夜深靜臥百蟲絕，", "山紅澗碧紛爛漫，時見松櫪皆十圍。當流赤足蹋澗石，", "嗟哉吾黨二三子，安得至老不更歸。"]'),
('yuding-2','天星送楊凝郎中賀正','韓愈','唐','御定全唐诗','yuding','','[]','天星牢落雞喔咿，僕夫起餐車載脂。正當窮冬寒未已，',40,'御定全唐詩/json/338.json','["天星牢落雞喔咿，僕夫起餐車載脂。正當窮冬寒未已，", "侍從近臣有虛位，公今此去歸何時。"]'),
('yuding-3','汴泗交流贈張僕射','韓愈','唐','御定全唐诗','yuding','','[]','汴泗交流郡城角，築場十步平如削。短垣三面繚逶迤，',88,'御定全唐詩/json/338.json','["汴泗交流郡城角，築場十步平如削。短垣三面繚逶迤，", "分曹決勝約前定，百馬攢蹄近相映。球驚杖奮合且離，", "超遙散漫兩閒暇，揮霍紛紜爭變化。發難得巧意氣粗，", "當今忠臣不可得，公馬莫走須殺賊。"]'),
('yuding-4','忽忽','韓愈','唐','御定全唐诗','yuding','','[]','忽忽乎餘未知生之為樂也，願脫去而無因。',59,'御定全唐詩/json/338.json','["忽忽乎餘未知生之為樂也，願脫去而無因。", "安得長翮大翼如雲生我身，乘風振奮出六合。", "絕浮塵，死生哀樂兩相棄，是非得失付閒人。"]'),
('yuding-5','鳴雁','韓愈','唐','御定全唐诗','yuding','','[]','嗷嗷鳴雁鳴且飛，窮秋南去春北歸。去寒就暖識所依，',56,'御定全唐詩/json/338.json','["嗷嗷鳴雁鳴且飛，窮秋南去春北歸。去寒就暖識所依，", "裴回反顧群侶違。哀鳴欲下洲渚非。江南水闊朝雲多，", "淩風一舉君謂何。"]'),
('yuding-6','龍移','韓愈','唐','御定全唐诗','yuding','','[]','天昏地黑蛟龍移，雷驚電激雄雌隨。',32,'御定全唐詩/json/338.json','["天昏地黑蛟龍移，雷驚電激雄雌隨。", "清泉百丈化為土，魚鱉枯死籲可悲。"]'),
('yuding-7','雉帶箭','韓愈','唐','御定全唐诗','yuding','','[]','原頭火燒靜兀兀，野雉畏鷹出複沒。將軍欲以巧伏人，',48,'御定全唐詩/json/338.json','["原頭火燒靜兀兀，野雉畏鷹出複沒。將軍欲以巧伏人，", "沖人決起百餘尺，紅翎白鏃相傾斜。將軍仰笑軍吏賀，"]'),
('yuding-8','條山蒼','韓愈','唐','御定全唐诗','yuding','','[]','條山蒼，河水黃。浪波沄沄去，松柏在山岡。',20,'御定全唐詩/json/338.json','["條山蒼，河水黃。浪波沄沄去，松柏在山岡。"]'),
('yuding-9','贈鄭兵曹','韓愈','唐','御定全唐诗','yuding','','[]','尊酒相逢十載前，君為壯夫我少年。尊酒相逢十載後，',48,'御定全唐詩/json/338.json','["尊酒相逢十載前，君為壯夫我少年。尊酒相逢十載後，", "當今賢俊皆周行，君何為乎亦遑遑。杯行到君莫停手，"]'),
('yuding-10','桃源圖','韓愈','唐','御定全唐诗','yuding','','[]','神仙有無何渺茫，桃源之說誠荒唐。流水盤回山百轉，',184,'御定全唐詩/json/338.json','["神仙有無何渺茫，桃源之說誠荒唐。流水盤回山百轉，", "南宮先生忻得之，波濤入筆驅文辭。文工畫妙各臻極，", "嬴顛劉蹶了不聞，地坼天分非所恤。種桃處處惟開花。", "川原近遠蒸紅霞。初來猶自念鄉邑，歲久此地還成家。", "漁舟之子來何所，物色相猜更問語。大蛇中斷喪前王，", "當時萬事皆眼見，不知幾許猶流傳。爭持酒食來相饋，", "夜半金雞啁哳鳴，火輪飛出客心驚。人間有累不可住，", "世俗寧知偽與真，至今傳者武陵人。"]'),
('yuding-11','東方半明','韓愈','唐','御定全唐诗','yuding','','[]','東方半明大星沒，獨有太白配殘月。嗟爾殘月勿相疑，',32,'御定全唐詩/json/338.json','["東方半明大星沒，獨有太白配殘月。嗟爾殘月勿相疑，", "雞三號，更五點。"]'),
('yuding-12','贈唐衢','韓愈','唐','御定全唐诗','yuding','','[]','虎有爪兮牛有角，虎可搏兮牛可觸。奈何君獨抱奇材，',40,'御定全唐詩/json/338.json','["虎有爪兮牛有角，虎可搏兮牛可觸。奈何君獨抱奇材，", "胡不上書自薦達，坐令四海如虞唐。"]'),
('yuding-13','貞女峽','韓愈','唐','御定全唐诗','yuding','','[]','江盤峽束春湍豪，風雷戰鬥魚龍逃。懸流轟轟射水府，',24,'御定全唐詩/json/338.json','["江盤峽束春湍豪，風雷戰鬥魚龍逃。懸流轟轟射水府，"]'),
('yuding-14','贈侯喜','韓愈','唐','御定全唐诗','yuding','','[]','吾党侯生字叔𨑓，呼我持竿釣溫水。平明鞭馬出都門，',120,'御定全唐詩/json/338.json','["吾党侯生字叔𨑓，呼我持竿釣溫水。平明鞭馬出都門，", "蝦蟆跳過雀兒浴，此縱有魚何足求。我為侯生不能已，", "暫動還休未可期，蝦行蛭渡似皆疑。舉竿引線忽有得，", "我今行事盡如此，此事正好為吾規。半世遑遑就舉選，", "便當提攜妻與子，南入箕潁無還時。叔𨑓君今氣方銳，"]'),
('yuding-15','古意','韓愈','唐','御定全唐诗','yuding','','[]','太華峰頭玉井蓮，開花十丈藕如船。冷比雪霜甘比蜜，',40,'御定全唐詩/json/338.json','["太華峰頭玉井蓮，開花十丈藕如船。冷比雪霜甘比蜜，", "安得長梯上摘實，下種七澤根株連。"]'),
('yuding-16','八月十五夜贈張功曹','韓愈','唐','御定全唐诗','yuding','','[]','纖雲四卷天無河，清風吹空月舒波。沙平水息聲影絕，',120,'御定全唐詩/json/338.json','["纖雲四卷天無河，清風吹空月舒波。沙平水息聲影絕，", "洞庭連天九疑高，蛟龍出沒猩鼯號。十生九死到官所，", "昨者州前捶大鼓，嗣皇繼聖登夔皋。赦書一日行萬里，", "州家申名使家抑，坎軻只得移荊蠻。判司卑官不堪說，", "君歌且休聽我歌，我歌今與君殊科。一年明月今宵多，"]'),
('yuding-17','謁衡嶽廟遂宿嶽寺題門樓','韓愈','唐','御定全唐诗','yuding','','[]','五嶽祭秩皆三公，四方環鎮嵩當中。火維地荒足妖怪，',136,'御定全唐詩/json/338.json','["五嶽祭秩皆三公，四方環鎮嵩當中。火維地荒足妖怪，", "我來正逢秋雨節，陰氣晦昧無清風。潛心默禱若有應，", "紫蓋連延接天柱，石廩騰擲堆祝融。森然魄動下馬拜，", "升階傴僂薦脯酒，欲以菲薄明其衷。廟令老人識神意，", "竄逐蠻荒幸不死，衣食才足甘長終。侯王將相望久絕，", "猿鳴鐘動不知曙，杲杲寒日生於東。"]'),
('yuding-18','岣嶁山','韓愈','唐','御定全唐诗','yuding','','[]','岣嶁山尖神禹碑，字青石赤形模奇。科鬥拳身薤倒披，',24,'御定全唐詩/json/338.json','["岣嶁山尖神禹碑，字青石赤形模奇。科鬥拳身薤倒披，"]'),
('yuding-19','永貞行','韓愈','唐','御定全唐诗','yuding','','[]','君不見太皇諒陰未出令，小人乘時偷國柄。',163,'御定全唐詩/json/338.json','["君不見太皇諒陰未出令，小人乘時偷國柄。", "北軍百萬虎與貔，天子自將非他師。一朝奪印付私黨，", "夜作詔書朝拜官，超資越序曾無難。公然白日受賄賂，", "董賢三公誰複惜，侯景九錫行可歎。國家功高德且厚，", "膺圖受禪登明堂，共流幽州鯀死羽。四門肅穆賢俊登，", "湖波連天日相騰，蠻俗生梗瘴癘烝。江氛嶺祲昏若凝，", "雄虺毒螫墮股肱，食中置藥肝心崩。左右使令詐難憑，"]'),
('yuding-20','洞庭湖阻風贈張十一署','韓愈','唐','御定全唐诗','yuding','','[]','十月陰氣盛，北風無時休。蒼茫洞庭岸，與子維雙舟。',120,'御定全唐詩/json/338.json','["十月陰氣盛，北風無時休。蒼茫洞庭岸，與子維雙舟。", "霧雨晦爭泄，波濤怒相投。犬雞斷四聽，糧絕誰與謀。", "相去不容步，險如礙山丘。清談可以飽，夢想接無由。", "男女喧左右，饑啼但啾啾。非懷北歸興，何用勝羈愁。", "雲外有白日，寒光自悠悠。能令暫開霽，過是吾無求。"]'),
('yuding-21','李花贈張十一署','韓愈','唐','御定全唐诗','yuding','','[]','江陵城西二月尾，花不見桃惟見李。風揉雨練雪羞比，',72,'御定全唐詩/json/338.json','["江陵城西二月尾，花不見桃惟見李。風揉雨練雪羞比，", "迷魂亂眼看不得，照耀萬樹繁如堆。念昔少年著游燕，", "只今四十已如此，後日更老誰論哉。力攜一尊獨就醉，"]'),
('yuding-22','杏花','韓愈','唐','御定全唐诗','yuding','','[]','居鄰北郭古寺空，杏花兩株能白紅。曲江滿園不可到，',88,'御定全唐詩/json/338.json','["居鄰北郭古寺空，杏花兩株能白紅。曲江滿園不可到，", "冬寒不嚴地恒泄，陽氣發亂無全功。浮花浪蕊鎮長有，", "鷓鴣鉤輈猿叫歇，杳杳深谷攢青楓。豈如此樹一來玩，", "明年更發應更好，道人莫忘鄰家翁。"]'),
('yuding-23','感春四首','韓愈','唐','御定全唐诗','yuding','','[]','我所思兮在何所，情多地遐兮遍處處。東西南北皆欲往，',249,'御定全唐詩/json/338.json','["我所思兮在何所，情多地遐兮遍處處。東西南北皆欲往，", "三杯取醉不復論，一生長恨奈何許。", "皇天平分成四時，春氣漫誕最可悲。雜花妝林草蓋地，", "豈如秋霜雖慘冽，摧落老物誰惜之。為此徑須沽酒飲，", "屈原離騷二十五，不肯餔啜糟與醨。惜哉此子巧言語，", "平明出門暮歸舍，酩酊馬上知為誰。", "朝騎一馬出，暝就一床臥。詩書漸欲拋，節行久已惰。", "冠欹感發禿，語誤驚齒墮。孤負平生心，已矣知何奈。", "我恨不如江頭人，長網橫江遮紫鱗。獨宿荒陂射鳧雁，", "今者無端讀書史，智慧只足勞精神。畫蛇著足無處用，", "數杯澆腸雖暫醉，皎皎萬慮醒還新。百年未滿不得死，"]'),
('yuding-24','寒食日出遊','韓愈','唐','御定全唐诗','yuding','','[]','李花初發君始病，我往看君花轉盛。走馬城西惆悵歸，',168,'御定全唐詩/json/338.json','["李花初發君始病，我往看君花轉盛。走馬城西惆悵歸，", "可憐物色阻攜手，空展霜縑吟九詠。紛紛落盡泥與塵，", "關山遠別固其理，寸步難見始知命。憶昔與君同貶官，", "各言生死兩追隨，直置心親無貌敬。念君又署南荒吏，", "囊空甑倒誰救之，我今一食日還並。自然憂氣損天和，", "今朝寒食行野外，綠楊匝岸蒲生迸。宋玉庭邊不見人，", "飲酒寧嫌盞底深，題詩尚倚筆鋒勁。明宵故欲相就醉，"]'),
('yuding-25','憶昨行和張十一','韓愈','唐','御定全唐诗','yuding','','[]','憶昨夾鐘之呂初吹灰，上公禮罷元侯回。車載牲牢甕舁酒，',170,'御定全唐詩/json/338.json','["憶昨夾鐘之呂初吹灰，上公禮罷元侯回。車載牲牢甕舁酒，", "青天白日花草麗，玉斝屢舉傾金罍。張君名聲座所屬，", "自期殞命在春序，屈指數日憐嬰孩。危辭苦語感我耳，", "陽山鳥路出臨武，驛馬拒地驅頻隤。踐蛇茹蠱不擇死，", "近者三奸悉破碎，羽窟無底幽黃能。眼中了了見鄉國，", "無妄之憂勿藥喜，一善自足禳千災。頭輕目朗肌骨健，", "嵩山東頭伊洛岸，勝事不假須穿栽。君當先行我待滿，"]'),
('yuding-0','劉生詩','韓愈','唐','御定全唐诗','yuding','','[]','生名師命其姓劉，自少軒輊非常儔。棄家如遺來遠遊，',120,'御定全唐詩/json/339.json','["生名師命其姓劉，自少軒輊非常儔。棄家如遺來遠遊，", "越女一笑三年留，南逾橫嶺入炎州。青鯨高磨波山浮，", "問胡不歸良有由，美酒傾水炙肥牛。妖歌慢舞爛不收，", "瞥然一餉成十秋，昔須未生今白頭。五管曆遍無賢侯，", "我為羅列陳前修，芟蒿斬蓬利鋤耰。天星回環數才周，"]'),
('yuding-1','鄭群贈簟','韓愈','唐','御定全唐诗','yuding','','[]','蘄州笛竹天下知，鄭君所寶尤瑰奇。攜來當晝不得臥，',96,'御定全唐詩/json/339.json','["蘄州笛竹天下知，鄭君所寶尤瑰奇。攜來當晝不得臥，", "法曹貧賤眾所易，腰腹空大何能為，自從五月困暑濕，", "日暮歸來獨惆悵，有賣直欲傾家資。誰謂故人知我意，", "青蠅側翅蚤虱避，肅肅疑有清飆吹。倒身甘寢百疾愈，"]'),
('yuding-2','豐陵行','韓愈','唐','御定全唐诗','yuding','','[]','羽衛煌煌一百里，曉出都門葬天子。群臣雜遝馳後先，',88,'御定全唐詩/json/339.json','["羽衛煌煌一百里，曉出都門葬天子。群臣雜遝馳後先，", "清風飄飄輕雨灑，偃蹇旗旆卷以舒。逾梁下阪笳鼓咽，", "皇帝孝心深且遠，資送禮備無贏餘。設官置衛鎖嬪妓，", "墓藏廟祭不可亂，欲言非職知何如。"]'),
('yuding-3','遊青龍寺贈崔大補闕','韓愈','唐','御定全唐诗','yuding','','[]','秋灰初吹季月管，日出卯南暉景短。友生招我佛寺行，',168,'御定全唐詩/json/339.json','["秋灰初吹季月管，日出卯南暉景短。友生招我佛寺行，", "然雲燒樹火實駢，金烏下啄赬虯卵。魂翻眼倒忘處所，", "二三道士席其間，靈液屢進玻黎碗。忽驚顏色變韶稚，", "前年嶺隅鄉思發，躑躅成山開不算。去歲羈帆湘水明，", "思君攜手安能得，今者相從敢辭懶。由來鈍騃寡參尋，", "年少得途未要忙，時清諫疏尤宜罕。何人有酒身無事，", "南山逼冬轉清瘦，刻畫圭角出崖窾。當憂複被冰雪埋，"]'),
('yuding-4','贈崔立之評事','韓愈','唐','御定全唐诗','yuding','','[]','崔侯文章苦捷敏，高浪駕天輸不盡。曾從關外來上都，',208,'御定全唐詩/json/339.json','["崔侯文章苦捷敏，高浪駕天輸不盡。曾從關外來上都，", "搖毫擲簡自不供，頃刻青紅浮海蜃。才豪氣猛易語言，", "勿嫌法官未登朝，猶勝赤尉長趨尹。時命雖乖心轉壯，", "子時專場誇觜距，余始張軍嚴韅靷。爾來但欲保封疆，", "頻蒙怨句刺棄遺，豈有閑官敢推引。深藏篋笥時一發，", "當今聖人求侍從，拔擢杞梓收楛箘。東馬嚴徐已奮飛，", "走章馳檄在得賢，燕雀紛拏要鷹隼。竊料二途必處一，", "牆根菊花好沽酒，錢帛縱空衣可准。暉暉簷日暖且鮮，", "能來取醉任喧呼，死後賢愚俱泯泯。"]'),
('yuding-5','送區弘南歸','韓愈','唐','御定全唐诗','yuding','','[]','穆昔南征軍不歸，蟲沙猿鶴伏以飛。洶洶洞庭莽翠微，',168,'御定全唐詩/json/339.json','["穆昔南征軍不歸，蟲沙猿鶴伏以飛。洶洶洞庭莽翠微，", "我遷于南日周圍，來見者眾莫依俙。爰有區子熒熒暉，", "雖有不逮驅騑騑，或采于薄漁於磯。服役不辱言不譏，", "子雖勤苦終何希，王都觀闕雙巍巍。騰蹋眾駿事鞍鞿，", "開書拆衣淚痕晞，雖不敕還情庶幾。朝暮盤羞惻庭闈，", "蜃沉海底氣升霏，彩雉野伏朝扇翬。處子窈窕王所妃，", "出送撫背我涕揮，行行正直慎脂韋。業成志樹來頎頎，"]'),
('yuding-6','三星行','韓愈','唐','御定全唐诗','yuding','','[]','我生之辰，月宿南斗。牛奮其角，箕張其口。',92,'御定全唐詩/json/339.json','["我生之辰，月宿南斗。牛奮其角，箕張其口。", "牛不見服箱，鬥不挹酒漿。箕獨有神靈，無時停簸揚。", "無善名已聞，無惡聲已讙。名聲相乘除，得少失有餘。", "三星各在天，什伍東西陳。嗟汝牛與鬥，汝獨不能神。"]'),
('yuding-7','剝啄行','韓愈','唐','御定全唐诗','yuding','','[]','剝剝啄啄，有客至門。我不出應，客去而嗔。從者語我，',100,'御定全唐詩/json/339.json','["剝剝啄啄，有客至門。我不出應，客去而嗔。從者語我，", "空堂幽幽，有秸有莞。門以兩板，叢書於間。窅窅深塹，", "子雖云爾，其口益蕃。我為子謀，有萬其全。凡今之人，", "變化咀嚼，有鬼有神。今去不勇，其如後艱。我謝再拜，"]'),
('yuding-8','青青水中蒲三首','韓愈','唐','御定全唐诗','yuding','','[]','青青水中蒲，下有一雙魚。君今上隴去，我在與誰居。',72,'御定全唐詩/json/339.json','["青青水中蒲，下有一雙魚。君今上隴去，我在與誰居。", "青青水中蒲，長在水中居。寄語浮萍草，相隨我不如。", "青青水中蒲，葉短不出水。婦人不下堂，行子在萬里。"]'),
('yuding-9','孟東野失子','韓愈','唐','御定全唐诗','yuding','','[]','失子將何尤，吾將上尤天。女實主下人，與奪一何偏。',336,'御定全唐詩/json/339.json','["失子將何尤，吾將上尤天。女實主下人，與奪一何偏。", "彼于女何有，乃令蕃且延。此獨何罪辜，生死旬日間。", "上呼無時聞，滴地淚到泉。地祇為之悲，瑟縮久不安。", "乃呼大靈龜，騎雲款天門。問天主下人，薄厚胡不均。", "天曰天地人，由來不相關。吾懸日與月，吾系星與辰。", "日月相噬齧，星辰踣而顛。吾不女之罪，知非女由因。", "且物各有分，孰能使之然。有子與無子，禍福未可原。", "魚子滿母腹，一一欲誰憐。細腰不自乳，舉族常孤鰥。", "鴟梟啄母腦，母死子始翻。蝮蛇生子時，坼裂腸與肝。", "好子雖雲好，未還恩與勤。惡子不可說，鴟梟蝮蛇然。", "有子且勿喜，無子固勿歎。上聖不待教，賢聞語而遷。", "下愚聞語惑，雖教無由悛。大靈頓頭受，即日以命還。", "地祇謂大靈，女往告其人。東野夜得夢，有夫玄衣巾。", "闖然入其戶，三稱天之言。再拜謝玄夫，收悲以歡忻。"]'),
('yuding-10','陸渾山火和皇甫湜用其韻','韓愈','唐','御定全唐诗','yuding','','[]','皇甫補官古賁渾，時當玄冬澤幹源。山狂穀很相吐吞，',259,'御定全唐詩/json/339.json','["皇甫補官古賁渾，時當玄冬澤幹源。山狂穀很相吐吞，", "天跳地踔顛乾坤，赫赫上照窮崖垠。截然高周燒四垣，", "水龍鼉龜魚與黿，鴉鴟雕鷹雉鵠鶤。燖炰煨爊孰飛奔，", "千鐘萬鼓咽耳喧。攢雜啾嚄沸篪塤，彤幢絳旃紫纛幡。", "炎官熱屬朱冠褌，髹其肉皮通髀臀。頹胸垤腹車掀轅，", "紅帷赤幕羅脤膰，fI池波風肉陵屯。谽呀鉅壑頗黎盆，", "齒牙嚼齧舌齶反，電光ze磹赬目fu，頊冥收威避玄根，", "命黑螭偵焚其元，天闕悠悠不可援。夢通上帝血面論，", "徐命之前問何冤，火行于冬古所存。我如禁之絕其飧，", "視桃著花可小騫，月及申酉利複怨。助汝五龍從九鯤，", "要餘和增怪又煩，雖欲悔舌不可捫。"]'),
('yuding-11','縣齋讀書','韓愈','唐','御定全唐诗','yuding','','[]','出宰山水縣，讀書松桂林。蕭條捐末事，邂逅得初心。',96,'御定全唐詩/json/339.json','["出宰山水縣，讀書松桂林。蕭條捐末事，邂逅得初心。", "哀狖醒俗耳，清泉潔塵襟。詩成有共賦，酒熟無孤斟。", "青竹時默釣，白雲日幽尋。南方本多毒，北客恒懼侵。", "謫譴甘自守，滯留愧難任。投章類縞帶，佇答逾兼金。"]'),
('yuding-12','新竹','韓愈','唐','御定全唐诗','yuding','','[]','筍添南階竹，日日成清閟。縹節已儲霜，黃苞猶掩翠。',96,'御定全唐詩/json/339.json','["筍添南階竹，日日成清閟。縹節已儲霜，黃苞猶掩翠。", "出欄抽五六，當戶羅三四。高標陵秋嚴，貞色奪春媚。", "稀生巧補林，並出疑爭地。縱橫乍依行，爛熳忽無次。", "風枝未飄吹，露粉先涵淚。何人可攜玩，清景空瞪視。"]'),
('yuding-13','晚菊','韓愈','唐','御定全唐诗','yuding','','[]','少年飲酒時，踴躍見菊花。今來不復飲，每見恒咨嗟。',48,'御定全唐詩/json/339.json','["少年飲酒時，踴躍見菊花。今來不復飲，每見恒咨嗟。", "佇立摘滿手，行行把歸家。此時無與語，棄置奈悲何。"]'),
('yuding-14','落齒','韓愈','唐','御定全唐诗','yuding','','[]','去年落一牙，今年落一齒。俄然落六七，落勢殊未已。',216,'御定全唐詩/json/339.json','["去年落一牙，今年落一齒。俄然落六七，落勢殊未已。", "餘存皆動搖，盡落應始止。憶初落一時，但念豁可恥。", "及至落二三，始憂衰即死。每一將落時，懍懍恒在已。", "叉牙妨食物，顛倒怯漱水。終焉舍我落，意與崩山比。", "今來落既熟，見落空相似。餘存二十餘，次第知落矣。", "倘常歲落一，自足支兩紀。如其落並空，與漸亦同指。", "人言齒之落，壽命理難恃。我言生有涯，長短俱死爾。", "人言齒之豁，左右驚諦視。我言莊周雲，水雁各有喜。", "語訛默固好，嚼廢軟還美。因歌遂成詩，持用詫妻子。"]'),
('yuding-15','哭楊兵部凝陸歙州參','韓愈','唐','御定全唐诗','yuding','','[]','人皆期七十，才半豈蹉跎。並出知己淚，自然白髮多。',48,'御定全唐詩/json/339.json','["人皆期七十，才半豈蹉跎。並出知己淚，自然白髮多。", "晨興為誰慟，還坐久滂沱。論文與晤語，已矣可如何。"]'),
('yuding-16','苦寒','韓愈','唐','御定全唐诗','yuding','','[]','四時各平分，一氣不可兼。隆寒奪春序，顓頊固不廉。',432,'御定全唐詩/json/339.json','["四時各平分，一氣不可兼。隆寒奪春序，顓頊固不廉。", "太昊弛維綱，畏避但守謙。遂令黃泉下，萌牙夭句尖。", "草木不復抽，百味失苦甜。凶飆攪宇宙，鋩刃甚割砭。", "日月雖雲尊，不能活烏蟾。羲和送日出，恇怯頻窺覘。", "炎帝持祝融，呵噓不相炎。而我當此時，恩光何由沾。", "肌膚生鱗甲，衣被如刀鐮。氣寒鼻莫嗅，血凍指不拈。", "濁醪沸入喉，口角如銜箝。將持匕箸食，觸指如排簽。", "侵爐不覺暖，熾炭屢已添。探湯無所益，何況纊與縑。", "虎豹僵穴中，蛟螭死幽潛。熒惑喪纏次，六龍冰脫髯。", "芒碭大包內，生類恐盡殲。啾啾窗間雀，不知已微纖。", "舉頭仰天鳴，所願晷刻淹。不如彈射死，卻得親炰燖。", "鸞皇苟不存，爾固不在占。其餘蠢動儔，俱死誰恩嫌。", "伊我稱最靈，不能女覆苫。悲哀激憤歎，五藏難安恬。", "中宵倚牆立，淫淚何漸漸。天王哀無辜，惠我下顧瞻。", "褰旒去耳纊，調和進梅鹽。賢能日登禦，黜彼傲與憸。", "生風吹死氣，豁達如褰簾。懸乳零落墮，晨光入前簷。", "雪霜頓銷釋，土脈膏且黏。豈徒蘭蕙榮，施及艾與蒹。", "日萼行鑠鑠，風條坐襜襜。天乎苟其能，吾死意亦厭。"]'),
('yuding-17','和虞部盧四酬翰林錢七赤藤杖歌','韓愈','唐','御定全唐诗','yuding','','[]','赤藤為杖世未窺，台郎始攜自滇池。滇王掃宮避使者，',96,'御定全唐詩/json/339.json','["赤藤為杖世未窺，台郎始攜自滇池。滇王掃宮避使者，", "途經百國皆莫識，君臣聚觀逐旌麾。共傳滇神出水獻，", "幾重包裹自題署，不以珍怪誇荒夷。歸來捧贈同舍子，", "南宮清深禁闈密，唱和有類吹塤篪。妍辭麗句不可繼，"]'),
('yuding-18','崔十六少府攝伊陽，以詩及書見投，因酬三十韻','韓愈','唐','御定全唐诗','yuding','','[]','崔君初來時，相識頗未慣。但聞赤縣尉，不比博士慢。',360,'御定全唐詩/json/339.json','["崔君初來時，相識頗未慣。但聞赤縣尉，不比博士慢。", "賃屋得連牆，往來忻莫間。我時亦新居，觸事苦難辦。", "蔬飧要同吃，破襖請來綻。謂言安堵後，貸借更何患。", "不知孤遺多，舉族仰薄宦。有時未朝餐，得米日已晏。", "隔牆聞讙呼，眾口極鵝雁。前計頓乖張，居然見真贗。", "嬌兒好眉眼，袴腳凍兩骭。捧書隨諸兄，累累兩角丱。", "冬惟茹寒齏，秋始識瓜瓣。問之不言饑，飫若厭芻豢。", "才名三十年，久合居給諫。白頭趨走裏，閉口絕謗訕。", "府公舊同袍，拔擢宰山澗。寄詩雜詼俳，有類說鵬鷃。", "上言酒味酸，冬衣竟未擐。下言人吏稀，惟足彪與虥。", "又言致豬鹿，此語乃善幻。三年國子師，腸肚習藜莧。", "況住洛之涯，魴鱒可罩汕。肯效屠門嚼，久嫌弋者篡。", "謀拙日焦拳，活計似鋤剗。男寒澀詩書，妻瘦剩腰襻。", "為官不事職，厥罪在欺謾。行當自劾去，漁釣老葭薍。", "歲窮寒氣驕，冰雪滑磴棧。音問難屢通，何由覿清盼。"]'),
('yuding-19','送侯參謀赴河中幕','韓愈','唐','御定全唐诗','yuding','','[]','憶昔初及第，各以少年稱。君頤始生須，我齒清如冰。',480,'御定全唐詩/json/339.json','["憶昔初及第，各以少年稱。君頤始生須，我齒清如冰。", "爾時心氣壯，百事謂己能。一別詎幾何，忽如隔晨興。", "我齒豁可鄙，君顏老可憎。相逢風塵中，相視迭嗟矜。", "幸同學省官，末路再得朋。東司絕教授，游宴以為恒。", "秋漁蔭密樹，夜博然明燈。雪徑抵樵叟，風廊折談僧。", "陸渾桃花間，有湯沸如烝。三月崧少步，躑躅紅千層。", "洲沙厭晚坐，嶺壁窮晨升。沈冥不計日，為樂不可勝。", "遷滿一已異，乖離坐難憑。行行事結束，人馬何蹻騰。", "感激生膽勇，從軍豈嘗曾。洸洸司徒公，天子爪與肱。", "提師十萬餘，四海欽風棱。河北兵未進，蔡州帥新薨。", "曷不請掃除，活彼黎與烝。鄙夫誠怯弱，受恩愧徒弘。", "猶思脫儒冠，棄死取先登。又欲面言事，上書求詔征。", "侵官固非是，妄作譴可懲。惟當待責免，耕劚歸溝塍。", "今君得所附，勢若脫鞲鷹。檄筆無與讓，幕謀識其膺。", "收績開史牒，翰飛逐溟鵬。男兒貴立事，流景不可乘。", "歲老陰沴作，雲頹雪翻崩。別袖拂洛水，征車轉崤陵。", "勤勤酒不進，勉勉恨已仍。送君出門歸，愁腸若牽繩。", "默坐念語笑，癡如遇寒蠅。策馬誰可適，晤言誰為應。", "席塵惜不掃，殘尊對空凝。信知後會時，日月屢環縆。", "生期理行役，歡緒絕難承。寄書惟在頻，無吝簡與繒。"]'),
('yuding-20','東都遇春','韓愈','唐','御定全唐诗','yuding','','[]','少年氣真狂，有意與春競。行逢二三月，九州花相映。',348,'御定全唐詩/json/339.json','["少年氣真狂，有意與春競。行逢二三月，九州花相映。", "川原曉服鮮，桃李晨妝靚。荒乘不知疲，醉死豈辭病。", "飲啖惟所便，文章倚豪橫。爾來曾幾時，白髮忽滿鏡。", "舊遊喜乖張，新輩足嘲評。心腸一變化，羞見時節盛。", "得閒無所作，貴欲辭視聽。深居疑避仇，默臥如當暝。", "朝曦入牖來，鳥喚昏不醒。為生鄙計算，鹽米告屢罄。", "坐疲都忘起，冠側懶複正。幸蒙東都官，獲離機與阱。", "乖慵遭傲僻，漸染生弊性。既去焉能追，有來猶莫騁。", "有船魏王池，往往縱孤泳。水容與天色，此處皆綠淨。", "岸樹共紛披，渚牙相緯經。懷歸苦不果，即事取幽迸。", "貪求匪名利，所得亦已並。悠悠度朝昏，落落捐季孟。", "群公一何賢，上戴天子聖。謀謨收禹績，四面出雄勁。", "轉輸非不勤，稽逋有軍令。在庭百執事，奉職各祗敬。", "我獨胡為哉，坐與億兆慶。譬如籠中鳥，仰給活性命。", "為詩告友生，負愧終究竟。"]'),
('yuding-21','感春五首','韓愈','唐','御定全唐诗','yuding','','[]','辛夷高花最先開，青天露坐始此回。已呼孺人戛鳴瑟，',200,'御定全唐詩/json/339.json','["辛夷高花最先開，青天露坐始此回。已呼孺人戛鳴瑟，", "如今到死得閒處，還有詩賦歌康哉。", "洛陽東風幾時來，川波岸柳春全回。宮門一鎖不復啟，", "孤吟屢闋莫與和，寸恨至短誰能裁。", "春田可耕時已催，王師北討何當回。放車載草農事濟，", "朝廷未省有遺策，肯不垂意瓶與罍。", "前隨杜尹拜表回，笑言溢口何歡咍。孔丞別我適臨汝，", "天公高居鬼神惡，欲保性命誠難哉。", "辛夷花房忽全開，將衰正盛須頻來。清晨輝輝燭霞日，", "迎繁送謝別有意，誰肯留戀少環回。"]'),
('yuding-22','酬裴十六功曹巡府西驛途中見寄','韓愈','唐','御定全唐诗','yuding','','[]','相公罷論道，聿至活東人。禦史坐言事，作吏府中塵。',168,'御定全唐詩/json/339.json','["相公罷論道，聿至活東人。禦史坐言事，作吏府中塵。", "遂令河南治，今古無儔倫。四海日富庶，道途隘蹄輪。", "府西三百里，候館同魚鱗。相公謂禦史，勞子去自巡。", "是時山水秋，光景何鮮新。哀鴻鳴清耳，宿霧褰高旻。", "遺我行旅詩，軒軒有風神。譬如黃金盤，照耀荊璞真。", "我來亦已幸，事賢友其仁。持竿洛水側，孤坐屢窮辰。", "多才自勞苦，無用只因循。辭免期匪遠，行行及山春。"]'),
('yuding-23','燕河南府秀才得生字','韓愈','唐','御定全唐诗','yuding','','[]','吾皇紹祖烈，天下再太平。詔下諸郡國，歲貢鄉曲英。',240,'御定全唐詩/json/339.json','["吾皇紹祖烈，天下再太平。詔下諸郡國，歲貢鄉曲英。", "元和五年冬，房公尹東京。功曹上言公，是月當登名。", "乃選二十縣，試官得鴻生。群儒負己材，相賀簡擇精。", "怒起簸羽翮，引吭吐鏗轟。此都自周公，文章繼名聲。", "自非絕殊尤，難使耳目驚。今者遭震薄，不能出聲鳴。", "鄙夫忝縣尹，愧栗難為情。惟求文章寫，不敢妒與爭。", "還家敕妻兒，具此煎炰烹。柿紅蒲萄紫，肴果相扶檠。", "芳荼出蜀門，好酒濃且清。何能充歡燕，庶以露厥誠。", "昨聞詔書下，權公作邦楨。文人得其職，文道當大行。", "陰風攪短日，冷雨澀不晴。勉哉戒徒馭，家國遲子榮。"]'),
('yuding-24','送李翱','韓愈','唐','御定全唐诗','yuding','','[]','廣州萬里途，山重江逶迤。行行何時到，誰能定歸期。',84,'御定全唐詩/json/339.json','["廣州萬里途，山重江逶迤。行行何時到，誰能定歸期。", "揖我出門去，顏色異恒時。雖雲有追送，足跡絕自茲。", "人生一世間，不自張與弛。譬如浮江木，縱橫豈自知。", "甯懷別時苦，勿作別後思。"]'),
('yuding-25','送石洪處士赴河陽幕得起字','韓愈','唐','御定全唐诗','yuding','','[]','長把種樹書，人雲避世士。忽騎將軍馬，自號報恩子。',72,'御定全唐詩/json/339.json','["長把種樹書，人雲避世士。忽騎將軍馬，自號報恩子。", "風雲入壯懷，泉石別幽耳。鉅鹿師欲老，常山險猶恃。", "豈惟彼相憂，固是吾徒恥。去去事方急，酒行可以起。"]'),
('yuding-26','送湖南李正字歸','韓愈','唐','御定全唐诗','yuding','','[]','長沙入楚深，洞庭值秋晚。人隨鴻雁少，江共蒹葭遠。',72,'御定全唐詩/json/339.json','["長沙入楚深，洞庭值秋晚。人隨鴻雁少，江共蒹葭遠。", "歷歷餘所經，悠悠子當返。孤游懷耿介，旅宿夢婉娩。", "風土稍殊音，魚蝦日異飯。親交俱在此，誰與同息偃。"]'),
('yuding-0','辛卯年雪','韓愈','唐','御定全唐诗','yuding','','[]','元和六年春，寒氣不肯歸。河南二月末，雪花一尺圍。',120,'御定全唐詩/json/340.json','["元和六年春，寒氣不肯歸。河南二月末，雪花一尺圍。", "崩騰相排拶，龍鳳交橫飛。波濤何飄揚，天風吹幡旗。", "白帝盛羽衛，鬖髿振裳衣。白霓先啟途，從以萬玉妃。", "翕翕陵厚載，嘩嘩弄陰機。生平未曾見，何暇議是非。", "或雲豐年祥，飽食可庶幾。善禱吾所慕，誰言寸誠微。"]'),
('yuding-1','醉留東野','韓愈','唐','御定全唐诗','yuding','','[]','昔年因讀李白杜甫詩，長恨二人不相從。吾與東野生並世，',46,'御定全唐詩/json/340.json','["昔年因讀李白杜甫詩，長恨二人不相從。吾與東野生並世，", "東野不回頭，有如寸筳撞巨鐘。我願身為雲，"]'),
('yuding-2','李花二首','韓愈','唐','御定全唐诗','yuding','','[]','平旦入西園，梨花數株若矜誇。旁有一株李，',132,'御定全唐詩/json/340.json','["平旦入西園，梨花數株若矜誇。旁有一株李，", "忽憶前時經此樹，正見芳意初萌牙。奈何趁酒不省錄，", "東風來吹不解顏，蒼茫夜氣生相遮。冰盤夏薦碧實脆，", "當春天地爭奢華，洛陽園苑尤紛拏。誰將平地萬堆雪，", "夜領張徹投盧仝，乘雲共至玉皇家。長姬香禦四羅列，", "清寒瑩骨肝膽醒，一生思慮無由邪。"]'),
('yuding-3','招楊之罘','韓愈','唐','御定全唐诗','yuding','','[]','柏生兩石間，萬歲終不大。野馬不識人，難以駕車蓋。',216,'御定全唐詩/json/340.json','["柏生兩石間，萬歲終不大。野馬不識人，難以駕車蓋。", "柏移就平地，馬羈入廄中。馬思自由悲，柏有傷根容。", "傷根柏不死，千丈日以至。馬悲罷還樂，振迅矜鞍轡。", "之罘南山來，文字得我驚。館置使讀書，日有求歸聲。", "我令之罘歸，失得柏與馬。之罘別我去，計出柏馬下。", "我自之罘歸，入門思而悲。之罘別我去，能不思我為。", "灑掃縣中居，引水經竹間。囂嘩所不及，何異山中閑。", "前陳百家書，食有肉與魚。先王遺文章，綴緝實在餘。", "禮稱獨學陋，易貴不遠複。作詩招之罘，晨夕抱饑渴。"]'),
('yuding-4','寄盧仝','韓愈','唐','御定全唐诗','yuding','','[]','玉川先生洛城裏，破屋數間而已矣。一奴長須不裹頭，',264,'御定全唐詩/json/340.json','["玉川先生洛城裏，破屋數間而已矣。一奴長須不裹頭，", "先生結髮憎俗徒，閉門不出動一紀。至今鄰僧乞米送，", "勸參留守謁大尹，言語才及輒掩耳。水北山人得名聲，", "少室山人索價高，兩以諫官征不起。彼皆刺口論世事，", "春秋三傳束高閣，獨抱遺經窮終始。往年弄筆嘲同異，", "去年生兒名添丁，意令與國充耘耔。國家丁口連四海，", "假如不在陳力列，立言垂範亦足恃。苗裔當蒙十世宥，", "昨晚長須來下狀，隔牆惡少惡難似。每騎屋山下窺闞，", "先生受屈未曾語，忽此來告良有以。嗟我身為赤縣令，", "先生又遣長須來，如此處置非所喜。況又時當長養節，", "放縱是誰之過歟，效尤戮僕愧前史。買羊沽酒謝不敏，"]'),
('yuding-5','酬司門盧四兄雲夫院長望秋作','韓愈','唐','御定全唐诗','yuding','','[]','長安雨洗新秋出，極目寒鏡開塵函。終南曉望蹋龍尾，',120,'御定全唐詩/json/340.json','["長安雨洗新秋出，極目寒鏡開塵函。終南曉望蹋龍尾，", "歸來得便即遊覽，暫似壯馬脫重銜。曲江荷花蓋十裏，", "白首寓居誰借問，平地寸步扃雲岩。雲夫吾兄有狂氣，", "望秋一章已驚絕，猶言低抑避謗讒。若使乘酣騁雄怪，", "馳坑跨穀終未悔，為利而止真貪饞。高揖群公謝名譽，"]'),
('yuding-6','誰氏子','韓愈','唐','御定全唐诗','yuding','','[]','非癡非狂誰氏子，去入王屋稱道士。白頭老母遮門啼，',88,'御定全唐詩/json/340.json','["非癡非狂誰氏子，去入王屋稱道士。白頭老母遮門啼，", "或雲欲學吹鳳笙，所慕靈妃媲蕭史。又雲時俗輕尋常，", "聖君賢相安可欺，幹死窮山竟何俟。嗚呼余心誠豈弟，", "誰其友親能哀憐，寫吾此詩持送似。"]'),
('yuding-7','河南令舍池台','韓愈','唐','御定全唐诗','yuding','','[]','灌池才盈五六丈，築台不過七八尺。欲將層級壓籬落，',40,'御定全唐詩/json/340.json','["灌池才盈五六丈，築台不過七八尺。欲將層級壓籬落，", "長令人吏遠趨走，已有蛙黽助狼藉。"]'),
('yuding-8','送無本師歸范陽','韓愈','唐','御定全唐诗','yuding','','[]','無本于為文，身大不及膽。吾嘗示之難，勇往無不敢。',241,'御定全唐詩/json/340.json','["無本于為文，身大不及膽。吾嘗示之難，勇往無不敢。", "蛟龍弄角牙，造次欲手攬。眾鬼囚大幽，下覷襲玄窞。", "天陽熙四海，注視首不頷。鯨鵬相摩窣，兩舉快一啖。", "夫豈能必然，固已謝黯黮。狂詞肆滂葩，低昂見舒慘。", "奸窮怪變得，往往造平澹。蜂蟬碎錦纈，綠池披菡萏。", "芝英擢荒榛，孤翮起連菼。家住幽都遠，未識氣先感。", "來尋吾何能，無殊嗜昌歜。始見洛陽春，桃枝綴紅糝。", "遂來長安裏，時卦轉習坎。老懶無鬥心，久不事鉛槧。", "欲以金帛酬，舉室常bC頷。念當委我去，雪霜刻以憯。", "獰飆攪空衢，天地與頓撼。勉率吐歌詩，慰女別後覽。"]'),
('yuding-9','石鼓歌','韓愈','唐','御定全唐诗','yuding','','[]','張生手持石鼓文，勸我試作石鼓歌。少陵無人謫仙死，',264,'御定全唐詩/json/340.json','["張生手持石鼓文，勸我試作石鼓歌。少陵無人謫仙死，", "大開明堂受朝賀，諸侯劍佩鳴相磨。搜于岐陽騁雄俊，", "從臣才藝咸第一，揀選撰刻留山阿。雨淋日炙野火燎，", "辭嚴義密讀難曉，字體不類隸與科。年深豈免有缺畫，", "金繩鐵索鎖紐壯，古鼎躍水龍騰梭。陋儒編詩不收入，", "嗟予好古生苦晚，對此涕淚雙滂沱。憶昔初蒙博士征，", "濯冠沐浴告祭酒，如此至寶存豈多。氈包席裹可立致，", "聖恩若許留太學，諸生講解得切磋。觀經鴻都尚填咽，", "大廈深簷與蓋覆，經歷久遠期無佗。中朝大官老於事，", "日銷月鑠就埋沒，六年西顧空吟哦。羲之俗書趁姿媚，", "方今太平日無事，柄任儒術崇丘軻。安能以此上論列，"]'),
('yuding-10','雙鳥詩','韓愈','唐','御定全唐诗','yuding','','[]','雙鳥海外來，飛飛到中州。一鳥落城市，一鳥集岩幽。',300,'御定全唐詩/json/340.json','["雙鳥海外來，飛飛到中州。一鳥落城市，一鳥集岩幽。", "不得相伴鳴，爾來三千秋。兩鳥各閉口，萬象銜口頭。", "春風卷地起，百鳥皆飄浮。兩鳥忽相逢，百日鳴不休。", "有耳聒皆聾，有口反自羞。百舌舊饒聲，從此恒低頭。", "得病不呻喚，泯默至死休。雷公告天公，百物須膏油。", "自從兩鳥鳴，聒亂雷聲收。鬼神怕嘲詠，造化皆停留。", "草木有微情，挑抉示九州。蟲鼠誠微物，不堪苦誅求。", "不停兩鳥鳴，百物皆生愁。不停兩鳥鳴，自此無春秋。", "不停兩鳥鳴，日月難旋輈。不停兩鳥鳴，大法失九疇。", "周公不為公，孔丘不為丘。天公怪兩鳥，各捉一處囚。", "百蟲與百鳥，然後鳴啾啾。兩鳥既別處，閉聲省愆尤。", "朝食千頭龍，暮食千頭牛。朝飲河生塵，暮飲海絕流。", "還當三千秋，更起鳴相酬。"]'),
('yuding-11','贈劉師服','韓愈','唐','御定全唐诗','yuding','','[]','羨君齒牙牢且潔，大肉硬餅如刀截。我今呀豁落者多，',88,'御定全唐詩/json/340.json','["羨君齒牙牢且潔，大肉硬餅如刀截。我今呀豁落者多，", "妻兒恐我生悵望，盤中不飣栗與梨。只今年才四十五，", "憶昔太公仕進初，口含兩齒無贏餘。虞翻十三比豈少，", "巨緡東釣倘可期，與子共飽鯨魚膾。"]'),
('yuding-12','題炭穀湫祠堂','韓愈','唐','御定全唐诗','yuding','','[]','萬生都陽明，幽暗鬼所寰。嗟龍獨何智，出入人鬼間。',240,'御定全唐詩/json/340.json','["萬生都陽明，幽暗鬼所寰。嗟龍獨何智，出入人鬼間。", "不知誰為助，若執造化關。厭處平地水，巢居插天山。", "列峰若攢指，石盂仰環環。巨靈高其捧，保此一掬慳。", "森沈固含蓄，本以儲陰奸。魚鱉蒙擁護，群嬉傲天頑。", "翾翾棲托禽，飛飛一何閑。祠堂像侔真，擢玉紆煙鬟。", "群怪儼伺候，恩威在其顏。我來日正中，悚惕思先還。", "寄立尺寸地，敢言來途艱。籲無吹毛刃，血此牛蹄殷。", "至令乘水旱，鼓舞寡與鰥。林叢鎮冥冥，窮年無由刪。", "妍英雜豔實，星瑣黃朱斑。石級皆險滑，顛躋莫牽攀。", "龍區雛眾碎，付與宿已頒。棄去可奈何，吾其死茅菅。"]'),
('yuding-13','聽穎師彈琴','韓愈','唐','御定全唐诗','yuding','','[]','昵昵兒女語，恩怨相爾汝。劃然變軒昂，勇士赴敵場。',96,'御定全唐詩/json/340.json','["昵昵兒女語，恩怨相爾汝。劃然變軒昂，勇士赴敵場。", "浮雲柳絮無根蒂，天地闊遠隨飛揚。喧啾百鳥群，", "嗟餘有兩耳，未省聽絲篁。自聞穎師彈，起坐在一旁。", "推手遽止之，濕衣淚滂滂。穎乎爾誠能，無以冰炭置我腸。"]'),
('yuding-14','送陸暢歸江南','韓愈','唐','御定全唐诗','yuding','','[]','舉舉江南子，名以能詩聞。一來取高第，官佐東宮軍。',144,'御定全唐詩/json/340.json','["舉舉江南子，名以能詩聞。一來取高第，官佐東宮軍。", "迎婦丞相府，誇映秀士群。鸞鳴桂樹間，觀者何繽紛。", "人事喜顛倒，旦夕異所雲。蕭蕭青雲幹，遂逐荊棘焚。", "歲晚鴻雁過，鄉思見新文。踐此秦關雪，家彼吳洲雲。", "悲啼上車女，骨肉不可分。感慨都門別，丈夫酒方醺。", "我實門下士，力薄蚋與蚊。受恩不即報，永負湘中墳。"]'),
('yuding-15','送進士劉師服東歸','韓愈','唐','御定全唐诗','yuding','','[]','猛虎落檻阱，坐食如孤豚。丈夫在富貴，豈必守一門。',144,'御定全唐詩/json/340.json','["猛虎落檻阱，坐食如孤豚。丈夫在富貴，豈必守一門。", "公心有勇氣，公口有直言。奈何任埋沒，不自求騰軒。", "僕本亦進士，頗嘗究根源。由來骨鯁材，喜被軟弱吞。", "低頭受侮笑，隱忍硉兀冤。泥雨城東路，夏槐作雲屯。", "還家雖闕短，把日親晨飧。攜持令名歸，自足貽家尊。", "時節不可玩，親交可攀援。勉來取金紫，勿久休中園。"]'),
('yuding-16','嘲魯連子','韓愈','唐','御定全唐诗','yuding','','[]','魯連細而黠，有似黃鷂子。田巴兀老蒼，憐汝矜爪觜。',60,'御定全唐詩/json/340.json','["魯連細而黠，有似黃鷂子。田巴兀老蒼，憐汝矜爪觜。", "開端要驚人，雄跨吾厭矣。高拱禪鴻聲，若輟一杯水。", "獨稱唐虞賢，顧未知之耳。"]'),
('yuding-17','贈張籍','韓愈','唐','御定全唐诗','yuding','','[]','吾老著讀書，餘事不掛眼。有兒雖甚憐，教示不免簡。',216,'御定全唐詩/json/340.json','["吾老著讀書，餘事不掛眼。有兒雖甚憐，教示不免簡。", "君來好呼出，踉蹌越門限。懼其無所知，見則先愧赧。", "昨因有緣事，上馬插手版。留君住廳食，使立侍盤盞。", "薄暮歸見君，迎我笑而莞。指渠相賀言，此是萬金產。", "吾愛其風骨，粹美無可揀。試將詩義授，如以肉貫丳。", "開祛露毫末，自得高蹇嵼。我身蹈丘軻，爵位不早綰。", "固宜長有人，文章紹編剗。感荷君子德，恍若乘朽棧。", "召令吐所記，解摘了瑟僴。顧視窗壁間，親戚競覘矕。", "喜氣排寒冬，逼耳鳴睍睆。如今更誰恨，便可耕灞滻。"]'),
('yuding-18','調張籍','韓愈','唐','御定全唐诗','yuding','','[]','李杜文章在，光焰萬丈長。不知群兒愚，那用故謗傷。',240,'御定全唐詩/json/340.json','["李杜文章在，光焰萬丈長。不知群兒愚，那用故謗傷。", "蚍蜉撼大樹，可笑不自量。伊我生其後，舉頸遙相望。", "夜夢多見之，晝思反微茫。徒觀斧鑿痕，不矚治水航。", "想當施手時，巨刃磨天揚。垠崖劃崩豁，乾坤擺雷硠。", "惟此兩夫子，家居率荒涼。帝欲長吟哦，故遣起且僵。", "剪翎送籠中，使看百鳥翔。平生千萬篇，金薤垂琳琅。", "仙官敕六丁，雷電下取將。流落人間者，太山一毫芒。", "我願生兩翅，捕逐出八荒。精誠忽交通，百怪入我腸。", "刺手拔鯨牙，舉瓢酌天漿。騰身跨汗漫，不著織女襄。", "顧語地上友，經營無太忙。乞君飛霞佩，與我高頡頏。"]'),
('yuding-19','盧郎中雲夫寄示送盤穀子詩兩章，歌以和之','韓愈','唐','御定全唐诗','yuding','','[]','昔尋李願向盤穀，正見高崖巨壁爭開張。是時新晴天井溢，',122,'御定全唐詩/json/340.json','["昔尋李願向盤穀，正見高崖巨壁爭開張。是時新晴天井溢，", "東蹈燕川食曠野，有饋木蕨芽滿筐。馬頭溪深不可厲，", "窮探極覽頗恣橫，物外日月本不忙。歸來辛苦欲誰為，", "旁無壯士遣屬和，遠憶盧老詩顛狂。開緘忽睹送歸作，", "我今進退幾時決，十年蠢蠢隨朝行。家請官供不報答，"]'),
('yuding-20','寄皇甫湜','韓愈','唐','御定全唐诗','yuding','','[]','敲門驚晝睡，問報睦州吏。手把一封書，上有皇甫字。',60,'御定全唐詩/json/340.json','["敲門驚晝睡，問報睦州吏。手把一封書，上有皇甫字。", "拆書放床頭，涕與淚垂四。昏昏還就枕，惘惘夢相值。", "悲哉無奇術，安得生兩翅。"]'),
('yuding-21','病中贈張十八','韓愈','唐','御定全唐诗','yuding','','[]','中虛得暴下，避冷臥北窗。不蹋曉鼓朝，安眠聽逢逢。',265,'御定全唐詩/json/340.json','["中虛得暴下，避冷臥北窗。不蹋曉鼓朝，安眠聽逢逢。", "籍也處閭裏，抱能未施邦。文章自娛戲，金石日擊撞。", "龍文百斛鼎，筆力可獨扛。談舌久不掉，非君亮誰雙。", "扶幾導之言，曲節初摐摐。半途喜開鑿，派別失大江。", "吾欲盈其氣，不令見麾幢。牛羊滿田野，解旆束空杠。", "傾尊與斟酌，四壁堆罌缸。玄帷隔雪風，照爐釘明釭。", "夜闌縱捭闔，哆口疏眉厖。勢侔高陽翁，坐約齊橫降。", "連日挾所有，形軀頓胮肛。將歸乃徐謂，子言得無哤。", "回軍與角逐，斫樹收窮龐。雌聲吐款要，酒壺綴羊腔。", "君乃昆侖渠，籍乃嶺頭瀧。譬如蟻蛭微，詎可陵崆uu。", "幸願終賜之，斬拔枿與樁。從此識歸處，東流水淙淙。"]'),
('yuding-22','雜詩','韓愈','唐','御定全唐诗','yuding','','[]','古史散左右，詩書置後前。豈殊蠹書蟲，生死文字間。',156,'御定全唐詩/json/340.json','["古史散左右，詩書置後前。豈殊蠹書蟲，生死文字間。", "古道自愚蠢，古言自包纏。當今固殊古，誰與為欣歡。", "獨攜無言子，共升昆侖顛。長風飄襟裾，遂起飛高圓。", "下視禹九州，一塵集豪端。遨嬉未雲幾，下已億萬年。", "向者誇奪子，萬墳厭其巔。惜哉抱所見，白黑未及分。", "慷慨為悲吒，淚如九河翻。指摘相告語，雖還今誰親。", "翩然下大荒，被發騎騏驎。"]'),
('yuding-23','寄崔二十六立之','韓愈','唐','御定全唐诗','yuding','','[]','西城員外丞，心跡兩屈奇。往歲戰詞賦，不將勢力隨。',576,'御定全唐詩/json/340.json','["西城員外丞，心跡兩屈奇。往歲戰詞賦，不將勢力隨。", "下驢入省門，左右驚紛披。傲兀坐試席，深叢見孤羆。", "文如翻水成，初不用意為。四座各低面，不敢捩眼窺。", "升階揖侍郎，歸舍日未欹。佳句喧眾口，考官敢瑕疵。", "連年收科第，若摘頷底髭。回首卿相位，通途無他岐。", "豈論校書郎，袍笏光參差。童稚見稱說，祝身得如斯。", "儕輩妒且熱，喘如竹筒吹。老婦願嫁女，約不論財貲。", "老翁不量分，累月笞其兒。攪攪爭附托，無人角雄雌。", "由來人間事，翻覆不可知。安有巢中鷇，插翅飛天陲。", "駒麛著爪牙，猛虎借與皮。汝頭有韁系，汝腳有索縻。", "陷身泥溝間，誰複稟指撝。不脫吏部選，可見偶與奇。", "又作朝士貶，得非命所施。客居京城中，十日營一炊。", "逼迫走巴蠻，恩愛座上離。昨來漢水頭，始得完孤羈。", "桁掛新衣裳，盎棄食殘糜。苟無饑寒苦，那用分高卑。", "憐我還好古，宦途同險巇。每旬遺我書，竟歲無差池。", "新篇奚其思，風幡肆逶迤。又論諸毛功，劈水看蛟螭。", "雷電生睒睗，角鬣相撐披。屬我感窮景，抱華不能摛。", "唱來和相報，愧歎俾我疵。又寄百尺彩，緋紅相盛衰。", "巧能喻其誠，深淺抽肝脾。開展放我側，方餐涕垂匙。", "朋交日凋謝，存者逐利移。子寧獨迷誤，綴綴意益彌。", "舉頭庭樹豁，狂飆卷寒曦。迢遞山水隔，何由應塤篪。", "別來就十年，君馬記騧驪。長女當及事，誰助出帨縭。", "諸男皆秀朗，幾能守家規。文字銳氣在，輝輝見旌麾。", "摧腸與戚容，能複持酒卮。我雖未耋老，發禿骨力羸。"]'),
('yuding-24','月蝕詩效玉川子作','韓愈','唐','御定全唐诗','yuding','','[]','元和庚寅鬥插子，月十四日三更中。森森萬木夜僵立，',376,'御定全唐詩/json/340.json','["元和庚寅鬥插子，月十四日三更中。森森萬木夜僵立，", "忽然有物來啖之，不知是何蟲。如何至神物，遭此狼狽凶。", "星如撒沙出，攢集爭強雄。油燈不照席，", "念此日月者，為天之眼睛。此猶不自保，吾道何由行。", "嘗聞古老言，疑是蝦蟆精。徑圓千里納女腹，", "黃帝有四目，帝舜重其明。今天只兩目，何故許食使偏盲。", "堯呼大水浸十日，不惜萬國赤子魚頭生。女於此時若食日，", "後時食月罪當死，天羅磕匝何處逃汝刑。", "玉川子立於庭而言曰：地行賤臣仝，再拜敢告上天公。", "臣有一寸刃，可刳凶蟆腸。無梯可上天，天階無由有臣蹤。", "寄箋東南風，天門西北祈風通。丁甯附耳莫漏泄，", "既從白帝祠，又食於蠟禮有加。忍令月被惡物食，", "終令誇蛾抉汝出，卜師燒錐鑽灼滿板如星羅。此外內外官，", "並光全耀歸我月，盲眼鏡淨無纖瑕。弊蛙拘送主府官，", "姮娥還宮室，太陽有室家。天雖高，耳屬地。感臣赤心，", "雖忿大傷，忍殺孩稚。還汝月明，安行於次。盡釋眾罪，"]'),
('yuding-25','孟生詩','韓愈','唐','御定全唐诗','yuding','','[]','孟生江海士，古貌又古心。嘗讀古人書，謂言古猶今。',324,'御定全唐詩/json/340.json','["孟生江海士，古貌又古心。嘗讀古人書，謂言古猶今。", "作詩三百首，窅默咸池音。騎驢到京國，欲和熏風琴。", "豈識天子居，九重鬱沉沉。一門百夫守，無籍不可尋。", "晶光蕩相射，旗戟翩以森。遷延乍卻走，驚怪靡自任。", "舉頭看白日，泣涕下沾襟。朅來游公卿，莫肯低華簪。", "諒非軒冕族，應對多差參。萍蓬風波急，桑榆日月侵。", "奈何從進士，此路轉嶇嶔。異質忌處群，孤芳難寄林。", "誰憐松桂性，競愛桃李陰。朝悲辭樹葉，夕感歸巢禽。", "顧我多慷慨，窮簷時見臨。清宵靜相對，發白聆苦吟。", "采蘭起幽念，眇然望東南。秦吳修且阻，兩地無數金。", "我論徐方牧，好古天下欽。竹實鳳所食，德馨神所歆。", "求觀眾丘小，必上泰山岑。求觀眾流細，必泛滄溟深。", "子其聽我言，可以當所箴。既獲則思返，無為久滯淫。", "卞和試三獻，期子在秋砧。"]'),
('yuding-26','射訓狐','韓愈','唐','御定全唐诗','yuding','','[]','有鳥夜飛名訓狐，矜凶挾狡誇自呼。乘時陰黑止我屋，',96,'御定全唐詩/json/340.json','["有鳥夜飛名訓狐，矜凶挾狡誇自呼。乘時陰黑止我屋，", "聚鬼征妖自朋扇，罷掉栱桷頹墍塗。慈母抱兒怕入席，", "縱之豈即遽有害，斗柄行拄西南隅。誰謂停奸計尤劇，", "咨餘往射豈得已，候女兩眼張睢盱。梟驚墮梁蛇走竇，"]'),
('yuding-27','將歸贈孟東野房蜀客','韓愈','唐','御定全唐诗','yuding','','[]','君門不可入，勢利互相推。借問讀書客，胡為在京師。',84,'御定全唐詩/json/340.json','["君門不可入，勢利互相推。借問讀書客，胡為在京師。", "舉頭未能對，閉眼聊自思。倏忽十六年，終朝苦寒饑。", "宦途竟寥落，鬢髮坐差池。潁水清且寂，箕山坦而夷。", "如今便當去，咄咄無自疑。"]'),
('yuding-28','答孟郊','韓愈','唐','御定全唐诗','yuding','','[]','規模背時利，文字覷天巧。人皆餘酒肉，子獨不得飽。',96,'御定全唐詩/json/340.json','["規模背時利，文字覷天巧。人皆餘酒肉，子獨不得飽。", "才春思已亂，始秋悲又攪。朝餐動及午，夜諷恒至卯。", "名聲暫膻腥，腸肚鎮煎煼。古心雖自鞭，世路終難拗。", "弱拒喜張臂，猛拿閑縮爪。見倒誰肯扶，從嗔我須咬。"]'),
('yuding-29','從仕','韓愈','唐','御定全唐诗','yuding','','[]','居閑食不足，從仕力難任。兩事皆害性，一生恒苦心。',48,'御定全唐詩/json/340.json','["居閑食不足，從仕力難任。兩事皆害性，一生恒苦心。", "黃昏歸私室，惆悵起歎音。棄置人間世，古來非獨今。"]'),
('yuding-30','短燈檠歌','韓愈','唐','御定全唐诗','yuding','','[]','長檠八尺空自長，短檠二尺便且光。黃簾綠幕朱戶閉，',72,'御定全唐詩/json/340.json','["長檠八尺空自長，短檠二尺便且光。黃簾綠幕朱戶閉，", "太學儒生東魯客，二十辭家來射策。夜書細字綴語言，", "一朝富貴還自恣，長檠高張照珠翠。籲嗟世事無不然，"]'),
('yuding-31','送劉師服','韓愈','唐','御定全唐诗','yuding','','[]','夏半陰氣始，淅然雲景秋。蟬聲入客耳，驚起不可留。',84,'御定全唐詩/json/340.json','["夏半陰氣始，淅然雲景秋。蟬聲入客耳，驚起不可留。", "草草具盤饌，不待酒獻酬。士生為名累，有似魚中鉤。", "齎材入市賣，貴者恒難售。豈不畏憔悴，為功忌中休。", "勉哉耘其業，以待歲晚收。"]'),
('yuding-0','符讀書城南','韓愈','唐','御定全唐诗','yuding','','[]','木之就規矩，在梓匠輪輿。人之能為人，由腹有詩書。',324,'御定全唐詩/json/341.json','["木之就規矩，在梓匠輪輿。人之能為人，由腹有詩書。", "詩書勤乃有，不勤腹空虛。欲知學之力，賢愚同一初。", "由其不能學，所入遂異閭。兩家各生子，提孩巧相如。", "少長聚嬉戲，不殊同隊魚。年至十二三，頭角稍相疏。", "二十漸乖張，清溝映汙渠。三十骨骼成，乃一龍一豬。", "飛黃騰踏去，不能顧蟾蜍。一為馬前卒，鞭背生蟲蛆。", "一為公與相，潭潭府中居。問之何因爾，學與不學歟。", "金璧雖重寶，費用難貯儲。學問藏之身，身在則有餘。", "君子與小人，不系父母且。不見公與相，起身自犁鉏。", "不見三公後，寒饑出無驢。文章豈不貴，經訓乃菑畬。", "潢潦無根源，朝滿夕已除。人不通古今，馬牛而襟裾。", "行身陷不義，況望多名譽。時秋積雨霽，新涼入郊墟。", "燈火稍可親，簡編可卷舒。豈不旦夕念，為爾惜居諸。", "恩義有相奪，作詩勸躊躇。"]'),
('yuding-1','示爽','韓愈','唐','御定全唐诗','yuding','','[]','宣城去京國，裏數逾三千。念汝欲別我，解裝具盤筵。',192,'御定全唐詩/json/341.json','["宣城去京國，裏數逾三千。念汝欲別我，解裝具盤筵。", "日昏不能散，起坐相引牽。冬夜豈不長，達旦燈燭然。", "座中悉親故，誰肯舍汝眠。念汝將一身，西來曾幾年。", "名科掩眾俊，州考居吏前。今從府公召，府公又時賢。", "時輩千百人，孰不謂汝妍。汝來江南近，裏閭故依然。", "昔日同戲兒，看汝立路邊。人生但如此，其實亦可憐。", "吾老世味薄，因循致留連。強顏班行內，何實非罪愆。", "才短難自力，懼終莫洗湔。臨分不汝誑，有路即歸田。"]'),
('yuding-2','人日城南登高','韓愈','唐','御定全唐诗','yuding','','[]','初正候才兆，涉七氣已弄。靄靄野浮陽，暉暉水披凍。',120,'御定全唐詩/json/341.json','["初正候才兆，涉七氣已弄。靄靄野浮陽，暉暉水披凍。", "聖朝身不廢，佳節古所用。親交既許來，子妷亦可從。", "盤蔬冬春雜，尊酒清濁共。令征前事為，觴詠新詩送。", "扶杖淩圮址，刺船犯枯葑。戀池群鴨回，釋嶠孤雲縱。", "人生本坦蕩，誰使妄倥傯。直指桃李闌，幽尋寧止重。"]'),
('yuding-3','病鴟','韓愈','唐','御定全唐诗','yuding','','[]','屋東惡水溝，有鴟墮鳴悲。青泥掩兩翅，拍拍不得離。',240,'御定全唐詩/json/341.json','["屋東惡水溝，有鴟墮鳴悲。青泥掩兩翅，拍拍不得離。", "君童叫相召，瓦礫爭先之。計校生平事，殺卻理亦宜。", "奪攘不愧恥，飽滿盤天嬉。晴日占光景，高風恣追隨。", "遂淩鸞鳳群，肯顧鴻鵠卑。今者命運窮，遭逢巧丸兒。", "中汝要害處，汝能不得施。于吾乃何有，不忍乘其危。", "丐汝將死命，浴以清水池。朝餐輟魚肉，暝宿防狐狸。", "自知無以致，蒙德久猶疑。飽入深竹叢，饑來傍階基。", "亮無責報心，固以聽所為。昨日有氣力，飛跳弄藩籬。", "今晨忽徑去，曾不報我知。僥倖非汝福，天衢汝休窺。", "京城事彈射，豎子不易欺。勿諱泥坑辱，泥坑乃良規。"]'),
('yuding-4','華山女','韓愈','唐','御定全唐诗','yuding','','[]','街東街西講佛經，撞鐘吹螺鬧宮庭。廣張罪福資誘脅，',120,'御定全唐詩/json/341.json','["街東街西講佛經，撞鐘吹螺鬧宮庭。廣張罪福資誘脅，", "華山女兒家奉道，欲驅異教歸仙靈。洗妝拭面著冠帔，", "不知誰人暗相報，訇然振動如雷霆。掃除眾寺人跡絕，", "抽簪脫釧解環佩，堆金疊玉光青熒。天門貴人傳詔召，", "豪家少年豈知道，來繞百匝腳不停。雲窗霧閣事恍惚，"]'),
('yuding-5','讀皇甫湜公安園池詩書其後二首','韓愈','唐','御定全唐诗','yuding','','[]','晉人目二子，其猶吹一吷。區區自其下，顧肯掛牙舌。',138,'御定全唐詩/json/341.json','["晉人目二子，其猶吹一吷。區區自其下，顧肯掛牙舌。", "春秋書王法，不誅其人身。爾雅注蟲魚，定非磊落人。", "湜也困公安，不自閑窮年。枉智思掎摭，", "我有一池水，蒲葦生其間。蟲魚沸相嚼，日夜不得閒。", "我初往觀之，其後益不觀。觀之亂我意，不如不觀完。", "用將濟諸人，捨得業孔顏。百年詎幾時，君子不可閑。"]'),
('yuding-6','路傍堠','韓愈','唐','御定全唐诗','yuding','','[]','堆堆路傍堠，一雙複一隻。迎我出秦關，送我入楚澤。',72,'御定全唐詩/json/341.json','["堆堆路傍堠，一雙複一隻。迎我出秦關，送我入楚澤。", "千以高山遮，萬以遠水隔。吾君勤聽治，照與日月敵。", "臣愚幸可哀，臣罪庶可釋。何當迎送歸，緣路高歷歷。"]'),
('yuding-7','食曲河驛','韓愈','唐','御定全唐诗','yuding','','[]','晨及曲河驛，淒然自傷情。群烏巢庭樹，乳燕飛簷楹。',72,'御定全唐詩/json/341.json','["晨及曲河驛，淒然自傷情。群烏巢庭樹，乳燕飛簷楹。", "而我抱重罪，孑孑萬里程。親戚頓乖角，圖史棄縱橫。", "下負明義重，上孤朝命榮。殺身諒無補，何用答生成。"]'),
('yuding-8','過南陽','韓愈','唐','御定全唐诗','yuding','','[]','南陽郭門外，桑下麥青青。行子去未已，春鳩鳴不停。',48,'御定全唐詩/json/341.json','["南陽郭門外，桑下麥青青。行子去未已，春鳩鳴不停。", "秦商邈既遠，湖海浩將經。孰忍生以戚，吾其寄餘齡。"]'),
('yuding-9','瀧吏','韓愈','唐','御定全唐诗','yuding','','[]','南行逾六旬，始下昌樂瀧。險惡不可狀，船石相舂撞。',433,'御定全唐詩/json/341.json','["南行逾六旬，始下昌樂瀧。險惡不可狀，船石相舂撞。", "往問瀧頭吏，潮州尚幾裏。行當何時到，土風複何似。", "瀧吏垂手笑，官何問之愚。譬官居京邑，何由知東吳。", "東吳遊宦鄉，官知自有由。潮州底處所，有罪乃竄流。", "儂幸無負犯，何由到而知。官今行自到，那遽妄問為。", "不虞卒見困，汗出愧且駭。吏曰聊戲官，儂嘗使往罷。", "嶺南大抵同，官去道苦遼。下此三千里，有州始名潮。", "惡溪瘴毒聚，雷電常洶洶。鱷魚大於船，牙眼怖殺儂。", "州南數十裏，有海無天地。颶風有時作，掀簸真差事。", "聖人于天下，於物無不容。比聞此州囚，亦在生還儂。", "官無嫌此州，固罪人所徙。官當明時來，事不待說委。", "官不自謹慎，宜即引分往。胡為此水邊，神色久戃慌。", "bd大瓶罌小，所任自有宜。官何不自量，滿溢以取斯。", "工農雖小人，事業各有守。不知官在朝，有益國家不。", "得無虱其間，不武亦不文。仁義飭其躬，巧奸敗群倫。", "叩頭謝吏言，始慚今更羞。曆官二十餘，國恩並未酬。", "凡吏之所訶，嗟實頗有之。不即金木誅，敢不識恩私。", "潮州雖雲遠，雖惡不可過。於身實已多，敢不持自賀。"]'),
('yuding-10','贈別元十八協律六首','韓愈','唐','御定全唐诗','yuding','','[]','知識久去眼，吾行其既遠。瞢瞢莫訾省，默默但寢飯。',528,'御定全唐詩/json/341.json','["知識久去眼，吾行其既遠。瞢瞢莫訾省，默默但寢飯。", "子兮何為者，冠佩立憲憲。何氏之從學，蘭蕙已滿畹。", "于何玩其光，以至歲向晚。治惟尚和同，無俟於謇謇。", "或師絕學賢，不以藝自挽。子兮獨如何，能自媚婉娩。", "金石出聲音，宮室發關楗。何人識章甫，而知駿蹄踠。", "惜乎吾無居，不得留息偃。臨當背面時，裁詩示繾綣。", "英英桂林伯，實惟文武特。遠勞從事賢，來吊逐臣色。", "南裔多山海，道裏屢紆直。風波無程期，所憂動不測。", "子行誠艱難，我去未窮極。臨別且何言，有淚不可拭。", "吾友柳子厚，其人藝且賢。吾未識子時，已覽贈子篇。", "寤寐想風采，於今已三年。不意流竄路，旬日同食眠。", "所聞昔已多，所得今過前。如何又須別，使我抱悁悁。", "勢要情所重，排斥則埃塵。骨肉未免然，又況四海人。", "嶷嶷桂林伯，矯矯義勇身。生平所未識，待我逾交親。", "遺我數幅書，繼以藥物珍。藥物防瘴癘，書勸養形神。", "不知四罪地，豈有再起辰。窮途致感激，肝膽還輪囷。", "讀書患不多，思義患不明。患足已不學，既學患不行。", "子今四美具，實大華亦榮。王官不可闕，未宜後諸生。", "嗟我擯南海，無由助飛鳴。", "寄書龍城守，君驥何時秣。峽山逢颶風，雷電助撞捽。", "乘潮簸扶胥，近岸指一發。兩岩雖雲牢，水石互飛發。", "屯門雖雲高，亦映波浪沒。餘罪不足惜，子生未宜忽。", "胡為不忍別，感謝情至骨。"]'),
('yuding-11','初南食貽元十八協律','韓愈','唐','御定全唐诗','yuding','','[]','鱟實如惠文，骨眼相負行。蠔相黏為山，百十各自生。',168,'御定全唐詩/json/341.json','["鱟實如惠文，骨眼相負行。蠔相黏為山，百十各自生。", "蒲魚尾如蛇，口眼不相營。蛤即是蝦蟆，同實浪異名。", "章舉馬甲柱，鬥以怪自呈。其餘數十種，莫不可歎驚。", "我來禦魑魅，自宜味南烹。調以鹹與酸，芼以椒與橙。", "腥臊始發越，咀吞面汗騂。惟蛇舊所識，實憚口眼獰。", "開籠聽其去，郁屈尚不平。賣爾非我罪，不屠豈非情。", "不祈靈珠報，幸無嫌怨並。聊歌以記之，又以告同行。"]'),
('yuding-12','宿曾江口示侄孫湘二首','韓愈','唐','御定全唐诗','yuding','','[]','雲昏水奔流，天水漭相圍。三江滅無口，其誰識涯圻。',144,'御定全唐詩/json/341.json','["雲昏水奔流，天水漭相圍。三江滅無口，其誰識涯圻。", "暮宿投民村，高處水半扉。犬雞俱上屋，不復走與飛。", "篙舟入其家，暝聞屋中唏。問知歲常然，哀此為生微。", "海風吹寒晴，波揚眾星輝。仰視北斗高，不知路所歸。", "舟行忘故道，屈曲高林間。林間無所有，奔流但潺潺。", "嗟我亦拙謀，致身落南蠻。茫然失所詣，無路何能還。"]'),
('yuding-13','答柳柳州食蝦蟆','韓愈','唐','御定全唐诗','yuding','','[]','蝦蟆雖水居，水特變形貌。強號為蛙哈，於實無所校。',204,'御定全唐詩/json/341.json','["蝦蟆雖水居，水特變形貌。強號為蛙哈，於實無所校。", "雖然兩股長，其奈脊皴皰。跳躑雖雲高，意不離濘淖。", "鳴聲相呼和，無理只取鬧。周公所不堪，灑灰垂典教。", "我棄愁海濱，恒願眠不覺。叵堪朋類多，沸耳作驚爆。", "端能敗笙磬，仍工亂學校。雖蒙勾踐禮，竟不聞報效。", "大戰元鼎年，孰強孰敗橈。居然當鼎味，豈不辱釣罩。", "余初不下喉，近亦能稍稍。常懼染蠻夷，失平生好樂。", "而君複何為，甘食比豢豹。獵較務同俗，全身斯為孝。", "哀哉思慮深，未見許回棹。"]'),
('yuding-14','別趙子','韓愈','唐','御定全唐诗','yuding','','[]','我遷于揭陽，君先揭陽居。揭陽去京華，其裏萬有餘。',204,'御定全唐詩/json/341.json','["我遷于揭陽，君先揭陽居。揭陽去京華，其裏萬有餘。", "不謂小郭中，有子可與娛。心平而行高，兩通詩與書。", "婆娑海水南，簸弄明月珠。及我遷宜春，意欲攜以俱。", "擺頭笑且言，我豈不足歟。又奚為於北，往來以紛如。", "海中諸山中，幽子頗不無。相期風濤觀，已久不可渝。", "又嘗疑龍蝦，果誰雄牙須。蚌蠃魚鱉蟲，瞿瞿以狙狙。", "識一已忘十，大同細自殊。欲一窮究之，時歲屢謝除。", "今子南且北，豈非亦有圖。人心未嘗同，不可一理區。", "宜各從所務，未用相賢愚。"]'),
('yuding-15','除官赴闕至江州寄鄂岳李大夫','韓愈','唐','御定全唐诗','yuding','','[]','盆城去鄂渚，風便一日耳。不枉故人書，無因帆江水。',168,'御定全唐詩/json/341.json','["盆城去鄂渚，風便一日耳。不枉故人書，無因帆江水。", "故人辭禮闈，旌節鎮江圻。而我竄逐者，龍鍾初得歸。", "別來已三歲，望望長迢遞。咫尺不相聞，平生那可計。", "我齒落且盡，君鬢白幾何。年皆過半百，來日苦無多。", "少年樂新知，衰暮思故友。譬如親骨肉，寧免相可不。", "我昔實愚蠢，不能降色辭。子犯亦有言，臣猶自知之。", "公其務貰過，我亦請改事。桑榆倘可收，願寄相思字。"]'),
('yuding-16','南山有高樹行贈李宗閔','韓愈','唐','御定全唐诗','yuding','','[]','南山有高樹，花葉何衰衰。上有鳳凰巢，鳳凰乳且棲。',240,'御定全唐詩/json/341.json','["南山有高樹，花葉何衰衰。上有鳳凰巢，鳳凰乳且棲。", "四旁多長枝，群鳥所托依。黃鵠據其高，眾鳥接其卑。", "不知何山鳥，羽毛有光輝。飛飛擇所處，正得眾所希。", "上承鳳凰恩，自期永不衰。中與黃鵠群，不自隱其私。", "下視眾鳥群，汝徒竟何為。不知挾丸子，心默有所規。", "彈汝枝葉間，汝翅不覺摧。或言由黃鵠，黃鵠豈有之。", "慎勿猜眾鳥，眾鳥不足猜。無人語鳳凰，汝屈安得知。", "黃鵠得汝去，婆娑弄毛衣。前汝下視鳥，各議汝瑕疵。", "汝豈無朋匹，有口莫肯開。汝落蒿艾間，幾時複能飛。", "哀哀故山友，中夜思汝悲。路遠翅翎短，不得持汝歸。"]'),
('yuding-17','猛虎行','韓愈','唐','御定全唐诗','yuding','','[]','猛虎雖雲惡，亦各有匹儕。群行深谷間，百獸望風低。',192,'御定全唐詩/json/341.json','["猛虎雖雲惡，亦各有匹儕。群行深谷間，百獸望風低。", "身食黃熊父，子食赤豹麛。擇肉于熊豹，肯視兔與狸。", "正晝當穀眠，眼有百步威。自矜無當對，氣性縱以乖。", "朝怒殺其子，暮還食其妃。匹儕四散走，猛虎還孤棲。", "狐鳴門兩旁，烏鵲從噪之。出逐猴入居，虎不知所歸。", "誰雲猛虎惡，中路正悲啼。豹來銜其尾，熊來攫其頤。", "猛虎死不辭，但慚前所為。虎坐無助死，況如汝細微。", "故當結以信，親當結以私。親故且不保，人誰信汝為。"]'),
('yuding-0','雪後寄崔二十六丞公','韓愈','唐','御定全唐诗','yuding','','[]','藍田十月雪塞關，我興南望愁群山。攢天嵬嵬凍相映，',96,'御定全唐詩/json/342.json','["藍田十月雪塞關，我興南望愁群山。攢天嵬嵬凍相映，", "殿前群公賜食罷，驊騮蹋路驕且閑。稱多量少鑒裁密，", "歸來殞涕掩關臥，心之紛亂誰能刪。詩翁憔悴劚荒棘，", "乾坤惠施萬物遂，獨於數子懷偏慳。朝欷暮唶不可解，"]'),
('yuding-1','送僧澄觀','韓愈','唐','御定全唐诗','yuding','','[]','浮屠西來何施為，擾擾四海爭賓士。構樓架閣切星漢，',144,'御定全唐詩/json/342.json','["浮屠西來何施為，擾擾四海爭賓士。構樓架閣切星漢，", "越商胡賈脫身罪，珪璧滿船甯計資。清淮無波平如席，", "影沈潭底龍驚遁，當晝無雲跨虛碧。借問經營本何人，", "皆言澄觀雖僧徒，公才吏用當今無。後從徐州辟書至，", "向風長歎不可見，我欲收斂加冠巾。洛陽窮秋厭窮獨，", "惜哉已老無所及，坐睨神骨空潸然。臨淮太守初到郡，"]'),
('yuding-2','山南鄭相公樊員外酬答為詩其末咸有見及語樊封以示愈依賦士四韻以獻','韓愈','唐','御定全唐诗','yuding','','[]','梁維西南屏，山厲水刻屈。稟生肖剿剛，難諧在民物。',169,'御定全唐詩/json/342.json','["梁維西南屏，山厲水刻屈。稟生肖剿剛，難諧在民物。", "滎公鼎軸老，享斡力健倔。帝咨女予往，牙纛前岔坲。", "威風挾惠氣，蓋壤兩劘拂。茫漫華黑間，指畫變恍欻。", "誠既富而美，章匯霍炳蔚。日延講大訓，龜判錯袞黻。", "樊子坐賓署，演孔刮老佛。金舂撼玉應，厥臭劇蕙鬱。", "遺我一言重，跽受惕齋栗。辭慳義卓闊，呀豁疚掊掘。", "如新去耵聹，雷霆逼颶f2。綴此豈為訓，俚言紹莊屈。"]'),
('yuding-3','奉和武相公鎮蜀時詠使宅韋太尉所養孔雀','韓愈','唐','御定全唐诗','yuding','','[]','穆穆鸞鳳友，何年來止茲。飄零失故態，隔絕抱長思。',48,'御定全唐詩/json/342.json','["穆穆鸞鳳友，何年來止茲。飄零失故態，隔絕抱長思。", "翠角高獨聳，金華煥相差。坐蒙恩顧重，畢命守階墀。"]'),
('yuding-4','感春三首','韓愈','唐','御定全唐诗','yuding','','[]','偶坐藤樹下，暮春下旬間。藤陰已可庇，落蕊還漫漫。',204,'御定全唐詩/json/342.json','["偶坐藤樹下，暮春下旬間。藤陰已可庇，落蕊還漫漫。", "亹亹新葉大，瓏瓏晚花幹。青天高寥寥，兩蝶飛翻翻。", "時節適當爾，懷悲自無端。", "黃黃蕪菁花，桃李事已退。狂風簸枯榆，狼藉九衢內。", "春序一如此，汝顏安足賴。誰能駕飛車，相從觀海外。", "晨游百花林，朱朱兼白白。柳枝弱而細，懸樹垂百尺。", "左右同來人，金紫貴顯劇。嬌童為我歌，哀響跨箏笛。", "豔姬蹋筵舞，清眸刺劍戟。心懷平生友，莫一在燕席。", "死者長眇芒，生者困乖隔。少年真可喜，老大百無益。"]'),
('yuding-5','早赴街西行香贈盧李二中舍人','韓愈','唐','御定全唐诗','yuding','','[]','天街東西異，祗命遂成遊。月明禦溝曉，蟬吟堤樹秋。',48,'御定全唐詩/json/342.json','["天街東西異，祗命遂成遊。月明禦溝曉，蟬吟堤樹秋。", "老僧情不薄，僻寺境還幽。寂寥二三子，歸騎得相收。"]'),
('yuding-6','晚寄張十八助教周郎博士','韓愈','唐','御定全唐诗','yuding','','[]','日薄風景曠，出歸偃前簷。晴雲如擘絮，新月似磨鐮。',48,'御定全唐詩/json/342.json','["日薄風景曠，出歸偃前簷。晴雲如擘絮，新月似磨鐮。", "田野興偶動，衣冠情久厭。吾生可攜手，歎息歲將淹。"]'),
('yuding-7','題張十八所居','韓愈','唐','御定全唐诗','yuding','','[]','君居泥溝上，溝濁萍青青。蛙讙橋未掃，蟬嘒門長扃。',48,'御定全唐詩/json/342.json','["君居泥溝上，溝濁萍青青。蛙讙橋未掃，蟬嘒門長扃。", "名秩後千品，詩文齊六經。端來問奇字，為我講聲形。"]'),
('yuding-8','奉酬盧給事雲夫四兄曲江荷花行見寄并呈上錢七兄閣老張十八助教','韓愈','唐','御定全唐诗','yuding','','[]','曲江千頃秋波淨，平鋪紅雲蓋明鏡。大明宮中給事歸，',74,'御定全唐詩/json/342.json','["曲江千頃秋波淨，平鋪紅雲蓋明鏡。大明宮中給事歸，", "我今官閑得婆娑，問言何處芙蓉多。撐舟昆明度雲錦，", "玉山前卻不復來，曲江汀瀅水準杯。我時相思不覺一回首，"]'),
('yuding-9','奉和錢七兄曹長盆池所植','韓愈','唐','御定全唐诗','yuding','','[]','翻翻江浦荷，而今生在此。擢擢菰葉長，芳根複誰徙。',48,'御定全唐詩/json/342.json','["翻翻江浦荷，而今生在此。擢擢菰葉長，芳根複誰徙。", "露涵兩鮮翠，風蕩相磨倚。但取主人知，誰言盆盎是。"]'),
('yuding-10','記夢','韓愈','唐','御定全唐诗','yuding','','[]','夜夢神官與我言，羅縷道妙角與根。挈攜陬維口瀾翻，',121,'御定全唐詩/json/342.json','["夜夢神官與我言，羅縷道妙角與根。挈攜陬維口瀾翻，", "我徒三人共追之，一人前度安不危。我亦平行蹋y槱e，", "神官見我開顏笑，前對一人壯非少。石壇坡陀可坐臥，", "壯非少者哦七言，六字常語一字難。我以指撮白玉丹，", "乃知仙人未賢聖，護短憑愚邀我敬。我能屈曲自世間，"]'),
('yuding-11','南內朝賀歸呈同官','韓愈','唐','御定全唐诗','yuding','','[]','薄雲蔽秋曦，清雨不成泥。罷賀南內衙，歸涼曉淒淒。',228,'御定全唐詩/json/342.json','["薄雲蔽秋曦，清雨不成泥。罷賀南內衙，歸涼曉淒淒。", "綠槐十二街，渙散馳輪蹄。余惟戇書生，孤身無所齎。", "三黜竟不去，致官九列齊。豈惟一身榮，佩玉冠簪犀。", "滉蕩天門高，著籍朝厥妻。文才不如人，行又無町畦。", "問之朝廷事，略不知東西。況於經籍深，豈究端與倪。", "君恩太山重，不見酬稗稊。所職事無多，又不自提撕。", "明庭集孔鸞，曷取於鳧鷖。樹以松與柏，不宜間蒿藜。", "婉孌自媚好，幾時不見擠。貪食以忘軀，鮮不調鹽醯。", "法吏多少年，磨淬出角圭。將舉汝愆尤，以為己階梯。", "收身歸關東，期不到死迷。"]'),
('yuding-12','朝歸','韓愈','唐','御定全唐诗','yuding','','[]','峨峨進賢冠，耿耿水蒼佩。服章豈不好，不與德相對。',84,'御定全唐詩/json/342.json','["峨峨進賢冠，耿耿水蒼佩。服章豈不好，不與德相對。", "顧影聽其聲，赬顏汗漸背。進乏犬雞效，又不勇自退。", "坐食取其肥，無堪等聾瞶。長風吹天墟，秋日萬里曬。", "抵暮但昏眠，不成歌慷慨。"]'),
('yuding-13','雜詩四首','韓愈','唐','御定全唐诗','yuding','','[]','朝蠅不須驅，暮蚊不可拍。蠅蚊滿八區，可盡與相格。',216,'御定全唐詩/json/342.json','["朝蠅不須驅，暮蚊不可拍。蠅蚊滿八區，可盡與相格。", "得時能幾時，與汝恣啖咋。涼風九月到，掃不見蹤跡。", "鵲鳴聲楂楂，烏雜訊護護。爭鬥庭宇間，持身博彈射。", "黃鵠能忍饑，兩翅久不擘。蒼蒼雲海路，歲晚將無獲。", "截橑為欂櫨，斫楹以為椽。束蒿以代之，小大不相權。", "雖無風雨災，得不覆且顛。解轡棄騏驥，蹇驢鞭使前。", "昆侖高萬里，歲盡道苦邅。停車臥輪下，絕意于神仙。", "雀鳴朝營食，鳩鳴暮覓群。獨有知時鶴，雖鳴不緣身。", "喑蟬終不鳴，有抱不列陳。蛙黽鳴無謂，合合只亂人。"]'),
('yuding-14','讀東方朔雜事','韓愈','唐','御定全唐诗','yuding','','[]','嚴嚴王母宮，下維萬仙家。噫欠為飄風，濯手大雨沱。',216,'御定全唐詩/json/342.json','["嚴嚴王母宮，下維萬仙家。噫欠為飄風，濯手大雨沱。", "方朔乃豎子，驕不加禁訶。偷入雷電室，輷輘掉狂車。", "王母聞以笑，衛官助呀呀。不知萬萬人，生身埋泥沙。", "簸頓五山踣，流漂八維蹉。曰吾兒可憎，奈此狡獪何。", "方朔聞不喜，褫身絡蛟蛇。瞻相北斗柄，兩手自相挼。", "群仙急乃言，百犯庸不科。向觀睥睨處，事在不可赦。", "欲不布露言，外口實喧嘩。王母不得已，顏嚬口齎嗟。", "頷頭可其奏，送以紫玉珂。方朔不懲創，挾恩更矜誇。", "詆欺劉天子，正晝溺殿衙。一旦不辭訣，攝身淩蒼霞。"]'),
('yuding-15','譴瘧鬼','韓愈','唐','御定全唐诗','yuding','','[]','屑屑水帝魂，謝謝無餘輝。如何不肖子，尚奮瘧鬼威。',204,'御定全唐詩/json/342.json','["屑屑水帝魂，謝謝無餘輝。如何不肖子，尚奮瘧鬼威。", "乘秋作寒熱，翁嫗所罵譏。求食歐泄間，不知臭穢非。", "醫師加百毒，熏灌無停機。灸師施艾炷，酷若獵火圍。", "詛師毒口牙，舌作霹靂飛。符師弄刀筆，丹墨交橫揮。", "咨汝之胄出，門戶何巍巍。祖軒而父頊，未沫於前徽。", "不修其操行，賤薄似汝稀。豈不忝厥祖，靦然不知歸。", "湛湛江水清，歸居安汝妃。清波為裳衣，白石為門畿。", "呼吸明月光，手掉芙蓉旗。降集隨九歌，飲芳而食菲。", "贈汝以好辭，咄汝去莫違。"]'),
('yuding-16','示兒','韓愈','唐','御定全唐诗','yuding','','[]','始我來京師，止攜一束書。辛勤三十年，以有此屋廬。',300,'御定全唐詩/json/342.json','["始我來京師，止攜一束書。辛勤三十年，以有此屋廬。", "此屋豈為華，於我自有餘。中堂高且新，四時登牢蔬。", "前榮饌賓親，冠婚之所於。庭內無所有，高樹八九株。", "有藤婁絡之，春華夏陰敷。東堂坐見山，雲風相吹噓。", "松果連南亭，外有瓜芋區。西偏屋不多，槐榆翳空虛。", "山鳥旦夕鳴，有類澗谷居。主婦治北堂，膳服適戚疏。", "恩封高平君，子孫從朝裾。開門問誰來，無非卿大夫。", "不知官高卑，玉帶懸金魚。問客之所為，峨冠講唐虞。", "酒食罷無為，棋槊以相娛。凡此座中人，十九持鈞樞。", "又問誰與頻，莫與張樊如。來過亦無事，考評道精粗。", "躚躚媚學子，牆屏日有徒。以能問不能，其蔽豈可祛。", "嗟我不修飾，事與庸人俱。安能坐如此，比肩於朝儒。", "詩以示兒曹，其無迷厥初。"]'),
('yuding-17','庭楸','韓愈','唐','御定全唐诗','yuding','','[]','庭楸止五株，共生十步間。各有藤繞之，上各相鉤聯。',180,'御定全唐詩/json/342.json','["庭楸止五株，共生十步間。各有藤繞之，上各相鉤聯。", "下葉各垂地，樹顛各雲連。朝日出其東，我常坐西偏。", "夕日在其西，我常坐東邊。當晝日在上，我在中央間。", "仰視何青青，上不見纖穿。朝暮無日時，我且八九旋。", "濯濯晨露香，明珠何聯聯。夜月來照之，蒨蒨自生煙。", "我已自頑鈍，重遭五楸牽。客來尚不見，肯到權門前。", "權門眾所趨，有客動百千。九牛亡一毛，未在多少間。", "往既無可顧，不往自可憐。"]'),
('yuding-18','玩月喜張十八員外以王六秘書至','韓愈','唐','御定全唐诗','yuding','','[]','前夕雖十五，月長未滿規。君來晤我時，風露渺無涯。',84,'御定全唐詩/json/342.json','["前夕雖十五，月長未滿規。君來晤我時，風露渺無涯。", "浮雲散白石，天宇開青池。孤質不自憚，中天為君施。", "玩玩夜遂久，亭亭曙將披。況當今夕圓，又以嘉客隨。", "惜無酒食樂，但用歌嘲為。"]'),
('yuding-19','和李相公攝事南郊，覽物興懷，呈一二知舊','韓愈','唐','御定全唐诗','yuding','','[]','燦燦辰角曙，亭亭寒露朝。川原共澄映，雲日還浮飄。',120,'御定全唐詩/json/342.json','["燦燦辰角曙，亭亭寒露朝。川原共澄映，雲日還浮飄。", "上宰嚴祀事，清途振華鑣。圓丘峻且坦，前對南山標。", "村樹黃複綠，中田稼何饒。顧瞻想岩穀，興歎倦塵囂。", "惟彼顛瞑者，去公豈不遼。為仁朝自治，用靜兵以銷。", "勿憚吐捉勤，可歌風雨調。聖賢相遇少，功德今宣昭。"]'),
('yuding-20','和裴僕射相公假山十一韻','韓愈','唐','御定全唐诗','yuding','','[]','公乎真愛山，看山旦連夕。猶嫌山在眼，不得著腳曆。',132,'御定全唐詩/json/342.json','["公乎真愛山，看山旦連夕。猶嫌山在眼，不得著腳曆。", "枉語山中人，匄我澗側石。有來應公須，歸必載金帛。", "當軒乍駢羅，隨勢忽開坼。有洞若神剜，有岩類天劃。", "終朝岩洞間，歌鼓燕賓戚。孰謂衡霍期，近在王侯宅。", "傅氏築已卑，磻溪釣何激。逍遙功德下，不與事相摭。", "樂我盛明朝，於焉傲今昔。"]'),
('yuding-21','與張十八同效阮步兵一日複一夕','韓愈','唐','御定全唐诗','yuding','','[]','一日復一日，一朝複一朝。只見有不如，不見有所超。',120,'御定全唐詩/json/342.json','["一日復一日，一朝複一朝。只見有不如，不見有所超。", "食作前日味，事作前日調。不知久不死，憫憫尚誰要。", "富貴自縶拘，貧賤亦煎焦。俯仰未得所，一世已解鑣。", "譬如籠中鶴，六翮無所搖。譬如兔得蹄，安用東西跳。", "還看古人書，複舉前人瓢。未知所窮竟，且作新詩謠。"]'),
('yuding-22','送諸葛覺往隨州讀書','韓愈','唐','御定全唐诗','yuding','','[]','鄴侯家多書，插架三萬軸。一一懸牙籤，新若手未觸。',156,'御定全唐詩/json/342.json','["鄴侯家多書，插架三萬軸。一一懸牙籤，新若手未觸。", "為人強記覽，過眼不再讀。偉哉群聖文，磊落載其腹。", "行年五十餘，出守數已六。京邑有舊廬，不容久食宿。", "台閣多官員，無地寄一足。我雖官在朝，氣勢日局縮。", "屢為丞相言，雖懇不見錄。送行過滻水，東望不轉目。", "今子從之遊，學問得所欲。入海觀龍魚，矯翮逐黃鵠。", "勉為新詩章，月寄三四幅。"]'),
('yuding-23','南溪始泛三首','韓愈','唐','御定全唐诗','yuding','','[]','榜舟南山下，上上不得返。幽事隨去多，孰能量近遠。',312,'御定全唐詩/json/342.json','["榜舟南山下，上上不得返。幽事隨去多，孰能量近遠。", "陰沈過連樹，藏昂抵橫阪。石粗肆磨礪，波惡厭牽挽。", "或倚偏岸漁，竟就平洲飯。點點暮雨飄，梢梢新月偃。", "餘年懍無幾，休日愴已晚。自是病使然，非由取高蹇。", "南溪亦清駛，而無楫與舟。山農驚見之，隨我勸不休。", "不惟兒童輩，或有杖白頭。饋我籠中瓜，勸我此淹留。", "我雲以病歸，此已頗自由。幸有用餘俸，置居在西疇。", "囷倉米谷滿，未有旦夕憂。上去無得得，下來亦悠悠。", "但恐煩裏閭，時有緩急投。願為同社人，雞豚燕春秋。", "足弱不能步，自宜收朝跡。羸形可輿致，佳觀安事擲。", "即此南阪下，久聞有水石。拖舟入其間，溪流正清激。", "隨波吾未能，峻瀨乍可刺。鷺起若導吾，前飛數十尺。", "亭亭柳帶沙，團團松冠壁。歸時還盡夜，誰謂非事役。"]'),
('yuding-0','題楚昭王廟','韓愈','唐','御定全唐诗','yuding','','[]','丘墳滿目衣冠盡，城闕連雲草樹荒。',32,'御定全唐詩/json/343.json','["丘墳滿目衣冠盡，城闕連雲草樹荒。", "猶有國人懷舊德，一間茅屋祭昭王。"]'),
('yuding-1','宿龍宮灘','韓愈','唐','御定全唐诗','yuding','','[]','浩浩複湯湯，灘聲抑更揚。奔流疑激電，驚浪似浮霜。',48,'御定全唐詩/json/343.json','["浩浩複湯湯，灘聲抑更揚。奔流疑激電，驚浪似浮霜。", "夢覺燈生暈，宵殘雨送涼。如何連曉語，一半是思鄉。"]'),
('yuding-2','叉魚招張功曹','韓愈','唐','御定全唐诗','yuding','','[]','叉魚春岸闊，此興在中宵。大炬然如晝，長船縛似橋。',216,'御定全唐詩/json/343.json','["叉魚春岸闊，此興在中宵。大炬然如晝，長船縛似橋。", "深窺沙可數，靜搒水無搖。刃下那能脫，波間或自跳。", "中鱗憐錦碎，當目訝珠銷。迷火逃翻近，驚人去暫遙。", "競多心轉細，得雋語時囂。潭罄知存寡，舷平覺獲饒。", "交頭疑湊餌，駢首類同條。濡沫情雖密，登門事已遼。", "盈車欺故事，飼犬驗今朝。血浪凝猶沸，腥風遠更飄。", "蓋江煙冪冪，拂棹影寥寥。獺去愁無食，龍移懼見燒。", "如棠名既誤，釣渭日徒消。文客驚先賦，篙工喜盡謠。", "膾成思我友，觀樂憶吾僚。自可捐憂累，何須強問鴞。"]'),
('yuding-3','李員外寄紙筆','韓愈','唐','御定全唐诗','yuding','','[]','題是臨池後，分從起草餘。兔尖針莫並，繭淨雪難如。',36,'御定全唐詩/json/343.json','["題是臨池後，分從起草餘。兔尖針莫並，繭淨雪難如。", "莫怪殷勤謝，虞卿正著書。"]'),
('yuding-4','次同冠峽','韓愈','唐','御定全唐诗','yuding','','[]','今日是何朝，天晴物色饒。落英千尺墮，遊絲百丈飄。',48,'御定全唐詩/json/343.json','["今日是何朝，天晴物色饒。落英千尺墮，遊絲百丈飄。", "泄乳交岩脈，懸流揭浪標。無心思嶺北，猿鳥莫相撩。"]'),
('yuding-5','答張十一功曹','韓愈','唐','御定全唐诗','yuding','','[]','山淨江空水見沙，哀猿啼處兩三家。筼簹競長纖纖筍，',40,'御定全唐詩/json/343.json','["山淨江空水見沙，哀猿啼處兩三家。筼簹競長纖纖筍，", "吟君詩罷看雙鬢，鬥覺霜毛一半加。"]'),
('yuding-6','郴州祈雨','韓愈','唐','御定全唐诗','yuding','','[]','乞雨女郎魂，炰羞潔且繁。廟開鼯鼠叫，神降越巫言。',48,'御定全唐詩/json/343.json','["乞雨女郎魂，炰羞潔且繁。廟開鼯鼠叫，神降越巫言。", "旱氣期銷蕩，陰官想駿奔。行看五馬入，蕭颯已隨軒。"]'),
('yuding-7','湘中酬張十一功曹','韓愈','唐','御定全唐诗','yuding','','[]','休垂絕徼千行淚，共泛清湘一葉舟。',32,'御定全唐詩/json/343.json','["休垂絕徼千行淚，共泛清湘一葉舟。", "今日嶺猿兼越鳥，可憐同聽不知愁。"]'),
('yuding-8','郴口又贈二首','韓愈','唐','御定全唐诗','yuding','','[]','山作劍攢江寫鏡，扁舟鬥轉疾於飛。',64,'御定全唐詩/json/343.json','["山作劍攢江寫鏡，扁舟鬥轉疾於飛。", "回頭笑向張公子，終日思歸此日歸。", "雪颭霜翻看不分，雷驚電激語難聞。", "沿涯宛轉到深處，何限青天無片雲。"]'),
('yuding-9','題木居士二首','韓愈','唐','御定全唐诗','yuding','','[]','火透波穿不計春，根如頭面幹如身。',64,'御定全唐詩/json/343.json','["火透波穿不計春，根如頭面幹如身。", "偶然題作木居士，便有無窮求福人。", "為神詎比溝中斷，遇賞還同爨下餘。", "朽蠹不勝刀鋸力，匠人雖巧欲何如。"]'),
('yuding-10','晚泊江口','韓愈','唐','御定全唐诗','yuding','','[]','郡城朝解纜，江岸暮依村。二女竹上淚，孤臣水底魂。',48,'御定全唐詩/json/343.json','["郡城朝解纜，江岸暮依村。二女竹上淚，孤臣水底魂。", "雙雙歸蟄燕，一一叫群猿。回首那聞語，空看別袖翻。"]'),
('yuding-11','湘中','韓愈','唐','御定全唐诗','yuding','','[]','猿愁魚踴水翻波，自古流傳是汨羅。',32,'御定全唐詩/json/343.json','["猿愁魚踴水翻波，自古流傳是汨羅。", "蘋藻滿盤無處奠，空聞漁父扣舷歌。"]'),
('yuding-12','別盈上人','韓愈','唐','御定全唐诗','yuding','','[]','山僧愛山出無期，俗士牽俗來何時。',32,'御定全唐詩/json/343.json','["山僧愛山出無期，俗士牽俗來何時。", "祝融峰下一回首，即是此生長別離。"]'),
('yuding-13','喜雪獻裴尚書','韓愈','唐','御定全唐诗','yuding','','[]','宿雲寒不卷，春雪墮如簁。騁巧先投隙，潛光半入池。',240,'御定全唐詩/json/343.json','["宿雲寒不卷，春雪墮如簁。騁巧先投隙，潛光半入池。", "喜深將策試，驚密仰簷窺。自下何曾汙，增高未覺危。", "比心明可燭，拂面愛還吹。妒舞時飄袖，欺梅並壓枝。", "地空迷界限，砌滿接高卑。浩蕩乾坤合，霏微物象移。", "為祥矜大熟，布澤荷平施。已分年華晚，猶憐曙色隨。", "氣嚴當酒換，灑急聽窗知。照曜臨初日，玲瓏滴晚澌。", "聚庭看嶽聳，掃路見雲披。陣勢魚麗遠，書文鳥篆奇。", "縱歡羅豔黠，列賀擁熊螭。履敝行偏冷，門扃臥更羸。", "悲嘶聞病馬，浪走信嬌兒。灶靜愁煙絕，絲繁念鬢衰。", "擬鹽吟舊句，授簡慕前規。捧贈同燕石，多慚失所宜。"]'),
('yuding-14','春雪','韓愈','唐','御定全唐诗','yuding','','[]','看雪乘清旦，無人坐獨謠。拂花輕尚起，落地暖初銷。',120,'御定全唐詩/json/343.json','["看雪乘清旦，無人坐獨謠。拂花輕尚起，落地暖初銷。", "已訝陵歌扇，還來伴舞腰。灑篁留密節，著柳送長條。", "入鏡鸞窺沼，行天馬度橋。遍階憐可掬，滿樹戲成搖。", "江浪迎濤日，風毛縱獵朝。弄閒時細轉，爭急忽驚飄。", "城險疑懸布，砧寒未搗綃。莫愁陰景促，夜色自相饒。"]'),
('yuding-15','聞梨花發贈劉師命','韓愈','唐','御定全唐诗','yuding','','[]','桃溪惆悵不能過，紅豔紛紛落地多。',32,'御定全唐詩/json/343.json','["桃溪惆悵不能過，紅豔紛紛落地多。", "聞道郭西千樹雪，欲將君去醉如何。"]'),
('yuding-16','春雪間早梅','韓愈','唐','御定全唐诗','yuding','','[]','梅將雪共春，彩豔不相因。逐吹能爭密，排枝巧妒新。',120,'御定全唐詩/json/343.json','["梅將雪共春，彩豔不相因。逐吹能爭密，排枝巧妒新。", "誰令香滿座，獨使淨無塵。芳意饒呈瑞，寒光助照人。", "玲瓏開已遍，點綴坐來頻。那是俱疑似，須知兩逼真。", "熒煌初亂眼，浩蕩忽迷神。未許瓊華比，從將玉樹親。", "先期迎獻歲，更伴占茲晨。願得長輝映，輕微敢自珍。"]'),
('yuding-17','早春雪中聞鶯','韓愈','唐','御定全唐诗','yuding','','[]','朝鶯雪裏新，雪樹眼前春。帶澀先迎氣，侵寒已報人。',72,'御定全唐詩/json/343.json','["朝鶯雪裏新，雪樹眼前春。帶澀先迎氣，侵寒已報人。", "共矜初聽早，誰貴後聞頻。暫囀那成曲，孤鳴豈及辰。", "風霜徒自保，桃李詎相親。寄謝幽棲友，辛勤不為身。"]'),
('yuding-18','梨花下贈劉師命','韓愈','唐','御定全唐诗','yuding','','[]','洛陽城外清明節，百花寥落梨花發。',32,'御定全唐詩/json/343.json','["洛陽城外清明節，百花寥落梨花發。", "今日相逢瘴海頭，共驚爛漫開正月。"]'),
('yuding-19','和歸工部送僧約','韓愈','唐','御定全唐诗','yuding','','[]','早知皆是自拘囚，不學因循到白頭。',32,'御定全唐詩/json/343.json','["早知皆是自拘囚，不學因循到白頭。", "汝既出家還擾擾，何人更得死前休。"]'),
('yuding-20','入關詠馬','韓愈','唐','御定全唐诗','yuding','','[]','歲老豈能充上駟，力微當自慎前程。',32,'御定全唐詩/json/343.json','["歲老豈能充上駟，力微當自慎前程。", "不知何故翻驤首，牽過關門妄一鳴。"]'),
('yuding-21','木芙蓉','韓愈','唐','御定全唐诗','yuding','','[]','新開寒露叢，遠比水間紅。豔色寧相妒，嘉名偶自同。',48,'御定全唐詩/json/343.json','["新開寒露叢，遠比水間紅。豔色寧相妒，嘉名偶自同。", "采江官渡晚，搴木古祠空。願得勤來看，無令便逐風。"]'),
('yuding-22','題張十一旅舍三詠：榴花','韓愈','唐','御定全唐诗','yuding','','[]','五月榴花照眼明，枝間時見子初成。',32,'御定全唐詩/json/343.json','["五月榴花照眼明，枝間時見子初成。", "可憐此地無車馬，顛倒青苔落絳英。"]'),
('yuding-23','題張十一旅舍三詠：井','韓愈','唐','御定全唐诗','yuding','','[]','賈誼宅中今始見，葛洪山下昔曾窺。',32,'御定全唐詩/json/343.json','["賈誼宅中今始見，葛洪山下昔曾窺。", "寒泉百尺空看影，正是行人渴死時。"]'),
('yuding-24','題張十一旅舍三詠：蒲萄','韓愈','唐','御定全唐诗','yuding','','[]','新莖未遍半猶枯，高架支離倒複扶。',32,'御定全唐詩/json/343.json','["新莖未遍半猶枯，高架支離倒複扶。", "若欲滿盤堆馬乳，莫辭添竹引龍須。"]'),
('yuding-25','峽石西泉','韓愈','唐','御定全唐诗','yuding','','[]','居然鱗介不能容，石眼環環水一鐘。',32,'御定全唐詩/json/343.json','["居然鱗介不能容，石眼環環水一鐘。", "聞說旱時求得雨，只疑科鬥是蛟龍。"]'),
('yuding-26','梁國惠康公主挽歌二首','韓愈','唐','御定全唐诗','yuding','','[]','定諡芳聲遠，移封大國新。巽宮尊長女，台室屬良人。',96,'御定全唐詩/json/343.json','["定諡芳聲遠，移封大國新。巽宮尊長女，台室屬良人。", "河漢重泉夜，梧桐半樹春。龍輀非厭翟，還輾禁城塵。", "秦地吹簫女，湘波鼓瑟妃。佩蘭初應夢，奔月竟淪輝。", "夫族迎魂去，宮官會葬歸。從今沁園草，無複更芳菲。"]'),
('yuding-27','和崔舍人詠月二十韻','韓愈','唐','御定全唐诗','yuding','','[]','三秋端正月，今夜出東溟。對日猶分勢，騰天漸吐靈。',240,'御定全唐詩/json/343.json','["三秋端正月，今夜出東溟。對日猶分勢，騰天漸吐靈。", "未高烝遠氣，半上霽孤形。赫奕當躔次，虛徐度杳冥。", "長河晴散霧，列宿曙分螢。浩蕩英華溢，蕭疏物象泠。", "池邊臨倒照，簷際送橫經。花樹參差見，皋禽斷續聆。", "牖光窺寂寞，砧影伴娉婷。幽坐看侵戶，閑吟愛滿庭。", "輝斜通壁練，彩碎射沙星。清潔雲間路，空涼水上亭。", "淨堪分顧兔，細得數飄萍。山翠相凝綠，林煙共冪青。", "過隅驚桂側，當午覺輪停。屬思摛霞錦，追歡罄縹瓶。", "郡樓何處望，隴笛此時聽。右掖連台座，重門限禁扃。", "風台觀滉漾，冰砌步青熒。獨有虞庠客，無由拾落蓂。"]'),
('yuding-28','詠雪贈張籍','韓愈','唐','御定全唐诗','yuding','','[]','只見縱橫落，寧知遠近來。飄颻還自弄，曆亂竟誰催。',481,'御定全唐詩/json/343.json','["只見縱橫落，寧知遠近來。飄颻還自弄，曆亂竟誰催。", "座暖銷那怪，池清失可猜。坳中初蓋底，垤處遂成堆。", "慢有先居後，輕多去卻回。度前鋪瓦隴，發本積牆隈。", "穿細時雙透，乘危忽半摧。舞深逢坎井，集早值層台。", "砧練終宜搗，階紈未暇裁。城寒裝睥睨，樹凍裹莓苔。", "片片勻如剪，紛紛碎若挼。定非燖鵠鷺，真是屑瓊瑰。", "緯繣觀朝萼，冥茫矚晚埃。當窗恒凜凜，出戶即皚皚。", "壓野榮芝菌，傾都委貨財。娥嬉華蕩漾，胥怒浪崔嵬。", "磧迥疑浮地，雲平想輾雷。隨車翻縞帶，逐馬散銀盃。", "萬屋漫汗合，千株照曜開。松篁遭挫抑，糞壤獲饒培。", "隔絕門庭遽，擠排陛級才。豈堪裨岳鎮，強欲效鹽梅。", "隱匿瑕疵盡，包羅委瑣該。誤雞宵呃喔，驚雀暗裴回。", "浩浩過三暮，悠悠匝九垓。鯨鯢陸死骨，玉石火炎灰。", "厚慮填溟壑，高愁cN鬥魁。日輪埋欲側，坤軸壓將頹。", "岸類長蛇攪，陵猶巨象豗。水官誇傑黠，木氣怯胚胎。", "著地無由卷，連天不易推。龍魚冷蟄苦，虎豹餓號哀。", "巧借奢華便，專繩困約災。威貪陵布被，光肯離金罍。", "賞玩捐他事，歌謠放我才。狂教詩硉矹，興與酒陪鰓。", "惟子能諳耳，諸人得語哉。助留風作黨，勸坐火為媒。", "雕刻文刀利，搜求智網恢。莫煩相屬和，傳示及提孩。"]'),
('yuding-29','酬王二十舍人雪中見寄','韓愈','唐','御定全唐诗','yuding','','[]','三日柴門擁不開，階平庭滿白皚皚。',32,'御定全唐詩/json/343.json','["三日柴門擁不開，階平庭滿白皚皚。", "今朝蹋作瓊瑤跡，為有詩從鳳沼來。"]'),
('yuding-30','送侯喜','韓愈','唐','御定全唐诗','yuding','','[]','已作龍鍾後時者，懶於街裏蹋塵埃。',32,'御定全唐詩/json/343.json','["已作龍鍾後時者，懶於街裏蹋塵埃。", "如今便別長官去，直到新年衙日來。"]'),
('yuding-31','學諸進士作精衛銜石填海','韓愈','唐','御定全唐诗','yuding','','[]','鳥有償冤者，終年抱寸誠。口銜山石細，心望海波平。',72,'御定全唐詩/json/343.json','["鳥有償冤者，終年抱寸誠。口銜山石細，心望海波平。", "渺渺功難見，區區命已輕。人皆譏造次，我獨賞專精。", "豈計休無日，惟應盡此生。何慚刺客傳，不著報讎名。"]'),
('yuding-32','奉酬振武胡十二丈大夫','韓愈','唐','御定全唐诗','yuding','','[]','傾朝共羨寵光頻，半歲遷騰作虎臣。戎旆暫停辭社樹，',40,'御定全唐詩/json/343.json','["傾朝共羨寵光頻，半歲遷騰作虎臣。戎旆暫停辭社樹，", "自笑平生誇膽氣，不離文字鬢毛新。"]'),
('yuding-33','奉和庫部盧四兄曹長元日朝回','韓愈','唐','御定全唐诗','yuding','','[]','天仗宵嚴建羽旄，春雲送色曉雞號。金爐香動螭頭暗，',40,'御定全唐詩/json/343.json','["天仗宵嚴建羽旄，春雲送色曉雞號。金爐香動螭頭暗，", "太平時節難身遇，郎署何須歎二毛。"]'),
('yuding-34','寒食直歸遇雨','韓愈','唐','御定全唐诗','yuding','','[]','寒食時看度，春遊事已違。風光連日直，陰雨半朝歸。',48,'御定全唐詩/json/343.json','["寒食時看度，春遊事已違。風光連日直，陰雨半朝歸。", "不見紅球上，那論彩索飛。惟將新賜火，向曙著朝衣。"]'),
('yuding-35','送李六協律歸荊南','韓愈','唐','御定全唐诗','yuding','','[]','早日羈游所，春風送客歸。柳花還漠漠，江燕正飛飛。',48,'御定全唐詩/json/343.json','["早日羈游所，春風送客歸。柳花還漠漠，江燕正飛飛。", "歌舞知誰在，賓僚逐使非。宋亭池水綠，莫忘蹋芳菲。"]'),
('yuding-36','題百葉桃花','韓愈','唐','御定全唐诗','yuding','','[]','百葉雙桃晚更紅，窺窗映竹見玲瓏。',32,'御定全唐詩/json/343.json','["百葉雙桃晚更紅，窺窗映竹見玲瓏。", "應知侍史歸天上，故伴仙郎宿禁中。"]'),
('yuding-37','春雪','韓愈','唐','御定全唐诗','yuding','','[]','新年都未有芳華，二月初驚見草芽。',32,'御定全唐詩/json/343.json','["新年都未有芳華，二月初驚見草芽。", "白雪卻嫌春色晚，故穿庭樹作飛花。"]'),
('yuding-38','戲題牡丹','韓愈','唐','御定全唐诗','yuding','','[]','幸自同開俱隱約，何須相倚鬥輕盈。陵晨並作新妝面，',40,'御定全唐詩/json/343.json','["幸自同開俱隱約，何須相倚鬥輕盈。陵晨並作新妝面，", "長年是事皆拋盡，今日欄邊暫眼明。"]'),
('yuding-39','盆池五首','韓愈','唐','御定全唐诗','yuding','','[]','老翁真個似童兒，汲水埋盆作小池。',160,'御定全唐詩/json/343.json','["老翁真個似童兒，汲水埋盆作小池。", "一夜青蛙鳴到曉，恰如方口釣魚時。", "莫道盆池作不成，藕稍初種已齊生。", "從今有雨君須記，來聽蕭蕭打葉聲。", "瓦沼晨朝水自清，小蟲無數不知名。", "忽然分散無蹤影，惟有魚兒作隊行。", "泥盆淺小詎成池，夜半青蛙聖得知。", "一聽暗來將伴侶，不煩鳴喚鬥雄雌。", "池光天影共青青，拍岸才添水數瓶。", "且待夜深明月去，試看涵泳幾多星。"]'),
('yuding-40','芍藥','韓愈','唐','御定全唐诗','yuding','','[]','浩態狂香昔未逢，紅燈爍爍綠盤籠。',32,'御定全唐詩/json/343.json','["浩態狂香昔未逢，紅燈爍爍綠盤籠。", "覺來獨對情驚恐，身在仙宮第幾重。"]'),
('yuding-41','奉和虢州劉給事使君三堂新題二十一詠：新亭','韓愈','唐','御定全唐诗','yuding','','[]','湖上新亭好，公來日出初。水文浮枕簟，瓦影蔭龜魚。',24,'御定全唐詩/json/343.json','["湖上新亭好，公來日出初。水文浮枕簟，瓦影蔭龜魚。"]'),
('yuding-42','奉和虢州劉給事使君三堂新題二十一詠：流水','韓愈','唐','御定全唐诗','yuding','','[]','汩汩幾時休，從春複到秋。只言池未滿，池滿強交流。',24,'御定全唐詩/json/343.json','["汩汩幾時休，從春複到秋。只言池未滿，池滿強交流。"]'),
('yuding-43','奉和虢州劉給事使君三堂新題二十一詠：竹洞','韓愈','唐','御定全唐诗','yuding','','[]','竹洞何年有，公初斫竹開。洞門無鎖鑰，俗客不曾來。',24,'御定全唐詩/json/343.json','["竹洞何年有，公初斫竹開。洞門無鎖鑰，俗客不曾來。"]'),
('yuding-44','奉和虢州劉給事使君三堂新題二十一詠：月臺','韓愈','唐','御定全唐诗','yuding','','[]','南館城陰闊，東湖水氣多。直須臺上看，始奈月明何。',24,'御定全唐詩/json/343.json','["南館城陰闊，東湖水氣多。直須臺上看，始奈月明何。"]'),
('yuding-45','奉和虢州劉給事使君三堂新題二十一詠：渚亭','韓愈','唐','御定全唐诗','yuding','','[]','自有人知處，那無步往蹤。莫教安四壁，面面看芙蓉。',24,'御定全唐詩/json/343.json','["自有人知處，那無步往蹤。莫教安四壁，面面看芙蓉。"]'),
('yuding-46','奉和虢州劉給事使君三堂新題二十一詠：竹溪','韓愈','唐','御定全唐诗','yuding','','[]','藹藹溪流慢，梢梢岸筱長。穿沙碧簳淨，落水紫苞香。',24,'御定全唐詩/json/343.json','["藹藹溪流慢，梢梢岸筱長。穿沙碧簳淨，落水紫苞香。"]'),
('yuding-47','奉和虢州劉給事使君三堂新題二十一詠：北湖','韓愈','唐','御定全唐诗','yuding','','[]','聞說遊湖棹，尋常到此回。應留醒心處，准擬醉時來。',24,'御定全唐詩/json/343.json','["聞說遊湖棹，尋常到此回。應留醒心處，准擬醉時來。"]'),
('yuding-48','奉和虢州劉給事使君三堂新題二十一詠：花島','韓愈','唐','御定全唐诗','yuding','','[]','蜂蝶去紛紛，香風隔岸聞。欲知花島處，水上覓紅雲。',24,'御定全唐詩/json/343.json','["蜂蝶去紛紛，香風隔岸聞。欲知花島處，水上覓紅雲。"]'),
('yuding-49','奉和虢州劉給事使君三堂新題二十一詠：柳溪','韓愈','唐','御定全唐诗','yuding','','[]','柳樹誰人種，行行夾岸高。莫將條系纜，著處有蟬號。',24,'御定全唐詩/json/343.json','["柳樹誰人種，行行夾岸高。莫將條系纜，著處有蟬號。"]'),
('yuding-50','奉和虢州劉給事使君三堂新題二十一詠：西山','韓愈','唐','御定全唐诗','yuding','','[]','新月迎宵掛，晴雲到晚留。為遮西望眼，終是懶回頭。',24,'御定全唐詩/json/343.json','["新月迎宵掛，晴雲到晚留。為遮西望眼，終是懶回頭。"]'),
('yuding-51','奉和虢州劉給事使君三堂新題二十一詠：竹徑','韓愈','唐','御定全唐诗','yuding','','[]','無塵從不掃，有鳥莫令彈。若要添風月，應除數百竿。',24,'御定全唐詩/json/343.json','["無塵從不掃，有鳥莫令彈。若要添風月，應除數百竿。"]'),
('yuding-52','奉和虢州劉給事使君三堂新題二十一詠：荷池','韓愈','唐','御定全唐诗','yuding','','[]','風雨秋池上，高荷蓋水繁。未諳鳴摵摵，那似卷翻翻。',24,'御定全唐詩/json/343.json','["風雨秋池上，高荷蓋水繁。未諳鳴摵摵，那似卷翻翻。"]'),
('yuding-53','奉和虢州劉給事使君三堂新題二十一詠：稻畦','韓愈','唐','御定全唐诗','yuding','','[]','罫布畦堪數，枝分水莫尋。魚肥知已秀，鶴沒覺初深。',24,'御定全唐詩/json/343.json','["罫布畦堪數，枝分水莫尋。魚肥知已秀，鶴沒覺初深。"]'),
('yuding-54','奉和虢州劉給事使君三堂新題二十一詠：柳巷','韓愈','唐','御定全唐诗','yuding','','[]','柳巷還飛絮，春餘幾許時。吏人休報事，公作送春詩。',24,'御定全唐詩/json/343.json','["柳巷還飛絮，春餘幾許時。吏人休報事，公作送春詩。"]'),
('yuding-55','奉和虢州劉給事使君三堂新題二十一詠：花源','韓愈','唐','御定全唐诗','yuding','','[]','源上花初發，公應日日來。丁寧紅與紫，慎莫一時開。',24,'御定全唐詩/json/343.json','["源上花初發，公應日日來。丁寧紅與紫，慎莫一時開。"]'),
('yuding-56','奉和虢州劉給事使君三堂新題二十一詠：北樓','韓愈','唐','御定全唐诗','yuding','','[]','郡樓乘曉上，盡日不能回。晚色將秋至，長風送月來。',24,'御定全唐詩/json/343.json','["郡樓乘曉上，盡日不能回。晚色將秋至，長風送月來。"]'),
('yuding-57','奉和虢州劉給事使君三堂新題二十一詠：鏡潭','韓愈','唐','御定全唐诗','yuding','','[]','非鑄複非熔，泓澄忽此逢。魚蝦不用避，只是照蛟龍。',24,'御定全唐詩/json/343.json','["非鑄複非熔，泓澄忽此逢。魚蝦不用避，只是照蛟龍。"]'),
('yuding-58','奉和虢州劉給事使君三堂新題二十一詠：孤嶼','韓愈','唐','御定全唐诗','yuding','','[]','朝游孤嶼南，暮戲孤嶼北。所以孤嶼鳥，與公盡相識。',24,'御定全唐詩/json/343.json','["朝游孤嶼南，暮戲孤嶼北。所以孤嶼鳥，與公盡相識。"]'),
('yuding-59','奉和虢州劉給事使君三堂新題二十一詠：方橋','韓愈','唐','御定全唐诗','yuding','','[]','非閣複非船，可居兼可過。君欲問方橋，方橋如此作。',24,'御定全唐詩/json/343.json','["非閣複非船，可居兼可過。君欲問方橋，方橋如此作。"]'),
('yuding-60','奉和虢州劉給事使君三堂新題二十一詠：梯橋','韓愈','唐','御定全唐诗','yuding','','[]','乍似上青冥，初疑躡菡萏。自無飛仙骨，欲度何由敢。',24,'御定全唐詩/json/343.json','["乍似上青冥，初疑躡菡萏。自無飛仙骨，欲度何由敢。"]'),
('yuding-61','奉和虢州劉給事使君三堂新題二十一詠：月池','韓愈','唐','御定全唐诗','yuding','','[]','寒池月下明，新月池邊曲。若不妒清妍，卻成相映燭。',24,'御定全唐詩/json/343.json','["寒池月下明，新月池邊曲。若不妒清妍，卻成相映燭。"]'),
('yuding-62','游城南十六首：賽神','韓愈','唐','御定全唐诗','yuding','','[]','白布長衫紫領巾，差科未動是閒人。',32,'御定全唐詩/json/343.json','["白布長衫紫領巾，差科未動是閒人。", "麥苗含穟桑生葚，共向田頭樂社神。"]'),
('yuding-63','游城南十六首：題于賓客莊','韓愈','唐','御定全唐诗','yuding','','[]','榆莢車前蓋地皮，薔薇蘸水筍穿籬。',32,'御定全唐詩/json/343.json','["榆莢車前蓋地皮，薔薇蘸水筍穿籬。", "馬蹄無入朱門跡，縱使春歸可得知。"]'),
('yuding-64','游城南十六首：晚春','韓愈','唐','御定全唐诗','yuding','','[]','草樹知春不久歸，百般紅紫鬥芳菲。',32,'御定全唐詩/json/343.json','["草樹知春不久歸，百般紅紫鬥芳菲。", "楊花榆莢無才思，惟解漫天作雪飛。"]'),
('yuding-65','游城南十六首：落花','韓愈','唐','御定全唐诗','yuding','','[]','已分將身著地飛，那羞踐踏損光暉。',32,'御定全唐詩/json/343.json','["已分將身著地飛，那羞踐踏損光暉。", "無端又被春風誤，吹落西家不得歸。"]'),
('yuding-66','游城南十六首：楸樹二首','韓愈','唐','御定全唐诗','yuding','','[]','幾歲生成為大樹，一朝纏繞困長藤。',64,'御定全唐詩/json/343.json','["幾歲生成為大樹，一朝纏繞困長藤。", "誰人與脫青羅帔，看吐高花萬萬層。", "幸自枝條能樹立，可煩蘿蔓作交加。", "傍人不解尋根本，卻道新花勝舊花。"]'),
('yuding-67','游城南十六首：風折花枝','韓愈','唐','御定全唐诗','yuding','','[]','浮豔侵天難就看，清香撲地只遙聞。',32,'御定全唐詩/json/343.json','["浮豔侵天難就看，清香撲地只遙聞。", "春風也是多情思，故揀繁枝折贈君。"]'),
('yuding-68','游城南十六首：贈同遊','韓愈','唐','御定全唐诗','yuding','','[]','喚起窗全曙，催歸日未西。無心花裏鳥，更與盡情啼。',24,'御定全唐詩/json/343.json','["喚起窗全曙，催歸日未西。無心花裏鳥，更與盡情啼。"]'),
('yuding-69','游城南十六首：贈張十八助教','韓愈','唐','御定全唐诗','yuding','','[]','喜君眸子重清朗，攜手城南曆舊遊。',32,'御定全唐詩/json/343.json','["喜君眸子重清朗，攜手城南曆舊遊。", "忽見孟生題竹處，相看淚落不能收。"]'),
('yuding-70','游城南十六首：題韋氏莊','韓愈','唐','御定全唐诗','yuding','','[]','昔者誰能比，今來事不同。寂寥青草曲，散漫白榆風。',48,'御定全唐詩/json/343.json','["昔者誰能比，今來事不同。寂寥青草曲，散漫白榆風。", "架倒藤全落，籬崩竹半空。寧須惆悵立，翻覆本無窮。"]'),
('yuding-71','游城南十六首：晚雨','韓愈','唐','御定全唐诗','yuding','','[]','廉纖晚雨不能晴，池岸草間蚯蚓鳴。',32,'御定全唐詩/json/343.json','["廉纖晚雨不能晴，池岸草間蚯蚓鳴。", "投竿跨馬蹋歸路，才到城門打鼓聲。"]'),
('yuding-72','游城南十六首：出城','韓愈','唐','御定全唐诗','yuding','','[]','暫出城門蹋青草，遠于林下見春山。',32,'御定全唐詩/json/343.json','["暫出城門蹋青草，遠于林下見春山。", "應須韋杜家家到，只有今朝一日閑。"]'),
('yuding-73','游城南十六首：把酒','韓愈','唐','御定全唐诗','yuding','','[]','擾擾馳名者，誰能一日閑。我來無伴侶，把酒對南山。',24,'御定全唐詩/json/343.json','["擾擾馳名者，誰能一日閑。我來無伴侶，把酒對南山。"]'),
('yuding-74','游城南十六首：嘲少年','韓愈','唐','御定全唐诗','yuding','','[]','直把春償酒，都將命乞花。只知閑信馬，不覺誤隨車。',24,'御定全唐詩/json/343.json','["直把春償酒，都將命乞花。只知閑信馬，不覺誤隨車。"]'),
('yuding-75','游城南十六首：楸樹','韓愈','唐','御定全唐诗','yuding','','[]','青幢紫蓋立童童，細雨浮煙作彩籠。',32,'御定全唐詩/json/343.json','["青幢紫蓋立童童，細雨浮煙作彩籠。", "不得畫師來貌取，定知難見一生中。"]'),
('yuding-76','游城南十六首：遣興','韓愈','唐','御定全唐诗','yuding','','[]','斷送一生惟有酒，尋思百計不如閑。',32,'御定全唐詩/json/343.json','["斷送一生惟有酒，尋思百計不如閑。", "莫憂世事兼身事，須著人間比夢間。"]'),
('yuding-0','送李尚書赴襄陽八韻得長字','韓愈','唐','御定全唐诗','yuding','','[]','帝憂南國切，改命付忠良。壤畫星搖動，旗分獸簸揚。',96,'御定全唐詩/json/344.json','["帝憂南國切，改命付忠良。壤畫星搖動，旗分獸簸揚。", "五營兵轉肅，千里地還方。控帶荊門遠，飄浮漢水長。", "賜書寬屬郡，戰馬隔鄰疆。縱獵雷霆迅，觀棋玉石忙。", "風流峴首客，花豔大堤倡。富貴由身致，誰教不自強。"]'),
('yuding-1','和席八十二韻','韓愈','唐','御定全唐诗','yuding','','[]','絳闕銀河曙，東風右掖春。官隨名共美，花與思俱新。',144,'御定全唐詩/json/344.json','["絳闕銀河曙，東風右掖春。官隨名共美，花與思俱新。", "綺陌朝遊間，綾衾夜直頻。橫門開日月，高閣切星辰。", "庭變寒前草，天銷霽後塵。溝聲通苑急，柳色壓城勻。", "綸綍謀猷盛，丹青步武親。芳菲含斧藻，光景暢形神。", "傍砌看紅藥，巡池詠白蘋。多情懷酒伴，餘事作詩人。", "倚玉難藏拙，吹竽久混真。坐慚空自老，江海未還身。"]'),
('yuding-2','和武相公早春聞鶯','韓愈','唐','御定全唐诗','yuding','','[]','早晚飛來入錦城，誰人教解百般鳴。',32,'御定全唐詩/json/344.json','["早晚飛來入錦城，誰人教解百般鳴。", "春風紅樹驚眠處，似妒歌童作豔聲。"]'),
('yuding-3','游太平公主山莊','韓愈','唐','御定全唐诗','yuding','','[]','公主當年欲占春，故將台榭押城闉。',32,'御定全唐詩/json/344.json','["公主當年欲占春，故將台榭押城闉。", "欲知前面花多少，直到南山不屬人。"]'),
('yuding-4','晚春','韓愈','唐','御定全唐诗','yuding','','[]','誰收春色將歸去，慢綠妖紅半不存。',32,'御定全唐詩/json/344.json','["誰收春色將歸去，慢綠妖紅半不存。", "榆莢只能隨柳絮，等閒撩亂走空園。"]'),
('yuding-5','大行皇太后挽歌詞三首','韓愈','唐','御定全唐诗','yuding','','[]','一紀尊名正，三時孝養榮。高居朝聖主，厚德載群生。',144,'御定全唐詩/json/344.json','["一紀尊名正，三時孝養榮。高居朝聖主，厚德載群生。", "武帳虛中禁，玄堂掩太平。秋天笳鼓歇，松柏遍山鳴。", "威儀備吉凶，文物雜軍容。配地行新祭，因山托故封。", "鳳飛終不返，劍化會相從。無複臨長樂，空聞報曉鐘。", "追攀萬國來，警衛百神陪。畫翣登秋殿，容衣入夜台。", "雲隨仙馭遠，風助聖情哀。只有朝陵日，妝奩一暫開。"]'),
('yuding-6','廣宣上人頻見過','韓愈','唐','御定全唐诗','yuding','','[]','三百六旬長擾擾，不沖風雨即塵埃。久慚朝士無裨補，',40,'御定全唐詩/json/344.json','["三百六旬長擾擾，不沖風雨即塵埃。久慚朝士無裨補，", "天寒古寺遊人少，紅葉窗前有幾堆。"]'),
('yuding-7','閒遊二首','韓愈','唐','御定全唐诗','yuding','','[]','雨後來更好，繞池遍青青。柳花閑度竹，菱葉故穿萍。',96,'御定全唐詩/json/344.json','["雨後來更好，繞池遍青青。柳花閑度竹，菱葉故穿萍。", "獨坐殊未厭，孤斟詎能醒。持竿至日暮，幽詠欲誰聽。", "茲遊苦不數，再到遂經旬。萍蓋汙池淨，藤籠老樹新。", "林烏鳴訝客，岸竹長遮鄰。子雲只自守，奚事九衢塵。"]'),
('yuding-8','酬馬侍郎寄酒','韓愈','唐','御定全唐诗','yuding','','[]','一壺情所寄，四句意能多。秋到無詩酒，其如月色何。',24,'御定全唐詩/json/344.json','["一壺情所寄，四句意能多。秋到無詩酒，其如月色何。"]'),
('yuding-9','和侯協律詠筍','韓愈','唐','御定全唐诗','yuding','','[]','竹亭人不到，新筍滿前軒。乍出真堪賞，初多未覺煩。',312,'御定全唐詩/json/344.json','["竹亭人不到，新筍滿前軒。乍出真堪賞，初多未覺煩。", "成行齊婢僕，環立比兒孫。驗長常攜尺，愁幹屢側盆。", "對吟忘膳飲，偶坐變朝昏。滯雨膏腴濕，驕陽氣候溫。", "得時方張王，挾勢欲騰騫。見角牛羊沒，看皮虎豹存。", "攢生猶有隙，散佈忽無垠。詎可持籌算，誰能以理言。", "縱橫公占地，羅列暗連根。狂劇時穿壁，橫強幾觸藩。", "深潛如避逐，遠去若追奔。始訝妨人路，還驚入藥園。", "萌芽防浸大，覆載莫偏恩。已複侵危砌，非徒出短垣。", "身甯虞瓦礫，計擬掩蘭蓀。且歎高無數，庸知上幾番。", "短長終不校，先後竟誰論。外恨苞藏密，中仍節目繁。", "暫須回步履，要取助盤飧。穰穰疑翻地，森森競塞門。", "戈矛頭戢戢，蛇虺首掀掀。婦懦咨料揀，兒癡謁盡髡。", "侯生來慰我，詩句讀驚魂。屬和才將竭，呻吟至日暾。"]'),
('yuding-10','過鴻溝','韓愈','唐','御定全唐诗','yuding','','[]','龍疲虎困割川原，億萬蒼生性命存。',32,'御定全唐詩/json/344.json','["龍疲虎困割川原，億萬蒼生性命存。", "誰勸君王回馬首，真成一擲賭乾坤。"]'),
('yuding-11','送張侍郎','韓愈','唐','御定全唐诗','yuding','','[]','司徒東鎮馳書謁，丞相西來走馬迎。',32,'御定全唐詩/json/344.json','["司徒東鎮馳書謁，丞相西來走馬迎。", "兩府元臣今轉密，一方逋寇不難平。"]'),
('yuding-12','贈刑部馬侍郎','韓愈','唐','御定全唐诗','yuding','','[]','紅旗照海壓南荒，征入中台作侍郎。',32,'御定全唐詩/json/344.json','["紅旗照海壓南荒，征入中台作侍郎。", "暫從相公平小寇，便歸天闕致時康。"]'),
('yuding-13','奉和裴相公東征途經女幾山下作','韓愈','唐','御定全唐诗','yuding','','[]','旗穿曉日雲霞雜，山倚秋空劍戟明。',32,'御定全唐詩/json/344.json','["旗穿曉日雲霞雜，山倚秋空劍戟明。", "敢請相公平賊後，暫攜諸吏上崢嶸。"]'),
('yuding-14','郾城晚飲奉贈副使馬侍郎及馮、李二員外','韓愈','唐','御定全唐诗','yuding','','[]','城上赤雲呈勝氣，眉間黃色見歸期。',32,'御定全唐詩/json/344.json','["城上赤雲呈勝氣，眉間黃色見歸期。", "幕中無事惟須飲，即是連鑣向闕時。"]'),
('yuding-15','酬別留後侍郎','韓愈','唐','御定全唐诗','yuding','','[]','為文無出相如右，謀帥難居郤縠先。',32,'御定全唐詩/json/344.json','["為文無出相如右，謀帥難居郤縠先。", "歸去雪銷溱洧動，西來旌旆拂晴天。"]'),
('yuding-16','同李二十八夜次襄城','韓愈','唐','御定全唐诗','yuding','','[]','周楚仍連接，川原乍屈盤。雲垂天不暖，塵漲雪猶幹。',48,'御定全唐詩/json/344.json','["周楚仍連接，川原乍屈盤。雲垂天不暖，塵漲雪猶幹。", "印綬歸台室，旌旗別將壇。欲知迎候盛，騎火萬星攢。"]'),
('yuding-17','同李二十八員外從裴相公野宿西界','韓愈','唐','御定全唐诗','yuding','','[]','四面星辰著地明，散燒煙火宿天兵。',32,'御定全唐詩/json/344.json','["四面星辰著地明，散燒煙火宿天兵。", "不關破賊須歸奏，自趁新年賀太平。"]'),
('yuding-18','過襄城','韓愈','唐','御定全唐诗','yuding','','[]','郾城辭罷過襄城，潁水嵩山刮眼明。',32,'御定全唐詩/json/344.json','["郾城辭罷過襄城，潁水嵩山刮眼明。", "已去蔡州三百里，家人不用遠來迎。"]'),
('yuding-19','宿神龜招李二十八馮十七','韓愈','唐','御定全唐诗','yuding','','[]','荒山野水照斜暉，啄雪寒鴉趁始飛。',32,'御定全唐詩/json/344.json','["荒山野水照斜暉，啄雪寒鴉趁始飛。", "夜宿驛亭愁不睡，幸來相就蓋征衣。"]'),
('yuding-20','次硤石','韓愈','唐','御定全唐诗','yuding','','[]','數日方離雪，今朝又出山。試憑高處望，隱約見潼關。',24,'御定全唐詩/json/344.json','["數日方離雪，今朝又出山。試憑高處望，隱約見潼關。"]'),
('yuding-21','和李司勳過連昌宮','韓愈','唐','御定全唐诗','yuding','','[]','夾道疏槐出老根，高甍巨桷壓山原。',32,'御定全唐詩/json/344.json','["夾道疏槐出老根，高甍巨桷壓山原。", "宮前遺老來相問，今是開元幾葉孫。"]'),
('yuding-22','次潼關先寄張十二閣老使君','韓愈','唐','御定全唐诗','yuding','','[]','荊山已去華山來，日出潼關四扇開。',32,'御定全唐詩/json/344.json','["荊山已去華山來，日出潼關四扇開。", "刺史莫辭迎候遠，相公親破蔡州回。"]'),
('yuding-23','次潼關上都統相公','韓愈','唐','御定全唐诗','yuding','','[]','暫辭堂印執兵權，儘管諸軍破賊年。',32,'御定全唐詩/json/344.json','["暫辭堂印執兵權，儘管諸軍破賊年。", "冠蓋相望催入相，待將功德格皇天。"]'),
('yuding-24','桃林夜賀晉公','韓愈','唐','御定全唐诗','yuding','','[]','西來騎火照山紅，夜宿桃林臘月中。',32,'御定全唐詩/json/344.json','["西來騎火照山紅，夜宿桃林臘月中。", "手把命珪兼相印，一時重疊賞元功。"]'),
('yuding-25','送李員外院長分司東都','韓愈','唐','御定全唐诗','yuding','','[]','去年秋露下，羈旅逐東征。今歲春光動，驅馳別上京。',48,'御定全唐詩/json/344.json','["去年秋露下，羈旅逐東征。今歲春光動，驅馳別上京。", "飲中相顧色，送後獨歸情。兩地無千里，因風數寄聲。"]'),
('yuding-26','晉公破賊回重拜台司，以詩示幕中賓客，愈奉和','韓愈','唐','御定全唐诗','yuding','','[]','南伐旋師太華東，天書夜到冊元功。將軍舊壓三司貴，',40,'御定全唐詩/json/344.json','["南伐旋師太華東，天書夜到冊元功。將軍舊壓三司貴，", "長慚典午非材職，得就閑官即至公。"]'),
('yuding-27','獨釣四首','韓愈','唐','御定全唐诗','yuding','','[]','侯家林館勝，偶入得垂竿。曲樹行藤角，平池散芡盤。',192,'御定全唐詩/json/344.json','["侯家林館勝，偶入得垂竿。曲樹行藤角，平池散芡盤。", "羽沈知食駛，緡細覺牽難。聊取誇兒女，榆條系從鞍。", "一徑向池斜，池塘野草花。雨多添柳耳，水長減蒲芽。", "坐厭親刑柄，偷來傍釣車。太平公事少，吏隱詎相賒。", "獨往南塘上，秋晨景氣醒。露排四岸草，風約半池萍。", "鳥下見人寂，魚來聞餌馨。所嗟無可召，不得倒吾瓶。", "秋半百物變，溪魚去不來。風能坼芡觜，露亦染梨腮。", "遠岫重疊出，寒花散亂開。所期終莫至，日暮與誰回。"]'),
('yuding-28','枯樹','韓愈','唐','御定全唐诗','yuding','','[]','老樹無枝葉，風霜不復侵。腹穿人可過，皮剝蟻還尋。',48,'御定全唐詩/json/344.json','["老樹無枝葉，風霜不復侵。腹穿人可過，皮剝蟻還尋。", "寄託惟朝菌，依投絕暮禽。猶堪持改火，未肯但空心。"]'),
('yuding-29','元日酬蔡州馬十二尚書去年蔡州元日見寄之什','韓愈','唐','御定全唐诗','yuding','','[]','元日新詩已去年，蔡州遙寄荷相憐。',32,'御定全唐詩/json/344.json','["元日新詩已去年，蔡州遙寄荷相憐。", "今朝縱有誰人領，自是三峰不敢眠。"]'),
('yuding-30','詠燈花同侯十一','韓愈','唐','御定全唐诗','yuding','','[]','今夕知何夕，花然錦帳中。自能當雪暖，那肯待春紅。',48,'御定全唐詩/json/344.json','["今夕知何夕，花然錦帳中。自能當雪暖，那肯待春紅。", "黃裏排金粟，釵頭綴玉蟲。更煩將喜事，來報主人公。"]'),
('yuding-31','祖席前字','韓愈','唐','御定全唐诗','yuding','','[]','祖席洛橋邊，親交共黯然。野晴山簇簇，霜曉菊鮮鮮。',48,'御定全唐詩/json/344.json','["祖席洛橋邊，親交共黯然。野晴山簇簇，霜曉菊鮮鮮。", "書寄相思處，杯銜欲別前。淮陽知不薄，終願早回船。"]'),
('yuding-32','秋字','韓愈','唐','御定全唐诗','yuding','','[]','淮南悲木落，而我亦傷秋。況與故人別，那堪羈宦愁。',48,'御定全唐詩/json/344.json','["淮南悲木落，而我亦傷秋。況與故人別，那堪羈宦愁。", "榮華今異路，風雨昔同憂。莫以宜春遠，江山多勝遊。"]'),
('yuding-33','送鄭尚書赴南海','韓愈','唐','御定全唐诗','yuding','','[]','番禺軍府盛，欲說暫停杯。蓋海旗幢出，連天觀閣開。',72,'御定全唐詩/json/344.json','["番禺軍府盛，欲說暫停杯。蓋海旗幢出，連天觀閣開。", "衙時龍戶集，上日馬人來。風靜鶢鶋去，官廉蚌蛤回。", "貨通師子國，樂奏武王台。事事皆殊異，無嫌屈大才。"]'),
('yuding-34','答道士寄樹雞','韓愈','唐','御定全唐诗','yuding','','[]','軟濕青黃狀可猜，欲烹還喚木盤回。',32,'御定全唐詩/json/344.json','["軟濕青黃狀可猜，欲烹還喚木盤回。", "煩君自入華陽洞，直割乖龍左耳來。"]'),
('yuding-35','左遷至藍關示侄孫湘','韓愈','唐','御定全唐诗','yuding','','[]','一封朝奏九重天，夕貶潮州路八千。欲為聖朝除弊事，',40,'御定全唐詩/json/344.json','["一封朝奏九重天，夕貶潮州路八千。欲為聖朝除弊事，", "知汝遠來應有意，好收吾骨瘴江邊。"]'),
('yuding-36','武關西逢配流吐番','韓愈','唐','御定全唐诗','yuding','','[]','嗟爾戎人莫慘然，湖南地近保生全。',32,'御定全唐詩/json/344.json','["嗟爾戎人莫慘然，湖南地近保生全。", "我今罪重無歸望，直去長安路八千。"]'),
('yuding-37','次鄧州界','韓愈','唐','御定全唐诗','yuding','','[]','潮陽南去倍長沙，戀闕那堪又憶家。心訝愁來惟貯火，',40,'御定全唐詩/json/344.json','["潮陽南去倍長沙，戀闕那堪又憶家。心訝愁來惟貯火，", "早晚王師收海嶽，普將雷雨發萌芽。"]'),
('yuding-38','題臨瀧寺','韓愈','唐','御定全唐诗','yuding','','[]','不覺離家已五千，仍將衰病入瀧船。',32,'御定全唐詩/json/344.json','["不覺離家已五千，仍將衰病入瀧船。", "潮陽未到吾能說，海氣昏昏水拍天。"]'),
('yuding-39','晚次宣溪，辱韶州張端公使君惠書敘別酬以絕句二章','韓愈','唐','御定全唐诗','yuding','','[]','韶州南去接宣溪，雲水蒼茫日向西。',64,'御定全唐詩/json/344.json','["韶州南去接宣溪，雲水蒼茫日向西。", "客淚數行先自落，鷓鴣休傍耳邊啼。", "兼金那足比清文，百首相隨愧使君。", "俱是嶺南巡管內，莫欺荒僻斷知聞。"]'),
('yuding-40','題秀禪師房','韓愈','唐','御定全唐诗','yuding','','[]','橋夾水松行百步，竹床莞席到僧家。',32,'御定全唐詩/json/344.json','["橋夾水松行百步，竹床莞席到僧家。", "暫拳一手支頭臥，還把魚竿下釣沙。"]'),
('yuding-41','將至韶州先寄張端公使君借圖經','韓愈','唐','御定全唐诗','yuding','','[]','曲江山水聞來久，恐不知名訪倍難。',32,'御定全唐詩/json/344.json','["曲江山水聞來久，恐不知名訪倍難。", "願借圖經將入界，每逢佳處便開看。"]'),
('yuding-42','過始興江口感懷','韓愈','唐','御定全唐诗','yuding','','[]','憶作兒童隨伯氏，南來今只一身存。',32,'御定全唐詩/json/344.json','["憶作兒童隨伯氏，南來今只一身存。", "目前百口還相逐，舊事無人可共論。"]'),
('yuding-43','韶州留別張端公使君','韓愈','唐','御定全唐诗','yuding','','[]','來往再逢梅柳新，別離一醉綺羅春。久欽江總文才妙，',40,'御定全唐詩/json/344.json','["來往再逢梅柳新，別離一醉綺羅春。久欽江總文才妙，", "已知奏課當征拜，那複淹留詠白蘋。"]'),
('yuding-44','從潮州量移袁州，張韶州端公以詩相賀，因酬之','韓愈','唐','御定全唐诗','yuding','','[]','明時遠逐事何如，遇赦移官罪未除。北望詎令隨塞雁，',40,'御定全唐詩/json/344.json','["明時遠逐事何如，遇赦移官罪未除。北望詎令隨塞雁，", "暫欲系船韶石下，上賓虞舜整冠裾。"]'),
('yuding-45','次石頭驛寄江西王十中丞閣老','韓愈','唐','御定全唐诗','yuding','','[]','憑高試回首，一望豫章城。人由戀德泣，馬亦別群鳴。',48,'御定全唐詩/json/344.json','["憑高試回首，一望豫章城。人由戀德泣，馬亦別群鳴。", "寒日夕始照，風江遠漸平。默然都不語，應識此時情。"]'),
('yuding-46','游西林寺題蕭二兄郎中舊堂','韓愈','唐','御定全唐诗','yuding','','[]','中郎有女能傳業，伯道無兒可保家。',32,'御定全唐詩/json/344.json','["中郎有女能傳業，伯道無兒可保家。", "偶到匡山曾住處，幾行衰淚落煙霞。"]'),
('yuding-47','自袁州還京行次安陸，先寄隨州周員外','韓愈','唐','御定全唐诗','yuding','','[]','行行指漢東，暫喜笑言同。雨雪離江上，蒹葭出夢中。',48,'御定全唐詩/json/344.json','["行行指漢東，暫喜笑言同。雨雪離江上，蒹葭出夢中。", "面猶含瘴色，眼已見華風。歲暮難相值，酣歌未可終。"]'),
('yuding-48','題廣昌館','韓愈','唐','御定全唐诗','yuding','','[]','白水龍飛已幾春，偶逢遺跡問耕人。',32,'御定全唐詩/json/344.json','["白水龍飛已幾春，偶逢遺跡問耕人。", "丘墳發掘當官路，何處南陽有近親。"]'),
('yuding-49','寄隨州周員外','韓愈','唐','御定全唐诗','yuding','','[]','陸孟丘楊久作塵，同時存者更誰人。',32,'御定全唐詩/json/344.json','["陸孟丘楊久作塵，同時存者更誰人。", "金丹別後知傳得，乞取刀圭救病身。"]'),
('yuding-50','酒中留上襄陽李相公','韓愈','唐','御定全唐诗','yuding','','[]','濁水污泥清路塵，還曾同制掌絲綸。眼穿長訝雙魚斷，',40,'御定全唐詩/json/344.json','["濁水污泥清路塵，還曾同制掌絲綸。眼穿長訝雙魚斷，", "知公不久歸鈞軸，應許閑官寄病身。"]'),
('yuding-51','去歲自刑部侍郎以罪貶潮州刺史乘驛赴任其後家亦譴逐小女道死殯之層峰驛旁山下蒙恩還朝過其墓留題驛梁','韓愈','唐','御定全唐诗','yuding','','[]','數條藤束木皮棺，草殯荒山白骨寒。驚恐入心身已病，',40,'御定全唐詩/json/344.json','["數條藤束木皮棺，草殯荒山白骨寒。驚恐入心身已病，", "致汝無辜由我罪，百年慚痛淚闌幹。"]'),
('yuding-52','賀張十八秘書得裴司空馬','韓愈','唐','御定全唐诗','yuding','','[]','司空遠寄養初成，毛色桃花眼鏡明。落日已曾交轡語，',40,'御定全唐詩/json/344.json','["司空遠寄養初成，毛色桃花眼鏡明。落日已曾交轡語，", "旦夕公歸伸拜謝，免勞騎去逐雙旌。"]'),
('yuding-53','杏園送張徹侍禦歸使','韓愈','唐','御定全唐诗','yuding','','[]','東風花樹下，送爾出京城。久抱傷春意，新添惜別情。',48,'御定全唐詩/json/344.json','["東風花樹下，送爾出京城。久抱傷春意，新添惜別情。", "歸來身已病，相見眼還明。更遣將詩酒，誰家逐後生。"]'),
('yuding-54','雨中寄張博士籍、侯主簿喜','韓愈','唐','御定全唐诗','yuding','','[]','放朝還不報，半路蹋泥歸。雨慣曾無節，雷頻自失威。',48,'御定全唐詩/json/344.json','["放朝還不報，半路蹋泥歸。雨慣曾無節，雷頻自失威。", "見牆生菌遍，憂麥作蛾飛。歲晚偏蕭索，誰當救晉饑。"]'),
('yuding-55','奉和兵部張侍郎酬，鄆州馬尚書祗召途中見寄開緘之日馬帥已再領鄆州之作','韓愈','唐','御定全唐诗','yuding','','[]','來朝當路日，承詔改轅時。再領須句國，仍遷少昊司。',48,'御定全唐詩/json/344.json','["來朝當路日，承詔改轅時。再領須句國，仍遷少昊司。", "暖風抽宿麥，清雨卷歸旗。賴寄新珠玉，長吟慰我思。"]'),
('yuding-56','早春與張十八博士籍遊楊尚書林亭寄第三閣老兼呈白馮二閣老','韓愈','唐','御定全唐诗','yuding','','[]','牆下春渠入禁溝，渠冰初破滿渠浮。',32,'御定全唐詩/json/344.json','["牆下春渠入禁溝，渠冰初破滿渠浮。", "鳳池近日長先暖，流到池時更不流。"]'),
('yuding-57','奉使常山，早次太原，呈副使吳郎中','韓愈','唐','御定全唐诗','yuding','','[]','朗朗聞街鼓，晨起似朝時。翻翻走驛馬，春儘是歸期。',48,'御定全唐詩/json/344.json','["朗朗聞街鼓，晨起似朝時。翻翻走驛馬，春儘是歸期。", "地失嘉禾處，風存蟋蟀辭。暮齒良多感，無事涕垂頤。"]'),
('yuding-58','夕次壽陽驛題吳郎中詩後','韓愈','唐','御定全唐诗','yuding','','[]','風光欲動別長安，春半城邊特地寒。',32,'御定全唐詩/json/344.json','["風光欲動別長安，春半城邊特地寒。", "不見園花兼巷柳，馬頭惟有月團團。"]'),
('yuding-59','鎮州初歸','韓愈','唐','御定全唐诗','yuding','','[]','別來楊柳街頭樹，擺弄春風只欲飛。',32,'御定全唐詩/json/344.json','["別來楊柳街頭樹，擺弄春風只欲飛。", "還有小園桃李在，留花不發待郎歸。"]'),
('yuding-60','同水部張員外籍曲江春遊，寄白二十二舍人','韓愈','唐','御定全唐诗','yuding','','[]','漠漠輕陰晚自開，青天白日映樓臺。',32,'御定全唐詩/json/344.json','["漠漠輕陰晚自開，青天白日映樓臺。", "曲江水滿花千樹，有底忙時不肯來。"]'),
('yuding-61','和水部張員外宣政衙賜百官櫻桃詩','韓愈','唐','御定全唐诗','yuding','','[]','漢家舊種明光殿，炎帝還書本草經。豈似滿朝承雨露，',40,'御定全唐詩/json/344.json','["漢家舊種明光殿，炎帝還書本草經。豈似滿朝承雨露，", "食罷自知無所報，空然慚汗仰皇扃。"]'),
('yuding-62','早春呈水部張十八員外二首','韓愈','唐','御定全唐诗','yuding','','[]','天街小雨潤如酥，草色遙看近卻無。',64,'御定全唐詩/json/344.json','["天街小雨潤如酥，草色遙看近卻無。", "最是一年春好處，絕勝煙柳滿皇都。", "莫道官忙身老大，即無年少逐春心。", "憑君先到江頭看，柳色如今深未深。"]'),
('yuding-63','送桂州嚴大夫同用南字','韓愈','唐','御定全唐诗','yuding','','[]','蒼蒼森八桂，茲地在湘南。江作青羅帶，山如碧玉篸。',48,'御定全唐詩/json/344.json','["蒼蒼森八桂，茲地在湘南。江作青羅帶，山如碧玉篸。", "戶多輸翠羽，家自種黃甘。遠勝登仙去，飛鸞不假驂。"]'),
('yuding-64','奉酬天平馬十二僕射暇日言懷見寄之作','韓愈','唐','御定全唐诗','yuding','','[]','天平篇什外，政事亦無雙。威令加徐土，儒風被魯邦。',48,'御定全唐詩/json/344.json','["天平篇什外，政事亦無雙。威令加徐土，儒風被魯邦。", "清為公論重，寬得士心降。歲晏偏相憶，長謠坐北窗。"]'),
('yuding-65','奉使鎮州，行次承天行營，奉酬裴司空','韓愈','唐','御定全唐诗','yuding','','[]','竄逐三年海上歸，逢公複此著征衣。',32,'御定全唐詩/json/344.json','["竄逐三年海上歸，逢公複此著征衣。", "旋吟佳句還鞭馬，恨不身先去鳥飛。"]'),
('yuding-66','鎮州路上謹酬裴司空相公重見寄','韓愈','唐','御定全唐诗','yuding','','[]','銜命山東撫亂師，日馳三百自嫌遲。',32,'御定全唐詩/json/344.json','["銜命山東撫亂師，日馳三百自嫌遲。", "風霜滿面無人識，何處如今更有詩。"]'),
('yuding-67','奉和僕射裴相公感恩言志','韓愈','唐','御定全唐诗','yuding','','[]','文武功成後，居為百辟師。林園窮勝事，鐘鼓樂清時。',48,'御定全唐詩/json/344.json','["文武功成後，居為百辟師。林園窮勝事，鐘鼓樂清時。", "擺落遺高論，雕鐫出小詩。自然無不可，範蠡爾其誰。"]'),
('yuding-68','和僕射相公朝回見寄','韓愈','唐','御定全唐诗','yuding','','[]','盡瘁年將久，公今始暫閑。事隨憂共減，詩與酒俱還。',48,'御定全唐詩/json/344.json','["盡瘁年將久，公今始暫閑。事隨憂共減，詩與酒俱還。", "放意機衡外，收身矢石間。秋颱風日迥，正好看前山。"]'),
('yuding-69','奉和李相公題蕭家林亭','韓愈','唐','御定全唐诗','yuding','','[]','山公自是林園主，嘆惜前賢造作時。',32,'御定全唐詩/json/344.json','["山公自是林園主，嘆惜前賢造作時。", "岩洞幽深門盡鎖，不因丞相幾人知。"]'),
('yuding-70','奉和杜相公太清宮紀事陳誠上李相公十六韻','韓愈','唐','御定全唐诗','yuding','','[]','耒耜興姬國，輴欙建夏家。在功誠可尚，於道詎為華。',192,'御定全唐詩/json/344.json','["耒耜興姬國，輴欙建夏家。在功誠可尚，於道詎為華。", "象帝威容大，仙宗寶曆賒。衛門羅戟槊，圖壁雜龍蛇。", "禮樂追尊盛，乾坤降福遐。四真皆齒列，二聖亦肩差。", "陽月時之首，陰泉氣未牙。殿階鋪水碧，庭炬坼金葩。", "紫極觀忘倦，青詞奏不嘩。噌吰宮夜辟，嘈囐鼓晨撾。", "褻味陳奚取，名香薦孔嘉。垂祥紛可錄，俾壽浩無涯。", "貴相山瞻峻，清文玉絕瑕。代工聲問遠，攝事敬恭加。", "皎潔當天月，葳蕤捧日霞。唱妍酬亦麗，俯仰但稱嗟。"]'),
('yuding-0','鄆州溪堂詩','韓愈','唐','御定全唐诗','yuding','','[]','帝奠九廛，有葉有年。有荒不條，河岱之間。及我憲考，',145,'御定全唐詩/json/345.json','["帝奠九廛，有葉有年。有荒不條，河岱之間。及我憲考，", "公不飲食，以訓以徇。孰饑無食，孰呻孰歎。孰冤不問，", "吹之喣之，摩手拊之。箴之石之，膊而磔之。凡公四封，", "公作溪堂。播播流水。淺有蒲蓮，深有葭葦。公以賓燕，", "既歌以舞，其鼓考考。公在溪堂，公禦琴瑟。公暨賓贊，", "公在中流，右詩左書。無我斁遺，此邦是庥。"]'),
('yuding-1','送張道士','韓愈','唐','御定全唐诗','yuding','','[]','大匠無棄材，尋尺各有施。況當營都邑，杞梓用不疑。',276,'御定全唐詩/json/345.json','["大匠無棄材，尋尺各有施。況當營都邑，杞梓用不疑。", "張侯嵩高來，面有熊豹姿。開口論利害，劍鋒白差差。", "恨無一尺捶，為國苔羌夷。詣闕三上書，臣非黃冠師。", "臣有膽與氣，不忍死茅茨。又不媚笑語，不能伴兒嬉。", "乃著道士服，眾人莫臣知。臣有平賊策，狂童不難治。", "其言簡且要，陛下幸聽之。天空日月高，下照理不遺。", "或是章奏繁，裁擇未及斯。寧當不俟報，歸袖風披披。", "答我事不爾，吾親屬吾思。昨宵夢倚門，手取連環持。", "今日有書至，又言歸何時。霜天熟柿栗，收拾不可遲。", "嶺北梁可構，寒魚下清伊。既非公家用，且複還其私。", "從容進退間，無一不合宜。時有利不利，雖賢欲奚為。", "但當勵前操，富貴非公誰。"]'),
('yuding-2','送鄭十校理得洛字','韓愈','唐','御定全唐诗','yuding','','[]','相公倦台鼎，分正新邑洛。才子富文華，校讎天祿閣。',60,'御定全唐詩/json/345.json','["相公倦台鼎，分正新邑洛。才子富文華，校讎天祿閣。", "壽觴佳節過，歸騎春衫薄。鳥哢正交加，楊花共紛泊。", "親交誰不羨，去去翔寥廓。"]'),
('yuding-3','送陸歙州傪','韓愈','唐','御定全唐诗','yuding','','[]','我衣之華兮，我佩之光。陸君之去兮，誰與翱翔。',63,'御定全唐詩/json/345.json','["我衣之華兮，我佩之光。陸君之去兮，誰與翱翔。", "斂此大惠兮，施於一州。今其去矣，胡不為留。", "我作此詩，歌于遠道。無疾其驅，天子有詔。"]'),
('yuding-4','送汴州監軍俱文珍','韓愈','唐','御定全唐诗','yuding','','[]','奉使羌池靜，臨戎汴水安。沖天鵬翅闊，報國劍鋩寒。',48,'御定全唐詩/json/345.json','["奉使羌池靜，臨戎汴水安。沖天鵬翅闊，報國劍鋩寒。", "曉日驅征騎，春風詠采蘭。誰言臣子道，忠孝兩全難。"]'),
('yuding-5','《贈崔立之','韓愈','唐','御定全唐诗','yuding','','[]','昔年十日雨，子桑苦寒饑。哀歌坐空室，不怨但自悲。',132,'御定全唐詩/json/345.json','["昔年十日雨，子桑苦寒饑。哀歌坐空室，不怨但自悲。", "其友名子輿，忽然憂且思。搴裳觸泥水，裹飯往食之。", "入門相對語，天命良不疑。好事漆園吏，書之存雄詞。", "千年事已遠，二字情可推。我讀此篇日，正當寒雪時。", "吾身固已困，吾友複何為。薄粥不足裹，深泥諒難馳。", "曾無子輿事，空賦子桑詩。"]'),
('yuding-6','海水','韓愈','唐','御定全唐诗','yuding','','[]','海水非不廣，鄧林豈無枝。風波一蕩薄，魚鳥不可依。',168,'御定全唐詩/json/345.json','["海水非不廣，鄧林豈無枝。風波一蕩薄，魚鳥不可依。", "海水饒大波，鄧林多驚風。豈無魚與鳥，巨細各不同。", "海有吞舟鯨，鄧有垂天鵬。苟非鱗羽大，蕩薄不可能。", "我鱗不盈寸，我羽不盈尺。一木有餘陰，一泉有餘澤。", "我將辭海水，濯鱗清冷池。我將辭鄧林，刷羽蒙籠枝。", "海水非愛廣，鄧林非愛枝。風波亦常事，鱗魚自不宜。", "我鱗日已大，我羽日已修。風波無所苦，還作鯨鵬遊。"]'),
('yuding-7','贈河陽李大夫','韓愈','唐','御定全唐诗','yuding','','[]','四海失巢穴，兩都困塵埃。感恩由未報，惆悵空一來。',48,'御定全唐詩/json/345.json','["四海失巢穴，兩都困塵埃。感恩由未報，惆悵空一來。", "裘破氣不暖，馬羸鳴且哀。主人情更重，空使劍鋒摧。"]'),
('yuding-8','苦寒歌','韓愈','唐','御定全唐诗','yuding','','[]','黃昏苦寒歌，夜半不能休。豈不有陽春，節歲聿其周，',40,'御定全唐詩/json/345.json','["黃昏苦寒歌，夜半不能休。豈不有陽春，節歲聿其周，", "填窗塞戶慎勿出，暄風暖景明年日。"]'),
('yuding-9','芍藥歌','韓愈','唐','御定全唐诗','yuding','','[]','丈人庭中開好花，更無凡木爭春華。翠莖紅蕊天力與，',72,'御定全唐詩/json/345.json','["丈人庭中開好花，更無凡木爭春華。翠莖紅蕊天力與，", "霜刀翦汝天女勞，何事低頭學桃李。嬌癡婢子無靈性，", "一尊春酒甘若飴，丈人此樂無人知。花前醉倒歌者誰，"]'),
('yuding-10','《贈徐州族侄','韓愈','唐','御定全唐诗','yuding','','[]','我年十八九，壯氣起胸中。作書獻雲闕，辭家逐秋蓬。',132,'御定全唐詩/json/345.json','["我年十八九，壯氣起胸中。作書獻雲闕，辭家逐秋蓬。", "歲時易遷次，身命多厄窮。一名雖雲就，片祿不足充。", "今者複何事，卑棲寄徐戎。蕭條資用盡，濩落門巷空。", "朝眠未能起，遠懷方鬱悰。擊門者誰子，問言乃吾宗。", "自雲有奇術，探妙知天工。既往悵何及，將來喜還通。", "期我語非佞，當為佐時雍。"]'),
('yuding-11','嘲鼾睡','韓愈','唐','御定全唐诗','yuding','','[]','澹師晝睡時，聲氣一何猥。頑飆吹肥脂，坑穀相嵬磊。',325,'御定全唐詩/json/345.json','["澹師晝睡時，聲氣一何猥。頑飆吹肥脂，坑穀相嵬磊。", "雄哮乍咽絕，每發壯益倍。有如阿鼻屍，長喚忍眾罪。", "馬牛驚不食，百鬼聚相待。木枕十字裂，鏡面生痱癗。", "鐵佛聞皺眉，石人戰搖腿。孰雲天地仁，吾欲責真宰。", "幽尋虱搜耳，猛作濤翻海。太陽不忍明，飛禦皆惰怠。", "乍如彭與黥，呼冤受菹醢。又如圈中虎，號瘡兼吼餒。", "雖令伶倫吹，苦韻難可改。雖令巫咸招，魂爽難複在。", "何山有靈藥，療此願與采。", "澹公坐臥時，長睡無不穩。吾嘗聞其聲，深慮五藏損。", "黃河弄濆薄，梗澀連拙鯀。南帝初奮槌，鑿竅泄混沌。", "迥然忽長引，萬丈不可忖。謂言絕於斯，繼出方袞袞。", "幽幽寸喉中，草木森苯mH。盜賊雖狡獪，亡魂敢窺閫。", "鴻蒙總合雜，詭譎騁戾很。乍如鬥呶呶，忽若怨懇懇。", "賦形苦不同，無路尋根本。何能堙其源，惟有土一畚。"]'),
('yuding-12','晝月','韓愈','唐','御定全唐诗','yuding','','[]','玉碗不磨著泥土，青天孔出白石補。兔入臼藏蛙縮肚，',24,'御定全唐詩/json/345.json','["玉碗不磨著泥土，青天孔出白石補。兔入臼藏蛙縮肚，"]'),
('yuding-13','贈張徐州莫辭酒','韓愈','唐','御定全唐诗','yuding','','[]','莫辭酒，此會固難同。請看女工機上帛，半作軍人旗上紅。',46,'御定全唐詩/json/345.json','["莫辭酒，此會固難同。請看女工機上帛，半作軍人旗上紅。", "莫辭酒，誰為君王之爪牙？春雷三月不作響，"]'),
('yuding-14','辭唱歌','韓愈','唐','御定全唐诗','yuding','','[]','抑逼教唱歌，不解看豔詞。坐中把酒人，豈有歡樂姿。',132,'御定全唐詩/json/345.json','["抑逼教唱歌，不解看豔詞。坐中把酒人，豈有歡樂姿。", "幸有伶者婦，腰身如柳枝。但令送君酒，如醉如憨癡。", "聲自肉中出，使人能逶隨。複遣慳吝者，贈金不皺眉。", "豈有長直夫，喉中聲雌雌。君心豈無恥，君豈是女兒。", "君教發直言，大聲無休時。君教哭古恨，不肯複吞悲。", "乍可阻君意，豔歌難可為。"]'),
('yuding-15','知音者誠希','韓愈','唐','御定全唐诗','yuding','','[]','知音者誠希，念子不能別。行行天未曉，攜酒踏明月。',24,'御定全唐詩/json/345.json','["知音者誠希，念子不能別。行行天未曉，攜酒踏明月。"]'),
('yuding-16','同竇、韋尋劉尊師不遇','韓愈','唐','御定全唐诗','yuding','','[]','秦客何年駐，仙源此地深。還隨躡鳧騎，來訪馭風襟。',48,'御定全唐詩/json/345.json','["秦客何年駐，仙源此地深。還隨躡鳧騎，來訪馭風襟。", "院閉青霞入，松高老鶴尋。猶疑隱形坐，敢起竊桃心。"]'),
('yuding-17','春雪','韓愈','唐','御定全唐诗','yuding','','[]','片片驅鴻急，紛紛逐吹斜。到江還作水，著樹漸成花。',72,'御定全唐詩/json/345.json','["片片驅鴻急，紛紛逐吹斜。到江還作水，著樹漸成花。", "越喜飛排瘴，胡愁厚蓋砂。兼雲封洞口，助月照天涯。", "暝見迷巢鳥，朝逢失轍車。呈豐盡相賀，寧止力耕家。"]'),
('yuding-18','酬藍田崔丞立之詠雪見寄','韓愈','唐','御定全唐诗','yuding','','[]','京城數尺雪，寒氣倍常年。泯泯都無地，茫茫豈是天。',120,'御定全唐詩/json/345.json','["京城數尺雪，寒氣倍常年。泯泯都無地，茫茫豈是天。", "崩奔驚亂射，揮霍訝相纏。不覺侵堂陛，方應折屋椽。", "出門愁落道，上馬恐平韉。朝鼓矜淩起，山齋酩酊眠。", "吾方嗟此役，君乃詠其妍。冰玉清顏隔，波濤盛句傳。", "朝飧思共飯，夜宿憶同氈。舉目無非白，雄文乃獨玄。"]'),
('yuding-19','潭州泊船呈諸公','韓愈','唐','御定全唐诗','yuding','','[]','夜寒眠半覺，鼓笛鬧嘈嘈。暗浪舂樓堞，驚風破竹篙。',48,'御定全唐詩/json/345.json','["夜寒眠半覺，鼓笛鬧嘈嘈。暗浪舂樓堞，驚風破竹篙。", "主人看使范，客子讀離騷。聞道松醪賤，何須吝錯刀。"]'),
('yuding-20','飲城南道邊古墓上逢中丞過贈禮部衛員外少室張道士','韓愈','唐','御定全唐诗','yuding','','[]','偶上城南土骨堆，共傾春酒三五杯。',32,'御定全唐詩/json/345.json','["偶上城南土骨堆，共傾春酒三五杯。", "為逢桃樹相料理，不覺中丞喝道來。"]'),
('yuding-21','池上絮','韓愈','唐','御定全唐诗','yuding','','[]','池上無風有落暉，楊花晴後自飛飛。',32,'御定全唐詩/json/345.json','["池上無風有落暉，楊花晴後自飛飛。", "為將纖質淩清鏡，濕卻無窮不得歸。"]'),
('yuding-22','《贈賈島','韓愈','唐','御定全唐诗','yuding','','[]','孟郊死葬北邙山，從此風雲得暫閑。',32,'御定全唐詩/json/345.json','["孟郊死葬北邙山，從此風雲得暫閑。", "天恐文章渾斷絕，更生賈島著人間。"]'),
('yuding-23','贈譯經僧','韓愈','唐','御定全唐诗','yuding','','[]','萬里休言道路賒，有誰教汝度流沙。',32,'御定全唐詩/json/345.json','["萬里休言道路賒，有誰教汝度流沙。", "只今中國方多事，不用無端更亂華。"]'),
('yuding-0','享惠昭太子廟樂章','王涯','唐','御定全唐诗','yuding','','[]','威儀畢陳，備樂將闋。苞茅酒縮，膋蕭香徹。宮臣展事，',25,'御定全唐詩/json/346.json','["威儀畢陳，備樂將闋。苞茅酒縮，膋蕭香徹。宮臣展事，"]'),
('yuding-1','望禁門松雪','王涯','唐','御定全唐诗','yuding','','[]','宿雲開霽景，佳氣此時濃。瑞雪凝清禁，祥煙冪小松。',72,'御定全唐詩/json/346.json','["宿雲開霽景，佳氣此時濃。瑞雪凝清禁，祥煙冪小松。", "依稀鴛瓦出，隱映鳳樓重。金闕晴光照，瓊枝瑞色封。", "葉鋪全類玉，柯偃乍疑龍。詎比寒山上，風霜老昔容。"]'),
('yuding-2','廣宣上人以詩賀放榜和謝','王涯','唐','御定全唐诗','yuding','','[]','延英面奉入春闈，亦選功夫亦選奇。在冶只求金不耗，',40,'御定全唐詩/json/346.json','["延英面奉入春闈，亦選功夫亦選奇。在冶只求金不耗，", "獨喜至公誰是證，彌天上人與新詩。"]'),
('yuding-3','九月九日勤政樓下觀百僚獻壽','王涯','唐','御定全唐诗','yuding','','[]','禦氣黃花節，臨軒紫陌頭。早陽生彩仗，霽色入仙樓。',72,'御定全唐詩/json/346.json','["禦氣黃花節，臨軒紫陌頭。早陽生彩仗，霽色入仙樓。", "獻壽皆鵷鷺，瞻天盡冕旒。菊樽過九日，鳳曆肇千秋。", "樂奏熏風起，杯酣瑞影收。年年歌舞度，此地慶皇休。"]'),
('yuding-4','春遊曲二首','王涯','唐','御定全唐诗','yuding','','[]','萬樹江邊杏，新開一夜風。滿園深淺色，照在綠波中。',48,'御定全唐詩/json/346.json','["萬樹江邊杏，新開一夜風。滿園深淺色，照在綠波中。", "上苑何窮樹，花間次第新。香車與絲騎，風靜亦生塵。"]'),
('yuding-5','太平詞','王涯','唐','御定全唐诗','yuding','','[]','風俗今和厚，君王在穆清。行看采華曲，儘是泰階平。',24,'御定全唐詩/json/346.json','["風俗今和厚，君王在穆清。行看采華曲，儘是泰階平。"]'),
('yuding-6','送春詞','王涯','唐','御定全唐诗','yuding','','[]','日日人空老，年年春更歸。相歡在尊酒，不用惜花飛。',24,'御定全唐詩/json/346.json','["日日人空老，年年春更歸。相歡在尊酒，不用惜花飛。"]'),
('yuding-7','塞上曲二首','王涯','唐','御定全唐诗','yuding','','[]','天驕遠塞行，出鞘寶刀鳴。定是酬恩日，今朝覺命輕。',48,'御定全唐詩/json/346.json','["天驕遠塞行，出鞘寶刀鳴。定是酬恩日，今朝覺命輕。", "塞虜常為敵，邊風已報秋。平生多志氣，箭底覓封侯。"]'),
('yuding-8','隴上行','王涯','唐','御定全唐诗','yuding','','[]','負羽到邊州，鳴笳度隴頭。雲黃知塞近，草白見邊秋。',24,'御定全唐詩/json/346.json','["負羽到邊州，鳴笳度隴頭。雲黃知塞近，草白見邊秋。"]'),
('yuding-9','思君恩','王涯','唐','御定全唐诗','yuding','','[]','雞鳴天漢曉，鶯語禁林春。誰入巫山夢，唯應洛水神。',24,'御定全唐詩/json/346.json','["雞鳴天漢曉，鶯語禁林春。誰入巫山夢，唯應洛水神。"]'),
('yuding-10','春閨思','王涯','唐','御定全唐诗','yuding','','[]','雪盡萱抽葉，風輕水變苔。玉關音信斷，又見發庭梅。',24,'御定全唐詩/json/346.json','["雪盡萱抽葉，風輕水變苔。玉關音信斷，又見發庭梅。"]'),
('yuding-11','春江曲','王涯','唐','御定全唐诗','yuding','','[]','搖漾越江春，相將采白蘋。歸時不覺夜，出浦月隨人。',24,'御定全唐詩/json/346.json','["搖漾越江春，相將采白蘋。歸時不覺夜，出浦月隨人。"]'),
('yuding-12','閨人贈遠五首','王涯','唐','御定全唐诗','yuding','','[]','花明綺陌春，柳拂禦溝新。為報遼陽客，流芳不待人。',120,'御定全唐詩/json/346.json','["花明綺陌春，柳拂禦溝新。為報遼陽客，流芳不待人。", "遠戍功名薄，幽閨年貌傷。妝成對春樹，不語淚千行。", "形影一朝別，煙波千里分。君看望君處，只是起行雲。", "啼鶯綠樹深，語燕雕梁晚。不省出門行，沙場知近遠。", "洞房今夜月，如練複如霜。為照離人恨，亭亭到曉光。"]'),
('yuding-13','從軍詞三首','王涯','唐','御定全唐诗','yuding','','[]','戈甲從軍久，風雲識陣難。今朝拜韓信，計日斬成安。',80,'御定全唐詩/json/346.json','["戈甲從軍久，風雲識陣難。今朝拜韓信，計日斬成安。", "燕頷多奇相，狼頭敢犯邊。寄言班定遠，正是立功年。", "旄頭夜落捷書飛，來奏金門著賜衣。", "白馬將軍頻破敵，黃龍戍卒幾時歸。"]'),
('yuding-14','塞下曲二首','王涯','唐','御定全唐诗','yuding','','[]','辛勤幾出黃花戍，迢遞初隨細柳營。',64,'御定全唐詩/json/346.json','["辛勤幾出黃花戍，迢遞初隨細柳營。", "塞晚每愁殘月苦，邊愁更逐斷蓬驚。", "年少辭家從冠軍，金妝寶劍去邀勳。", "不知馬骨傷寒水，唯見龍城起暮雲。"]'),
('yuding-15','平戎辭','王涯','唐','御定全唐诗','yuding','','[]','太白秋高助發兵，長風夜卷虜塵清。',32,'御定全唐詩/json/346.json','["太白秋高助發兵，長風夜卷虜塵清。", "男兒解卻腰間劍，喜見從王道化平。"]'),
('yuding-16','遊春詞二首','王涯','唐','御定全唐诗','yuding','','[]','曲江綠柳變煙條，寒穀冰隨暖氣銷。',64,'御定全唐詩/json/346.json','["曲江綠柳變煙條，寒穀冰隨暖氣銷。", "才見春光生綺陌，已聞清樂動雲韶。", "經過柳陌與桃蹊，尋逐春光著處迷。", "鳥度時時沖絮起，花繁袞袞壓枝低。"]'),
('yuding-17','秋思二首','王涯','唐','御定全唐诗','yuding','','[]','網軒涼吹動輕衣，夜聽更長玉漏稀。',64,'御定全唐詩/json/346.json','["網軒涼吹動輕衣，夜聽更長玉漏稀。", "月度天河光轉濕，鵲驚秋樹葉頻飛。", "宮連太液見滄波，暑氣微消秋意多。", "一夜清風蘋末起，露珠翻盡滿池荷。"]'),
('yuding-18','漢苑行','王涯','唐','御定全唐诗','yuding','','[]','二月春風遍柳條，九天仙樂奏雲韶。',32,'御定全唐詩/json/346.json','["二月春風遍柳條，九天仙樂奏雲韶。", "蓬萊殿后花如錦，紫閣階前雪未銷。"]'),
('yuding-19','秋夜曲','王涯','唐','御定全唐诗','yuding','','[]','桂魄初生秋露微，輕羅已薄未更衣。',32,'御定全唐詩/json/346.json','["桂魄初生秋露微，輕羅已薄未更衣。", "銀箏夜久殷勤弄，心怯空房不忍歸。"]'),
('yuding-20','獻壽辭','王涯','唐','御定全唐诗','yuding','','[]','宮殿參差列九重，祥雲瑞氣捧階濃。',32,'御定全唐詩/json/346.json','["宮殿參差列九重，祥雲瑞氣捧階濃。", "微臣欲獻唐堯壽，遙指南山對袞龍。"]'),
('yuding-21','秋思贈遠二首','王涯','唐','御定全唐诗','yuding','','[]','當年只自守空帷，夢裏關山覺別離。',64,'御定全唐詩/json/346.json','["當年只自守空帷，夢裏關山覺別離。", "不見鄉書傳雁足，唯看新月吐蛾眉。", "厭攀楊柳臨清閣，閑采芙蕖傍碧潭。", "走馬台邊人不見，拂雲堆畔戰初酣。"]'),
('yuding-22','春閨思','王涯','唐','御定全唐诗','yuding','','[]','愁見遊空百尺絲，春風挽斷更傷離。',32,'御定全唐詩/json/346.json','["愁見遊空百尺絲，春風挽斷更傷離。", "閑花落盡青苔地，盡日無人誰得知。"]'),
('yuding-23','宮詞三十首','王涯','唐','御定全唐诗','yuding','','[]','白人宜著紫衣裳，冠子梳頭雙眼長。',384,'御定全唐詩/json/346.json','["白人宜著紫衣裳，冠子梳頭雙眼長。", "新睡起來思舊夢，見人忘卻道勝常。", "春來新插翠雲釵，尚著雲頭踏殿鞋。", "欲得君王回一顧，爭扶玉輦下金階。", "五更初起覺風寒，香炷燒來夜已殘。", "欲卷珠簾驚雪滿，自將紅燭上樓看。", "各將金鎖鎖宮門，院院青娥侍至尊。", "頭白監門掌來去，問頻多是最承恩。", "夜久盤中蠟滴稀，金刀剪起盡霏霏。", "傳聲總是君王喚，紅燭臺前著舞衣。", "箏翻禁曲覺聲難，玉柱皆非舊處安。", "記得君王曾道好，長因下輦得先彈。", "一叢高鬢綠雲光，官樣輕輕淡淡黃。", "為看九天公主貴，外邊爭學內家裝。", "宜春院裏駐仙輿，夜宴笙歌總不如。", "傳索金箋題寵號，鐙前御筆與親書。", "永巷重門漸半開，宮官著鎖隔門回。", "誰知曾笑他人處，今日將身自入來。", "春風簾裏舊青娥，無奈新人奪寵何。", "寒食禁花開滿樹，玉堂終日閉時多。", "碧繡簷前柳散垂，守門宮女欲攀時。", "曾經玉輦從容處，不敢臨風折一枝。", "鴉飛深在禁城牆，多繞重樓複殿傍。", "時向春簷瓦溝上，散開朝翅占朝光。"]'),
('yuding-0','禦溝新柳','賈棱','唐','御定全唐诗','yuding','','[]','御苑陽和早，章溝柳色新。托根偏近日，布葉乍迎春。',72,'御定全唐詩/json/347.json','["御苑陽和早，章溝柳色新。托根偏近日，布葉乍迎春。", "秀質方含翠，清陰欲庇人。輕雲度斜景，多露滴行塵。", "嫋嫋堪離贈，依依獨望頻。王孫如可賞，攀折在芳辰。"]'),
('yuding-1','禦溝新柳','劉遵古','唐','御定全唐诗','yuding','','[]','韶光先禁柳，幾處覆溝新。映水疑分翠，含煙欲占春。',72,'御定全唐詩/json/347.json','["韶光先禁柳，幾處覆溝新。映水疑分翠，含煙欲占春。", "悠悠遲日晚，嫋嫋好風頻。吐節茸猶嫩，通條澤稍均。", "遠和瑤草色，暗拂玉樓塵。願假騫飛便，歸棲及此辰。"]'),
('yuding-2','洛陽清明日雨霽','李正封','唐','御定全唐诗','yuding','','[]','曉日清明天，夜來嵩少雨。千門尚煙火，九陌無塵土。',48,'御定全唐詩/json/347.json','["曉日清明天，夜來嵩少雨。千門尚煙火，九陌無塵土。", "酒綠河橋春，漏閑宮殿午。遊人戀芳草，半犯嚴城鼓。"]'),
('yuding-3','詠露','李正封','唐','御定全唐诗','yuding','','[]','霏霏靈液重，雲表無聲落。沾樹急玄蟬，灑池棲皓鶴。',60,'御定全唐詩/json/347.json','["霏霏靈液重，雲表無聲落。沾樹急玄蟬，灑池棲皓鶴。", "流塵清遠陌，飛月澄高閣。宵潤玉堂簾，曙寒金井索。", "佳人比珠淚，坐感紅綃薄。"]'),
('yuding-4','夏遊招隱寺暴雨晚晴','李正封','唐','御定全唐诗','yuding','','[]','竹柏風雨過，蕭疏台殿涼。石渠寫奔溜，金刹照頹陽。',48,'御定全唐詩/json/347.json','["竹柏風雨過，蕭疏台殿涼。石渠寫奔溜，金刹照頹陽。", "鶴飛岩煙碧，鹿鳴澗草香。山僧引清梵，幡蓋繞回廊。"]'),
('yuding-5','禪門寺暮鐘','李正封','唐','御定全唐诗','yuding','','[]','簨簴高懸于闐鐘，黃昏發地殷龍宮。',32,'御定全唐詩/json/347.json','["簨簴高懸于闐鐘，黃昏發地殷龍宮。", "遊人憶到嵩山夜，疊閣連樓倚太空。"]'),
('yuding-6','貢院樓北新栽小松','李正封','唐','御定全唐诗','yuding','','[]','青蒼初得地，華省植來新。尚帶山中色，猶含洞裏春。',72,'御定全唐詩/json/347.json','["青蒼初得地，華省植來新。尚帶山中色，猶含洞裏春。", "近樓依北戶，隱砌淨遊塵。鶴壽應成蓋，龍形未有鱗。", "為梁資大廈，封爵恥嬴秦。幸此觀光日，清風屢得親。"]'),
('yuding-7','南至隔仗望含元殿香爐','崔立之','唐','御定全唐诗','yuding','','[]','千官望長至，萬國拜含元。隔仗爐光出，浮霜煙氣翻。',72,'御定全唐詩/json/347.json','["千官望長至，萬國拜含元。隔仗爐光出，浮霜煙氣翻。", "飄飄縈內殿，漠漠澹前軒。聖日開如捧，卿雲近欲渾。", "輪囷灑宮闕，蕭索散乾坤。願倚天風便，披香奉至尊。"]'),
('yuding-8','曲池潔寒流','崔立之','唐','御定全唐诗','yuding','','[]','閑尋欹岸步，因向曲池看。透底何澄澈，回流乍屈盤。',72,'御定全唐詩/json/347.json','["閑尋欹岸步，因向曲池看。透底何澄澈，回流乍屈盤。", "稍隨高樹古，迥與遠天寒。月入鏡華轉，星臨珠影攢。", "纖鱗時蔽石，轉吹或生瀾。願假涓微效，來濡拙筆端。"]'),
('yuding-9','賦得春風扇微和','崔立之','唐','御定全唐诗','yuding','','[]','時令忽已變，年光俄又春。高低惠風入，遠近芳氣新。',72,'御定全唐詩/json/347.json','["時令忽已變，年光俄又春。高低惠風入，遠近芳氣新。", "靡靡才偃草，泠泠不動塵。溫和乍扇物，煦嫗偏感人。", "去出桂林漫，來過蕙圃頻。晨輝正澹蕩，披拂長相親。"]'),
('yuding-10','南至日隔仗望含元殿香爐','郭遵','唐','御定全唐诗','yuding','','[]','冕旒親負扆，卉服盡朝天。暘谷移初日，金爐出禦煙。',72,'御定全唐詩/json/347.json','["冕旒親負扆，卉服盡朝天。暘谷移初日，金爐出禦煙。", "芬馨流遠近，散漫入貂蟬。霜仗凝逾白，朱欄映轉鮮。", "如看浮闕在，稍覺逐風遷。為沐皇家慶，來瞻羽衛前。"]'),
('yuding-11','賦得春風扇微和','郭遵','唐','御定全唐诗','yuding','','[]','微風飄淑氣，散漫及茲晨。習習何處至，熙熙與春親。',72,'御定全唐詩/json/347.json','["微風飄淑氣，散漫及茲晨。習習何處至，熙熙與春親。", "曖空看早辨，映日度逾頻。高拂非煙雜，低垂眾卉新。", "霽天輕有靄，綺陌盡無塵。還似登臺意，元和欲煦人。"]'),
('yuding-12','賦得風動萬年枝','韋紓','唐','御定全唐诗','yuding','','[]','嘉名標萬祀，擢秀出深宮。嫩葉含煙靄，芳柯振惠風。',72,'御定全唐詩/json/347.json','["嘉名標萬祀，擢秀出深宮。嫩葉含煙靄，芳柯振惠風。", "參差搖翠色，綺靡舞晴空。氣稟禎祥異，榮沾雨露同。", "天年方未極，聖壽比應崇。幸列華林裏，知殊眾木中。"]'),
('yuding-13','賦得風動萬年枝','樊陽源','唐','御定全唐诗','yuding','','[]','珍木羅前殿，乘春任好風。振柯方嫋嫋，舒葉乍濛濛。',72,'御定全唐詩/json/347.json','["珍木羅前殿，乘春任好風。振柯方嫋嫋，舒葉乍濛濛。", "影動丹墀上，聲傳紫禁中。離披偏向日，淩亂半分空。", "輕拂祥煙散，低搖翠色同。長令占天眷，四氣借全功。"]'),
('yuding-14','賦得風動萬年枝','許稷','唐','御定全唐诗','yuding','','[]','瓊樹偏春早，光飛處處宜。曉浮三殿日，暗度萬年枝。',72,'御定全唐詩/json/347.json','["瓊樹偏春早，光飛處處宜。曉浮三殿日，暗度萬年枝。", "婀娜搖仙禁，繽翻映玉池。含芳煙乍合，拂砌影初移。", "為近韶陽煦，皆先眾卉垂。成陰知可待，不與眾芳隨。"]'),
('yuding-15','閏月定四時','許稷','唐','御定全唐诗','yuding','','[]','玉律窮三紀，推為積閏期。月餘因妙算，歲遍自成時。',72,'御定全唐詩/json/347.json','["玉律窮三紀，推為積閏期。月餘因妙算，歲遍自成時。", "乍覺年華改，翻憐物候遲。六旬知不惑，四氣本無欺。", "月桂虧還正，階蓂落複滋。從斯分曆象，共仰定毫釐。"]'),
('yuding-16','謝真人還舊山','範傳正','唐','御定全唐诗','yuding','','[]','麾蓋從仙府，笙歌入舊山。水流丹灶缺，雲起草堂關。',72,'御定全唐詩/json/347.json','["麾蓋從仙府，笙歌入舊山。水流丹灶缺，雲起草堂關。", "白鹿行為衛，青鸞舞自閑。種松鱗未立，移石蘚仍斑。", "望路煙霞外，回輿岩岫間。豈唯遼海鶴，空歎令威還。"]'),
('yuding-17','范成君擊洞陰磬','範傳正','唐','御定全唐诗','yuding','','[]','歷歷聞金奏，微微下玉京。為祥家諜久，偏識洞陰名。',72,'御定全唐詩/json/347.json','["歷歷聞金奏，微微下玉京。為祥家諜久，偏識洞陰名。", "澹佇人間聽，鏗鏘古曲成。何須百獸舞，自暢九天情。", "注目看無見，留心記未精。雲霄如可托，借鶴向層城。"]'),
('yuding-18','賦得春風扇微和','範傳正','唐','御定全唐诗','yuding','','[]','曖曖當遲日，微微扇好風。吹搖新葉上，光動淺花中。',72,'御定全唐詩/json/347.json','["曖曖當遲日，微微扇好風。吹搖新葉上，光動淺花中。", "澹蕩凝清晝，氤氳曖碧空。稍看生綠水，已覺散芳叢。", "徙倚情偏適，裴回賞未窮。妍華不可狀，竟夕氣融融。"]'),
('yuding-19','賦得春風扇微和','豆盧榮','唐','御定全唐诗','yuding','','[]','春晴生縹緲，軟吹和初遍。池影動淵淪，山容發蔥蒨。',72,'御定全唐詩/json/347.json','["春晴生縹緲，軟吹和初遍。池影動淵淪，山容發蔥蒨。", "遲遲入綺閣，習習流芳甸。樹杪颺鶯啼，階前落花片。", "韶光恐閑放，旭日宜遊宴。文客拂塵衣，仁風願回扇。"]'),
('yuding-20','賦得春風扇微和','邵偃','唐','御定全唐诗','yuding','','[]','微風扇和氣，韶景共芳晨。始見郊原綠，旋過御苑春。',72,'御定全唐詩/json/347.json','["微風扇和氣，韶景共芳晨。始見郊原綠，旋過御苑春。", "三條開廣陌，八水泛通津。煙動花間葉，香流馬上人。", "逶迤雲彩曙，嘹唳鳥聲頻。為報東堂客，明朝桂樹新。"]'),
('yuding-21','賦得春風扇微和','柳道倫','唐','御定全唐诗','yuding','','[]','青陽初入律，淑氣應春風。始辨梅花裏，俄分柳色中。',72,'御定全唐詩/json/347.json','["青陽初入律，淑氣應春風。始辨梅花裏，俄分柳色中。", "依微開夕照，澹蕩媚晴空。拂水生蘋末，經岩觸桂叢。", "稍抽蘭葉紫，微吐杏花紅。願逐仁風布，將俾生植功。"]'),
('yuding-22','賦得春風扇微和','陳九流','唐','御定全唐诗','yuding','','[]','喜見陽和至，遙知橐鑰功。遲遲散南陽，嫋嫋逐東風。',72,'御定全唐詩/json/347.json','["喜見陽和至，遙知橐鑰功。遲遲散南陽，嫋嫋逐東風。", "暗入芳園裏，潛吹草木中。蘭蓀才有綠，桃杏未成紅。", "已覺寒光盡，還看淑氣通。由來榮與悴，今日發應同。"]'),
('yuding-23','謝真人仙駕還舊山','夏方慶','唐','御定全唐诗','yuding','','[]','何年成道去，綽約化童顏。天上辭仙侶，人間憶舊山。',72,'御定全唐詩/json/347.json','["何年成道去，綽約化童顏。天上辭仙侶，人間憶舊山。", "滄桑今已變，蘿蔓尚堪攀。雲覆瑤壇淨，苔生丹灶閑。", "逍遙堪白石，寂寞閉玄關。應是悲塵世，思將羽駕還。"]'),
('yuding-0','公子行','陳羽','唐','御定全唐诗','yuding','','[]','金羈白麵郎，何處蹋青來。馬嬌郎半醉，躞蹀望樓臺。',48,'御定全唐詩/json/348.json','["金羈白麵郎，何處蹋青來。馬嬌郎半醉，躞蹀望樓臺。", "似見樓上人，玲瓏窗戶開。隔花聞一笑，落日不知回。"]'),
('yuding-1','古意','陳羽','唐','御定全唐诗','yuding','','[]','十三學繡羅衣裳，自憐紅袖聞馨香。人言此是嫁時服，',144,'御定全唐詩/json/348.json','["十三學繡羅衣裳，自憐紅袖聞馨香。人言此是嫁時服，", "車馬駢闐賀門館，自然不失為公卿。是時妾家猶未貧，", "郎家居近禦溝水，豪門客盡躡珠履。雕盤酒器常不幹，", "朝參暮拜白玉堂，繡衣著盡黃金縷。妾貌漸衰郎漸薄，", "妾年四十絲滿頭，郎年五十封公侯。男兒全盛日忘舊，", "歸來略略不相顧，卻令侍婢生光輝。郎恨婦人易衰老，"]'),
('yuding-2','長相思','陳羽','唐','御定全唐诗','yuding','','[]','相思長相思，相思無限極。相思苦相思，相思損容色。',64,'御定全唐詩/json/348.json','["相思長相思，相思無限極。相思苦相思，相思損容色。", "容色真可惜，相思不可徹。日日長相思，相思腸斷絕。", "腸斷絕，淚還續，閒人莫作相思曲。"]'),
('yuding-3','送戴端公赴容州','陳羽','唐','御定全唐诗','yuding','','[]','分命諸侯重，葳蕤繡服香。八蠻治險阻，千騎蹋繁霜。',48,'御定全唐詩/json/348.json','["分命諸侯重，葳蕤繡服香。八蠻治險阻，千騎蹋繁霜。", "山斷旌旗出，天晴劍佩光。還將小戴禮，遠出化南方。"]'),
('yuding-4','送殷華之洪州','陳羽','唐','御定全唐诗','yuding','','[]','離堂悲楚調，君奏豫章行。愁處雪花白，夢中江水清。',48,'御定全唐詩/json/348.json','["離堂悲楚調，君奏豫章行。愁處雪花白，夢中江水清。", "扣船歌月色，避浪宿猿聲。還作經年別，相思湖草生。"]'),
('yuding-5','春日晴原野望','陳羽','唐','御定全唐诗','yuding','','[]','東風吹暖氣，消散入晴天。漸變池塘色，欲生楊柳煙。',48,'御定全唐詩/json/348.json','["東風吹暖氣，消散入晴天。漸變池塘色，欲生楊柳煙。", "蒙茸花向月，潦倒客經年。鄉思應愁望，江湖春水連。"]'),
('yuding-6','湘妃怨','陳羽','唐','御定全唐诗','yuding','','[]','舜欲省蠻陬，南巡非逸遊。九山沉白日，二女泣滄洲。',48,'御定全唐詩/json/348.json','["舜欲省蠻陬，南巡非逸遊。九山沉白日，二女泣滄洲。", "目極楚雲斷，恨連湘水流。至今聞鼓瑟，咽絕不勝愁。"]'),
('yuding-7','冬晚送友人使西蕃','陳羽','唐','御定全唐诗','yuding','','[]','驛使向天西，巡羌複入氐。玉關晴有雪，砂磧雨無泥。',48,'御定全唐詩/json/348.json','["驛使向天西，巡羌複入氐。玉關晴有雪，砂磧雨無泥。", "落淚軍中笛，驚眠塞上雞。逢春鄉思苦，萬里草萋萋。"]'),
('yuding-8','春園即事','陳羽','唐','御定全唐诗','yuding','','[]','水隔群物遠，夜深風起頻。霜中千樹橘，月下五湖人。',48,'御定全唐詩/json/348.json','["水隔群物遠，夜深風起頻。霜中千樹橘，月下五湖人。", "聽鶴忽忘寢，見山如得鄰。明年還到此，共看洞庭春。"]'),
('yuding-9','送友人及第歸江東','陳羽','唐','御定全唐诗','yuding','','[]','五陵春色泛花枝，心醉花前遠別離。落羽恥為關右客，',40,'御定全唐詩/json/348.json','["五陵春色泛花枝，心醉花前遠別離。落羽恥為關右客，", "家住洞庭多釣伴，因來相賀話相思。"]'),
('yuding-10','梓州與溫商夜別','陳羽','唐','御定全唐诗','yuding','','[]','鳳凰城裏花時別，玄武江邊月下逢。客舍莫辭先買酒，',40,'御定全唐詩/json/348.json','["鳳凰城裏花時別，玄武江邊月下逢。客舍莫辭先買酒，", "明日又行西蜀路，不堪天際遠山重。"]'),
('yuding-11','長安臥病秋夜言懷','陳羽','唐','御定全唐诗','yuding','','[]','九重門鎖禁城秋，月過南宮漸映樓。紫陌夜深槐露滴，',40,'御定全唐詩/json/348.json','["九重門鎖禁城秋，月過南宮漸映樓。紫陌夜深槐露滴，", "楚客病來鄉思苦，寂寥燈下不勝愁。"]'),
('yuding-12','喜雪上竇相公','陳羽','唐','御定全唐诗','yuding','','[]','千門萬戶雪花浮，點點無聲落瓦溝。全似玉塵銷更積，',40,'御定全唐詩/json/348.json','["千門萬戶雪花浮，點點無聲落瓦溝。全似玉塵銷更積，", "平地已沾盈尺潤，年豐須荷富人侯。"]'),
('yuding-13','宴楊駙馬山亭','陳羽','唐','御定全唐诗','yuding','','[]','垂楊拂岸草茸茸，繡戶窗前花影重。鱠下玉盤紅縷細，',40,'御定全唐詩/json/348.json','["垂楊拂岸草茸茸，繡戶窗前花影重。鱠下玉盤紅縷細，", "落日泛舟同醉處，回潭百丈映千峰。"]'),
('yuding-14','西蜀送許中庸歸秦赴舉','陳羽','唐','御定全唐诗','yuding','','[]','春色華陽國，秦人此別離。驛樓橫水影，鄉路入花枝。',96,'御定全唐詩/json/348.json','["春色華陽國，秦人此別離。驛樓橫水影，鄉路入花枝。", "日暖鶯飛好，山晴馬去遲。劍門當石隘，棧閣入雲危。", "獨鶴心千里，貧交酒一卮。桂條攀偃蹇，蘭葉藉參差。", "旅夢驚蝴蝶，殘芳怨子規。碧霄今夜月，惆悵上峨嵋。"]'),
('yuding-15','小苑春望宮池柳色','陳羽','唐','御定全唐诗','yuding','','[]','宛宛如絲柳，含黃一望新。未成溝上暗，且向日邊春。',72,'御定全唐詩/json/348.json','["宛宛如絲柳，含黃一望新。未成溝上暗，且向日邊春。", "嫋娜方遮水，低迷欲醉人。托空芳鬱鬱，逐溜影鱗鱗。", "弄水滋宵露，垂枝染夕塵。夾堤連太液，還似映天津。"]'),
('yuding-16','中秋夜臨鏡湖望月','陳羽','唐','御定全唐诗','yuding','','[]','鏡裏秋宵望，湖平月彩深。圓光珠入浦，浮照鵲驚林。',72,'御定全唐詩/json/348.json','["鏡裏秋宵望，湖平月彩深。圓光珠入浦，浮照鵲驚林。", "澹動光還碎，嬋娟影不沉。遠時生岸曲，空處落波心。", "迥徹輪初滿，孤明魄未侵。桂枝如可折，何惜夜登臨。"]'),
('yuding-17','江上愁思二首','陳羽','唐','御定全唐诗','yuding','','[]','江上翁開門，開門向衰草。只知愁子孫，不覺生涯老。',48,'御定全唐詩/json/348.json','["江上翁開門，開門向衰草。只知愁子孫，不覺生涯老。", "江上草莖枯，莖枯葉複焦。那堪芳意盡，夜夜沒寒潮。"]'),
('yuding-18','梁城老人怨','陳羽','唐','御定全唐诗','yuding','','[]','朝為耕種人，暮作刀槍鬼。相看父子血，共染城濠水。',24,'御定全唐詩/json/348.json','["朝為耕種人，暮作刀槍鬼。相看父子血，共染城濠水。"]'),
('yuding-19','送靈一上人','陳羽','唐','御定全唐诗','yuding','','[]','十年勞遠別，一笑喜相逢。又上青山去，青山千萬重。',24,'御定全唐詩/json/348.json','["十年勞遠別，一笑喜相逢。又上青山去，青山千萬重。"]'),
('yuding-20','經夫差廟','陳羽','唐','御定全唐诗','yuding','','[]','姑蘇城畔千年木，刻作夫差廟裏神。',32,'御定全唐詩/json/348.json','["姑蘇城畔千年木，刻作夫差廟裏神。", "冠蓋寂寥塵滿室，不知簫鼓樂何人。"]'),
('yuding-21','九月十日即事','陳羽','唐','御定全唐诗','yuding','','[]','漢江天外東流去，巴塞連山萬里秋。',32,'御定全唐詩/json/348.json','["漢江天外東流去，巴塞連山萬里秋。", "節過重陽人病起，一枝殘菊不勝愁。"]'),
('yuding-22','夏日宴九華池贈主人','陳羽','唐','御定全唐诗','yuding','','[]','池上涼臺五月涼，百花開盡水芝香。',32,'御定全唐詩/json/348.json','["池上涼臺五月涼，百花開盡水芝香。", "黃金買酒邀詩客，醉倒簷前青玉床。"]'),
('yuding-23','長安早春言志','陳羽','唐','御定全唐诗','yuding','','[]','九衢日暖樹蒼蒼，萬里吳人憶水鄉。',32,'御定全唐詩/json/348.json','["九衢日暖樹蒼蒼，萬里吳人憶水鄉。", "漢主未曾親羽獵，不知將底諫君王。"]'),
('yuding-24','讀蘇屬國傳','陳羽','唐','御定全唐诗','yuding','','[]','天山西北居延海，沙塞重重不見春。',32,'御定全唐詩/json/348.json','["天山西北居延海，沙塞重重不見春。", "腸斷帝鄉遙望日，節旄零落漢家臣。"]'),
('yuding-25','吳城覽古','陳羽','唐','御定全唐诗','yuding','','[]','吳王舊國水煙空，香徑無人蘭葉紅。',32,'御定全唐詩/json/348.json','["吳王舊國水煙空，香徑無人蘭葉紅。", "春色似憐歌舞地，年年先發館娃宮。"]'),
('yuding-26','犍為城下夜泊聞夷歌','陳羽','唐','御定全唐诗','yuding','','[]','犍為城下牂牁路，空塚灘西賈客舟。',32,'御定全唐詩/json/348.json','["犍為城下牂牁路，空塚灘西賈客舟。", "此夜可憐江上月，夷歌銅鼓不勝愁。"]'),
('yuding-27','和王中丞使君春日過高評事幽居','陳羽','唐','御定全唐诗','yuding','','[]','風光滿路旗幡出，林下高人待使君。',32,'御定全唐詩/json/348.json','["風光滿路旗幡出，林下高人待使君。", "笑藉紫蘭相向醉，野花千樹落紛紛。"]'),
('yuding-28','和王中丞中和日','陳羽','唐','御定全唐诗','yuding','','[]','節應中和天地晴，繁弦疊鼓動高城。',32,'御定全唐詩/json/348.json','["節應中和天地晴，繁弦疊鼓動高城。", "漢家分刺諸侯貴，一曲陽春江水清。"]'),
('yuding-29','同韋中丞花下夜飲贈歌人','陳羽','唐','御定全唐诗','yuding','','[]','銀燭煌煌半醉人，嬌歌宛轉動朱唇。',32,'御定全唐詩/json/348.json','["銀燭煌煌半醉人，嬌歌宛轉動朱唇。", "繁花落盡春風裏，繡被郎官不負春。"]'),
('yuding-30','若耶溪逢陸澧','陳羽','唐','御定全唐诗','yuding','','[]','溪上春晴聊看竹，誰言驛使此相逢。',32,'御定全唐詩/json/348.json','["溪上春晴聊看竹，誰言驛使此相逢。", "擔簦躡屐仍多病，笑殺雲間陸士龍。"]'),
('yuding-31','夜泊荊溪','陳羽','唐','御定全唐诗','yuding','','[]','小雪已晴蘆葉暗，長波乍急鶴聲嘶。',32,'御定全唐詩/json/348.json','["小雪已晴蘆葉暗，長波乍急鶴聲嘶。", "孤舟一夜宿流水，眼看山頭月落溪。"]'),
('yuding-32','南山別僧','陳羽','唐','御定全唐诗','yuding','','[]','惆悵人間多別離，梅花滿眼獨行時。',32,'御定全唐詩/json/348.json','["惆悵人間多別離，梅花滿眼獨行時。", "無家度日多為客，欲共山僧何處期。"]'),
('yuding-33','戲題山居二首','陳羽','唐','御定全唐诗','yuding','','[]','雲蓋秋松幽洞近，水穿危石亂山深。',64,'御定全唐詩/json/348.json','["雲蓋秋松幽洞近，水穿危石亂山深。", "門前自有千竿竹，免向人家看竹林。", "雖有柴門長不關，片雲高木共身閑。", "猶嫌住久人知處，見欲移居更上山。"]'),
('yuding-34','山中秋夜喜周士閑見過','陳羽','唐','御定全唐诗','yuding','','[]','青山高處上不易，白雲深處行亦難。',32,'御定全唐詩/json/348.json','["青山高處上不易，白雲深處行亦難。", "留君不宿對秋月，莫厭山空泉石寒。"]'),
('yuding-35','過櫟陽山溪','陳羽','唐','御定全唐诗','yuding','','[]','眾草穿沙芳色齊，蹋莎行草過春溪。',32,'御定全唐詩/json/348.json','["眾草穿沙芳色齊，蹋莎行草過春溪。", "閑雲相引上山去，人到山頭雲卻低。"]'),
('yuding-36','姑蘇台懷古','陳羽','唐','御定全唐诗','yuding','','[]','憶昔吳王爭霸日，歌鐘滿地上高臺。',32,'御定全唐詩/json/348.json','["憶昔吳王爭霸日，歌鐘滿地上高臺。", "三千宮女看花處，人盡台崩花自開。"]'),
('yuding-37','將歸舊山留別','陳羽','唐','御定全唐诗','yuding','','[]','相共游梁今獨還，異鄉搖落憶空山。',32,'御定全唐詩/json/348.json','["相共游梁今獨還，異鄉搖落憶空山。", "信陵死後無公子，徒向夷門學抱關。"]'),
('yuding-38','遊洞靈觀','陳羽','唐','御定全唐诗','yuding','','[]','初訪西城禮少君，獨行深入洞天雲。',32,'御定全唐詩/json/348.json','["初訪西城禮少君，獨行深入洞天雲。", "風吹青桂寒花落，香繞仙壇處處聞。"]'),
('yuding-39','旅次沔陽，聞克復，而用師者窮兵黷武，因書簡之','陳羽','唐','御定全唐诗','yuding','','[]','江上煙消漢水清，王師大破綠林兵。',32,'御定全唐詩/json/348.json','["江上煙消漢水清，王師大破綠林兵。", "干戈用盡人成血，韓信空傳壯士名。"]'),
('yuding-40','湘君祠','陳羽','唐','御定全唐诗','yuding','','[]','二妃怨處雲沉沉，二妃哭處湘水深。',32,'御定全唐詩/json/348.json','["二妃怨處雲沉沉，二妃哭處湘水深。", "商人酒滴廟前草，蕭索風生斑竹林。"]'),
('yuding-41','送辛吉甫常州覲省','陳羽','唐','御定全唐诗','yuding','','[]','西去蘭陵家不遠，到家還及采蘭時。',32,'御定全唐詩/json/348.json','["西去蘭陵家不遠，到家還及采蘭時。", "新年送客我為客，惆悵門前黃柳絲。"]'),
('yuding-42','題舞花山大師遺居','陳羽','唐','御定全唐诗','yuding','','[]','西過流沙歸路長，一生遺跡在東方。',32,'御定全唐詩/json/348.json','["西過流沙歸路長，一生遺跡在東方。", "空堂寂寞閉燈影，風動四山松柏香。"]'),
('yuding-43','廣陵秋夜對月即事','陳羽','唐','御定全唐诗','yuding','','[]','霜落寒空月上樓，月中歌吹滿揚州。',32,'御定全唐詩/json/348.json','["霜落寒空月上樓，月中歌吹滿揚州。", "相看醉舞倡樓月，不覺隋家陵樹秋。"]'),
('yuding-44','早秋滻水送人歸越','陳羽','唐','御定全唐诗','yuding','','[]','涼葉蕭蕭生遠風，曉鴉飛度望春宮。',32,'御定全唐詩/json/348.json','["涼葉蕭蕭生遠風，曉鴉飛度望春宮。", "越人歸去一搖首，腸斷馬嘶秋水東。"]'),
('yuding-45','小江驛送陸侍禦歸湖上山','陳羽','唐','御定全唐诗','yuding','','[]','鶴唳天邊秋水空，荻花蘆葉起西風。',32,'御定全唐詩/json/348.json','["鶴唳天邊秋水空，荻花蘆葉起西風。", "今夜渡江何處宿，會稽山在月明中。"]'),
('yuding-46','送李德輿歸穿石洞山居','陳羽','唐','御定全唐诗','yuding','','[]','烏巾年少歸何處，一片彩霞仙洞中。',32,'御定全唐詩/json/348.json','["烏巾年少歸何處，一片彩霞仙洞中。", "惆悵別時花似雪，行人不肯醉春風。"]'),
('yuding-47','酬幽居閑上人喜及第後見贈','陳羽','唐','御定全唐诗','yuding','','[]','九霄心在勞相問，四十年間豈足驚。',32,'御定全唐詩/json/348.json','["九霄心在勞相問，四十年間豈足驚。", "風動自然雲出岫，高僧不用笑浮生。"]'),
('yuding-48','洛下贈徹公','陳羽','唐','御定全唐诗','yuding','','[]','天竺沙門洛下逢，請為同社笑相容。',32,'御定全唐詩/json/348.json','["天竺沙門洛下逢，請為同社笑相容。", "支頤忽望碧雲裏，心愛嵩山第幾重。"]'),
('yuding-49','觀朱舍人歸葬吳中','陳羽','唐','御定全唐诗','yuding','','[]','翩翩絳旐寒流上，行引東歸萬里魂。',32,'御定全唐詩/json/348.json','["翩翩絳旐寒流上，行引東歸萬里魂。", "幾處州人臨水哭，共看遺草有王言。"]'),
('yuding-50','題清鏡寺留別','陳羽','唐','御定全唐诗','yuding','','[]','路入千山愁自知，雪花撩亂壓松枝。',32,'御定全唐詩/json/348.json','["路入千山愁自知，雪花撩亂壓松枝。", "世人並道離別苦，誰信山僧輕別離。"]'),
('yuding-51','從軍行','陳羽','唐','御定全唐诗','yuding','','[]','海畔風吹凍泥裂，枯桐葉落枝梢折。',32,'御定全唐詩/json/348.json','["海畔風吹凍泥裂，枯桐葉落枝梢折。", "橫笛聞聲不見人，紅旗直上天山雪。"]'),
('yuding-52','宿淮陰作','陳羽','唐','御定全唐诗','yuding','','[]','秋燈點點淮陰市，楚客聯檣宿淮水。',32,'御定全唐詩/json/348.json','["秋燈點點淮陰市，楚客聯檣宿淮水。", "夜深風起魚鱉腥，韓信祠堂明月裏。"]'),
('yuding-53','春日南山行','陳羽','唐','御定全唐诗','yuding','','[]','處處看山不可行，野花相向笑無成。',32,'御定全唐詩/json/348.json','["處處看山不可行，野花相向笑無成。", "長嫌為客過州縣，漸被時人識姓名。"]'),
('yuding-54','步虛詞二首','陳羽','唐','御定全唐诗','yuding','','[]','漢武清齋讀鼎書，太官扶上畫雲車。',64,'御定全唐詩/json/348.json','["漢武清齋讀鼎書，太官扶上畫雲車。", "壇上月明宮殿閉，仰看星斗禮空虛。", "樓殿層層阿母家，昆侖山頂駐紅霞。", "笙歌出見穆天子，相引笑看琪樹花。"]'),
('yuding-55','襄陽過孟浩然舊居','陳羽','唐','御定全唐诗','yuding','','[]','襄陽城郭春風起，漢水東流去不還。',32,'御定全唐詩/json/348.json','["襄陽城郭春風起，漢水東流去不還。", "孟子死來江樹老，煙霞猶在鹿門山。"]'),
('yuding-56','送友人游嵩山','陳羽','唐','御定全唐诗','yuding','','[]','嵩山歸路繞天壇，雪影松聲滿穀寒。',32,'御定全唐詩/json/348.json','["嵩山歸路繞天壇，雪影松聲滿穀寒。", "君見九龍潭上月，莫辭清夜訪袁安。"]'),
('yuding-57','伏翼西洞送夏方慶','陳羽','唐','御定全唐诗','yuding','','[]','洞裏春晴花正開，看花出洞幾時回。',32,'御定全唐詩/json/348.json','["洞裏春晴花正開，看花出洞幾時回。", "殷勤好去武陵客，莫引世人相逐來。"]'),
('yuding-58','贈人','陳羽','唐','御定全唐诗','yuding','','[]','或棹孤舟或杖藜，尋常適意釣長溪。',32,'御定全唐詩/json/348.json','["或棹孤舟或杖藜，尋常適意釣長溪。", "草堂竹徑在何處，落日孤煙寒渚西。"]'),
('yuding-59','句','陳羽','唐','御定全唐诗','yuding','','[]','稚子新能編筍笠，山妻舊解補荷衣。秋山隔岸清猿叫，',24,'御定全唐詩/json/348.json','["稚子新能編筍笠，山妻舊解補荷衣。秋山隔岸清猿叫，"]'),
('yuding-0','東風二章','歐陽詹','唐','御定全唐诗','yuding','','[]','東風葉時，匪沃匪飄。莫雪凝川，莫陰冱郊。',146,'御定全唐詩/json/349.json','["東風葉時，匪沃匪飄。莫雪凝川，莫陰冱郊。", "朝不徯夕乃銷，東風之行地上兮。上德臨慝，匪戮匪梟。", "莫暴在野，莫醜在階。以踣以殲，夕不徯朝。", "隴西公來浚都兮。", "東風葉時，匪鑿匪穮。莫蟄在泉，莫枯在條。", "宵不徯晨乃繇。東風之行地上兮。上德為政，匪食匪招。", "莫顧于家，莫流於遼。以飽以回，晨不徯宵。", "隴西公來浚都兮。"]'),
('yuding-1','有所恨二章','歐陽詹','唐','御定全唐诗','yuding','','[]','相思君子，籲嗟萬里。亦既至止，曷不覯止。本不信巫，',50,'御定全唐詩/json/349.json','["相思君子，籲嗟萬里。亦既至止，曷不覯止。本不信巫，", "相思遺衣，為憶以貽。亦既受止，曷不保持。本不欺友，"]'),
('yuding-2','玩月','歐陽詹','唐','御定全唐诗','yuding','','[]','八月十五夕，舊嘉蟾兔光。斯從古人好，共下今宵堂。',96,'御定全唐詩/json/349.json','["八月十五夕，舊嘉蟾兔光。斯從古人好，共下今宵堂。", "素魄皎孤凝，芳輝紛四揚。裴回林上頭，泛灩天中央。", "皓露助流華，輕風佐浮涼。清冷到肌骨，潔白盈衣裳。", "惜此苦宜玩，攬之非可將。含情顧廣庭，願勿沉西方。"]'),
('yuding-3','詠德上韋檢察','歐陽詹','唐','御定全唐诗','yuding','','[]','少華類太華，太室似少室。亞相與丞相，亦複無異質。',96,'御定全唐詩/json/349.json','["少華類太華，太室似少室。亞相與丞相，亦複無異質。", "渟如月臨水，肅若松照日。輝影互光澄，陰森兩蔥郁。", "連城鸞鳳分，同氣龜龍出。並力革夷心，通籌整師律。", "英豪願回席，蠻貊皆屈膝。中外行分途，寰瀛待清謐。"]'),
('yuding-4','寓興','歐陽詹','唐','御定全唐诗','yuding','','[]','桃李有奇質，樗櫟無妙姿。皆承慶雲沃，一種春風吹。',48,'御定全唐詩/json/349.json','["桃李有奇質，樗櫟無妙姿。皆承慶雲沃，一種春風吹。", "美惡苟同歸，喧囂徒爾為。相將任玄造，聊醉手中卮。"]'),
('yuding-5','答韓十八駑驥吟','歐陽詹','唐','御定全唐诗','yuding','','[]','故人舒其憤，昨示駑驥篇。駑以易售陳，驥以難知言。',204,'御定全唐詩/json/349.json','["故人舒其憤，昨示駑驥篇。駑以易售陳，驥以難知言。", "委曲感既深，咨嗟詞亦殷。伊情有遠瀾，餘志遜其源。", "室在周孔堂，道通堯舜門。調雅聲寡同，途遐勢難翻。", "顧茲萬恨來，假彼二物雲。賤貴而貴賤，世人良共然。", "巴蕉一葉妖，茙葵一花妍。畢無才實資，手植階墀前。", "楩楠十圍瑰，松柏百尺堅。罔念梁棟功，野長丘墟邊。", "傷哉昌黎韓，焉得不迍邅。上帝本厚生，大君方建元。", "寶將庇群甿，庶此規崇軒。班爾圖永安，掄擇期精專。", "君看廣廈中，豈有樹庭萱。"]'),
('yuding-6','益昌行','歐陽詹','唐','御定全唐诗','yuding','','[]','驅馬至益昌，倍驚風俗和。耕夫隴上謠，負者途中歌。',156,'御定全唐詩/json/349.json','["驅馬至益昌，倍驚風俗和。耕夫隴上謠，負者途中歌。", "處處川復原，重重山與河。人煙遍餘田，時稼無閑坡。", "問業一何修，太守德化加。問身一何安，太守恩懷多。", "賢哉我太守，在古無以過。愛人甚愛身，治郡如治家。", "雲雷既奮騰，草木遂萌芽。乃知良二千，德足為國華。", "今時固精求，漢帝非徒嗟。四海有青春，眾植佇揚葩。", "期當作說霖，天下同滂沱。"]'),
('yuding-7','自淮中卻赴洛途中作','歐陽詹','唐','御定全唐诗','yuding','','[]','惆悵策疲馬，孤蓬被風吹。昨東今又西，冉冉長路岐。',48,'御定全唐詩/json/349.json','["惆悵策疲馬，孤蓬被風吹。昨東今又西，冉冉長路岐。", "歲晚樹無葉，夜寒霜滿枝。旅人恒苦辛，冥寞天何知。"]'),
('yuding-8','晨裝行','歐陽詹','唐','御定全唐诗','yuding','','[]','村店月西出，山林鵯鵊聲。旅燈徹夜席，束囊事晨征。',48,'御定全唐詩/json/349.json','["村店月西出，山林鵯鵊聲。旅燈徹夜席，束囊事晨征。", "寂寂人尚眠，悠悠天未明。豈無偃息心，所務前有程。"]'),
('yuding-9','新都行','歐陽詹','唐','御定全唐诗','yuding','','[]','縹緲空中絲，蒙籠道傍樹。翻茲葉間吹，惹破花上露。',48,'御定全唐詩/json/349.json','["縹緲空中絲，蒙籠道傍樹。翻茲葉間吹，惹破花上露。", "悠揚絲意去，苒蒻花枝住。何計脫纏綿，天長春日暮。"]'),
('yuding-10','銅雀妓','歐陽詹','唐','御定全唐诗','yuding','','[]','蕭條登古台，回首黃金屋。落葉不歸林，高陵永為穀。',48,'御定全唐詩/json/349.json','["蕭條登古台，回首黃金屋。落葉不歸林，高陵永為穀。", "妝容徒自麗，舞態閱誰目。惆悵繐帷空，歌聲苦於哭。"]'),
('yuding-11','太原旅懷呈薛十八侍禦齊十二奉禮','歐陽詹','唐','御定全唐诗','yuding','','[]','前來稱英雋，有食主人魚。後來曰賢才，又受主人車。',96,'御定全唐詩/json/349.json','["前來稱英雋，有食主人魚。後來曰賢才，又受主人車。", "伊予亦投刺，恩煦胡凋疏。既睹主人面，複見主人書。", "餬口百家周。賃廡三月餘。眼見寒序臻，坐送秋光除。", "西日惄饑腸，北風疾絺裾。升堂有知音，此意當何如。"]'),
('yuding-12','李評事公進示文集因贈之','歐陽詹','唐','御定全唐诗','yuding','','[]','風雅不墜地，五言始君先。希微嘉會章，杳冥河梁篇。',156,'御定全唐詩/json/349.json','["風雅不墜地，五言始君先。希微嘉會章，杳冥河梁篇。", "理蔓語無枝，言一意則千。往來更後人，澆蕩醨前源。", "傾筐實不收，朴樕華爭繁。大教護微旨，哲人生令孫。", "高飆激頹波，坐使橫流翻。昔日越重阻，側聆滄海傳。", "逮茲覿清揚，幸睹青琅編。泠泠中山醇，片片昆丘璠。", "一杯有餘味，再覽增光鮮。對寶人皆鑒，握鞶良自妍。", "吾其告先師，六義今還全。"]'),
('yuding-13','徐十八晦落第','歐陽詹','唐','御定全唐诗','yuding','','[]','嘉谷不夏熟，大器當晚成。徐生異凡鳥，安得非時鳴。',48,'御定全唐詩/json/349.json','["嘉谷不夏熟，大器當晚成。徐生異凡鳥，安得非時鳴。", "汲汲有所為，驅驅無本情。懿哉蒼梧鳳，終見排雲征。"]'),
('yuding-14','春日途中寄故園所親','歐陽詹','唐','御定全唐诗','yuding','','[]','客路度年華，故園雲未返。悠悠去源水，日日只有遠。',48,'御定全唐詩/json/349.json','["客路度年華，故園雲未返。悠悠去源水，日日只有遠。", "始歎秋葉零，又看春草晚。寄書南飛鴻，相憶劇鄉縣。"]'),
('yuding-15','蜀中將歸留辭韓相公貫之','歐陽詹','唐','御定全唐诗','yuding','','[]','寧體即雲構，方前恒玉食。貧居豈及此，要自懷歸憶。',48,'御定全唐詩/json/349.json','["寧體即雲構，方前恒玉食。貧居豈及此，要自懷歸憶。", "在夢關山遠，如流歲華逼。明晨首鄉路，迢遞孤飛翼。"]'),
('yuding-16','江夏留別華二','歐陽詹','唐','御定全唐诗','yuding','','[]','弭棹已傷別，不堪離緒催。十年一心人，千里同舟來。',48,'御定全唐詩/json/349.json','["弭棹已傷別，不堪離緒催。十年一心人，千里同舟來。", "鄉路我尚遙，客遊君未回。將何慰兩端，互勉臨岐杯。"]'),
('yuding-17','送潭州陸戶曹之任','歐陽詹','唐','御定全唐诗','yuding','','[]','三語又為掾，大家聞屈聲。多年名下人，四姓江南英。',48,'御定全唐詩/json/349.json','["三語又為掾，大家聞屈聲。多年名下人，四姓江南英。", "衡嶽半天秀，湘潭無底清。何言驅車遠，去有蒙莊情。"]'),
('yuding-18','福州送鄭楚材赴京，時監察劉公亮有感激鄭意','歐陽詹','唐','御定全唐诗','yuding','','[]','美人河岳靈，家本滎水濆。門承若蘭族，身蘊如瓊文。',120,'御定全唐詩/json/349.json','["美人河岳靈，家本滎水濆。門承若蘭族，身蘊如瓊文。", "早折青桂枝，俯窺鴻鵠群。邇來丹霄姿，遠逐蒼梧雲。", "有伊光鑒人，惜茲瑤蕙熏。中酣前激昂，四座同氛氳。", "海郡梅霪晴，山郵炎景曛。回翔罷南遊，鳴唳期西聞。", "秦塞鸞鳳征，越江雲雨分。從茲一別離，佇致如堯君。"]'),
('yuding-19','初發太原，途中寄太原所思','歐陽詹','唐','御定全唐诗','yuding','','[]','驅馬覺漸遠，回頭長路塵。高城已不見，況複城中人。',72,'御定全唐詩/json/349.json','["驅馬覺漸遠，回頭長路塵。高城已不見，況複城中人。", "去意自未甘，居情諒猶辛。五原東北晉，千里西南秦。", "一屨不出門，一車無停輪。流萍與系匏，早晚期相親。"]'),
('yuding-20','汝川行','歐陽詹','唐','御定全唐诗','yuding','','[]','汝墳春女蠶忙月，朝起采桑日西沒。輕綃裙露紅羅襪，',40,'御定全唐詩/json/349.json','["汝墳春女蠶忙月，朝起采桑日西沒。輕綃裙露紅羅襪，", "相歡誰是游冶郎，蠶休不得岐路旁。"]'),
('yuding-21','智達上人水精念珠歌','歐陽詹','唐','御定全唐诗','yuding','','[]','水已清，清中不易當其精。精華極，何宜更複加磨拭。',120,'御定全唐詩/json/349.json','["水已清，清中不易當其精。精華極，何宜更複加磨拭。", "良工磨拭成貫珠，泓澄洞澈看如無。星輝月耀莫之逾，", "既指其珠當佛身，亦欲珠明佛像智。咨董母，訪朱公。", "得之玓瓅群奇中，龍龕鷲嶺長隨躬。朝自守持纖掌透，", "連連寒溜下陰軒，熒熒泫露垂秋草。皎晶晶，彰煌煌，"]'),
('yuding-22','許州途中','歐陽詹','唐','御定全唐诗','yuding','','[]','秦川行盡潁川長，吳江越嶺已同方。征途渺渺煙茫茫，',40,'御定全唐詩/json/349.json','["秦川行盡潁川長，吳江越嶺已同方。征途渺渺煙茫茫，", "林間啼鳥野中芳，有似故園皆斷腸。"]'),
('yuding-23','賦得秋河曙耿耿送郭秀才應舉','歐陽詹','唐','御定全唐诗','yuding','','[]','月沒天欲明，秋河尚凝白。皚皚積光素，耿耿橫虛碧。',96,'御定全唐詩/json/349.json','["月沒天欲明，秋河尚凝白。皚皚積光素，耿耿橫虛碧。", "南斗接，北辰連，空蒙鴻洞浮高天。蕩蕩漫漫皆晶然，", "雞唱漏盡東方作，曲渚蒼蒼曉霜落。雁叫疑從清淺驚，", "念排雲漢將飛翻，仰之踴躍當華軒。夜來陪餞歐陽子，"]'),
('yuding-24','送袁秀才下第歸毗陵','歐陽詹','唐','御定全唐诗','yuding','','[]','羸馬出都門，修途指江東。關河昨夜雨，草木非春風。',48,'御定全唐詩/json/349.json','["羸馬出都門，修途指江東。關河昨夜雨，草木非春風。", "矢舍雖未中，璞全終待攻。層霄秋可翔，豈不隨高鴻。"]'),
('yuding-25','聞鄰舍唱涼州有所思','歐陽詹','唐','御定全唐诗','yuding','','[]','有善伊涼曲，離別在天涯。虛堂正相思，所妙發鄰家。',48,'御定全唐詩/json/349.json','["有善伊涼曲，離別在天涯。虛堂正相思，所妙發鄰家。", "聲音雖類聞，形影終以遐。因之增遠懷，惆悵菖蒲花。"]'),
('yuding-26','陪太原鄭行軍中丞登汾上閣中丞詩曰「汾樓秋水闊宛似到閶門惆悵江湖思，惟將南客論」南客即詹也輒書即事上答','歐陽詹','唐','御定全唐诗','yuding','','[]','並州汾上閣，登望似吳閶。貫郭河通路，縈村水逼鄉。',48,'御定全唐詩/json/349.json','["並州汾上閣，登望似吳閶。貫郭河通路，縈村水逼鄉。", "城槐臨枉渚，巷市接飛梁。莫論江湖思，南人正斷腸。"]'),
('yuding-27','送少微上人歸德峰','歐陽詹','唐','御定全唐诗','yuding','','[]','不負人間累，棲身任所從。灰心聞密行，菜色見羸容。',48,'御定全唐詩/json/349.json','["不負人間累，棲身任所從。灰心聞密行，菜色見羸容。", "幻世方同悟，深居願繼蹤。孤雲與禪誦，到後在何峰。"]'),
('yuding-28','荊南夏夜水樓懷昭丘直上人雲夢李莘','歐陽詹','唐','御定全唐诗','yuding','','[]','無機成旅逸，中夜上江樓。雲盡月如練，水涼風似秋。',48,'御定全唐詩/json/349.json','["無機成旅逸，中夜上江樓。雲盡月如練，水涼風似秋。", "鳧聲聞夢澤，黛色上昭丘。不遠人情在，良宵恨獨遊。"]'),
('yuding-29','酬裴十二秀才孩子詠','歐陽詹','唐','御定全唐诗','yuding','','[]','算日未成年，英姿已褎然。王家千里後，荀氏八龍先。',48,'御定全唐詩/json/349.json','["算日未成年，英姿已褎然。王家千里後，荀氏八龍先。", "蔥蒨松猶嫩，清明月漸圓。將何一枝桂，容易賞名賢。"]'),
('yuding-30','旅次舟中對月寄薑公','歐陽詹','唐','御定全唐诗','yuding','','[]','中宵天色淨，片月出滄洲。皎潔臨孤島，嬋娟入亂流。',48,'御定全唐詩/json/349.json','["中宵天色淨，片月出滄洲。皎潔臨孤島，嬋娟入亂流。", "應同故園夜，獨起異鄉愁。那得休蓬轉，從君上庾樓。"]'),
('yuding-31','除夜長安客舍','歐陽詹','唐','御定全唐诗','yuding','','[]','十上書仍寢，如流歲又遷。望家思獻壽，算甲恨長年。',48,'御定全唐詩/json/349.json','["十上書仍寢，如流歲又遷。望家思獻壽，算甲恨長年。", "虛牖傳寒柝，孤燈照絕編。誰應問窮轍，泣盡更潸然。"]'),
('yuding-32','早秋登慈恩寺塔','歐陽詹','唐','御定全唐诗','yuding','','[]','寶塔過千仞，登臨盡四維。毫端分馬頰，墨點辨蛾眉。',48,'御定全唐詩/json/349.json','["寶塔過千仞，登臨盡四維。毫端分馬頰，墨點辨蛾眉。", "地迥風彌緊，天長日久遲。因高欲有賦，遠意慘生悲。"]'),
('yuding-33','太原和嚴長官八月十五日夜西山童子上方玩月寄中丞少尹','歐陽詹','唐','御定全唐诗','yuding','','[]','西寺碧雲端，東溟白雪團。年來一夜玩，君在半天看。',48,'御定全唐詩/json/349.json','["西寺碧雲端，東溟白雪團。年來一夜玩，君在半天看。", "素魄當懷上，清光在下寒。宜裁濟江什，有阻惠連歡。"]'),
('yuding-34','九日廣陵同陳十五先輩登高懷林十二先輩','歐陽詹','唐','御定全唐诗','yuding','','[]','客路重陽日，登高寄上樓。風煙今令節，台閣古雄州。',48,'御定全唐詩/json/349.json','["客路重陽日，登高寄上樓。風煙今令節，台閣古雄州。", "泛菊聊斟酒，持萸懶插頭。情人共惆悵，良久不同遊。"]'),
('yuding-35','題嚴光釣台','歐陽詹','唐','御定全唐诗','yuding','','[]','弭棹曆塵跡，悄然關我情。伊無昔時節，豈有今日名。',48,'御定全唐詩/json/349.json','["弭棹曆塵跡，悄然關我情。伊無昔時節，豈有今日名。", "辭貴不辭賤，是心誰複行。欽哉此溪曲，永獨古風清。"]'),
('yuding-36','送高士安下第歸岷南寧覲','歐陽詹','唐','御定全唐诗','yuding','','[]','偕隱有賢親，岷南四十春。棲雲自匪石，觀國暫同塵。',48,'御定全唐詩/json/349.json','["偕隱有賢親，岷南四十春。棲雲自匪石，觀國暫同塵。", "就養思兒戲，延年愛鳥伸。還看謝時去，有類潁陽人。"]'),
('yuding-37','述德上興元嚴僕射','歐陽詹','唐','御定全唐诗','yuding','','[]','山橫碧立並雄岷，大阜洪川共降神。心合雲雷清禍亂，',40,'御定全唐詩/json/349.json','["山橫碧立並雄岷，大阜洪川共降神。心合雲雷清禍亂，", "何幸腐儒無一藝，得為門下食魚人。"]'),
('yuding-38','及第後酬故園親故','歐陽詹','唐','御定全唐诗','yuding','','[]','才非天授學非師，以此成名曩豈期。楊葉射頻因偶中，',40,'御定全唐詩/json/349.json','["才非天授學非師，以此成名曩豈期。楊葉射頻因偶中，", "猶著褐衣何足羨，如君即是載鳴時。"]'),
('yuding-39','題華十二判官汝州宅內亭','歐陽詹','唐','御定全唐诗','yuding','','[]','高居勝景誰能有，佳意幽情共可歡。新柳繞門青翡翠，',40,'御定全唐詩/json/349.json','["高居勝景誰能有，佳意幽情共可歡。新柳繞門青翡翠，", "只在城隍也趨府，豈如吾子道斯安。"]'),
('yuding-40','薛舍人使君觀察韓判官侍禦許雨晴到所居既霽先呈即事','歐陽詹','唐','御定全唐诗','yuding','','[]','江皋昨夜雨收梅，寂寂衡門與釣台。西島落花隨水至，',40,'御定全唐詩/json/349.json','["江皋昨夜雨收梅，寂寂衡門與釣台。西島落花隨水至，", "豈不偶然聊為竹，空令石徑掃莓苔。"]'),
('yuding-41','元日陪早朝','歐陽詹','唐','御定全唐诗','yuding','','[]','斗柄東回歲又新，邃旒南面挹來賓。和光仿佛樓臺曉，',40,'御定全唐詩/json/349.json','["斗柄東回歲又新，邃旒南面挹來賓。和光仿佛樓臺曉，", "江皋腐草今何幸，亦與恒星拱北辰。"]'),
('yuding-42','和太原鄭中丞登龍興寺閣','歐陽詹','唐','御定全唐诗','yuding','','[]','青窗朱戶半天開，極目凝神望幾回。晉國頹墉生草樹，',40,'御定全唐詩/json/349.json','["青窗朱戶半天開，極目凝神望幾回。晉國頹墉生草樹，", "獨恨侍游違長者，不知高意是誰陪。"]'),
('yuding-43','詠德上太原李尚書','歐陽詹','唐','御定全唐诗','yuding','','[]','那以公方郭細侯，並州非復舊並州。九重帝宅司丹地，',40,'御定全唐詩/json/349.json','["那以公方郭細侯，並州非復舊並州。九重帝宅司丹地，", "王褒見德空知頌，身在三千最上頭。"]'),
('yuding-44','和嚴長官秋日登太原龍興寺閣野望','歐陽詹','唐','御定全唐诗','yuding','','[]','百丈化城樓，君登最上頭。九霄回棧路，八到視並州。',96,'御定全唐詩/json/349.json','["百丈化城樓，君登最上頭。九霄回棧路，八到視並州。", "煙火遺堯庶，山河啟聖猷。短垣齊介嶺，片白指分流。", "清鐸中天籟，哀鳴下界秋。境閑知道勝，心遠見名浮。", "豈念乘肥馬，方應駕大牛。自憐蓬逐吹，不得與良遊。"]'),
('yuding-45','小苑春望宮池柳色','歐陽詹','唐','御定全唐诗','yuding','','[]','東風韶景至，垂柳禦溝新。媚作千門秀，連為一道春。',72,'御定全唐詩/json/349.json','["東風韶景至，垂柳禦溝新。媚作千門秀，連為一道春。", "柔荑生女指，嫩葉長龍鱗。舞絮回青岸，翻煙拂綠蘋。", "王孫初命賞，佳客欲傷神。芳意堪相贈，一枝先遠人。"]'),
('yuding-46','蜀門與林蘊分路後屢有山川似閩中因寄林蘊蘊亦閩人也','歐陽詹','唐','御定全唐诗','yuding','','[]','村步如延壽，川原似福平。無人相共識，獨自故鄉情。',24,'御定全唐詩/json/349.json','["村步如延壽，川原似福平。無人相共識，獨自故鄉情。"]'),
('yuding-47','讀周太公傳','歐陽詹','唐','御定全唐诗','yuding','','[]','論兵去商虐，講德興周道。屠沽未遇時，豈異茲川老。',24,'御定全唐詩/json/349.json','["論兵去商虐，講德興周道。屠沽未遇時，豈異茲川老。"]'),
('yuding-48','樂津店北陂','歐陽詹','唐','御定全唐诗','yuding','','[]','嬋娟有麗玉如也，美笑當予系予馬。',32,'御定全唐詩/json/349.json','["嬋娟有麗玉如也，美笑當予系予馬。", "羅幃碧簟豈相容，行到山頭憶山下。"]'),
('yuding-49','出蜀門','歐陽詹','唐','御定全唐诗','yuding','','[]','北客今朝出蜀門，翛然領得入時魂。',32,'御定全唐詩/json/349.json','["北客今朝出蜀門，翛然領得入時魂。", "遊人莫道歸來易，三不曾聞古老言。"]'),
('yuding-50','題第五司戶侍禦','歐陽詹','唐','御定全唐诗','yuding','','[]','曾稱野鶴比群公，忽作長松向府中。',32,'御定全唐詩/json/349.json','["曾稱野鶴比群公，忽作長松向府中。", "驄馬不騎人不識，泠然三尺別生風。"]'),
('yuding-51','建溪行待陳詡','歐陽詹','唐','御定全唐诗','yuding','','[]','偕行那得會心期，先者貪前後者遲。',32,'御定全唐詩/json/349.json','["偕行那得會心期，先者貪前後者遲。", "空憶麗詞能狀物，每看奇異但相思。"]'),
('yuding-52','述德上興元嚴僕射','歐陽詹','唐','御定全唐诗','yuding','','[]','推車閫外主恩新，今日梁川草遍春。',32,'御定全唐詩/json/349.json','["推車閫外主恩新，今日梁川草遍春。", "玉色據鞍雙節下，揚兵百萬路無塵。"]'),
('yuding-53','許州送張中丞出臨潁鎮','歐陽詹','唐','御定全唐诗','yuding','','[]','心誦陰符口不言，風驅千騎出轅門。',32,'御定全唐詩/json/349.json','["心誦陰符口不言，風驅千騎出轅門。", "孫吳去後無長策，誰敵留侯直下孫。"]'),
('yuding-54','睹亡友題詩處','歐陽詹','唐','御定全唐诗','yuding','','[]','舊友親題壁上詩，傷看緣跡不緣詞。',32,'御定全唐詩/json/349.json','["舊友親題壁上詩，傷看緣跡不緣詞。", "門前猶是長安道，無複回車下筆時。"]'),
('yuding-55','題秦嶺','歐陽詹','唐','御定全唐诗','yuding','','[]','南下斯須隔帝鄉，北行一步掩南方。',32,'御定全唐詩/json/349.json','["南下斯須隔帝鄉，北行一步掩南方。", "悠悠煙景兩邊意，蜀客秦人各斷腸。"]'),
('yuding-56','自南山卻赴京師，石臼嶺頭即事寄嚴僕射','歐陽詹','唐','御定全唐诗','yuding','','[]','鳥企蛇盤地半天，下窺千仞到浮煙。',32,'御定全唐詩/json/349.json','["鳥企蛇盤地半天，下窺千仞到浮煙。", "因高回望沾恩處，認得梁州落日邊。"]'),
('yuding-57','與洪孺卿自梁州迴途中經駱谷見野果有閩中懸壼子即同採摘因呈之洪亦閩人','歐陽詹','唐','御定全唐诗','yuding','','[]','青苞朱實忽離離，摘得盈筐淚更垂。',32,'御定全唐詩/json/349.json','["青苞朱實忽離離，摘得盈筐淚更垂。", "上德同之豈無意，故園山路一枝枝。"]'),
('yuding-58','韋晤宅聽歌','歐陽詹','唐','御定全唐诗','yuding','','[]','服制虹霓鬢似雲，蕭郎屋裏上清人。',32,'御定全唐詩/json/349.json','["服制虹霓鬢似雲，蕭郎屋裏上清人。", "等閒逐酒傾杯樂，飛盡虹梁一夜塵。"]'),
('yuding-59','與林蘊同之蜀途次嘉陵江認得越鳥聲呈林林亦閩中人也','歐陽詹','唐','御定全唐诗','yuding','','[]','正是閩中越鳥聲，幾回留聽暗沾纓。',32,'御定全唐詩/json/349.json','["正是閩中越鳥聲，幾回留聽暗沾纓。", "傷心激念君深淺，共有離鄉萬里情。"]'),
('yuding-60','送聞上人游嵩山','歐陽詹','唐','御定全唐诗','yuding','','[]','二室峰峰昔願遊，從雲從鶴思悠悠。',32,'御定全唐詩/json/349.json','["二室峰峰昔願遊，從雲從鶴思悠悠。", "丹梯石路君先去，為上青冥最上頭。"]'),
('yuding-61','永安寺照上人房','歐陽詹','唐','御定全唐诗','yuding','','[]','草席蒲團不掃塵，松閑石上似無人。',32,'御定全唐詩/json/349.json','["草席蒲團不掃塵，松閑石上似無人。", "群陰欲午鐘聲動，自煮溪蔬養幻身。"]'),
('yuding-62','山中老僧','歐陽詹','唐','御定全唐诗','yuding','','[]','笑向來人話古時，繩床竹杖自扶持。',32,'御定全唐詩/json/349.json','["笑向來人話古時，繩床竹杖自扶持。", "秋深頭冷不能剃，白黑蒼然發到眉。"]'),
('yuding-63','贈魯山李明府','歐陽詹','唐','御定全唐诗','yuding','','[]','外戶通宵不閉關，抱孫弄子萬家閑。',32,'御定全唐詩/json/349.json','["外戶通宵不閉關，抱孫弄子萬家閑。", "若將邑號稱賢宰，又是皇唐李魯山。"]'),
('yuding-64','泉州赴上都留別舍弟及故人','歐陽詹','唐','御定全唐诗','yuding','','[]','天長地闊多岐路，身即飛蓬共水萍。',32,'御定全唐詩/json/349.json','["天長地闊多岐路，身即飛蓬共水萍。", "匹馬將驅豈容易，弟兄親故滿離亭。"]'),
('yuding-65','送張驃騎邠甯行營','歐陽詹','唐','御定全唐诗','yuding','','[]','寶馬雕弓金僕姑，龍驤虎視出皇都。',32,'御定全唐詩/json/349.json','["寶馬雕弓金僕姑，龍驤虎視出皇都。", "揚鞭莫怪輕胡虜，曾在漁陽敵萬夫。"]');
